-- Poems batch 247
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('2d929f34-97f9-4050-987d-82688dce26ba','避難周姓家席地而眠偶成','陳著','宋','宋诗','song-poetry','','[]','夜宿山家謝主翁，安排席藁地爐東。',64,'全唐诗/poet.song.223000.json','["夜宿山家謝主翁，安排席藁地爐東。", "枕頭就借支機石，帕額聊防箭隙風。", "酒甕下眠添古話，牛衣中卧有時通。", "老吾看破人閒事，錦帳牙牀總是空。"]'),
('dfda332b-cf0a-41f5-bd9d-61dbb213bf13','周翁留飲酒','陳著','宋','宋诗','song-poetry','','[]','曉對山翁坐破窗，地爐撥火兩相忘。',64,'全唐诗/poet.song.223000.json','["曉對山翁坐破窗，地爐撥火兩相忘。", "茅柴酒與人情好，蘿蔔羹和野味長。", "外面干戈何日定，前頭尺寸逐時量。", "而今難說山居穩，飛馬窮搜過虎狼。"]'),
('31fc557f-6392-430d-97f0-56d8a12a0ae0','余牀帳爲過兵捲去答梅山弟用余韻見寄','陳著','宋','宋诗','song-poetry','','[]','一牀破帳護衰翁，席捲俄隨掠騎東。',64,'全唐诗/poet.song.223000.json','["一牀破帳護衰翁，席捲俄隨掠騎東。", "與婦同圍膚炭火，呼兒排作肉屏風。", "從來不起羊羔想，困倒何妨蝶夢通。", "亂世流離多露宿，蓋頭有屋未爲空。"]'),
('f4994bd5-351f-4aa6-9b9b-58087d138c80','十一月八日渾家避難周姓家終夜以榾柮火爲禦寒之具','陳著','宋','宋诗','song-poetry','','[]','獸炭銀山醉夢鄉，何如榾柮地爐裝。',64,'全唐诗/poet.song.223000.json','["獸炭銀山醉夢鄉，何如榾柮地爐裝。", "微煙暖火權春燠，錯節盤根傲夜長。", "夙許孤寒陪暖席，不將光燄買烘堂。", "風饕雪虐天昏黑，獨占山家一脈陽。"]'),
('4127f3bb-68b6-423c-9148-6d36bb60e73d','長至日山家偶成','陳著','宋','宋诗','song-poetry','','[]','疇昔隨班舞御香，如今忍凍坐山房。',64,'全唐诗/poet.song.223000.json','["疇昔隨班舞御香，如今忍凍坐山房。", "臺雲誰取書黄瑞，宮日空舒刺繡光。", "懶把酒杯心自醉，閒欹肱枕意何長。", "晚窗閉眼消詳易，頼有生生不斷腸。"]'),
('7a7aab73-b611-447e-828b-b73bbb02f5a1','次韻內兄舒通叟太博寓雲南僧舍','陳著','宋','宋诗','song-poetry','','[]','河海翻飛信有由，相逢莫學楚囚愁。',64,'全唐诗/poet.song.223000.json','["河海翻飛信有由，相逢莫學楚囚愁。", "人方椎髻說蘇子，天把布衣存武侯。", "世變古今張與翕，人心造化去中留。", "雲南高處應看透，許得溪翁入坐不。"]'),
('cf70890f-51cb-4e2d-ada0-d9dde379835d','又次前韻','陳著','宋','宋诗','song-poetry','','[]','吁嗟天數不人由，舉目江河萬里愁。',64,'全唐诗/poet.song.223000.json','["吁嗟天數不人由，舉目江河萬里愁。", "爲厲可無忠義鬼，覓封忍見笑談侯。", "功名只作無時看，氣節須從險處留。", "歸去來辭非浪賦，曾知此老此心不。"]'),
('41f28843-09a9-433d-ad3a-263f2ca956e4','三次書懷','陳著','宋','宋诗','song-poetry','','[]','默察天翻地覆由，寸心無處著私愁。',64,'全唐诗/poet.song.223000.json','["默察天翻地覆由，寸心無處著私愁。", "忠唐不復瞻雙廟，誤漢皆知罪五侯。", "牧馬入南飛浙水，狩車遵北感陳留。", "山川滿目花如舊，邂逅春風可問不。"]'),
('6ad5c84b-cbe0-40fb-96c3-86e93631af2f','四次寄意','陳著','宋','宋诗','song-poetry','','[]','正大從來不徑由，窮崖今却伴猨愁。',64,'全唐诗/poet.song.223000.json','["正大從來不徑由，窮崖今却伴猨愁。", "棲棲宇內知師孔，吃吃人閒愛說侯。", "昨夜撞鐘搜句到，他年籠壁把名留。", "崆峒麥熟關時事，此意還曾入詠不。"]'),
('b4843131-f337-437a-8c50-6fa0d5596515','聞西兵復至又爲逃隠計二首  其一','陳著','宋','宋诗','song-poetry','','[]','千邨奔走浪塵沙，又報西兵沸鼓笳。',64,'全唐诗/poet.song.223000.json','["千邨奔走浪塵沙，又報西兵沸鼓笳。", "厄會有誰知死所，危途無處問生涯。", "孤鐙閉戶一山雨，遠夢當書三處家。", "最怕入深饑莫忍，難逢流水出胡麻。"]'),
('e5afe679-2346-439d-9f67-da75888711f9','聞西兵復至又爲逃隠計二首  其二','陳著','宋','宋诗','song-poetry','','[]','軍屯多似撒星沙，夜月猶聞奏月笳。',64,'全唐诗/poet.song.223000.json','["軍屯多似撒星沙，夜月猶聞奏月笳。", "尚有空囊隨杜甫，幸無複壁累王涯。", "草根木實逃生飯，石室泥龕到處家。", "天下蒼生是誰誤，當年悔不壞庭麻。"]'),
('eb1e53a7-cf0a-4913-bc5f-43f92c42886f','中和節寓山菴','陳著','宋','宋诗','song-poetry','','[]','小菴亦是小桃源，時事方難住更便。',64,'全唐诗/poet.song.223000.json','["小菴亦是小桃源，時事方難住更便。", "啼鳥落花忘客主，青山流水見因緣。", "得過一日是一日，浪說百年誰百年。", "分付妻兒更深避，掃巖趺坐學枯禪。"]'),
('8a2731d9-2382-4ccd-9a54-951c9af58f70','二月十八日過邑有感二首  其一','陳著','宋','宋诗','song-poetry','','[]','植杖東風立曉寒，淒其極目甚窮邊。',64,'全唐诗/poet.song.223000.json','["植杖東風立曉寒，淒其極目甚窮邊。", "黑塵猶暗新焦土，青日無光老晦天。", "花鳳逢春誰借景，杜鵑懷古自啼年。", "吾今且忍須臾死，得見昇平或有緣。"]'),
('521d004d-3db6-4dd0-a0e0-911df2f6eba1','二月十八日過邑有感二首  其二','陳著','宋','宋诗','song-poetry','','[]','說著時難心自寒，斜陽焦土更無邊。',64,'全唐诗/poet.song.223000.json','["說著時難心自寒，斜陽焦土更無邊。", "故家空夢鶑花地，殘戶不成蠶麥天。", "造物未應終絕物，今年莫省是何年。", "鬰攸獨免侵鄉校，也向斯文要結緣。"]'),
('a0422dbc-1f9f-4f04-808c-233eb46357f6','次韻梅山弟感時四首  其一','陳著','宋','宋诗','song-poetry','','[]','吟情本是謝玄暉，邂逅年來世事非。',64,'全唐诗/poet.song.223000.json','["吟情本是謝玄暉，邂逅年來世事非。", "到處望風千甲解，無人留日一戈揮。", "杜鵑入洛啼拌死，鴻雁辭南去有歸。", "浩蕩春光天萬里，孤雲葉葉向誰飛。"]'),
('3c312edc-a160-44dd-b484-5ca3f687761a','次韻梅山弟感時四首  其二','陳著','宋','宋诗','song-poetry','','[]','世事滔滔趁夕暉，仰天咄咄付非非。',64,'全唐诗/poet.song.223000.json','["世事滔滔趁夕暉，仰天咄咄付非非。", "乾坤誰解中撐拄，江海方聽北指揮。", "風舞南人新萬戶，灰颺西嶺舊三歸。", "只應天竺孤峯在，一自飛來不更飛。"]'),
('ce16345d-3fab-4f68-8c1b-812068b3dbb7','次韻梅山弟感時四首  其三','陳著','宋','宋诗','song-poetry','','[]','春造曾分寸草暉，晚經霜雪始知非。',64,'全唐诗/poet.song.223000.json','["春造曾分寸草暉，晚經霜雪始知非。", "中心痛事神孤往，前面虛名手一揮。", "肯使曉猨隨隴笑，不煩倦鳥引雲歸。", "絕糧只管餐松菊，贏得身輕入險飛。"]'),
('322fe8f1-e4f5-4951-883f-dc3e0529308d','次韻梅山弟感時四首  其四','陳著','宋','宋诗','song-poetry','','[]','邊將才無日越暉，中朝人是李斯非。',64,'全唐诗/poet.song.223000.json','["邊將才無日越暉，中朝人是李斯非。", "順流兵馬竟掀舞，死戰規模誰發揮。", "忍看金莖移露去，空歌玉樹送春歸。", "不圖世變今如此，真與塵埃蠓蚋飛。"]'),
('5a0f7051-3250-4bcc-9e4d-dec2f0aa05b8','次韻董伯和二首  其一','陳著','宋','宋诗','song-poetry','','[]','事難言處只長吁，沸海烹煎一鼎如。',64,'全唐诗/poet.song.223000.json','["事難言處只長吁，沸海烹煎一鼎如。", "貧累轉添知有命，故交自絕本無書。", "仕方見境大槐蟻，走不離鄉千里魚。", "已分歸農謀半菽，尚憂龍歲起秦閭。"]'),
('c4ba83dd-d6c2-415f-9b6a-f55e8c0063c3','次韻董伯和二首  其二','陳著','宋','宋诗','song-poetry','','[]','時難何必苦嗟吁，自有山莊只自如。',64,'全唐诗/poet.song.223000.json','["時難何必苦嗟吁，自有山莊只自如。", "行擔應携杏花譜，閉門堪著竹林書。", "行觀塵外乘風鶴，坐看人閒減水魚。", "宇宙平安終有日，却從舊卜大門閭。"]'),
('d3a66260-2500-4e53-a116-4fa5c5c9f99d','次韻弟觀到蔡峰莊','陳著','宋','宋诗','song-poetry','','[]','簇簇羣山似鐵圍，中閒著屋與山依。',64,'全唐诗/poet.song.223000.json','["簇簇羣山似鐵圍，中閒著屋與山依。", "園多芋栗佐清飲，池足芰荷供隠衣。", "疇昔搬家牛自跨，有時見客鶴先飛。", "未宜回首林邱舊，賸把詩脾厭翠微。"]'),
('47d18bd9-dc82-4cc8-ac6b-03fbb2318c52','次韻前人寒食','陳著','宋','宋诗','song-poetry','','[]','今年寒食倍心寒，不獨松楸感涕潸。',64,'全唐诗/poet.song.223000.json','["今年寒食倍心寒，不獨松楸感涕潸。", "青草遥悲新瘞塚，蒼梧錯認舊來山。", "人生醉夢乾坤裏，時節晦冥風雨閒。", "只有杜鵑知此意，傍雲啼去又啼還。"]'),
('5bc77bd0-7320-4a5c-a4c9-97bdd59c215f','次韻前人訪舊','陳著','宋','宋诗','song-poetry','','[]','鐵石心腸本自頑，著身無所奈時艱。',64,'全唐诗/poet.song.223000.json','["鐵石心腸本自頑，著身無所奈時艱。", "仙丹難問桃花洞，詩笠聊尋飯顆山。", "道義豈隨天地閉，風埃不放水雲閒。", "相逢休說如今事，回首斜陽古漢關。"]'),
('4c3d4d6c-7222-419c-8c21-c04eb4fb0185','次韻前人傷古','陳著','宋','宋诗','song-poetry','','[]','當年天與袴中兒，天到如今不與時。',64,'全唐诗/poet.song.223000.json','["當年天與袴中兒，天到如今不與時。", "事變風濤掀地軸，軍聲電雹散雷槌。", "鬼藍柄國苦相誤，佛會守城甘自癡。", "旗蓋已隨□駕去，留西太乙更誰欺。"]'),
('45f0b1d4-c2aa-48aa-9726-88c8983a959f','次韻前人形役','陳著','宋','宋诗','song-poetry','','[]','誰能禪寂效裴休，自愛清名慕李舟。',64,'全唐诗/poet.song.223000.json','["誰能禪寂效裴休，自愛清名慕李舟。", "雲路中年開轍迹，風波晚歲轉船頭。", "見花如刺時難痛，遇事生根老滯憂。", "但欲漁樵相爾汝，怕人知我問來由。"]'),
('878038f6-9b9b-4f71-b3c6-f72b0aca8550','春晚課摘茶','陳著','宋','宋诗','song-poetry','','[]','玉川子後是吾生，自課園中拾晚榮。',64,'全唐诗/poet.song.223000.json','["玉川子後是吾生，自課園中拾晚榮。", "攙雨金芒排世好，飽春香瓣見天成。", "不煩鉦鼓騰山噉，賸有旗鎗戰酒兵。", "鳳舞賜團今絕想，只憑苦硬養幽清。"]'),
('d4ac4cf7-b90c-4440-ab21-f61c3f5d7924','次韻梅山弟感時','陳著','宋','宋诗','song-poetry','','[]','翳日腥雲澒洞塵，是雖天做亦由人。',64,'全唐诗/poet.song.223000.json','["翳日腥雲澒洞塵，是雖天做亦由人。", "難禁老淚如囚楚，忍託空言寫過秦。", "風雪正培陽氣脈，山林幸有歲寒身。", "功名已付無何有，要及餘光耕富春。"]'),
('d1dc1c7d-8e95-4c89-8aee-f8e64d679add','三月二十五日醵飲於西峰寺分韻得因字','陳著','宋','宋诗','song-poetry','','[]','牢穿不借踏青晨，信與林泉有夙因。',64,'全唐诗/poet.song.223000.json','["牢穿不借踏青晨，信與林泉有夙因。", "忙裏偶成真率會，醉來不省亂離身。", "歸途西嶺何妨晚，吹雨南風正送春。", "燒筍煮茶須再到，一山古意要詩人。"]'),
('8b2d60ce-3504-4db9-9932-222e74373508','次韻董聲可重五','陳著','宋','宋诗','song-poetry','','[]','人事俄隨世事殊，尚存榴艾伴嘻吁。',64,'全唐诗/poet.song.223000.json','["人事俄隨世事殊，尚存榴艾伴嘻吁。", "懷沙到處哀新鬼，瑞市何時見醉夫。", "榮賜休思當暑葛，早衰空感望秋蒲。", "辟兵禁惡□兒戲，無計能逃急急符。"]'),
('04d107f8-1a61-47cb-94ef-3642cad78fb5','次韻弟觀喜雨二首  其一','陳著','宋','宋诗','song-poetry','','[]','天敕龍瓢到底傾，阿香飛駕會蒼冥。',64,'全唐诗/poet.song.223000.json','["天敕龍瓢到底傾，阿香飛駕會蒼冥。", "風霆震疊四溟立，宇宙清凉萬物醒。", "行蟻知幾先畏濕，升蝸向上漫遺腥。", "平生霖雨蒼生志，對景空懷海上亭。"]'),
('83a0d75f-92b3-4957-bae5-15f1250a8749','次韻弟觀喜雨二首  其二','陳著','宋','宋诗','song-poetry','','[]','世事紛紛付渺茫，且迎雨信看農忙。',64,'全唐诗/poet.song.223000.json','["世事紛紛付渺茫，且迎雨信看農忙。", "鳩聲隔樹宿雲濕，牛影落田新水凉。", "處處叢祠羣卜稼，家家蓐食早炊糧。", "及時種得苗青活，便覺秋風飯粒香。"]'),
('5a446887-95a1-475f-8bed-279b722bfa8d','感時二首  其一','陳著','宋','宋诗','song-poetry','','[]','國事如今到底輸，九天難叩哭窮途。',64,'全唐诗/poet.song.223000.json','["國事如今到底輸，九天難叩哭窮途。", "精忠無一郭中令，異志居多劉寄奴。", "經哨地空如大漠，逃生山險甚飛狐。", "回頭鐘鼎王侯宅，今是誰人便豢芻。"]'),
('b14eb77b-eed2-4f47-b165-5fef3ca6180b','感時二首  其二','陳著','宋','宋诗','song-poetry','','[]','一點忠忱無處輸，與滔滔者走危途。',64,'全唐诗/poet.song.223000.json','["一點忠忱無處輸，與滔滔者走危途。", "新聲感泣尚書客，破鏡傳盟公主奴。", "流散莫非中澤雁，死亡誰是首邱狐。", "平生師友多黄土，吞哭何曾奠束芻。"]'),
('665d69cd-f09b-4b11-8555-279e6cf79517','六月六日倪{奥/田}菴坐雨','陳著','宋','宋诗','song-poetry','','[]','山外黄塵不到門，南風松竹翠紛紛。',64,'全唐诗/poet.song.223000.json','["山外黄塵不到門，南風松竹翠紛紛。", "暗中有虎村嗥合，夜半聞雞老睡分。", "带得兒來同坐雨，飛歸家去欲排雲。", "收書忽報今朝喜，病女加餐藥奏勳。"]'),
('9ef5d9aa-59d2-4fff-8e4d-ab1746e3f1e3','九月十日醵飲丹山','陳著','宋','宋诗','song-poetry','','[]','舉頭又是菊花天，走遍山林命苟全。',64,'全唐诗/poet.song.223000.json','["舉頭又是菊花天，走遍山林命苟全。", "忍賦庚寅傷亂世，漫書甲子記流年。", "陶籬一醉虛拋久，蕭寺重遊夢覺然。", "今是何時成此會，教人平地說神仙。"]'),
('e6122498-af01-4b18-ba1b-4c8944f80c16','次韻賦南山廣莫軒','陳著','宋','宋诗','song-poetry','','[]','洗眼來看廣莫詩，煙霏空翠雨微微。',64,'全唐诗/poet.song.223000.json','["洗眼來看廣莫詩，煙霏空翠雨微微。", "四平地上一山起，獨拄天南羣望歸。", "喬木不隨兵燄動，好雲時入寺門飛。", "乾坤浩蕩難言處，猛拍闌干閣口機。"]'),
('f728fe1c-ac1a-43e6-bdb1-8bf543efc83b','次韻梅山弟詠梅','陳著','宋','宋诗','song-poetry','','[]','冬塞方嚴春自通，老根芳脈與天融。',64,'全唐诗/poet.song.223000.json','["冬塞方嚴春自通，老根芳脈與天融。", "清於仙李月梁上，瘦似神蘇雪窖中。", "庾嶺依然開信早，孤山無復課詩工。", "一枝在手驛風遠，渺渺予懷誰與同。"]'),
('0ac7d988-0b7d-491a-afab-45e404495d3e','雪中偶成','陳著','宋','宋诗','song-poetry','','[]','寒光晧晧照殘年，方信人閒別有天。',64,'全唐诗/poet.song.223000.json','["寒光晧晧照殘年，方信人閒別有天。", "一色邨中見流水，半乾屋上有炊烟。", "洛人僵卧今誰問，塞馬飛馳正自便。", "想得南枝梅好在，風檐獨立思悠然。"]'),
('4bf623d4-8112-401a-ab50-042585616d03','次韻弟觀雪中二首  其一','陳著','宋','宋诗','song-poetry','','[]','翦耳嚴風利似刀，吹噓滕六做功勞。',64,'全唐诗/poet.song.223000.json','["翦耳嚴風利似刀，吹噓滕六做功勞。", "大包天地爲一色，老盡山林無二毛。", "借煖尚能賒綠蟻，禦寒終不羨裘羔。", "天涯多少窮途客，欲寄書難雁影高。"]'),
('45a20fc0-1651-402a-9309-979bf40401ff','次韻弟觀雪中二首  其二','陳著','宋','宋诗','song-poetry','','[]','萬里長天一樣雲，紛紛吹下玉成塵。',64,'全唐诗/poet.song.223000.json','["萬里長天一樣雲，紛紛吹下玉成塵。", "能令下界皆稱瑞，誰謂南人不識真。", "積凍已多爲麥地，培湯更辦百花春。", "强將光景寬衰老，呵手微吟意欠新。"]'),
('094a73d0-774b-4823-b839-472be298a968','送江瑶與人','陳著','宋','宋诗','song-poetry','','[]','玉瑶分自海仙匳，藜腹新來約束嚴。',64,'全唐诗/poet.song.223000.json','["玉瑶分自海仙匳，藜腹新來約束嚴。", "入手頗憂窮鬼捩，收涎已絕老饕饜。", "何妨带甲歸庖慣，相與調珍助齒甜。", "要識淡中滋味永，多加椒酒少施鹽。"]'),
('a3e490a1-f3f4-4abc-bfb4-d0093802782b','正月四日到張車偶成','陳著','宋','宋诗','song-poetry','','[]','晴行半日到張車，石路崎嶇趁水斜。',64,'全唐诗/poet.song.223000.json','["晴行半日到張車，石路崎嶇趁水斜。", "一窟山中成草市，數株松下見梅花。", "居民盡老他無事，就土爲生自有涯。", "誰料如今同沸鼎，不時飛馬漲塵沙。"]'),
('d4dff140-e414-4b5f-873b-66e42839167b','正月五日訪王韋軒知府東塢真詔道中','陳著','宋','宋诗','song-poetry','','[]','晴光欲雪做新元，訪舊西來第一番。',64,'全唐诗/poet.song.223000.json','["晴光欲雪做新元，訪舊西來第一番。", "十五里行千曲路，兩三處見數家邨。", "山培浮土爲田肉，澗束湍流有石痕。", "安穩不知危世事，更從何處覓桃源。"]'),
('183d4531-50bd-447c-8d28-b61a27ac2e5e','次韻董伯和鐙夕有感二首  其一','陳著','宋','宋诗','song-poetry','','[]','萬鐙無復豔端門，一簇星毬里域春。',64,'全唐诗/poet.song.223000.json','["萬鐙無復豔端門，一簇星毬里域春。", "羌調悲酸吹笛社，邨聲祥瑞賣餳人。", "鬼神亦要民心樂，山谷聊舒世態顰。", "最好今宵天上月，安知時事有陳新。"]'),
('a6c46ee1-a7da-4d8f-9bd3-1dd1739d4eac','次韻董伯和鐙夕有感二首  其二','陳著','宋','宋诗','song-poetry','','[]','數枝鐙火古祠門，妝點山中一鬨春。',64,'全唐诗/poet.song.223000.json','["數枝鐙火古祠門，妝點山中一鬨春。", "俚語爲求蠶麥福，隊遊多是布荆人。", "强隨戲鼓看狂舞，忍聽嘶鼙入小顰。", "見說九街羅綺地，傳呼禁夜令方新。"]'),
('29d0c983-1a40-4cb4-a762-cfada6cd2119','次韻董三餘約賞月丹瑞香','陳著','宋','宋诗','song-poetry','','[]','老仙平日鍊心丹，荏苒光陰百歲閒。',64,'全唐诗/poet.song.223000.json','["老仙平日鍊心丹，荏苒光陰百歲閒。", "隨分種花供冷眼，逢人留酒有溫顔。", "乾坤只作醒中夢，風月何妨忙處閒。", "有約酬春爭起舞，要看北道破先慳。"]'),
('7241635f-9604-4613-b402-a1914206b679','二月二十五日醉吟','陳著','宋','宋诗','song-poetry','','[]','午酒三杯率處真，不知門外有風塵。',64,'全唐诗/poet.song.223000.json','["午酒三杯率處真，不知門外有風塵。", "溪山花木一簾影，兄弟妻孥滿屋春。", "萬事到頭皆有命，兩閒立脚要求仁。", "羲皇以上已難問，且做淵明左右人。"]'),
('918f0aee-423f-4118-87ff-c83a6298262a','次韻梅山弟感春','陳著','宋','宋诗','song-poetry','','[]','老來危迹感秋蓬，萬事都歸馬耳風。',64,'全唐诗/poet.song.223000.json','["老來危迹感秋蓬，萬事都歸馬耳風。", "百五節爲春好處，兩三年在亂離中。", "濺花難禁少陵淚，縛柳休辭韓子窮。", "最是殘鐙風雨夜，杜鵑聲裏夢西東。"]'),
('cc042012-3958-4997-b845-53a96e4bce1e','用前韻記夢中所感','陳著','宋','宋诗','song-poetry','','[]','風引歸舟遠翠蓬，轉頭三見柳花風。',64,'全唐诗/poet.song.223000.json','["風引歸舟遠翠蓬，轉頭三見柳花風。", "傷心殆盡王摩詰，痛哭真成賈太中。", "尚有鬼神知夜問，誰知兄弟坐天窮。", "此時此意無人會，放讀離騷太乙東。"]'),
('e8047d17-2cc6-4b83-a03c-24a4afcb06e2','上巳日同弟觀張子開會內弟貝端甫家','陳著','宋','宋诗','song-poetry','','[]','邨環十里即朱陳，時節過從氣誼真。',64,'全唐诗/poet.song.223000.json','["邨環十里即朱陳，時節過從氣誼真。", "酒味同甘山脈水，韭香一洗俗饕塵。", "雲南近日偶無事，天下幾人知此春。", "相對無言無盡意，不將桃李著精神。"]'),
('2329bf0c-031b-45bc-bfbc-59f7ec978658','三月五日過雲南竺湘家舊寓南軒懷朝兒','陳著','宋','宋诗','song-poetry','','[]','憶昨携兒寄小軒，兒今何在小軒存。',64,'全唐诗/poet.song.223000.json','["憶昨携兒寄小軒，兒今何在小軒存。", "喚爹若有褰裳語，戀母猶多淚席痕。", "兩樹桃花飛痛血，一山松影護遊魂。", "銷凝良久忽如見，我與同歸家處邨。"]'),
('57214e9e-d3a5-4796-bae1-f7a9e46be85d','山人送檜植於當門偶成','陳著','宋','宋诗','song-poetry','','[]','山人知我歲寒情，十里移來老眼醒。',64,'全唐诗/poet.song.223000.json','["山人知我歲寒情，十里移來老眼醒。", "鑿破蒼苔方丈地，種爲門戶四時青。", "春寒亦自雪霜意，世變從他風雨腥。", "牢立本根須暢茂，不施巧結看真形。"]'),
('01b91d23-61bd-435d-bda7-b9d55cb0f455','戊寅三月十一日爲桑麥說苦','陳著','宋','宋诗','song-poetry','','[]','一年景象在春光，底事今年春反常。',64,'全唐诗/poet.song.223000.json','["一年景象在春光，底事今年春反常。", "四十日來無點雨，二三月裏却多霜。", "麥苗病燥飯虧料，桑葉死寒蠶絕糧。", "天下蒼生不堪命，但看人事即陰陽。"]'),
('e3d457af-b483-4c3f-837d-f0ec89e10f18','脾疼大作','陳著','宋','宋诗','song-poetry','','[]','夜來宿痼起心脾，輾轉無眠不自支。',64,'全唐诗/poet.song.223000.json','["夜來宿痼起心脾，輾轉無眠不自支。", "水鳥信天那得飽，河魚作祟却乘饑。", "苦無藥力課神效，爛煮菜根爲善醫。", "造物怕生安樂病，時將疼痛玉吾衰。"]'),
('43125c57-485c-46a7-9411-495f399a7082','昨方爲桑麥說苦今日忽喜得雨','陳著','宋','宋诗','song-poetry','','[]','連日南風雨不成，今朝忽有洗檐聲。',64,'全唐诗/poet.song.223000.json','["連日南風雨不成，今朝忽有洗檐聲。", "春膏喚起地元氣，仁脈流行天本情。", "桑婦驚傳二葉迸，田翁癡望兩歧生。", "窮閻繫命皆蠶麥，最是難供急急征。"]'),
('9afdc9e7-d245-4632-bee6-40a2b2815ae3','聞杜鵑','陳著','宋','宋诗','song-poetry','','[]','帝魂舊話是耶非，知得安危動處幾。',64,'全唐诗/poet.song.223000.json','["帝魂舊話是耶非，知得安危動處幾。", "自出蜀啼隨地氣，直過洛去洩天機。", "春風萬古此心在，雲樹千山何日歸。", "聽到如今轉難聽，恨無雙翼與俱飛。"]'),
('ad672de6-bdf0-4b4b-8406-0082bd963e98','與弟觀姪津哭伯求弟道茅山泊東林寺坐雨','陳著','宋','宋诗','song-poetry','','[]','西來本自趁晴天，雨卧東林日似年。',64,'全唐诗/poet.song.223000.json','["西來本自趁晴天，雨卧東林日似年。", "百念已成沈水石，一行真坐逆灘船。", "何妨華鄂添詩集，暫與闍黎結飯緣。", "决意明朝向東去，山堂未到已潸然。"]'),
('f613e3d7-8637-4268-b26c-b620330fe12b','題雪竇西麓菴','陳著','宋','宋诗','song-poetry','','[]','踏遍山南紫翠關，轉西尋麓更幽閒。',64,'全唐诗/poet.song.223000.json','["踏遍山南紫翠關，轉西尋麓更幽閒。", "菊花數本竹邊路，茅屋幾閒溪外山。", "巧著軒窗隨上下，賸留書畫在中閒。", "是菴信美非吾土，自有菟裘足往還。"]'),
('0549d07d-1752-4cc6-9565-887d259a608d','同黄東發提舉遊杖錫山','陳著','宋','宋诗','song-poetry','','[]','十八盤頭翠碧函，參差檐棟倚巖嶄。',64,'全唐诗/poet.song.223000.json','["十八盤頭翠碧函，參差檐棟倚巖嶄。", "桑根已換如來座，峯頂猶存太白巖。", "地有粟泥堪當飯，山無松木獨宜杉。", "半天圖畫風塵外，我有新題居士銜。"]'),
('fc7814b2-aadc-4ef0-92e8-3755ed787c70','次韻前人食素餛飩','陳著','宋','宋诗','song-poetry','','[]','庖手餛飩匪一朝，饌素多品此爲高。',64,'全唐诗/poet.song.223000.json','["庖手餛飩匪一朝，饌素多品此爲高。", "薄施豆膩佐皮軟，省著椒香防乳消。", "湯餠粗堪相伯仲，肉包那敢奏功勞。", "還方謹勿傳方去，要使安貧無妄饕。"]'),
('b2037608-2272-4ad9-bcab-5d07e1c57571','杖錫山別前人','陳著','宋','宋诗','song-poetry','','[]','結約登臨百里深，流連風雨一窗陰。',64,'全唐诗/poet.song.223000.json','["結約登臨百里深，流連風雨一窗陰。", "新寒鐙火照清夢，絕靜山林生古音。", "此日與君相別處，有天知我不言心。", "歸途步步須回首，蒼壁擎雲幾萬尋。"]'),
('c6ff78e1-f883-4060-ae87-c726d6680314','次韻前人取別二首  其一','陳著','宋','宋诗','song-poetry','','[]','初心高處欲窮遊，兀坐書窗七月秋。',64,'全唐诗/poet.song.223000.json','["初心高處欲窮遊，兀坐書窗七月秋。", "風雨已成貧甫嘆，山雲却爲老韓收。", "從來人事有圓缺，可是天公分去留。", "正爾無聊負暄立，赤書忽落剡溪頭。"]'),
('87e2a384-a7e5-4561-9891-7430e192c7cf','次韻前人取別二首  其二','陳著','宋','宋诗','song-poetry','','[]','雲旆吹晴踏翠巔，寫成詩卷思翻然。',64,'全唐诗/poet.song.223000.json','["雲旆吹晴踏翠巔，寫成詩卷思翻然。", "誰知同賦有齊己，人指醉吟爲樂天。", "意自源頭水中湧，語如山色雨餘鮮。", "尾貂分付歸鴻去，欲便尋盟未有緣。"]'),
('e0a76173-5734-402c-bfce-b922600ee1aa','黄子羽山長爲不及同山行次余東發別余韻見寄因再用韻以謝二首  其一','陳著','宋','宋诗','song-poetry','','[]','文脈絲垂感慨深，奎躔今直鄮山陰。',64,'全唐诗/poet.song.223000.json','["文脈絲垂感慨深，奎躔今直鄮山陰。", "末流自逐狂瀾倒，獨步直成空谷音。", "四海園林春事裏，一家松竹歲寒心。", "相知不必長相見，明月春風處處尋。"]'),
('ce236f76-5a71-4165-ad81-9b51a674fe05','黄子羽山長爲不及同山行次余東發別余韻見寄因再用韻以謝二首  其二','陳著','宋','宋诗','song-poetry','','[]','憶昨追隨太史遊，欠招吟脚共評秋。',64,'全唐诗/poet.song.223000.json','["憶昨追隨太史遊，欠招吟脚共評秋。", "自憐蒲柳難禁老，君向桑榆盡可收。", "人物多從危世見，山林盍有好詩留。", "和篇忽轉雲南去，便當同行雲上頭。"]'),
('d2320094-4bd5-468f-b059-032304325267','十月二十四日過弟觀寓所出萊菔相款','陳著','宋','宋诗','song-poetry','','[]','趁溪茅舍竹籬陰，石徑如蛇屈曲深。',64,'全唐诗/poet.song.223000.json','["趁溪茅舍竹籬陰，石徑如蛇屈曲深。", "吏卒不行烟冷處，弟兄聊說歲寒心。", "牀頭無酒可歸算，窗外有雞留伴吟。", "過午忽修萊菔供，悠長滋味在山林。"]'),
('1d03ce1a-03e7-45c2-b0cf-dcc1d567d602','次韻剡張知錄見寄','陳著','宋','宋诗','song-poetry','','[]','危途盍把隠爲師，名姓翻嫌世或知。',64,'全唐诗/poet.song.223000.json','["危途盍把隠爲師，名姓翻嫌世或知。", "栗里已成終老計，桐鄉猶記舊遊時。", "雲山杳杳勤搜便，風雨瀟瀟獨寄詩。", "目送心期無別語，厚培根本做春枝。"]'),
('c21b4f45-3365-47aa-8fae-edf903aca9ef','留范景山','陳著','宋','宋诗','song-poetry','','[]','滿天風雨作新正，下訪勞君一日程。',64,'全唐诗/poet.song.223000.json','["滿天風雨作新正，下訪勞君一日程。", "長揖不交隨俗禮，苦言惟有隔年情。", "鐙生暈處醒相對，犬吠聲中心自驚。", "人事難齊時事險，聚頭時節且遲行。"]'),
('39a55f89-cafe-4b82-9502-7f12dfa66c47','遊蔡峰過黄沙坑懷朝兒','陳著','宋','宋诗','song-poetry','','[]','入谷崎嶇十里程，更崎嶇處見沙坑。',64,'全唐诗/poet.song.223000.json','["入谷崎嶇十里程，更崎嶇處見沙坑。", "幼兒曾寄流鴻影，老我難忘舐犢情。", "後日早知爲死別，當時寸步亦同行。", "如今但有東風淚，灑入流泉慟失聲。"]'),
('71d2a91f-60b7-41c8-9f7e-6ec0b3d88899','溪上墺','陳著','宋','宋诗','song-poetry','','[]','滿坡翠竹閒梅花，梅竹中閒住幾家。',64,'全唐诗/poet.song.223000.json','["滿坡翠竹閒梅花，梅竹中閒住幾家。", "本爲牛羊安著脚，近來狼虎肆磨牙。", "青山綠水成烹鼎，白紙烏薪等撒沙。", "邂逅老農聊慰勞，且隨時刻做生涯。"]'),
('50e07045-605b-433c-9958-c667ea92c7ff','蔡峰似徐鱗卿','陳著','宋','宋诗','song-poetry','','[]','老去襟懷得喪齊，東風吹煖送行藜。',64,'全唐诗/poet.song.223000.json','["老去襟懷得喪齊，東風吹煖送行藜。", "羣山捧谷雲居下，一嶺分疆水向西。", "有路不來多事馬，滿邨交唱太平雞。", "主人九十清談健，樽酒流連日又低。"]'),
('eb60d061-2145-40b4-8e28-f69afffb1f79','三井','陳著','宋','宋诗','song-poetry','','[]','兩崖削鐵上擎空，下有靈潭與井同。',64,'全唐诗/poet.song.223000.json','["兩崖削鐵上擎空，下有靈潭與井同。", "龍出世時磐石透，水無底處洞天通。", "餘波噴作雷霆怒，大旱騰爲霖雨功。", "兄弟相携看奇迹，脚跟牢立嶮巇中。"]'),
('e837d1c5-3830-463d-9884-fbe168ffc04f','董伯和竹溪寓居','陳著','宋','宋诗','song-poetry','','[]','三井西邊十畝坡，與雲盤礴傲羲娥。',64,'全唐诗/poet.song.223000.json','["三井西邊十畝坡，與雲盤礴傲羲娥。", "危時自說昇平話，險地今爲安樂窩。", "魚鼈收溪供草酌，竹松臨戶當花窠。", "故園臺榭姑蘇問，萬事從來蟻一柯。"]'),
('40b31980-b012-488b-938b-b6aa16fff1bd','次韻徐鱗卿','陳著','宋','宋诗','song-poetry','','[]','百罹身世不成家，贏得蕭蕭兩鬢華。',64,'全唐诗/poet.song.223000.json','["百罹身世不成家，贏得蕭蕭兩鬢華。", "夢想山行三載裏，綢繆親誼百年賒。", "蒼顔一見如枯柏，佳語相延總粲花。", "別後有詩須狎寄，莫嫌踏險路谽谺。"]'),
('3717593c-7d61-4c0e-abfc-77a9a389db31','九月十日鄉人醵飲丹山分韻得東字','陳著','宋','宋诗','song-poetry','','[]','山光肅肅浄杉松，草草提携里曲同。',64,'全唐诗/poet.song.223000.json','["山光肅肅浄杉松，草草提携里曲同。", "不是休官住林下，無緣問菊到籬東。", "世途險迫閒爲福，鄉誼綢繆醵有功。", "酒散月明多感處，牛山故國正西風。"]'),
('886f8859-c123-4324-beb3-853a243db834','示都兒學書','陳著','宋','宋诗','song-poetry','','[]','都子方知硯石親，字雖小技盍留神。',64,'全唐诗/poet.song.223000.json','["都子方知硯石親，字雖小技盍留神。", "魯公米帖猶存古，王氏蘭亭已失真。", "莫事鋒鋩多巧銳，要令骨肉兩停勻。", "中心端正手圓活，此外無方可教人。"]'),
('bccbb48d-f414-45b5-9873-2654a1fc6333','次韻戴帥初不赴丹山醵飲二首  其一','陳著','宋','宋诗','song-poetry','','[]','吁嗟世事已難言，得遇重陽强作歡。',64,'全唐诗/poet.song.223000.json','["吁嗟世事已難言，得遇重陽强作歡。", "白髮不供新樣眼，黄花却喜舊儒冠。", "兩三杯裏意存古，四十年前盟未寒。", "青壁丹崖本深窈，誰知冷處有人看。"]'),
('2b0f49ab-4fed-4830-9184-fcc14644afd4','次韻戴帥初不赴丹山醵飲二首  其二','陳著','宋','宋诗','song-poetry','','[]','危時時節已難得，況得知心盍共杯。',64,'全唐诗/poet.song.223000.json','["危時時節已難得，況得知心盍共杯。", "我檄方從風裏去，君詩却占日前來。", "何須一醉獨重九，但是相過多幾回。", "門外斜陽送行處，眼光飛過碧崔嵬。"]'),
('b2d5e3b3-e58b-48b1-ae11-311517fa2904','次韻帥初浙西回及得新居三首  其一','陳著','宋','宋诗','song-poetry','','[]','聞得胥江尚漲沙，往來雖便重嗟嗟。',64,'全唐诗/poet.song.223000.json','["聞得胥江尚漲沙，往來雖便重嗟嗟。", "舊遊怕說銅駝棘，遺曲難聽玉樹花。", "滿目山川誰是客，無情天地若爲家。", "栖栖又入西峯下，踏破山鞋幾兩麻。"]'),
('461ce124-4da3-4bec-83e1-be0cd69f6c71','次韻帥初浙西回及得新居三首  其二','陳著','宋','宋诗','song-poetry','','[]','自昔恒河可聚沙，今爲何日更堪嗟。',64,'全唐诗/poet.song.223000.json','["自昔恒河可聚沙，今爲何日更堪嗟。", "未應絕物從孤竹，尚可依人住浣花。", "疲俗交□□□□，□時仍重讀書家。", "老吾幸有相過便，尚得如蓬倚直麻。"]'),
('a047593b-df44-466e-bed4-4a8daafcbca3','次韻帥初浙西回及得新居三首  其三','陳著','宋','宋诗','song-poetry','','[]','家有圖書便不貧，一灣門徑碧溪濱。',64,'全唐诗/poet.song.223000.json','["家有圖書便不貧，一灣門徑碧溪濱。", "山林深密宜今世，梅竹婆娑似故人。", "少閉柴門延野叟，多營菜圃慰脾神。", "幾年役役方休息，收放渾如一釣綸。"]'),
('d2664bc9-cf36-44fe-93f6-db322b34a37b','載酒過俞叔可運幹夜話','陳著','宋','宋诗','song-poetry','','[]','晴邊杖屨學偷閒，十里溪山送入檐。',64,'全唐诗/poet.song.223000.json','["晴邊杖屨學偷閒，十里溪山送入檐。", "門外方爭危處路，竹閒自下舊時簾。", "數杯同醉寒時煖，一枕高眠苦後甜。", "何幸詩壇有盟主，狎相來往亦何嫌。"]'),
('ba90b859-8337-4084-8ac4-5284ddacaf87','次韻史芝田來訪','陳著','宋','宋诗','song-poetry','','[]','珊然環佩下芝山，醉夢人閒醒眼看。',64,'全唐诗/poet.song.223000.json','["珊然環佩下芝山，醉夢人閒醒眼看。", "三世相家知有後，十分謙德似無官。", "騷盟寬與江湖接，清氣直將星斗干。", "難得相逢容易別，因風時爲勸加餐。"]'),
('e951d8c8-26c1-4de4-ae69-6e80b4b82fcc','晴郊意行到梅山示弟茝','陳著','宋','宋诗','song-poetry','','[]','安排聚首易參差，信意行來始是奇。',64,'全唐诗/poet.song.223000.json','["安排聚首易參差，信意行來始是奇。", "山色堪餐饒有菊，樵歌相應自成詩。", "危時杯酌旱雲雨，老境襟期春水澌。", "醉裏更無門外話，一聲寒雁弟兄知。"]'),
('f5a21fed-2806-4486-919a-20d6683c84d4','次韻范純甫','陳著','宋','宋诗','song-poetry','','[]','與雲俱捲出山遲，邂逅初寒旺菊時。',64,'全唐诗/poet.song.223000.json','["與雲俱捲出山遲，邂逅初寒旺菊時。", "縱欲插花安得笑，無從賒酒若爲詩。", "乾坤許闊自多礙，風雨又□自故知。", "白首猶存舊烏帽，龍山何處渺余思。"]'),
('6ee016ce-ae5b-47f4-94e0-127ff48dedcf','次韻黄子羽七十自嘆','陳著','宋','宋诗','song-poetry','','[]','棄瓢巢父固云稀，解印陶潛未是非。',64,'全唐诗/poet.song.223000.json','["棄瓢巢父固云稀，解印陶潛未是非。", "風雨似知人世換，溪山自愛主翁歸。", "時消孤悶有茶屋，天把獨醒存芰衣。", "我亦歲寒松下草，相望百里借春暉。"]'),
('19c75cec-753d-444b-bbf2-647517af01ec','次韻盧致遠見示','陳著','宋','宋诗','song-poetry','','[]','新春欲洗舊氛埃，並竹尋溪試一來。',64,'全唐诗/poet.song.223000.json','["新春欲洗舊氛埃，並竹尋溪試一來。", "凍雨忽交疏霰下，嚴風不放寸雲開。", "主人雅量詩相住，老客歸心夢亦催。", "滑道何妨徐著步，袖中金薤不虛回。"]'),
('aec23169-065b-4f6e-9edf-b54756447dcc','次韻戴帥初以水漲不及赴茂林醵飲重午','陳著','宋','宋诗','song-poetry','','[]','回頭林谷已云遲，心不懷疑遁自肥。',64,'全唐诗/poet.song.223000.json','["回頭林谷已云遲，心不懷疑遁自肥。", "有菊可尋方覺是，無根自藥豈吾非。", "危時一醉便爲福，好客相過莫放歸。", "欲弔湘纍波浩渺，但須珍重芰荷衣。"]'),
('4ca7b5cb-4668-41f6-952c-3c6919ea3d4c','次韻前人祈雨未應二首  其一','陳著','宋','宋诗','song-poetry','','[]','交秋苦旱走疲農，惟合投忱地府龍。',64,'全唐诗/poet.song.223000.json','["交秋苦旱走疲農，惟合投忱地府龍。", "里社相師憑梵唄，山川無語笑盲聾。", "忍教地寶罹枯渴，安得天機捷應舂。", "聯日定勞君眼力，雨晴只隔望春峯。"]'),
('fe260002-4f5c-484c-a34d-12b54448de2e','次韻前人祈雨未應二首  其二','陳著','宋','宋诗','song-poetry','','[]','龍君非是忍忘農，一敬初終自見龍。',64,'全唐诗/poet.song.223000.json','["龍君非是忍忘農，一敬初終自見龍。", "雨感通時元有待，天分曉處可曾聾。", "雷車怒激騰東海，火傘忙收入下舂。", "我輩報神無別事，請裁佳句勒霞峯。"]'),
('7f68da58-5175-45dc-ad82-41ea0f9b3d5b','連山王開詩試子午花四首  其一','陳著','宋','宋诗','song-poetry','','[]','三數莖鬚細撚金，圓齊五瓣外紅深。',64,'全唐诗/poet.song.223000.json','["三數莖鬚細撚金，圓齊五瓣外紅深。", "酷憎媚俗長垂首，善處驕陽不動心。", "色變化成丹竈火，時開落應土圭針。", "感懷南北多分裂，此獨全名古到今。"]'),
('a969d09b-1817-41a1-a305-b3eec32ab1eb','連山王開詩試子午花四首  其二','陳著','宋','宋诗','song-poetry','','[]','嫩綠扶疏紅倒垂，紅閒黄染數莖絲。',64,'全唐诗/poet.song.223000.json','["嫩綠扶疏紅倒垂，紅閒黄染數莖絲。", "牢存本色心爲主，懶競時妝面向誰。", "受二氣中開止晝，當三伏裏傲炎曦。", "陰崖故國長安路，萬里傾陽共藿葵。"]'),
('4f9e87a4-1b02-4eb7-ab19-b20bfe049999','連山王開詩試子午花四首  其三','陳著','宋','宋诗','song-poetry','','[]','赤日黄塵任漲浮，直莖疏葉裏垂頭。',64,'全唐诗/poet.song.223000.json','["赤日黄塵任漲浮，直莖疏葉裏垂頭。", "金心不逐時妝褪，赭面應爲世態羞。", "分晝夜閒開落準，備離坎氣品題優。", "倚欄感物傷懷處，何日崔盧入此甌。"]'),
('f81147f8-dcbe-40b9-93a7-3d194cd7cadb','連山王開詩試子午花四首  其四','陳著','宋','宋诗','song-poetry','','[]','低垂不足畏炎氛，自是居高避俗喧。',64,'全唐诗/poet.song.223000.json','["低垂不足畏炎氛，自是居高避俗喧。", "五瓣圓黏猩血重，數絲牢綴蠟心存。", "雅持本色明清晝，肯駐殘妝媚黑昏。", "林下何人修煉到，丹餘流入此芳根。"]'),
('c160e21d-c4aa-4aa1-ae53-ef4941371b21','訪趙景文不值','陳著','宋','宋诗','song-poetry','','[]','見了西山歎復歌，老天元不奈人何。',64,'全唐诗/poet.song.223000.json','["見了西山歎復歌，老天元不奈人何。", "一身死護松楸活，滿眼生來蘭玉多。", "忍處要如頑鐵石，平生能定惡風波。", "世閒終有安時節，細把林泉歲月磨。"]'),
('274d9653-1860-4aed-b616-fb2a2cd9ecc0','次韻朱景伯來見','陳著','宋','宋诗','song-poetry','','[]','平生四海弟兄之，況是鄉關見白眉。',64,'全唐诗/poet.song.223000.json','["平生四海弟兄之，況是鄉關見白眉。", "方醉夢中能獨醒，自離亂後篤相知。", "溪山坎坎勞飛旆，風雨瀟瀟苦說詩。", "老耳不堪聞別語，青鐙對影復何時。"]'),
('0bf077f8-9ba2-4019-9fba-ec2dcfb2d97f','次韻戴帥初見寄二首  其一','陳著','宋','宋诗','song-poetry','','[]','胸次玲瓏達事端，入山買屋貯清寒。',64,'全唐诗/poet.song.223000.json','["胸次玲瓏達事端，入山買屋貯清寒。", "奉親最樂危時見，與俗相忘實處看。", "閒輟琴書翻兔冊，旋添竹樹隔牛闌。", "疏衣淡飯門多閉，章甫何妨獨舊冠。"]'),
('379baa8a-4849-4b66-8f8b-c37e66715193','次韻戴帥初見寄二首  其二','陳著','宋','宋诗','song-poetry','','[]','水鏡空平取友端，頻來山外伴酸寒。',64,'全唐诗/poet.song.223000.json','["水鏡空平取友端，頻來山外伴酸寒。", "交朋舊在弟兄列，古道新交世俗看。", "地近詩筒多便翼，月明心事兩危闌。", "自家頭惱冬烘甚，猶幸偷安未毀冠。"]'),
('15717e95-721f-4ac9-af5d-c762ba7cf666','次韻弟觀授學陳子得家','陳著','宋','宋诗','song-poetry','','[]','憶昨依依話別端，瀟瀟暮雨滿山寒。',64,'全唐诗/poet.song.223000.json','["憶昨依依話別端，瀟瀟暮雨滿山寒。", "去家幸是老親健，坐館當如初宦看。", "歸夢隨風揚綠袂，吟情逐日寫詩闌。", "從今穩入林深處，塗炭何緣行污冠。"]'),
('60aeb30d-638f-46b1-be73-f017999653a0','賦陳子得書樓','陳著','宋','宋诗','song-poetry','','[]','危樓得地著身安，冬日烘檐夏氣寒。',64,'全唐诗/poet.song.223000.json','["危樓得地著身安，冬日烘檐夏氣寒。", "木末清風平與接，山中本色晚宜看。", "課兒勤讀書充架，留客高談袖滿闌。", "門外流渠源水活，不妨時濯自吾冠。"]'),
('89bf4256-7008-4509-935f-44d3304e9f55','次韻張子開喜雨','陳著','宋','宋诗','song-poetry','','[]','甘澤連朝拍稻疇，老天著意做今秋。',64,'全唐诗/poet.song.223000.json','["甘澤連朝拍稻疇，老天著意做今秋。", "軟炊已報生塵甑，艱食俄忘淅米矛。", "甽口漲新浮白膩，禾頭濯秀濕青油。", "疲農歡喜還長嘆，官已催租不待收。"]'),
('691a2fb1-d97a-473f-b86e-5530a41ec2c7','送酒與元春兄','陳著','宋','宋诗','song-poetry','','[]','九月風光又一年，君家無酒坐無錢。',64,'全唐诗/poet.song.223000.json','["九月風光又一年，君家無酒坐無錢。", "翠微雖負菊花約，安樂應甘飲米權。", "舉世方爭沈醉境，誰人能顧獨醒賢。", "兩從事□聊相諗，會取一般平淡天。"]'),
('a522542a-9473-4615-80f4-db31b8c2b026','與延慶老若圭游雪竇杖錫二首  其一','陳著','宋','宋诗','song-poetry','','[]','坐斷青蓮七寶池，又携鐵錫踏嶔崎。',64,'全唐诗/poet.song.223000.json','["坐斷青蓮七寶池，又携鐵錫踏嶔崎。", "一千丈雪與心照，二十里雲隨步飛。", "崖壁遍留吟墨迹，樵芻爭看袒紅衣。", "山林湖海本無二，處處風光屬指揮。"]'),
('2c4c97db-dd8e-4481-87f1-12add37e9914','與延慶老若圭游雪竇杖錫二首  其二','陳著','宋','宋诗','song-poetry','','[]','有意西遊萬玉峯，往來何事太怱怱。',64,'全唐诗/poet.song.223000.json','["有意西遊萬玉峯，往來何事太怱怱。", "知心能幾片雲外，回首應多明月中。", "爭供粟泥懷太白，終留梨實待興公。", "從今若枉詩相問，我住丹霞水竹叢。"]'),
('88abd999-3e4a-419c-b497-311367af3703','同趙景文到梅山弟家','陳著','宋','宋诗','song-poetry','','[]','脚力猶支一里閒，得閑便不記艱難。',64,'全唐诗/poet.song.223000.json','["脚力猶支一里閒，得閑便不記艱難。", "可人本色山林屋，避世珍羞芋栗盤。", "來往任教詩眼熱，笑談能化老身寒。", "感懷棠棣詩章在，試把絲桐檃括彈。"]'),
('f84616b0-3a2d-4c73-9f66-aedb8e1eb69e','次韻戴帥初見寄','陳著','宋','宋诗','song-poetry','','[]','兒造從來自不情，百千萬變底人驚。',64,'全唐诗/poet.song.223000.json','["兒造從來自不情，百千萬變底人驚。", "人生水上浮漚影，物論風前亂葉聲。", "自笑醉吟空贅傳，誰知橘隠竟無名。", "況今衰老知何用，惟有關門答五行。"]'),
('403df236-af51-49eb-9096-2e3962245021','壽同父兄七十二首  其一','陳著','宋','宋诗','song-poetry','','[]','光風顔色雪髯鮮，已到人閒稀有年。',64,'全唐诗/poet.song.223000.json','["光風顔色雪髯鮮，已到人閒稀有年。", "心好共稱生下佛，身閑自謂飲中仙。", "安貧真味齊眉饋，養善良方高枕眠。", "更看鐙宵兒迎婦，一家春與月團圓。"]'),
('3763fbf1-3cbb-4327-8272-9fd2bbc7c092','壽同父兄七十二首  其二','陳著','宋','宋诗','song-poetry','','[]','吾家兄弟篤天倫，晚景怡怡僅兩人。',64,'全唐诗/poet.song.223000.json','["吾家兄弟篤天倫，晚景怡怡僅兩人。", "門戶相依杏陰舊，藩籬不隔棣華春。", "難逢燕夜如今日，回愧鱗年以次身。", "造物倘容頑健在，願爲老櫟伴莊椿。"]'),
('ece9d509-1b39-4111-9288-6a3b3038005e','閒居有感','陳著','宋','宋诗','song-poetry','','[]','參差梅竹槿花籬，强對溪山傲百罹。',64,'全唐诗/poet.song.223000.json','["參差梅竹槿花籬，强對溪山傲百罹。", "終日書聲清屋氣，四時蔬食壽家規。", "苦兒知學何妨懶，老婦安貧未覺衰。", "無處可修牀下拜，門前心事碧天涯。"]'),
('3b5ceb39-ee9e-49d5-8c83-13f0a7b53bec','壬午九日有感','陳著','宋','宋诗','song-poetry','','[]','修茂堂中九日杯，今年無復壽兄來。',64,'全唐诗/poet.song.223000.json','["修茂堂中九日杯，今年無復壽兄來。", "把萸空感同看會，插菊難教一笑開。", "不使犬雞當厄去，却聞鴻雁送聲哀。", "浮生忽忽何須感，荒草牛山戲馬臺。"]'),
('9bb9546c-1a1f-4bd4-b41c-2dd0c1fdb1a6','出門寄弟覩子得','陳著','宋','宋诗','song-poetry','','[]','半年腿卧近方仁，一出門來拂濯身。',64,'全唐诗/poet.song.223000.json','["半年腿卧近方仁，一出門來拂濯身。", "交十月天邨景好，連三日雨晚晴新。", "青山無語自知我，黄葉是愁還可人。", "誰信幽居便忘世，漁樵亦自有經綸。"]'),
('c8b40400-df85-4d08-840f-7e9823c73bd9','偶成寄吳竹修','陳著','宋','宋诗','song-poetry','','[]','天自高高倚蓋斜，遑知人事可嗟嗟。',64,'全唐诗/poet.song.223000.json','["天自高高倚蓋斜，遑知人事可嗟嗟。", "公移急甚擘張弩，私繫甚如求破家。", "鎮一方浮勞地柱，救衆生病瓣天花。", "萬般巧計輸平實，笑殺當年複壁涯。"]'),
('30a039be-e6f6-4e70-bd72-1ce221a67c54','次韻吳竹修慶余免役','陳著','宋','宋诗','song-poetry','','[]','大道荆榛萬徑斜，中閒役事最堪嗟。',64,'全唐诗/poet.song.223000.json','["大道荆榛萬徑斜，中閒役事最堪嗟。", "私心自分齊編戶，公法仍條存宦家。", "免把血軀供刻木，尚存醒眼傲空花。", "要知天理無窮處，風雪嚴時春有涯。"]'),
('05818c13-c3fd-46c3-8ded-cd8b97ccf5f7','次前韻與前人同舟自城歸','陳著','宋','宋诗','song-poetry','','[]','夜泊南津夢岸斜，老來行役祇堪嗟。',64,'全唐诗/poet.song.223000.json','["夜泊南津夢岸斜，老來行役祇堪嗟。", "滿篷風露五更月，殘夢溪山百里家。", "蹴起睡奴催縴路，坐同吟伴說梅花。", "此歸又且深深住，瀾倒中閒要見涯。"]'),
('a637ba71-ae4b-4319-9c7e-f151306f52ce','謝前人留宿飲食','陳著','宋','宋诗','song-poetry','','[]','芒屩東歸日已斜，故人留滯豈來嗟。',64,'全唐诗/poet.song.223000.json','["芒屩東歸日已斜，故人留滯豈來嗟。", "數杯爛醉饑時藥，一枕熟眠安處家。", "湖海友朋多宿草，乾坤今古一風花。", "但將無事看時事，來往溪山詩未涯。"]'),
('bb318787-62bd-4354-ad69-6912a46e7b8e','又似前人','陳著','宋','宋诗','song-poetry','','[]','薄俗交朋赴字斜，可人一見祇驚嗟。',64,'全唐诗/poet.song.223000.json','["薄俗交朋赴字斜，可人一見祇驚嗟。", "心憑實地應多事，詩引清風歸一家。", "休看馬頭秋後葉，自培門裏歲寒花。", "何時相接從容步，遍歷山巔與水涯。"]'),
('869aa077-8f67-420a-8509-f4e1dd0ee52c','寄魏倅萬初','陳著','宋','宋诗','song-poetry','','[]','衣冠古雅御風行，爲我遲留半日程。',64,'全唐诗/poet.song.223000.json','["衣冠古雅御風行，爲我遲留半日程。", "未盍簪時勞夢寐，一傾蓋後見生平。", "相看惟有興亡歎，欠死難將出處評。", "回首梅花古松下，忍寒終不惹春情。"]'),
('8dcb504a-fbe5-4762-8cbe-e250b5db98a2','寄崇福主澤南洲','陳著','宋','宋诗','song-poetry','','[]','天地中閒澒洞塵，山林須是好三分。',64,'全唐诗/poet.song.223000.json','["天地中閒澒洞塵，山林須是好三分。", "危時安飯僧家鼓，濁世清風相國墳。", "老後重來如夢見，靜中自韻以心聞。", "同遊話到溪頭別，寂寂斜陽淡淡雲。"]'),
('a0402ae8-13aa-4567-ba75-2d2575630c4e','賡吳竹修雪詩二首  其一','陳著','宋','宋诗','song-poetry','','["\u897f\u6e56"]','寒勒銀河不放流，幻飛六出眩人眸。',64,'全唐诗/poet.song.223000.json','["寒勒銀河不放流，幻飛六出眩人眸。", "誰知青女老成手，自媚玄冥冬盡頭。", "積峻便如羣玉府，遇□還作□毛毬。", "西湖西畔孤山上，欲訪梅花有路不。"]'),
('b64eb3e6-be98-49ee-ae93-9f93de38a8d7','賡吳竹修雪詩二首  其二','陳著','宋','宋诗','song-poetry','','[]','天將潔白洗紛華，誰識人閒有嘆嗟。',64,'全唐诗/poet.song.223000.json','["天將潔白洗紛華，誰識人閒有嘆嗟。", "馿子已無詩客路，羔兒偏屬武流家。", "驚心玉樹傷遺曲，回首瓊林憶賜花。", "畢竟紛紛總成幻，抱琴無語剡溪涯。"]'),
('8892b616-d90e-4b0b-b732-1926a0d4824b','次韻戴帥初除夕并寄弟觀二首  其一','陳著','宋','宋诗','song-poetry','','[]','天如旋磨又今春，留得非才未死身。',64,'全唐诗/poet.song.223000.json','["天如旋磨又今春，留得非才未死身。", "浮世生來真逆旅，危時老去少同人。", "俗情一夜分寒煖，道眼百年無舊新。", "但恐明朝官事動，叫囂隳突滿鄉鄰。"]'),
('03f98c77-56d0-4286-839a-13e3389dbe5e','次韻戴帥初除夕并寄弟觀二首  其二','陳著','宋','宋诗','song-poetry','','[]','兄弟相依友在鄰，又添一歲話情真。',64,'全唐诗/poet.song.223000.json','["兄弟相依友在鄰，又添一歲話情真。", "梅花素入兩年眼，椒酒難醫百病身。", "敝帚自珍從衆笑，破皮非怪亦多嗔。", "柴門一任風開閉，靜看爭春車馬塵。"]'),
('9f792ab4-90ef-4cb4-87d6-d24cffe395c9','次韻單君範行李中諸詩前數章自道後二章爲單君作也八首  其一','陳著','宋','宋诗','song-poetry','','[]','心如古井不生瀾，無奈形骸寄兩閒。',64,'全唐诗/poet.song.223000.json','["心如古井不生瀾，無奈形骸寄兩閒。", "老境陽春亦風雪，危時明月自江山。", "琴書有舊聊相與，門戶雖貧未是閒。", "兒女不知何世界，勸傳花事已斕斑。"]'),
('58c50fd5-f564-43bc-a844-85078aa9e43a','次韻單君範行李中諸詩前數章自道後二章爲單君作也八首  其二','陳著','宋','宋诗','song-poetry','','[]','宇宙中閒戰血腥，不才難應少微星。',64,'全唐诗/poet.song.223000.json','["宇宙中閒戰血腥，不才難應少微星。", "窮頑得壽非三甲，老拙無文況六丁。", "醉後時歌東里曲，閒中堪伴北山靈。", "門前總是塵埃事，惟有梅花照眼醒。"]'),
('faf81e26-c7e9-4ad9-baeb-333f21c21f4a','次韻單君範行李中諸詩前數章自道後二章爲單君作也八首  其三','陳著','宋','宋诗','song-poetry','','[]','老不能狂心自箕，覽觀宇宙百非宜。',64,'全唐诗/poet.song.223000.json','["老不能狂心自箕，覽觀宇宙百非宜。", "沈舟那管帆爭水，抱瑟難隨竽用時。", "祇把書醫憑几困，閒從龜决訪山疑。", "夜來窗下青鐙下，兀兀無言渺渺思。"]'),
('b687f02e-b87b-45bd-8006-f746d536bd4b','次韻單君範行李中諸詩前數章自道後二章爲單君作也八首  其四','陳著','宋','宋诗','song-poetry','','[]','紛紛萬變自鴻荒，人事都歸夢一場。',64,'全唐诗/poet.song.223000.json','["紛紛萬變自鴻荒，人事都歸夢一場。", "龔勝餘生祇廉里，淵明初意豈柴桑。", "山林有味兒親圃，風雨無眠客對牀。", "衰老近來諸事廢，漁樵唱和是文章。"]'),
('18f1f743-5417-4f68-8745-50a5f460d8fa','次韻單君範行李中諸詩前數章自道後二章爲單君作也八首  其五','陳著','宋','宋诗','song-poetry','','[]','殘生光景滿腔愁，平地江河洶湧流。',64,'全唐诗/poet.song.223000.json','["殘生光景滿腔愁，平地江河洶湧流。", "可痛事多周正月，不言心有晉春秋。", "俗饕無夢亦尋鹿，人飽自歌誰飯牛。", "咄咄向天天不管，方來畢竟幾時休。"]'),
('dc235dc2-76dc-4e0e-83e8-9769d378ae8b','次韻單君範行李中諸詩前數章自道後二章爲單君作也八首  其六','陳著','宋','宋诗','song-poetry','','[]','欲言心事鼻先酸，最怕清流亦倒瀾。',64,'全唐诗/poet.song.223000.json','["欲言心事鼻先酸，最怕清流亦倒瀾。", "塵路爭車甘下澤，雪毛滿鏡自南冠。", "高懸古月看時變，相與春風到歲寒。", "案有陶詩須細和，無魚歸鋏不須彈。"]'),
('edeff788-780b-4ced-87ab-82c69bad23e8','次韻單君範行李中諸詩前數章自道後二章爲單君作也八首  其七','陳著','宋','宋诗','song-poetry','','[]','浮世憧憧爲底忙，百年光景等風狂。',64,'全唐诗/poet.song.223000.json','["浮世憧憧爲底忙，百年光景等風狂。", "乾坤自隘胸襟豁，言語無多意思長。", "但覺高歌同夜酌，未應別賦寫春傷。", "吾儕漸喜無人識，自做無名草木香。"]'),
('a5b52b9e-ef32-4284-bb72-e3a970f908c9','次韻單君範行李中諸詩前數章自道後二章爲單君作也八首  其八','陳著','宋','宋诗','song-poetry','','[]','山林氣骨本來癯，客氣乘時敢闞虛。',64,'全唐诗/poet.song.223000.json','["山林氣骨本來癯，客氣乘時敢闞虛。", "韓愈無醫惟贈遣，宗元何病豈工書。", "不煩天女梵花散，自有鄉人儺茢除。", "到底羣邪須一正，請師孔禱莫躊躇。"]'),
('5d95a409-3b94-4355-9e24-cdf2fe4a6d58','次戴帥初與次兒瀹詩','陳著','宋','宋诗','song-poetry','','[]','世變紛紛蜂蝶叢，人情落落馬牛風。',64,'全唐诗/poet.song.223000.json','["世變紛紛蜂蝶叢，人情落落馬牛風。", "山林猶喜典刑在，師友相從氣義同。", "坎有亨心方善處，兌爲麗澤要深窮。", "暮春樂處兒知否，好趁曾門詠舞童。"]'),
('760b366c-1204-4fe3-a856-12d8a5fb8dab','同范景山到城西墺遊鹿苑寺','陳著','宋','宋诗','song-poetry','','[]','片帆带月趁潮行，曉及三江作住程。',64,'全唐诗/poet.song.223000.json','["片帆带月趁潮行，曉及三江作住程。", "上冢偶隨龐老去，過溪忽見遠公迎。", "山疑無路亦多路，鳥獨有聲時一聲。", "幸自醉鄉風喚醒，斜陽煙草舊花城。"]'),
('f93d44e3-80a6-415a-9a9e-a1553330e271','留前人處有感','陳著','宋','宋诗','song-poetry','','[]','友壻從來義斷金，舊春一別到如今。',64,'全唐诗/poet.song.223000.json','["友壻從來義斷金，舊春一別到如今。", "琴幃絕奏香鐙冷，花圃猶荒風雨深。", "三夜書窗同話古，十年人事百傷心。", "杜鵑只管催歸去，不道□行有苦吟。"]'),
('07bec9aa-347f-414f-a943-e20336de32e3','城中赴范純甫酒有感','陳著','宋','宋诗','song-poetry','','[]','杜鵑啼斷洛陽橋，心與萍流絮與飄。',64,'全唐诗/poet.song.223000.json','["杜鵑啼斷洛陽橋，心與萍流絮與飄。", "風雨故都同死夢，山林晚景十年饒。", "相逢得醉有今日，萬事忘言付落潮。", "見說隠居歸我里，尚堪雞黍狎招邀。"]'),
('d2a0caec-2fed-4542-9432-ff509ba4b7c5','天台徐德源許以穀應借','陳著','宋','宋诗','song-poetry','','[]','枯淡生涯寄草萊，短供不給甑塵埃。',64,'全唐诗/poet.song.223000.json','["枯淡生涯寄草萊，短供不給甑塵埃。", "吾徒例有絕糧事，世俗何從索米來。", "邂逅指囷如魯肅，分明流飯自天台。", "不將乞字書爲帖，拙語聊干一笑開。"]'),
('629d8b0f-e5b3-44c0-b7e4-ef8a8b0d3146','次韻杜孟傳送歸剡','陳著','宋','宋诗','song-poetry','','[]','天空地闊本無言，兔走烏飛自做年。',64,'全唐诗/poet.song.223000.json','["天空地闊本無言，兔走烏飛自做年。", "老景光陰炊黍外，客窗風雨釀梅前。", "事隨笑去戶門福，詩爲別來朋友賢。", "河水洋洋山杳杳，一聲歸櫓綠楊邊。"]'),
('7e7da8dd-b6a6-4fc7-813a-c14e2c3c33d9','和吳竹修','陳著','宋','宋诗','song-poetry','','[]','滔滔世事黯難言，忽忽光陰況晚年。',64,'全唐诗/poet.song.223000.json','["滔滔世事黯難言，忽忽光陰況晚年。", "草野姓名螢爝裏，江湖消息馬風前。", "論交有得無新故，處變如常是聖賢。", "何幸相知足磨琢，言詩須到賜商邊。"]'),
('aa366b4a-4e60-4d39-a480-5fc90c3eda57','癸未生日書於本堂','陳著','宋','宋诗','song-poetry','','[]','與雲俱卷十年强，百短難醫獨命長。',64,'全唐诗/poet.song.223000.json','["與雲俱卷十年强，百短難醫獨命長。", "自有青天看晚節，不將白髮換時妝。", "田園活計雨聲好，湖海醒心山氣香。", "得一日閒勝一歲，老來免得別思量。"]'),
('c214b75d-7f03-48ea-8972-3f1e7320f992','次韻吳竹修立秋日','陳著','宋','宋诗','song-poetry','','[]','白帝來時赤帝歸，年年流轉不違時。',64,'全唐诗/poet.song.223000.json','["白帝來時赤帝歸，年年流轉不違時。", "書鐙有約花先喜，庭樹無情葉自知。", "楸市漫勞兵後夢，蓴鄉僅免客中思。", "老軀便動衣裘想，胠篋其如穴壁兒。"]'),
('24198c53-2003-4fe7-9454-77bb21e193af','次韻前人貴糴','陳著','宋','宋诗','song-poetry','','[]','麥甑淒涼稻尚青，粒珠乘急價掀騰。',64,'全唐诗/poet.song.223000.json','["麥甑淒涼稻尚青，粒珠乘急價掀騰。", "市平本易無千斛，倉糴良艱且五升。", "長是信天還自活，未能送鬼任多憎。", "回頭鐘鼓羣峯寺，飽飯高眠獨有僧。"]'),
('fe6c2407-4cda-4ae1-8865-75334bec9eea','次韻四明孫常州','陳著','宋','宋诗','song-poetry','','[]','忽忽光陰日隙塵，回頭十載兩襟分。',64,'全唐诗/poet.song.223000.json','["忽忽光陰日隙塵，回頭十載兩襟分。", "聽經偶枉真人駕，過首猶懷處士墳。", "危世清風誰一面，青山啼鳥自相聞。", "慇懃寄到新詩卷，奇字終須問子雲。"]'),
('b46573d7-268e-4ba1-920a-c09f5d04c162','拜先外舅墓坐雨用趙景文韻二首  其一','陳著','宋','宋诗','song-poetry','','[]','說著韜翁淚泫然，得來展墓及春先。',64,'全唐诗/poet.song.223000.json','["說著韜翁淚泫然，得來展墓及春先。", "松楸舊壠驚如許，風雨寒宵坐有緣。", "餘味淡交微醉酒，回頭流俗未烹鮮。", "明朝又別西山去，多少懷思集晚年。"]'),
('5022947c-54d0-44c8-8965-82de59d3697d','拜先外舅墓坐雨用趙景文韻二首  其二','陳著','宋','宋诗','song-poetry','','[]','卷懷經笥袖名鞭，千載陰何暗結緣。',64,'全唐诗/poet.song.223000.json','["卷懷經笥袖名鞭，千載陰何暗結緣。", "清似歲寒松獨立，健於霜曉鶻爭先。", "塵埃事與心相避，醉夢人看眼亦鮮。", "肯使雞林浪傳去，紛紛吟梓不同年。"]'),
('41ad7e0c-98b3-48a4-8336-aa48cd0849b0','贊前人第四子良漢周歲','陳著','宋','宋诗','song-poetry','','[]','昨見初綳浴露兒，如今又滿一年期。',64,'全唐诗/poet.song.223000.json','["昨見初綳浴露兒，如今又滿一年期。", "山林深處壽高木，薇蕨清風生瑞芝。", "試取印來知異日，能將字認已多時。", "諸郎自是詩書種，嫡出源源分外奇。"]'),
('975999d0-5c22-4b85-8670-047540c19f45','梅山弟來同飲醉書本堂','陳著','宋','宋诗','song-poetry','','[]','誰將糟粕視詩書，兄弟何妨做拙儒。',64,'全唐诗/poet.song.223000.json','["誰將糟粕視詩書，兄弟何妨做拙儒。", "流水青山同醉處，清風明月幾歸途。", "樵歌相與爲吟友，草市誰教見瑞夫。", "宇宙如今惟有酒，太和樓下渺烟蕪。"]'),
('b7fb2382-3f7f-4fcd-9727-b6a96f1e6250','歲首戒子到外家展駕寄內弟竺少博','陳著','宋','宋诗','song-poetry','','[]','古俗流傳重歲新，交相來往篤親親。',64,'全唐诗/poet.song.223000.json','["古俗流傳重歲新，交相來往篤親親。", "外家在望無十里，內表如今能幾人。", "筋力難施身已老，形骸不索意方真。", "兒曹能拜何妨遣，要使綢繆百世春。"]'),
('b1d9eda5-9f52-4532-9955-adf2ab4599fe','二月四日梅山弟留飲','陳著','宋','宋诗','song-poetry','','[]','醉中咄咄向空書，開眼猶能傲薄夫。',64,'全唐诗/poet.song.223000.json','["醉中咄咄向空書，開眼猶能傲薄夫。", "多事光陰存社櫟，十年筋力老園蕪。", "籓籬吾道難爲黨，衣食諸人未信儒。", "懷抱海深姑寄酒，習家池上不同途。"]'),
('68b33c6f-616e-4cbf-adf3-249269e41027','春日偶成二首  其一','陳著','宋','宋诗','song-poetry','','[]','老景還逢春一番，尚能消受自溫存。',64,'全唐诗/poet.song.223000.json','["老景還逢春一番，尚能消受自溫存。", "蠶寒風雨梨花屋，蕨熟人煙樺角邨。", "無事課兒多閉戶，有時見客一開樽。", "旁觀莫笑謀生拙，元是詩書舊子孫。"]'),
('8bf31250-b206-4c0f-891d-fe219f38c5bf','春日偶成二首  其二','陳著','宋','宋诗','song-poetry','','[]','烏兔催更日夜番，獨於衰朽尚相存。',64,'全唐诗/poet.song.223000.json','["烏兔催更日夜番，獨於衰朽尚相存。", "世情富貴鮑魚市，老眼風流麻鳥邨。", "牢立詩肩撐雨屋，施營酒料續春樽。", "芒鞋又辦遊山計，我亦興公不姓孫。"]'),
('0312ee5c-2d6e-48d0-b921-16a7e18eb38d','用戴帥初韻寄孫常州','陳著','宋','宋诗','song-poetry','','[]','溪繞山圍楊柳遮，戰蝸國裏退閒家。',64,'全唐诗/poet.song.223000.json','["溪繞山圍楊柳遮，戰蝸國裏退閒家。", "兒孫滿眼堂萬卷，賓客多賢館五花。", "立脚東皋看倦鳥，回頭溫水笑跳蟆。", "相知惟有詩相寄，便羽一封三印斜。"]'),
('da6816aa-fa6f-4520-bf7b-ab8a0fa423a0','送丹山主者周東隠','陳著','宋','宋诗','song-poetry','','[]','飛來峯頭飛鐵錫，一坐八載丹霞岑。',64,'全唐诗/poet.song.223000.json','["飛來峯頭飛鐵錫，一坐八載丹霞岑。", "山林成陰饕眼淺，議論近古咻機深。", "白雲泊對不留迹，明月行空是歸心。", "可無坡翁挽戒老，試聽重新鐘鼓音。"]'),
('edc4d7d7-fb81-4a38-a2e9-cfca3d3627c1','夜酌丹山','陳著','宋','宋诗','song-poetry','','[]','石路深深著梵宮，綠陰截斷出塵紅。',64,'全唐诗/poet.song.223000.json','["石路深深著梵宮，綠陰截斷出塵紅。", "春風杖屨閒忙外，明月山林醒醉中。", "有酒何須白蓮社，無詩可入碧紗籠。", "歸途自有兒扶笑，不用過溪勞遠公。"]'),
('491fe73c-49f3-4a19-bc73-2a5538a23925','東隠退永固齡叟留之慈雲西堂','陳著','宋','宋诗','song-poetry','','[]','識破機關便出林，滿天劫火可能侵。',64,'全唐诗/poet.song.223000.json','["識破機關便出林，滿天劫火可能侵。", "水流不去青山影，風與俱高白鶴心。", "物外弟兄相契合，眼中世界幾浮沉。", "是知處處虛西榻，難得慈雲一片陰。"]'),
('4cb98379-4611-4bbc-b84f-8255e8696255','拜趙端齋墓有感而書','陳著','宋','宋诗','song-poetry','','[]','流俗滔滔逐亂塵，典刑卓卓老宗臣。',64,'全唐诗/poet.song.223000.json','["流俗滔滔逐亂塵，典刑卓卓老宗臣。", "山川在眼孤忠淚，風雨無家一夢身。", "及奠生芻吾已晚，忍看宿草自成春。", "方來世事誰能料，須認分兵護墓人。"]'),
('2a772415-ba35-47ed-8f68-35d389b0cc5f','詠孫常州飛蓬亭','陳著','宋','宋诗','song-poetry','','[]','藕花池上竹梅陰，一艤中閒用意深。',64,'全唐诗/poet.song.223000.json','["藕花池上竹梅陰，一艤中閒用意深。", "畫舫規模供燕適，虛舟世界看浮沉。", "快風未信千帆福，逆水難憑百丈心。", "惟有此蓬飛已定，更無驚浪怒濤侵。"]'),
('fe2313e8-22f6-4c25-90f2-25d242037bfa','過仙山詠孫松磵新菴','陳著','宋','宋诗','song-poetry','','[]','雅懷欲友漢劉樊，巧築屠蘇壓大蘭。',64,'全唐诗/poet.song.223000.json','["雅懷欲友漢劉樊，巧築屠蘇壓大蘭。", "檐宿白雲山氣重，門無赤日樹陰寒。", "少年自得老成趣，危世誰如肥遁安。", "下界黄塵從擾擾，不妨高枕夢邯鄲。"]'),
('a6643d8e-2e2d-46a1-ae17-ed4b5270454f','甲申夏到杖錫憶戊寅秋同黄東發遊','陳著','宋','宋诗','song-poetry','','[]','布襪青鞋共踏雲，七年往事不堪論。',64,'全唐诗/poet.song.223000.json','["布襪青鞋共踏雲，七年往事不堪論。", "湖山宿草夢魂到，風雨秋鐙詩卷存。", "後死猶能傳耆舊，平生相屬□兒孫。", "老禪携手經行處，薄采芷蘭招楚原。"]'),
('0abf3240-479b-45c7-8a9d-23addee9f0db','暇日偶成','陳著','宋','宋诗','song-poetry','','[]','天賜衰年一屋清，住深不接過門聲。',64,'全唐诗/poet.song.223000.json','["天賜衰年一屋清，住深不接過門聲。", "带泥筍角燒易熟，得雨芥心批又生。", "山與雲宜時弄色，鳥乘春旺自呼名。", "誰能計較方來事，粥料何妨逐日營。"]'),
('692eced4-c6a8-4aca-9d8a-a1d655c05cc1','夏五再遊慈雲','陳著','宋','宋诗','song-poetry','','[]','青山屏繞碧溪灣，不是閒身欲到難。',64,'全唐诗/poet.song.223000.json','["青山屏繞碧溪灣，不是閒身欲到難。", "好客易招纔隔水，先塋在望莫憑闌。", "三杯便是人閒福，半榻聊分物外安。", "扶醉有兒歸路穩，不妨風露舊南冠。"]'),
('0615f06a-8a0f-4037-a74e-4a9dec45585d','詩似來石門同少野','陳著','宋','宋诗','song-poetry','','[]','出林危世是亨途，道眼相逢菜味腴。',64,'全唐诗/poet.song.223000.json','["出林危世是亨途，道眼相逢菜味腴。", "愈契大顛非爲佛，坡知老印本來儒。", "携晴雪瀑藤花路，話舊青鐙柏子廬。", "萬事已拋松枕外，不妨姓字落江湖。"]'),
('1f481b88-8da5-46fa-82cd-b120b258a305','用帥初韻謝其壽我之意','陳著','宋','宋诗','song-poetry','','[]','錦雲忽把老瞳遮，壽語何爲及我家。',64,'全唐诗/poet.song.223000.json','["錦雲忽把老瞳遮，壽語何爲及我家。", "怕說庚寅賦湘芷，漫書甲子譜陶花。", "長途交騖鼠爲虎，孤迹偷生蛇放蟆。", "人世到今何足問，桑榆況已日西斜。"]'),
('db6b2c53-deef-4890-8663-0e26605d69d5','兄弟醵飲訪雪航次弟觀韻二首  其一','陳著','宋','宋诗','song-poetry','','[]','天女多年爲散花，晚年來此寄年華。',64,'全唐诗/poet.song.223000.json','["天女多年爲散花，晚年來此寄年華。", "貧因好客甘如薺，詩解醒人苦似茶。", "入室漫爲雲作主，開窗惟許月通家。", "有時得句忙題處，滿壁淋漓字濕鴉。"]'),
('899c82b9-dd18-44e8-9788-fa1b5bcd1e25','兄弟醵飲訪雪航次弟觀韻二首  其二','陳著','宋','宋诗','song-poetry','','[]','夢斷天邊飛佩霞，短筇松路趁溪斜。',64,'全唐诗/poet.song.223000.json','["夢斷天邊飛佩霞，短筇松路趁溪斜。", "歸鴉山外煙如畫，過雁雲閒雪欲花。", "跌岩琴書誰我輩，承平鐘鼓自僧家。", "從今載酒須同醉，兄已頭童弟髮華。"]'),
('d03fdfb6-0684-4adf-99c3-f522f4fb138e','偶成','陳著','宋','宋诗','song-poetry','','[]','生計何曾問有無，心安便是邵堯夫。',64,'全唐诗/poet.song.223000.json','["生計何曾問有無，心安便是邵堯夫。", "攙春菜奉清饕味，耐凍梅呈本相癯。", "閉戶茶香浮雪屋，推窗山影落冰壺。", "終朝幸自無他事，忽聽兒童報索租。"]'),
('45708ac3-dba9-4e34-b7ab-bad0df270fd9','遊慈雲','陳著','宋','宋诗','song-poetry','','[]','老懷不與世情便，纔說閒行興翼然。',64,'全唐诗/poet.song.223000.json','["老懷不與世情便，纔說閒行興翼然。", "微濕易乾沙軟路，大寒却暖雪晴天。", "未曾到寺香先妙，底用尋梅山自妍。", "笑問松邊人立石，汝知今日是何年。"]'),
('161bd69a-b9ae-4ade-ae48-11e014733736','次兒瀹以年字韻呈喜而又賦','陳著','宋','宋诗','song-poetry','','[]','一詩未足見兒賢，意氣中閒頗藹然。',64,'全唐诗/poet.song.223000.json','["一詩未足見兒賢，意氣中閒頗藹然。", "忠厚人家宜有後，亂離時世始知天。", "老懷信汝窮須達，俗眼從渠醜做妍。", "培得根深花自茂，莫將今日看他年。"]'),
('7ec06dc3-1b5c-41bf-9b43-dcd85719e229','深瀹既聚用前韻示之併示姪溥','陳著','宋','宋诗','song-poetry','','[]','吾將語汝汝來前，勿聽吾言藐藐然。',64,'全唐诗/poet.song.223000.json','["吾將語汝汝來前，勿聽吾言藐藐然。", "君子最難端造處，人心易失本來天。", "須知妻係家興廢，自有人分行醜妍。", "三世一門詩禮在，莫教春意有窮年。"]'),
('efdb14ff-dde4-4112-9256-938ed7bcda3b','遊慈雲','陳著','宋','宋诗','song-poetry','','[]','曉日烘晴一白晞，青鞋踏滑叩禪扉。',64,'全唐诗/poet.song.223000.json','["曉日烘晴一白晞，青鞋踏滑叩禪扉。", "千山流水溪聲活，二麥涵滋野色肥。", "僵卧不妨晴又出，興來誰肯夜空歸。", "弟兄歡笑兒扶醉，滿袖新詩下翠微。"]'),
('f5e22e48-2036-479b-a9c3-14ca42555c5e','次韻趙景文見寄懷親','陳著','宋','宋诗','song-poetry','','[]','薄俗滔滔逐水流，誰能古道兩綢繆。',64,'全唐诗/poet.song.223000.json','["薄俗滔滔逐水流，誰能古道兩綢繆。", "白雲終日靜相向，紫氣有時來更留。", "啼鳥已呼春到了，醉馿曾記舊遊不。", "山林樂事輸君早，未遇仙炊已轉頭。"]'),
('c72c1f64-f80a-4e6a-a43e-5e255687b47f','七十見梅有感','陳著','宋','宋诗','song-poetry','','["\u897f\u6e56"]','萬木都由冬折磨，孤根却做老生涯。',64,'全唐诗/poet.song.223000.json','["萬木都由冬折磨，孤根却做老生涯。", "寒心欲吐知誰主，瘦骨相依有自家。", "祇許江南鴻雁見，肯交春後蝶蜂譁。", "風吹不斷西湖夢，一曲從他月落笳。"]'),
('84515b44-d298-4c90-9e38-f7b30ed4723c','送單君範赴汪西皋館','陳著','宋','宋诗','song-poetry','','[]','溪水沄沄雲出山，行邊意思自相關。',64,'全唐诗/poet.song.223000.json','["溪水沄沄雲出山，行邊意思自相關。", "欲從杖履吾已老，猶喜詩書君未閒。", "道脈不隨多事去，文風似放一分還。", "紛紛世變忘言外，春在西皋花柳閒。"]'),
('e1d8f7d5-4089-4617-8051-c5f514fa48b3','次兒生日八句示之','陳著','宋','宋诗','song-poetry','','[]','祖心流慶我生兒，說與吾兒初誕時。',64,'全唐诗/poet.song.223000.json','["祖心流慶我生兒，說與吾兒初誕時。", "吉夢覺來珠蚌坼，喜聲浮動玉麟知。", "如今弱冠歸妻後，此是平生進德基。", "自有季方家樣在，一門詩禮要扶持。"]'),
('f55ba88d-fad6-4aeb-9a72-b85342e3eea5','凝光亭偶成','陳著','宋','宋诗','song-poetry','','[]','一寸春暉值萬金，誰能白髮繫光陰。',64,'全唐诗/poet.song.223000.json','["一寸春暉值萬金，誰能白髮繫光陰。", "燕鶑已付忺新耳，蠶麥猶關活世心。", "坐到夕陽如夢寐，看來時事只沉吟。", "暖風吹面忘懷處，何日何人更似今。"]'),
('8c4afb49-9d18-450c-9ddf-e24478503cf6','梅山弟池邊醉吟','陳著','宋','宋诗','song-poetry','','[]','兩岡銜口水流脣，茅屋三間松四鄰。',64,'全唐诗/poet.song.223000.json','["兩岡銜口水流脣，茅屋三間松四鄰。", "花影落池塵外境，鳥聲喜客靜中春。", "生涯已付桑林舊，活句還隨菜酒新。", "滋味悠長有兄弟，不知山外更何人。"]'),
('aa68e2c3-af1c-4f08-a233-d1ba4155c730','弟觀喜董稼山至有詩因次韻二首  其一','陳著','宋','宋诗','song-poetry','','[]','蒼狗白衣紛過雲，到頭故我始爲真。',64,'全唐诗/poet.song.223000.json','["蒼狗白衣紛過雲，到頭故我始爲真。", "山林高看平沈世，風雨難摧獨樂春。", "時出苦言醫俗耳，多培好事壽閒身。", "仰天咄咄今何日，百里相過有若人。"]'),
('82837319-bf1b-457c-89e9-267d6cdab2ec','弟觀喜董稼山至有詩因次韻二首  其二','陳著','宋','宋诗','song-poetry','','[]','誤辱高軒訪子雲，須知我自是玄真。',64,'全唐诗/poet.song.223000.json','["誤辱高軒訪子雲，須知我自是玄真。", "石心已落千尋海，霜鬢難留一髮春。", "門外道途新舊眼，兵前朋友死生身。", "如今聚首休輕別，他日黄金枉鑄人。"]'),
('038d628c-d604-40d2-8978-ac73ddb64430','次弟觀與齡叟詩韻','陳著','宋','宋诗','song-poetry','','[]','雪竇飛來一片雲，寺門興起總由身。',64,'全唐诗/poet.song.223000.json','["雪竇飛來一片雲，寺門興起總由身。", "鐘魚飯衆有今日，鉦鼓粥神多信人。", "兩閣眼空風黑夜，四山手植雨清春。", "我今亦是陶潛輩，三笑圖中就寫真。"]'),
('9419303e-2152-44bc-a14b-34f7a4ac3e6c','八句呈董稼山','陳著','宋','宋诗','song-poetry','','[]','樓閣高虛壓翠微，詩囊酒擔答春暉。',64,'全唐诗/poet.song.223000.json','["樓閣高虛壓翠微，詩囊酒擔答春暉。", "山環水抱花相映，天闊雲開鶴自飛。", "已有新陰共醉卧，何妨清話放遲歸。", "浮生難得如今日，回首人間萬事非。"]'),
('81575fa4-25a5-48a1-9066-42cb19c0253e','別齡叟八句','陳著','宋','宋诗','song-poetry','','[]','翠竹黄花曲曲香，中間猶有太平腔。',64,'全唐诗/poet.song.223000.json','["翠竹黄花曲曲香，中間猶有太平腔。", "淡交一飯雲山鉢，詩夢對牀風雨窗。", "忽動歸心隨晚策，尚留醉興寄春缸。", "閒行除却禪關外，牢閉柴門學老龐。"]'),
('1dbd7024-4be8-4390-835a-3c579507debd','次韻黄長孺','陳著','宋','宋诗','song-poetry','','[]','人情相得古來難，肯溯溪山伴退閒。',64,'全唐诗/poet.song.223000.json','["人情相得古來難，肯溯溪山伴退閒。", "瀟灑風流屏褥外，和平氣象瑟琴閒。", "鵲巢自愛居南國，鶴帳從教怨北山。", "只恐杜鵑聲夢裏，與君飛去又飛還。"]'),
('cc6a57f6-3ce0-428e-bb16-0c109cdb9df2','長孺因吾二詩有負米分鄰之語因又次韻餞其歸二首  其一','陳著','宋','宋诗','song-poetry','','[]','聲氣相投玉應金，花閒話到翠成陰。',64,'全唐诗/poet.song.223000.json','["聲氣相投玉應金，花閒話到翠成陰。", "一清門戶無同脈，萬古詩書可立心。", "母子要知烏哺反，夫妻應感白頭吟。", "若言相諗早須覺，難得青春長似今。"]'),
('73f648d2-d55d-40d4-8f8e-63cdc3fda9fc','長孺因吾二詩有負米分鄰之語因又次韻餞其歸二首  其二','陳著','宋','宋诗','song-poetry','','[]','紛紛薄俗事輕脣，自喜衰年德有鄰。',64,'全唐诗/poet.song.223000.json','["紛紛薄俗事輕脣，自喜衰年德有鄰。", "危世孤兒華髮母，歸舟百里碧波春。", "不因噬指感懷切，肯學嘔心搜句新。", "娛舞慈庭應細說，丹山筍蕨正宜人。"]'),
('2bc00a37-aa9a-4b81-ab77-2657e66d82d6','次韻黄虛谷','陳著','宋','宋诗','song-poetry','','[]','弓招消息下幽京，羣起張弮不受檠。',64,'全唐诗/poet.song.223000.json','["弓招消息下幽京，羣起張弮不受檠。", "衰朽分爲林下物，英雄誰取彀中名。", "坐看年少摶雙翼，爭把時銛驅五兵。", "萬事要終方有見，休憑水到說渠成。"]'),
('5c8a5131-5dbb-4aca-a245-ba5baac2e16a','答范景山晝詩見意','陳著','宋','宋诗','song-poetry','','[]','綠陰門外漲黄塵，來往清風自可人。',64,'全唐诗/poet.song.223000.json','["綠陰門外漲黄塵，來往清風自可人。", "契闊一尊鐙雨舊，平安數字麥寒春。", "閒居有味何妨拙，古道無情却耐貧。", "漠漠水雲山隔斷，何時王翰卜爲鄰。"]'),
('e58207c1-38bf-4086-85f6-e41536d66366','次韻弟觀晚春風雨','陳著','宋','宋诗','song-poetry','','[]','天正宜晴却又非，雲頑未是放開時。',64,'全唐诗/poet.song.223000.json','["天正宜晴却又非，雲頑未是放開時。", "可曾路滑官移緩，但覺山寒農務遲。", "風雨顛狂如醉漢，乾坤正大亦嬉兒。", "陰陽自有人調燮，牢閉柴門只自規。"]'),
('cc452d2b-69ad-4d40-85c6-373e5f552a73','次韻石秀叔聞鶑','陳著','宋','宋诗','song-poetry','','[]','分得天機自動簧，與春相約不參商。',64,'全唐诗/poet.song.223000.json','["分得天機自動簧，與春相約不參商。", "無情有態眉如畫，是曲非腔口尚黄。", "公子舊呼歸夢境，友生新好出邨莊。", "山窗詩客先聽處，寫入烏絲句亦香。"]'),
('97c5dc55-1cc7-4633-995e-9bd06f92aeeb','次韻姪溥到雲南外家回','陳著','宋','宋诗','song-poetry','','[]','二竹家傳一髮微，眼中難問是和非。',64,'全唐诗/poet.song.223000.json','["二竹家傳一髮微，眼中難問是和非。", "詩書事冷官符惞，韋布形枯繒戶肥。", "兒戲仙樓空夢見，老過顛嶺只愁歸。", "山溪亦有不平處，終日諠聲水戰磯。"]'),
('cf8d7c4c-7355-476e-87de-21f816354b0c','四月八日携子姪到上乘偶成','陳著','宋','宋诗','song-poetry','','[]','白首猶堪數里行，相過一笑見山堂。',64,'全唐诗/poet.song.223000.json','["白首猶堪數里行，相過一笑見山堂。", "殘僧門徑靜於夜，新夏林塘暖自涼。", "且借吟牀娛半日，何妨歸笠戴斜陽。", "我來豈敢辭筋力，先隴松楸倚寺旁。"]'),
('3569a9f8-6e35-43e9-8fe4-e60194380088','次韻長兒生日示諸弟','陳著','宋','宋诗','song-poetry','','[]','吾愛吾兒責望兒，終身實處看平時。',64,'全唐诗/poet.song.223000.json','["吾愛吾兒責望兒，終身實處看平時。", "夫妻琴瑟方爲順，伯仲壎箎便是詩。", "要向魯鄒中進步，先從曾閔上求知。", "酒邊見汝傾心句，不覺摇頭笑脫頤。"]'),
('6b57635e-b6bb-4d19-bb98-731a5ba0878f','用弟觀韻二首  其一','陳著','宋','宋诗','song-poetry','','[]','住世光陰曉日霜，浮生誰弱又誰强。',64,'全唐诗/poet.song.223000.json','["住世光陰曉日霜，浮生誰弱又誰强。", "干戈時節貧差穩，詩禮人家話亦香。", "何用移文來北隴，可能把酒博西凉。", "妻無慍見兒堪教，門外從他沸一鐺。"]'),
('24fb7aca-ec73-4c5e-8e1c-348e3931d619','用弟觀韻二首  其二','陳著','宋','宋诗','song-poetry','','[]','粉兒乳子等蓬麻，書種精神見始啞。',64,'全唐诗/poet.song.223000.json','["粉兒乳子等蓬麻，書種精神見始啞。", "自分閒居培玉樹，無心勞役讖金沙。", "如龍當有騰高日，何恙能侵積慶家。", "乳哺薄乖隨勿藥，番成點浪□塗鴉。"]'),
('cc526c27-70a3-472d-aed4-ece6aea7bd65','季秋入城郡人迎鮑王有感','陳著','宋','宋诗','song-poetry','','[]','滿城呵道漲黄塵，儀衛森嚴亞玉宸。',64,'全唐诗/poet.song.223000.json','["滿城呵道漲黄塵，儀衛森嚴亞玉宸。", "幕帟遊魂勳閥舊，鼓笳殺氣譜家新。", "西風兒戲知何世，末俗民心只有神。", "兀坐僧窗增感慨，梁公已矣更誰人。"]'),
('6e4e6284-0668-4ab4-941d-6af759b405ed','次弟觀與雪航韻','陳著','宋','宋诗','song-poetry','','[]','老友姑從方外求，危時亦可少紓憂。',64,'全唐诗/poet.song.223000.json','["老友姑從方外求，危時亦可少紓憂。", "笑圖難贅餘人契，病室應關一世愁。", "淡飯是緣終有味，故山雖好莫回頭。", "滿航雪意元無價，住色空中是應酬。"]'),
('a5f7cd77-527d-4598-b6e3-8820444561da','次弟觀爲陳子得納婦別李親家','陳著','宋','宋诗','song-poetry','','[]','馬頭姻締熱相尋，誰識清交舊紱簪。',64,'全唐诗/poet.song.223000.json','["馬頭姻締熱相尋，誰識清交舊紱簪。", "澤底李無門望態，村中陳有世婚心。", "別來得見百罹後，坐到忘言兩意深。", "醉裏送君何所有，嚼梅花碎寫成吟。"]'),
('b07f8e55-ab56-4ed0-815c-45f586e22efe','姪溥生男命曰迎孫取迎長之義且爲方來期也因賦八句','陳著','宋','宋诗','song-poetry','','[]','應夢熊祥月又圓，以迎命汝豈徒然。',64,'全唐诗/poet.song.223000.json','["應夢熊祥月又圓，以迎命汝豈徒然。", "遲之蓐卧十朝後，恰似陽來一日前。", "極處逢生天意在，長孫得嫡祖心傳。", "相期他日成人事，復見升平要著鞭。"]'),
('56ceb101-ae68-403c-9d65-776db2391148','次單君範遺次兒韻效魯直體','陳著','宋','宋诗','song-poetry','','[]','世變不常有陰晴，吾道由來自坦平。',64,'全唐诗/poet.song.223000.json','["世變不常有陰晴，吾道由來自坦平。", "安得天資白受采，要憑學力濁爲清。", "三日刮目迎呂遜，一月坐春盍孔程。", "便須從今加鞭去，庶免轅越轍幽并。"]'),
('fc821346-271e-4c43-9e76-d4e509fac1d4','次韻竺梅潭見示','陳著','宋','宋诗','song-poetry','','[]','曾携古調坐琴清，獨有知心老滅明。',64,'全唐诗/poet.song.223000.json','["曾携古調坐琴清，獨有知心老滅明。", "百拙相安無異政，三年一信自同情。", "綏强粗祖太邱實，宰社終慚戶牖平。", "桃李春風重回首，誰知倚樹有新盟。"]'),
('d8fdbc53-54fc-4de5-b967-520e0b9b0968','次韻夜坐','陳著','宋','宋诗','song-poetry','','[]','山林分老不求官，梅月窗深耐坐寒。',64,'全唐诗/poet.song.223000.json','["山林分老不求官，梅月窗深耐坐寒。", "浮世人如春夢亂，明朝事作宿緣看。", "膝邊鐙火心相付，眉裏杯盤量自寬。", "睡去醒來朝復暮，百年如此是平安。"]'),
('cc124269-170a-4798-8679-f91ce106354c','單君範過西皋迂途來訪一詩道別','陳著','宋','宋诗','song-poetry','','[]','老境途迎作夢看，出門相送是愁端。',64,'全唐诗/poet.song.223000.json','["老境途迎作夢看，出門相送是愁端。", "分携不去有心在，長揖無言回首難。", "霧雨暗山家信遠，春風吹笠客心寒。", "儒生例是多勞役，幸得琴書路尚寬。"]'),
('9aee9952-bedb-4ddc-ba31-d0e2e91d39e3','送同少野赴華藏寺二首  其一','陳著','宋','宋诗','song-poetry','','[]','絮帽蒙頭太白峯，忽然霹靂起虛空。',64,'全唐诗/poet.song.223000.json','["絮帽蒙頭太白峯，忽然霹靂起虛空。", "遁菴强出本心退，荼毒高遷好樣同。", "南北雲山十年夢，東西浙水一家風。", "無邊福量如何說，龍象都歸禽縱中。"]'),
('94ebcfa8-f073-470a-88c9-4c36637ebd30','送同少野赴華藏寺二首  其二','陳著','宋','宋诗','song-poetry','','[]','落花流水去帆孤，風雨交情奈老夫。',64,'全唐诗/poet.song.223000.json','["落花流水去帆孤，風雨交情奈老夫。", "詩屋知誰共雲月，笑圖和我入江湖。", "千山遮眼夢自到，萬笠傳聲書可無。", "家有壽翁垂百歲，尚因歸省及桑榆。"]'),
('abbb1500-8640-4dbf-95d5-77c61c713f1d','次前人韻以寄','陳著','宋','宋诗','song-poetry','','[]','流俗誰能問故知，慇懃書信驛同驅。',64,'全唐诗/poet.song.223000.json','["流俗誰能問故知，慇懃書信驛同驅。", "古心地老天荒日，閒意風來月往時。", "交一臂閒機尚失，隔千里外會難期。", "從今要識相思瘦，認取青山槁木枝。"]'),
('a311c042-5387-43ae-8bab-2f8ea819036a','朝歸生日','陳著','宋','宋诗','song-poetry','','[]','當年分得月中胎，八歲精神愈覺開。',64,'全唐诗/poet.song.223000.json','["當年分得月中胎，八歲精神愈覺開。", "小學路頭方謹入，平生根脚要深培。", "家貧只問子賢否，父老何妨兄教來。", "須識此身關繫大，莫如流俗赴波頹。"]'),
('7573315e-8298-45cc-8ba0-3729701a5c45','次韻女淑壽兄詩','陳著','宋','宋诗','song-poetry','','[]','道韞生來亦謝芝，解吟今有壽兄時。',64,'全唐诗/poet.song.223000.json','["道韞生來亦謝芝，解吟今有壽兄時。", "着行布字銀鉤細，鎔意成辭金薤垂。", "義氣流行親手足，笑風吹到老鬚眉。", "自家兒女能如此，一味清甘足解頤。"]'),
('cea6aa88-0e48-4348-9c9d-c363b53b9a10','又用韻示長兒','陳著','宋','宋诗','song-poetry','','[]','向來枯卉亦生芝，種學纔深可瑞時。',64,'全唐诗/poet.song.223000.json','["向來枯卉亦生芝，種學纔深可瑞時。", "語海方知蝸井淺，培風當使翼雲垂。", "可能任運如彭澤，也要名家似蜀眉。", "理義本來非外鑠，自求兩字盍觀頤。"]'),
('048b934a-0057-47fd-9327-2017fce2701b','丙戌五月朔閒坐偶成','陳著','宋','宋诗','song-poetry','','[]','石火光中見歲華，溪雲深處寄生涯。',64,'全唐诗/poet.song.223000.json','["石火光中見歲華，溪雲深處寄生涯。", "詩書屋下無嬉具，桑竹窗前有美花。", "拗境日增多活媿，囂塵天與一貧遮。", "乾坤自隘鄉鄰好，猶得開門守故家。"]'),
('fe022209-39ac-43a5-93fa-47a409ae7492','宿天甯寺偶成','陳著','宋','宋诗','song-poetry','','[]','參差新復古禪關，殘樹疏篁百畝閒。',64,'全唐诗/poet.song.223000.json','["參差新復古禪關，殘樹疏篁百畝閒。", "清曉軒窗初過雨，黄塵城市自深山。", "一家暫付客天外，半榻聊分僧夏閒。", "猶有故人相訪問，到無言處是時難。"]'),
('152f19d2-fdfe-441e-9f86-9565099b4108','因閒坐偶成韻謝黄虛谷','陳著','宋','宋诗','song-poetry','','[]','夢曾騎馬踏京華，老矣盟鷗寄水涯。',64,'全唐诗/poet.song.223000.json','["夢曾騎馬踏京華，老矣盟鷗寄水涯。", "回首故人多宿草，攢眉晚節自寒花。", "南風漫把初心鼓，西日難將隻手遮。", "猶有窮吟誰管領，何時王翰作鄰家。"]'),
('cf87abca-111f-4556-8478-f1c001a40ea0','次韻黄長孺','陳著','宋','宋诗','song-poetry','','[]','玉潤深慚冰未清，午軒杯酒見人情。',64,'全唐诗/poet.song.223000.json','["玉潤深慚冰未清，午軒杯酒見人情。", "艱難方識山林味，親戚還兼朋友盟。", "安用白頭傷世變，又看黄葉報秋成。", "羨君燕奉潘輿處，淡泊中閒禮樂聲。"]'),
('e432d084-2583-4530-8514-8f216fb56661','用長孺七夕韻','陳著','宋','宋诗','song-poetry','','[]','炳炳雙星從古然，滔滔多話到今傳。',64,'全唐诗/poet.song.223000.json','["炳炳雙星從古然，滔滔多話到今傳。", "渺茫河上曾無事，醉夢人閒自並緣。", "妄不易祛姑立我，巧如可乞豈爲天。", "癡兒甘受三年詐，獨有崔生此話賢。"]'),
('1fdd8bb9-c239-4ce5-bb60-576da0e7b772','七月望郡庠賦秋聲詩且欲不犯題字及見所作良可發笑因賦二首示諸兒  其一','陳著','宋','宋诗','song-poetry','','[]','天教少昊管金行，發越清商妙莫名。',64,'全唐诗/poet.song.223000.json','["天教少昊管金行，發越清商妙莫名。", "萬宇虛涼機自動，千林摇落氣難平。", "怒爲伍子潮江吼，細入歐公夜壁鳴。", "最是幽窗多感處，數聲唳月雁南征。"]'),
('ab4963e9-0ccd-4e48-b175-a9d4377f759c','七月望郡庠賦秋聲詩且欲不犯題字及見所作良可發笑因賦二首示諸兒  其二','陳著','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','氣應商聲慘又清，人閒難聽亦難名。',64,'全唐诗/poet.song.223000.json','["氣應商聲慘又清，人閒難聽亦難名。", "非神非鬼洞庭樂，爲鶴爲風淝水兵。", "老葉自吟高處調，寒蛩相趁閙中鳴。", "西風機籟年年事，分付與天心自平。"]'),
('36aaf16b-797b-4159-bce9-341a77de86af','次吳竹修寄澤南洲韻','陳著','宋','宋诗','song-poetry','','[]','君客蓬堧偶滯留，我尋菊伴枉經由。',64,'全唐诗/poet.song.223000.json','["君客蓬堧偶滯留，我尋菊伴枉經由。", "翠微輕失相逢笑，白髮堪禁幾別愁。", "只爲交情如管鮑，未能忘物似聃周。", "何妨重約論文酒，尚有橙黄橘綠秋。"]'),
('69e6d0ea-5e1f-45c6-b653-cca9d6b29d8f','次韻梅山弟','陳著','宋','宋诗','song-poetry','','[]','挂畫燒香書滿前，丰標清出剡溪源。',64,'全唐诗/poet.song.223000.json','["挂畫燒香書滿前，丰標清出剡溪源。", "平坡肘腋眠牛壟，小屋規模放鶴園。", "外事任如黄葉寂，閒心暗與白雲論。", "應須參到希夷處，自是三峯直下孫。"]'),
('1c6dbc49-df92-452a-bbed-e6f50a943511','盧竹溪得處士號邑尹有詩盧以其唱及其自和來求余次韻','陳著','宋','宋诗','song-poetry','','[]','夢破邯鄲百念齊，長汀西畔半分溪。',64,'全唐诗/poet.song.223000.json','["夢破邯鄲百念齊，長汀西畔半分溪。", "護符清出黄冠品，承命有加紫詔泥。", "徑捷更誰疑晚節，山居有客侈新題。", "老吾亦是三峯裔，何幸相逢有子兮。"]'),
('498bad14-3e6f-47cc-9034-b22178922ba6','兒姪輩爲燕老集石秀叔以詩來和之二首  其一','陳著','宋','宋诗','song-poetry','','[]','身是書中老僕童，布衣不溯馬頭風。',64,'全唐诗/poet.song.223000.json','["身是書中老僕童，布衣不溯馬頭風。", "雖無二頃資窮巷，猶有三峯著睡翁。", "虛室漫留莊叟白，新詩忽見相州紅。", "危時流俗滔滔去，鐵石心腸獨我同。"]'),
('fd5f884d-63c5-4ed6-881d-14b6920e3d46','兒姪輩爲燕老集石秀叔以詩來和之二首  其二','陳著','宋','宋诗','song-poetry','','[]','白髮扶携綠髮迎，今爲何日自歡聲。',64,'全唐诗/poet.song.223000.json','["白髮扶携綠髮迎，今爲何日自歡聲。", "任供觴豆人情便，存古門庭俗眼驚。", "壽語相期滋我愧，醉吟多感有兒賡。", "但令里曲皆知孝，此酒何如考叔羹。"]'),
('9d734a5b-87a2-4a10-86dd-2bff657166e4','丙戌十一月十六日迎孫試周八句','陳著','宋','宋诗','song-poetry','','[]','杏林深處長孫枝，春意烘堂看試兒。',64,'全唐诗/poet.song.223000.json','["杏林深處長孫枝，春意烘堂看試兒。", "脊硬不移匍匐手，語遲厚養粹凝姿。", "喜開三世瑶環瑞，滿望重闈白髮慈。", "與汝家傳雙色筆，文章得力豈無時。"]'),
('e0713e83-b88a-479e-9409-3980257ade70','吳竹修以詩寄次韻以復','陳著','宋','宋诗','song-poetry','','[]','避世歸來星一周，小丹山下剡溪頭。',64,'全唐诗/poet.song.223000.json','["避世歸來星一周，小丹山下剡溪頭。", "風塵滿眼醒如醉，宇宙關心笑亦愁。", "書几日聽諸子業，菜畦時共老妻遊。", "吟鞭倘踐相過約，雞黍猶能食仲由。"]'),
('57c60afb-b8d8-47bc-add4-a2182a93ac1f','用前韻似齡叟','陳著','宋','宋诗','song-poetry','','[]','早歲雄心撼不周，晚年歸契老禪遊。',64,'全唐诗/poet.song.223000.json','["早歲雄心撼不周，晚年歸契老禪遊。", "肯除酒戒容元亮，欲答梅詩愧子由。", "隠几雲山長在眼，出門風雪又回頭。", "元宵有約慈雲閣，鐙火能無感舊愁。"]'),
('deeffbd8-44cd-4eb4-9fcd-d8c7638b1ad1','贊王來山愛竹祠前枯竹再生','陳著','宋','宋诗','song-poetry','','[]','清護祠香立翠寒，誰知活處發霜痕。',64,'全唐诗/poet.song.223000.json','["清護祠香立翠寒，誰知活處發霜痕。", "生生與善相爲脈，節節是仁皆可根。", "方信虛中涵造化，何妨直下長兒孫。", "更須就此封培去，千畝成陰百世門。"]'),
('0ff33c2e-e9e9-458b-b6d3-e9bc09fc0d3f','次韻崇福老澤南洲','陳著','宋','宋诗','song-poetry','','[]','邯鄲枕上夢回身，景照窗前醉卧人。',64,'全唐诗/poet.song.223000.json','["邯鄲枕上夢回身，景照窗前醉卧人。", "山別是天遲放晚，鳥知何世早呼春。", "乾坤大事三緘外，湖海清交一笑新。", "山去莫嫌來往密，免教雲樹兩馳神。"]'),
('f431379e-71b1-4aa4-ad6d-7ee3eb10e37f','示梅山弟八句','陳著','宋','宋诗','song-poetry','','[]','浮世蘧廬付一呀，詩書餘瀝子孫家。',64,'全唐诗/poet.song.223000.json','["浮世蘧廬付一呀，詩書餘瀝子孫家。", "兩池分受高低水，四岸量栽次第花。", "笑傲溪山如故舊，招邀雲月共生涯。", "相逢數酌春風酒，不信人間有戰蝸。"]'),
('a739c848-dfb6-46be-bced-a6f0f3586227','次韻竹石亭','陳著','宋','宋诗','song-poetry','','[]','卷收湖海入高懷，勘破人閒蛇影杯。',64,'全唐诗/poet.song.223000.json','["卷收湖海入高懷，勘破人閒蛇影杯。", "老骨耐看寒後柏，古心相沃渴中梅。", "何妨風日同清美，不怕山雲礙往來。", "多少詩香播牙頰，夕陽移酒坐蘭苔。"]'),
('910198fd-b3a7-4471-9f68-f886a76614b3','和息菴呈蒙山韻','陳著','宋','宋诗','song-poetry','','[]','象驂來自海之濱，何幸相逢孤獨園。',64,'全唐诗/poet.song.223000.json','["象驂來自海之濱，何幸相逢孤獨園。", "好句不妨詩共屋，戲言敢及賦名坤。", "江湖自有清風調，雲月難招流俗魂。", "千里文章本同味，幾時樽酒細重論。"]'),
('bd6a1988-911a-4a61-99da-40ece2c2dcb5','詩送讀易堂張碧窗之揚','陳著','宋','宋诗','song-poetry','','[]','占得資身話柄高，六鼇島上足逍遥。',64,'全唐诗/poet.song.223000.json','["占得資身話柄高，六鼇島上足逍遥。", "南風又送飛霞佩，北道相期明月橋。", "要坐虎皮專說易，肯携鳳侶共吹簫。", "此行直上青霄去，不比閑纏鶴背腰。"]'),
('250a4bd2-ca44-4a2e-85ef-efcc6d868bee','呈齡叟','陳著','宋','宋诗','song-poetry','','[]','寥寥古道獨開門，一見無言心已聞。',64,'全唐诗/poet.song.223000.json','["寥寥古道獨開門，一見無言心已聞。", "別後黄塵留四月，坐來清雨洗三分。", "鱗鱗秧活方吞水，翼翼山飛欲舞雲。", "此景此生如此酒，證明耐久有南薰。"]'),
('a22a6ae8-b6b1-403b-bc4b-1d0a60e02b6e','留西山','陳著','宋','宋诗','song-poetry','','[]','老憊無如汗枕何，起看玉宇瀉銀河。',64,'全唐诗/poet.song.223000.json','["老憊無如汗枕何，起看玉宇瀉銀河。", "殘山賸水淒涼甚，明月清風感愴多。", "無計閉門遮外事，真成開眼夢南柯。", "坐來不覺東方白，又是餘生一夜過。"]'),
('d17fe780-2445-4aba-9dca-608a9132e5ca','贈平原師妙覺歸溫州','陳著','宋','宋诗','song-poetry','','[]','喝破炎塵一錫飛，迂程千里訪衰遲。',64,'全唐诗/poet.song.223000.json','["喝破炎塵一錫飛，迂程千里訪衰遲。", "袖中明月無時價，面上清風似故知。", "契順何求惟勇義，參寥欲去且談詩。", "便應立脚五山頂，未死相聞倘有期。"]'),
('31a63231-cdce-4fe7-b9c5-bafd57325fed','次韻趙寄菴','陳著','宋','宋诗','song-poetry','','[]','家住黄沙綠水灣，功名土苴任天慳。',64,'全唐诗/poet.song.223000.json','["家住黄沙綠水灣，功名土苴任天慳。", "顧瞻宇宙驚多礙，收卷江湖憩一閒。", "處子聲容心自鐵，太公年幾鬢纔斑。", "老來難得重相見，明月清風處處山。"]'),
('2d3a0b61-9409-4f14-8f93-057f7d441f0b','見雪','陳著','宋','宋诗','song-poetry','','[]','馮夷老手妙莊嚴，一色工夫一夜添。',64,'全唐诗/poet.song.223000.json','["馮夷老手妙莊嚴，一色工夫一夜添。", "統捲山河還太極，平拋珠玉到窮閻。", "瘦吟相諗梅寒苦，渴飲何妨秫凍甜。", "黄竹方哀糴方湧，幸猶三白是豐占。"]'),
('f0691e03-d042-43c7-858e-d4578da59785','次黄長孺元夕韻','陳著','宋','宋诗','song-poetry','','[]','流俗誰知運會元，逢場作戲逐時論。',64,'全唐诗/poet.song.223000.json','["流俗誰知運會元，逢場作戲逐時論。", "梅花簪燭行呼野，竹葉裝巾醉舞村。", "幸是深山寬夜禁，苦無佳月破天昏。", "鼇山盛事當年夢，老不禁寒早閉門。"]'),
('549ab05d-44ad-438e-a1ea-a9183a917fa8','上乘展墓示子姪','陳著','宋','宋诗','song-poetry','','[]','吾行荷謝老天公，不放南來送雨風。',64,'全唐诗/poet.song.223000.json','["吾行荷謝老天公，不放南來送雨風。", "筇杖步前皆雅興，梅花香底欠詩工。", "塵埃辟易青山外，邱壟淒涼落照中。", "一片初心分付處，兒孫他日記衰翁。"]'),
('aa4a3975-5352-4277-954e-653dce0d33c5','次韻盧致遠祈雨喜應','陳著','宋','宋诗','song-poetry','','[]','四郊多少出雲山，六月如何得雨慳。',64,'全唐诗/poet.song.223000.json','["四郊多少出雲山，六月如何得雨慳。", "天意茫茫知不外，秋成岌岌有無閒。", "人非稼穡誰爲命，職在蛟龍可聽閒。", "終藉精忱起靈蟄，鶴驂带得夜瓢還。"]'),
('b30585b1-72cf-42e1-a3fe-2c64fd047c7b','次韻內姪竺稷留別','陳著','宋','宋诗','song-poetry','','[]','外家忠厚世多才，挑轡相過一笑開。',64,'全唐诗/poet.song.223000.json','["外家忠厚世多才，挑轡相過一笑開。", "珍重年光記親戚，綿延義脈到雲來。", "後生要積爲山簣，前事休論覆水杯。", "榾柮爐頭好情話，莫衝風雪便輕回。"]'),
('d732d4ab-d64e-4cef-a1a7-f024cda9eb96','避難雪竇之西坑遊西麓菴','陳著','宋','宋诗','song-poetry','','[]','山閒築屋古西坡，小小規模浄似磨。',64,'全唐诗/poet.song.223000.json','["山閒築屋古西坡，小小規模浄似磨。", "兩壁鼓鐘來雪竇，四圍松竹護雲窩。", "軒窗有趣高僧遠，門戶無遮俗客多。", "我寄前林時一到，未知風月意云何。"]'),
('5b293f7e-5df4-4c5f-8e77-2f35f71b6f37','戴時芳時可學子吳叔度文可載酒西坑勞苦','陳著','宋','宋诗','song-poetry','','[]','驚魂何事到西坑，豈是三生願莫償。',64,'全唐诗/poet.song.223000.json','["驚魂何事到西坑，豈是三生願莫償。", "兩寺鼓鐘醒客夢，一邨草木助吟香。", "人情物變多時樣，水色山光自古妝。", "我本無何鄉裏住，仰天頫地兩茫茫。"]'),
('8dbb7129-3169-43b8-8af1-8be2da60937e','次韻趙景文見寄','陳著','宋','宋诗','song-poetry','','[]','十載扃門白髮翁，一絲飛毒忽纏胸。',64,'全唐诗/poet.song.223000.json','["十載扃門白髮翁，一絲飛毒忽纏胸。", "浮雲隨讋驚雷散，躍鐵終逃劫火鎔。", "尚有先廬供手實，幸叨儒籍免身傭。", "關津本不征風月，來往何妨信一筇。"]'),
('506893e7-0326-46fb-bf32-3f72275b7fe8','次韻似前人','陳著','宋','宋诗','song-poetry','','[]','山居隨意旋添成，截斷人閒利欲腥。',64,'全唐诗/poet.song.223000.json','["山居隨意旋添成，截斷人閒利欲腥。", "蘭茁不妨虛白屋，松苗如見舊氈青。", "書癡面目唾亦笑，酒聖風流心自醒。", "閒裏光陰天下樂，誰知此處是思亭。"]'),
('436eb6f3-e4cb-4397-8959-7660726b3e7d','次韻弟觀似單君範','陳著','宋','宋诗','song-poetry','','[]','聚忽如萍散忽雲，今朝得見滿腔春。',64,'全唐诗/poet.song.223000.json','["聚忽如萍散忽雲，今朝得見滿腔春。", "詩書有味兵前友，官府無名天下人。", "相對兩窮消白日，不交一語到紅塵。", "梅花紙帳寒初試，儘可留連似病身。"]'),
('971463e9-9d9a-4989-acb7-b18498efff69','旦起誦邵堯夫詩','陳著','宋','宋诗','song-poetry','','[]','二十年前塵路忙，如今都住寂寥鄉。',64,'全唐诗/poet.song.223000.json','["二十年前塵路忙，如今都住寂寥鄉。", "梅花時節溪山好，菜粥人家門戶香。", "否往泰來天外事，早眠晏起枕中方。", "案頭只有堯夫集，參得透時滋味長。"]'),
('e8ec4132-8810-4161-a03b-739bc1d3474e','收芋偶成','陳著','宋','宋诗','song-poetry','','[]','數窠岷紫破窮搜，珍重留爲老齒羞。',64,'全唐诗/poet.song.223000.json','["數窠岷紫破窮搜，珍重留爲老齒羞。", "粒飯如拳饒地力，糝羹得手擅風流。", "家貧自盍勤多種，歲晚何當飽一收。", "回首人閒劍炊米，誰知煨燼有爐頭。"]'),
('50b34dfe-15f3-4dc2-8be7-3cf05795f673','西窗與弟姪戴時芳酌酒','陳著','宋','宋诗','song-poetry','','[]','一檐晴色好相陪，可意人能幾度來。',64,'全唐诗/poet.song.223000.json','["一檐晴色好相陪，可意人能幾度來。", "便覺酒香隨意動，共將書氣拓塵開。", "有生盍作無生看，未晚何妨到晚回。", "安得分時皆是趣，停雲歸鳥亦悠哉。"]'),
('fe625d30-8810-4055-b004-c374a57c678c','次韻齡叟','陳著','宋','宋诗','song-poetry','','[]','儒酸自是分當窮，老退非干勢不容。',64,'全唐诗/poet.song.223000.json','["儒酸自是分當窮，老退非干勢不容。", "并日莫留饞半菽，餘生休說壽三松。", "眼中落落同人少，脚底兢兢坎險重。", "惟有靈山老吟友，暗中心事兩雲龍。"]'),
('77516c05-7c41-41ad-858c-6e63757826b4','次韻里人紓憤','陳著','宋','宋诗','song-poetry','','[]','浮生分付四休休，自謂眉閒絕點愁。',64,'全唐诗/poet.song.223000.json','["浮生分付四休休，自謂眉閒絕點愁。", "鶴在雞羣空有志，鴻罹魚網莫抽頭。", "妄災勿藥終須喜，坎難維心底用憂。", "榮辱兩忘饒落魄，何妨痛飲學巢囚。"]'),
('f13f470d-3b56-48c1-a2c1-2d77895a97ac','余生日悶中示諸兒','陳著','宋','宋诗','song-poetry','','[]','吾今七十有七歲，多事多憂多病餘。',64,'全唐诗/poet.song.223000.json','["吾今七十有七歲，多事多憂多病餘。", "舉室忍貧饞煮字，長兒留遠夢收書。", "券逋積滯泥中獸，戶計偷生釜底魚。", "回首當年有今日，苟延如此要何如。"]'),
('7d9ec344-1140-49e7-876a-23bd4838a9e6','次韻少野','陳著','宋','宋诗','song-poetry','','[]','古調難逢鍾子期，近交祇數巳公詩。',64,'全唐诗/poet.song.223000.json','["古調難逢鍾子期，近交祇數巳公詩。", "家風自別閒相似，心事無涯話有時。", "草木味中猶著我，荆榛叢裏更同誰。", "衰年如許會能幾，俯仰悠悠雲水知。"]'),
('82fa5385-8578-41b1-a283-bedd60e82358','次韻戴帥初贈銅山寺主僧若珣','陳著','宋','宋诗','song-poetry','','[]','憶昔曾尋紫翠堆，轉頭非舊幾年來。',64,'全唐诗/poet.song.223000.json','["憶昔曾尋紫翠堆，轉頭非舊幾年來。", "僧檐蔓草幾成樹，佛座蓮花半纈苔。", "忽自吟邊飛錫到，再從空裏把山開。", "江湖總是風光地，應世因緣第一回。"]'),
('d67c3e81-30d8-4b2d-b389-2c5b8d06d6d7','賦胡貴常所寓西樓','陳著','宋','宋诗','song-poetry','','[]','早挾台山紫翠光，來棲高處足徜徉。',64,'全唐诗/poet.song.223000.json','["早挾台山紫翠光，來棲高處足徜徉。", "浮雲相伴身爲客，落月應同夢到鄉。", "雁笛入聯饒獨唱，鳳簫在袖待雙翔。", "拍懷湖海何妨共，倘許扶携上大牀。"]'),
('d48c3fa4-a070-4039-8471-5ba43f39f46e','次韻弟茝醉中示弟觀二首 自道','陳著','宋','宋诗','song-poetry','','[]','六十家婆八十翁，此心無事便融融。',64,'全唐诗/poet.song.223000.json','["六十家婆八十翁，此心無事便融融。", "肉香韭甲磁盆內，蝶夢梅花紙帳中。", "自有乾坤無俯仰，誰知否泰是窮通。", "出門一笑春風闊，孤鶴橫天忽自東。"]'),
('34bfa6ef-116c-41f5-bcbb-afd0cff58f04','次韻弟茝醉中示弟觀二首 爲弟茝道','陳著','宋','宋诗','song-poetry','','[]','斑髮朱顔楚秀翁，陶陶樂意與天融。',64,'全唐诗/poet.song.223000.json','["斑髮朱顔楚秀翁，陶陶樂意與天融。", "凌虛長嘯天無際，耐靜高眠日過中。", "茅屋生涯消幾許，梅花氣味最相通。", "詩書風日何妨共，載得歸來自甬東。"]'),
('c69659d1-3caf-4db8-ad04-91fc9858c544','寄史景正教授','陳著','宋','宋诗','song-poetry','','[]','物表樓前話一番，晨星落落破癡昏。',64,'全唐诗/poet.song.223000.json','["物表樓前話一番，晨星落落破癡昏。", "詩書非事口儒學，韋布不知身相門。", "壹是古心交耐友，多將新意發陳言。", "吾今老矣難重會，川泳雲飛有子孫。"]'),
('f2e975ae-55f0-4d60-809d-0c083a860326','次趙景文絕糧','陳著','宋','宋诗','song-poetry','','[]','赤嶠歸來似夢中，春風滿面掃儒窮。',64,'全唐诗/poet.song.223000.json','["赤嶠歸來似夢中，春風滿面掃儒窮。", "祇愁不祭鬼成餒，那問乏供兒哭空。", "饑卧何妨專雪屋，清貧消得喚冰翁。", "浮生總是閒煩惱，天已安排十二宮。"]'),
('6d31aa48-1d21-40c2-b418-82d5cf5067f3','送女清適甯海胡氏回次韻弟觀浄慈詩寫情','陳著','宋','宋诗','song-poetry','','[]','自恨當年許嫁輕，臨歧悲哽不能聲。',64,'全唐诗/poet.song.223000.json','["自恨當年許嫁輕，臨歧悲哽不能聲。", "痛腸恃酒翻多病，險道登天僅得晴。", "女欲有家生世事，誰知與父別時情。", "是雖壻玉□堪抱，南望雲山淚自傾。"]'),
('257113ec-9738-4e36-b447-e5385a45ebab','贈黄長孺奉母還家','陳著','宋','宋诗','song-poetry','','[]','潘御迓從靈緒鄉，簫吟歡動喜還堂。',64,'全唐诗/poet.song.223000.json','["潘御迓從靈緒鄉，簫吟歡動喜還堂。", "詩書餘澤心猶古，桃李春風話亦香。", "卜築已投山契合，奉甘先與菜商量。", "行邊好語須聽取，去却來時後會長。"]'),
('0dd6a254-ed4d-4bfc-bd56-e4c7efdee3ee','送別單君範','陳著','宋','宋诗','song-poetry','','[]','寒山曾約醉梅香，桃李花時願始償。',64,'全唐诗/poet.song.223000.json','["寒山曾約醉梅香，桃李花時願始償。", "四海舊交知有幾，三年一見去何忙。", "春光自好別情惡，老語無多贈意長。", "送到溪頭重回首，東風吹不住垂楊。"]'),
('edd5634f-8b6c-4982-b337-185fcf545a49','次韻弟茝客懷','陳著','宋','宋诗','song-poetry','','[]','竹洲西畔綠楊陰，一別春光直到今。',64,'全唐诗/poet.song.223000.json','["竹洲西畔綠楊陰，一別春光直到今。", "老境不生貧富夢，浮雲應識去來心。", "神明官府頌聲滿，風月弟兄詩味深。", "歸辦山中□紅飯，古來流水一張琴。"]'),
('b237bd78-f1be-425b-9c1d-10ef9630cf53','次韻西山寺主清月','陳著','宋','宋诗','song-poetry','','[]','一居西崦一東溟，曠落乾坤本不扃。',64,'全唐诗/poet.song.223000.json','["一居西崦一東溟，曠落乾坤本不扃。", "古月淒涼惟有夢，清風來往了無形。", "翩然好語真心白，中是當年□眼青。", "握手笑談明日事，雪庭庭畔綠楊汀。"]'),
('937b0587-1048-4ca5-a002-02ebcc5f51e4','次韻胡景參制機見壽二首  其一','陳著','宋','宋诗','song-poetry','','[]','倚囊仙叟付良姻，一實交孚略具文。',64,'全唐诗/poet.song.223000.json','["倚囊仙叟付良姻，一實交孚略具文。", "共喜樹高堪託蔓，自憐蕕臭不投薰。", "移厨幸免勞都督，問字何妨□子雲。", "月峽霞峰總奇絕，閒中相望足爲羣。"]'),
('90395d7c-a358-4185-aa37-5a797f88d8f0','次韻胡景參制機見壽二首  其二','陳著','宋','宋诗','song-poetry','','[]','南風吹笠走長鬚，一軸新詩一幅書。',64,'全唐诗/poet.song.223000.json','["南風吹笠走長鬚，一軸新詩一幅書。", "虎榜陳人有韓愈，鶴山佳壻得肩吾。", "行年八十死將似，求活須臾計已疏。", "慚愧珍羞□初度，忽忘門戶是窮儒。"]'),
('caf7e64d-8e19-4e89-aea4-a322f33357d1','次韻曹久可見寄','陳著','宋','宋诗','song-poetry','','[]','古道難知薄俗新，窮塗別語記城闉。',64,'全唐诗/poet.song.223000.json','["古道難知薄俗新，窮塗別語記城闉。", "君携夙學長湖塾，我寄殘生農望春。", "相見笑談雖未準，一詩來往尚堪論。", "出門凝眺空銷黯，流水行雲冷看人。"]'),
('dd255803-426c-48b4-a703-e9ad281150b8','次韻吳應奎解嘲','陳著','宋','宋诗','song-poetry','','[]','兩別因循久釀疑，其如老病骨纍纍。',64,'全唐诗/poet.song.223000.json','["兩別因循久釀疑，其如老病骨纍纍。", "心銘自勒家庭苦，手綆曾懸坎井危。", "吠雪有聲非我累，仰天無愧要相知。", "交情須看寒松柏，傲盡春風桃李時。"]'),
('59f3dcf4-4bdd-4ef4-a772-b658fc77cb10','次前韻吳山甫解嘲','陳著','宋','宋诗','song-poetry','','[]','望春山下剡溪湄，窮處無聊甚係纍。',64,'全唐诗/poet.song.223000.json','["望春山下剡溪湄，窮處無聊甚係纍。", "竹會依然思二阮，苗凶行矣入三危。", "梟聲只盍聞而睡，蛇影堪期達者知。", "試問流空千古月，過雲妨得幾何時。"]'),
('75d9c1d9-99ed-4404-bcf6-49df4beaa0e6','雪寒','陳著','宋','宋诗','song-poetry','','[]','巫山神女欲回車，滕六留雲布玉華。',64,'全唐诗/poet.song.223000.json','["巫山神女欲回車，滕六留雲布玉華。", "流水不冰翻有氣，老梅雖凍自宜花。", "幸逃僵死榆關戍，相伴饑眠草屋家。", "種麥已遲天豈恝，一聲晴意曉檐鴉。"]'),
('d546ca2b-f938-4b61-972d-2290bb8eb850','爲齡叟作','陳著','宋','宋诗','song-poetry','','[]','多年坐鎮翠微西，鐘鼓聲中好品題。',64,'全唐诗/poet.song.223000.json','["多年坐鎮翠微西，鐘鼓聲中好品題。", "見大不嫌山寺小，立高應笑世人低。", "掃莓苔地皆新築，倚竹梅雲是退棲。", "最與老天相狎處，無邊風月省提携。"]'),
('6b395e7d-18eb-455b-9c34-6197d4bb3adf','元夕醉梅山弟家  其一','陳著','宋','宋诗','song-poetry','','[]','行年八十病餘身，梅塢留連率見真。',64,'全唐诗/poet.song.223000.json','["行年八十病餘身，梅塢留連率見真。", "花到詩家方吐氣，酒無菜飣不成春。", "世情風雨妨歸路，古道山林有主人。", "珍重此時相得處，弟兄門外是浮塵。"]'),
('3dda0261-39b0-4d57-b0f0-f4e90c7eff22','元夕醉梅山弟家  其二','陳著','宋','宋诗','song-poetry','','[]','爲吾大患爲吾身，假合將來認作真。',64,'全唐诗/poet.song.223000.json','["爲吾大患爲吾身，假合將來認作真。", "烏兔有誰相與老，燕鶑於我已非春。", "再生未死客中客，萬事無聞人外人。", "獨有梅花尚知己，不妨一醉且同塵。"]'),
('3be6392f-46f0-473c-bc13-cf47b674f25c','梅山弟家醉中  其一','陳著','宋','宋诗','song-poetry','','[]','僵寒危病分泉臺，誰料今猶事酒杯。',64,'全唐诗/poet.song.223000.json','["僵寒危病分泉臺，誰料今猶事酒杯。", "可是食羊供未足，祇因齏甕喚教回。", "紫荆老樹死中活，棠棣春花笑處開。", "兒輩不知身是贅，勸餐雲母壽方來。"]'),
('fe720588-599f-487e-8051-5bf0564c0e88','梅山弟家醉中  其二','陳著','宋','宋诗','song-poetry','','[]','得閒處處是春臺，分付浮生水上杯。',64,'全唐诗/poet.song.223000.json','["得閒處處是春臺，分付浮生水上杯。", "詩酒未爲知瘦杜，簞瓢元不誤賢回。", "無情宇宙今猶古，有脚陰陽闔又開。", "世變何窮故如此，只將方寸靠雲來。"]'),
('0616a73c-b29c-40fb-8447-5564ea9c5172','偶成','陳著','宋','宋诗','song-poetry','','[]','烏飛兔走傲崑崙，人世浮浮託命根。',64,'全唐诗/poet.song.223000.json','["烏飛兔走傲崑崙，人世浮浮託命根。", "梅竹僅留三畝宅，桑麻方見萬枝孫。", "雲相迎送話詩客，風自閉開無事門。", "適意手攀檐外柳，旁觀撫掌笑遊魂。"]'),
('f412e799-546f-4e25-8f54-35219284a4b8','次韻陳晟別瀹','陳著','宋','宋诗','song-poetry','','[]','世態悠悠合與分，人生總是一浮雲。',64,'全唐诗/poet.song.223000.json','["世態悠悠合與分，人生總是一浮雲。", "瘦□悽惻來東野，妙墨淋漓恍右軍。", "棠嶠別時如夢寐，竹林何日共朝曛。", "吾今耄矣雖多感，風月相期未厭聞。"]'),
('31fb88cd-3f9f-43e6-be51-1f4381a2dab8','重陽坐邑中旅舍','陳著','宋','宋诗','song-poetry','','[]','禿鬢蕭蕭八十翁，爲誰留滯客檐中。',64,'全唐诗/poet.song.223000.json','["禿鬢蕭蕭八十翁，爲誰留滯客檐中。", "有詩不賦滿城雨，無酒可當吹帽風。", "與菊相逢還自笑，看萸欲健莫知窮。", "回頭戲馬臺何處，萬里秋聲有過鴻。"]'),
('e52930c5-9313-4dab-81da-3e8e9928baa4','次韻單君範','陳著','宋','宋诗','song-poetry','','[]','駒隙光陰自去留，眉頭底用著閑愁。',64,'全唐诗/poet.song.223000.json','["駒隙光陰自去留，眉頭底用著閑愁。", "人生枕上皆槐國，世事棋中幾弈秋。", "爲子孫謀惟蠹簡，有風月處即菟裘。", "醉多醒語不覺曉，何處鐘聲出梵樓。"]'),
('9d3bdc69-9465-43c1-8a0e-efd3f1321734','次韻梅山弟靜中大觀','陳著','宋','宋诗','song-poetry','','[]','默默融融內自觀，紛紛藉藉外何關。',64,'全唐诗/poet.song.223000.json','["默默融融內自觀，紛紛藉藉外何關。", "託言鵬化未爲大，相與鳶飛方是閒。", "萬古乾坤全易上，四時風月小詩閒。", "天寒一步不輕動，祇爲梅花費往還。"]'),
('27d900a0-6b87-4233-968d-749c6a9ce086','十月十二日到慈雲見去歲與齡叟詩因次韻','陳著','宋','宋诗','song-poetry','','[]','短筇敲路又投西，滿眼皆詩不用題。',64,'全唐诗/poet.song.223000.json','["短筇敲路又投西，滿眼皆詩不用題。", "風撼材聲如海怒，天鋪雪意放雲低。", "自憐白髮貂裘敝，欲借紅爐紙帳棲。", "記取年年此時節，兩翁一醉笑扶携。"]'),
('c6c75af7-40ce-494e-afaf-f75f866d02e8','次韻張子華寄示正月四日與其兄及俞叔可兄弟四人會飲詩','陳著','宋','宋诗','song-poetry','','[]','兩家昆季賀正來，投轄留連肯放回。',64,'全唐诗/poet.song.223000.json','["兩家昆季賀正來，投轄留連肯放回。", "恰第四朝春正好，合三百歲老相陪。", "有光西洛菜羹社，同醉東坡蕉葉杯。", "何似添儂八十一，呼爲五老共徘徊。"]'),
('ed7bd549-d06d-4d18-8523-b3119bd6271e','次前韻戲似','陳著','宋','宋诗','song-poetry','','[]','喜逢新歲带春回，四老過從賀泰來。',64,'全唐诗/poet.song.223000.json','["喜逢新歲带春回，四老過從賀泰來。", "君若燕毛分次第，我當鶴髮領徘徊。", "忺懷爵躍空相望，弱脚蹣跚阻一陪。", "傳語諸賢任拋外，百年夫婦自銜杯。"]'),
('3d2a111f-b4e1-4334-9c5b-1ba232cff27b','二月九日偶成','陳著','宋','宋诗','song-poetry','','[]','老境何須更問年，得須臾活便翛然。',64,'全唐诗/poet.song.223000.json','["老境何須更問年，得須臾活便翛然。", "平生交際無金谷，窮健中閒自葛天。", "終日閉門知拙味，有時放杖信嬉緣。", "兒孫子曰一聲處，已覺詩書世的傳。"]'),
('359a9a4e-cadb-422d-aeb2-660c9ba32286','次韻戴時芳病中','陳著','宋','宋诗','song-poetry','','[]','平生英氣欲摩天，晚節逢罹欲自憐。',64,'全唐诗/poet.song.223000.json','["平生英氣欲摩天，晚節逢罹欲自憐。", "紙帳漫移春夢枕，畫叉難繼日支錢。", "那知病及窮韓愈，肯把貧謀富計然。", "但得身安字堪煮，寄聲自有故山鵑。"]'),
('15b7caa3-d196-42af-989f-a19de0054b88','次韻張子華中秋感時','陳著','宋','宋诗','song-poetry','','[]','乾坤萬里一長吁，老憊悠悠據槁梧。',64,'全唐诗/poet.song.223000.json','["乾坤萬里一長吁，老憊悠悠據槁梧。", "未死自慚前死欠，有生不若此生無。", "縱聞新詔開途轍，難把陳言入範模。", "寄語嵩峯子張子，山林深隠是耆儒。"]'),
('dee8dc5a-9055-491c-b4c7-a044d8852f76','姪溥酒邊呈詩二首因次韻  其一','陳著','宋','宋诗','song-poetry','','[]','家住山深絕外喧，三峯直下老雲孫。',64,'全唐诗/poet.song.223000.json','["家住山深絕外喧，三峯直下老雲孫。", "古聲不入唐詩社，泥飲甯知杜酒村。", "饋案一真宜晚歲，竹林相醉任多番。", "上天下地雖寬大，何物□生偶尚存。"]'),
('dd0ee34d-b410-4206-869e-9750f0a94f72','姪溥酒邊呈詩二首因次韻  其二','陳著','宋','宋诗','song-poetry','','[]','人生等是蚋蚊微，年到如今死蹉時。',64,'全唐诗/poet.song.223000.json','["人生等是蚋蚊微，年到如今死蹉時。", "齏甕餘酸聊自分，蔗鄉翻苦要誰知。", "山川豈特雁堪唳，風雨不知雞可詩。", "時一出門雲萬里，回頭只許影相隨。"]'),
('635d38f0-575a-4102-b447-912c97064a32','次韻石秀叔城歸卜鄰','陳著','宋','宋诗','song-poetry','','[]','從來熱處易留人，孤負初心墊角巾。',64,'全唐诗/poet.song.223000.json','["從來熱處易留人，孤負初心墊角巾。", "盍與溪山酬素約，任將風月洗黄塵。", "口猶有齒先嘗乳，事付無言但飲醇。", "見說明朝又東去，莫教虛夢覓詩鄰。"]'),
('58da4a43-59d8-4eef-80a2-59c5617c9f37','題梅逸林隠君祠','陳著','宋','宋诗','song-poetry','','[]','潔蠲老筆記祠庭，更把辭情韻入聲。',64,'全唐诗/poet.song.223000.json','["潔蠲老筆記祠庭，更把辭情韻入聲。", "誓守松楸爲得死，肯戕桑梓買偷生。", "衣冠圖畫君心事，香火焚修子血誠。", "孝義本來無世變，有誰下馬拂陰塋。"]'),
('17cf9f32-6c68-457c-8a16-de8bca30a8af','次韻王聖傳自歎','陳著','宋','宋诗','song-poetry','','[]','道義相從自一宗，世人擾擾等雞蟲。',64,'全唐诗/poet.song.223000.json','["道義相從自一宗，世人擾擾等雞蟲。", "桂坊素襲多文富，橘隠何憂五鬼窮。", "寬以平田爲日用，笑將逆境付天公。", "何時王翰相鄰住，樽酒論詩兩醉翁。"]'),
('86841a01-a546-4e6b-a425-2469e58327f1','用前韻自述','陳著','宋','宋诗','song-poetry','','[]','憶昔微官玷瞽宗，歸來十載坐山窮。',64,'全唐诗/poet.song.223000.json','["憶昔微官玷瞽宗，歸來十載坐山窮。", "有家却似髠頭釋，無齒真成吮乳翁。", "□□□清秦吉了，餓猶未死信天公。", "餘生趯趯只如此，看取東坡賦二蟲。"]'),
('cc171ef7-db24-4bdc-9f2f-13ceb2cf7443','外甥黄阿相生日','陳著','宋','宋诗','song-poetry','','[]','湖山聚秀繫斯文，汝更崢嶸瑞戶門。',64,'全唐诗/poet.song.223000.json','["湖山聚秀繫斯文，汝更崢嶸瑞戶門。", "嵩里是人誇宅相，慈溪之後有曾孫。", "書聲自可怡重慶，家學何妨漲一源。", "遠大相期吾耄矣，莫將苦語等閒言。"]'),
('65cdf1fb-1712-462c-b797-2bdbfc6e1065','送嚴伯長教授邑庠任滿','陳著','宋','宋诗','song-poetry','','[]','手揚教鐸下龍汀，三載從容擅最稱。',64,'全唐诗/poet.song.223000.json','["手揚教鐸下龍汀，三載從容擅最稱。", "祿釜半虛家繼廩，書窗獨冷仕如僧。", "狎曾問字春風坐，惜欠論心夜雨鐙。", "此去蘭臺芸閣邃，尚須時寄一溪藤。"]'),
('5791f03b-fbfe-4fca-baad-e77535aa9948','次韻義烏賈養晦元夕書懷','陳著','宋','宋诗','song-poetry','','[]','新得新晴縱夜遊，紗籠喝道肯遲留。',64,'全唐诗/poet.song.223000.json','["新得新晴縱夜遊，紗籠喝道肯遲留。", "風流買市皆如願，雪艷歌筵總莫愁。", "不放晴光半分過，亦知人世一漚浮。", "星星鐙火須臾事，何似長看素月流。"]'),
('31b2be1a-c891-4b19-be5a-8186823674df','次韻王監叔','陳著','宋','宋诗','song-poetry','','[]','君家深似武陵源，又出雲來旆影翻。',64,'全唐诗/poet.song.223000.json','["君家深似武陵源，又出雲來旆影翻。", "負笈肯忘鄞北里，彯纓長說海東門。", "健收風月歸談麈，醉挽河江入酒樽。", "回首溪山吾耄矣，笑盟知有幾番溫。"]'),
('9a94cd8d-6d14-4d60-8733-01f56b097cc8','次韻姪溥偶成','陳著','宋','宋诗','song-poetry','','[]','玉藤新月照雙明，便覺梅天暑溽輕。',64,'全唐诗/poet.song.223000.json','["玉藤新月照雙明，便覺梅天暑溽輕。", "兩屋清風交□影，一團和氣壽家聲。", "肯陪醉興林遊暢，更喜騷懷草夢成。", "向上路頭須努力，蓆門元不困陳平。"]'),
('05d1c693-b22c-4c3f-9beb-1b3b2f4f67d9','次韻前人重陽','陳著','宋','宋诗','song-poetry','','[]','說道貧閒亦自忙，誰知碩果自存陽。',64,'全唐诗/poet.song.223000.json','["說道貧閒亦自忙，誰知碩果自存陽。", "堪憐凍病如無己，不復狂遊似季常。", "過眼世情多逐臭，閉門家話自生香。", "重陽已在西風裏，空有龍山入夢鄉。"]'),
('77f640b7-12ba-40c6-99cd-b74694ea933a','十月九日醉中二首  其一','陳著','宋','宋诗','song-poetry','','[]','八十二年真過分，兩三閒屋漫偷安。',64,'全唐诗/poet.song.223000.json','["八十二年真過分，兩三閒屋漫偷安。", "家人病退藥方熟，兒子歸來酒量寬。", "祇把詩書供日用，不知宇宙有風寒。", "開門但放溪山入，心本無他誰得干。"]'),
('67d52ea9-0166-4cd7-8f5e-a7c2fb4a5b0e','十月九日醉中二首  其二','陳著','宋','宋诗','song-poetry','','[]','人生欲滿十分難，得七分安便是安。',64,'全唐诗/poet.song.223000.json','["人生欲滿十分難，得七分安便是安。", "鳥信天公終不死，□於雲路本來寬。", "須知老眼今如古，肯徇時情暖換寒。", "說與兒曹能解意，相看一笑倚闌干。"]'),
('ba6bb472-b459-4616-bbcd-c8c1d3ceae88','送阮子俊歸池陽','陳著','宋','宋诗','song-poetry','','[]','袖携諸老義門詩，燁燁精神起病衰。',64,'全唐诗/poet.song.223000.json','["袖携諸老義門詩，燁燁精神起病衰。", "千里遠來風教地，一言不及浪遊私。", "山家飯粟論交淡，驛路逢梅信步遲。", "古道藹然三代上，由來好事要扶持。"]'),
('870bff11-4267-4d27-901f-56c68cf0a2a2','次韻吳山甫','陳著','宋','宋诗','song-poetry','','[]','誰敲拄杖碧溪灣，得見霞城老則山。',64,'全唐诗/poet.song.223000.json','["誰敲拄杖碧溪灣，得見霞城老則山。", "對面相驚風鑒舊，論心不放雨鐙閒。", "浮生夢蟻淒涼外，春事啼鵑遠近間。", "幸有新詩相慰藉，忍攀垂柳送東還。"]'),
('d1ac6f66-675e-4d31-a133-6d9a688cefdd','山甫用前韻留別因又次韻送行','陳著','宋','宋诗','song-poetry','','[]','二十年來一見慳，好風吹到小丹山。',64,'全唐诗/poet.song.223000.json','["二十年來一見慳，好風吹到小丹山。", "心交融暢醒如醉，詩話綢繆忙亦閒。", "邨況非今非古處，花時半雨半晴間。", "君今更欲尋僧去，知有吟邊債未還。"]'),
('daf1b9e1-a389-45dc-9984-7b38da2d2b16','鄉人爲予再賞鳳花求賦','陳著','宋','宋诗','song-poetry','','[]','朝陽鳴處發天和，化作靈根植寶坡。',64,'全唐诗/poet.song.223000.json','["朝陽鳴處發天和，化作靈根植寶坡。", "翠脊雙飛供襯色，血誠百喙染芳窠。", "儀韶難赴風雲會，任數何妨歲月多。", "翼翼自珍無一語，暗聽遊客賦卷阿。"]'),
('eb61ce6d-9ab3-4988-bf6b-cb564f71b94b','次韻石秀叔慈雲逃席自解','陳著','宋','宋诗','song-poetry','','[]','山林幸自絕塵氛，舊事誰嗟散幅裙。',64,'全唐诗/poet.song.223000.json','["山林幸自絕塵氛，舊事誰嗟散幅裙。", "方外老交心似水，坐中高論氣騰雲。", "杯盤引興真相率，鐘鼓催晨醉不聞。", "但願長留風月主，從今徑造免移文。"]'),
('26fcd98e-769c-4188-8ec1-bfe455997096','董君藻之子時修隨其師戴時可來見八句勉之','陳著','宋','宋诗','song-poetry','','[]','分明眉目綠雙丫，意氣融融十歲華。',64,'全唐诗/poet.song.223000.json','["分明眉目綠雙丫，意氣融融十歲華。", "若要終身行路正，須防小學入門差。", "人心不古皆流俗，師範如今獨當家。", "八十老翁無長語，九經中有好生涯。"]'),
('137350c2-0298-442e-be06-1409cd38f65e','次韻楊君貴來訪','陳著','宋','宋诗','song-poetry','','[]','雲自悠悠日自長，棲棲破屋七峯陽。',64,'全唐诗/poet.song.223000.json','["雲自悠悠日自長，棲棲破屋七峯陽。", "危時不死風潮泡，耄境猶生石火光。", "銜袖慇懃迂客旆，聯珠錯落照山場。", "扶衰展玩無時節，細把詩中一味芳。"]'),
('f6951721-4eb3-408c-bfd0-9203a998e197','君貴用前韻來謝又次韻答之','陳著','宋','宋诗','song-poetry','','[]','青鞋踏過剡山長，黄菊初香替紫陽。',64,'全唐诗/poet.song.223000.json','["青鞋踏過剡山長，黄菊初香替紫陽。", "情話綢繆無世變，意吟瀟灑似秋光。", "別來杏苑驚三載，問及花崖夢一場。", "我亦風前霜後葉，饒君青髮擅春芳。"]'),
('3aa4125d-1492-4c09-9043-8dfe513ac968','次韻史猷父','陳著','宋','宋诗','song-poetry','','[]','西崦殘暉薄首邱，與猨同嘯鶴同遊。',64,'全唐诗/poet.song.223000.json','["西崦殘暉薄首邱，與猨同嘯鶴同遊。", "山林一出資驚笑，風雨多情管滯留。", "前別忽來如再世，後期禁得又三秋。", "湖天倘有相從分，爲我何妨割半洲。"]'),
('890fff9f-2491-4a25-be3a-db88f49e57d5','次韻應誠則次楊君貴來求乃父長卿墓銘','陳著','宋','宋诗','song-poetry','','[]','眼中宿草感懷長，聽徹啼鵑送洛陽。',64,'全唐诗/poet.song.223000.json','["眼中宿草感懷長，聽徹啼鵑送洛陽。", "萍世生涯隨日異，花崖門徑尚風光。", "心知父志能全我，文得家傳早擅場。", "天也有人方寸事，本根深處自流芳。"]'),
('71cba7d5-231d-44f2-b926-995271c26732','送李仲實官郡學任滿歸餘姚','陳著','宋','宋诗','song-poetry','','[]','手分教雨□鄰庠，咫尺何分明越鄉。',64,'全唐诗/poet.song.223000.json','["手分教雨□鄰庠，咫尺何分明越鄉。", "一正不爲崖壁異，三年相與藻芹香。", "梅花時節催行色，藜燄風流要當行。", "應有青雲扶健翼，摩挲老眼看翱翔。"]'),
('1d9fa28c-8e9f-4473-99c9-c82c476865f1','送衢州孔明達官郡學得代送行次韻','陳著','宋','宋诗','song-poetry','','[]','三載分氈正學規，初心元不爲窮饑。',64,'全唐诗/poet.song.223000.json','["三載分氈正學規，初心元不爲窮饑。", "官身恰似僧遊錫，歸面無慚婦織機。", "霄漢故交爲有後，山林遺老辱相知。", "前程步步須珍重，歲晚江空人物稀。"]'),
('db3f20cf-df7f-4236-ac82-a8e289b032a4','賈養晦以其父叔厚所賦臨清亭詩求和因用韻寄題','陳著','宋','宋诗','song-poetry','','[]','湖邊小築扁臨清，眼力高人巧思營。',64,'全唐诗/poet.song.223000.json','["湖邊小築扁臨清，眼力高人巧思營。", "再世規模爲日久，一區光景得天成。", "兒孫受用功名外，朋友過從水□情。", "我亦要投瀟灑約，恨無鶴骨駕雲輕。"]'),
('dc538208-f660-4b22-8b76-9cef7627dc34','四月朔日鄉飲於邑董氏之依綠亭口占','陳著','宋','宋诗','song-poetry','','[]','道義爲鄉自不同，肯隨流俗唾衰翁。',64,'全唐诗/poet.song.223000.json','["道義爲鄉自不同，肯隨流俗唾衰翁。", "高談驚散洗紅雨，清飲喚回依綠風。", "直欲鳶魚相上下，那知烏兔有西東。", "得閒不樂真堪笑，金谷平泉總是空。"]'),
('83c310f5-5ddb-4b00-b9fb-1c0bb5bdd02a','贈陸可復西遊','陳著','宋','宋诗','song-poetry','','[]','梅弄疏花近黓天，摇摇征旆浙西船。',64,'全唐诗/poet.song.223000.json','["梅弄疏花近黓天，摇摇征旆浙西船。", "江湖闊處多奇遇，風月初心及少年。", "莫向晚唐中入局，須從老杜上加鞭。", "耄夫拙語幾乎駡，免示他人作怪傳。"]'),
('8acf63b3-91f4-4f71-b8e7-15c54297c356','次韻楊君貴','陳著','宋','宋诗','song-poetry','','[]','趁小春晴踏險來，相從溪屋冷生涯。',64,'全唐诗/poet.song.223000.json','["趁小春晴踏險來，相從溪屋冷生涯。", "山林眼力空時態，風月詩聲起病懷。", "薄酒出篘多亦醉，晚菘入饌淡爲佳。", "人閒樂處聊示耳，此外本無邱與崖。"]'),
('670a0615-3530-49e0-ae45-d1e973e7c141','王得淦次子侑生日求詩','陳著','宋','宋诗','song-poetry','','[]','梅窗生得甯馨兒，乳腹方離氣已奇。',64,'全唐诗/poet.song.223000.json','["梅窗生得甯馨兒，乳腹方離氣已奇。", "傅就外居來歲事，學從小入去年時。", "擅三元美家誰繼，有二郎賢父自知。", "可是耄夫虛贊祝，向來功業是人爲。"]'),
('b24c8a2a-1ae1-4dda-8aa5-9f0ecafaa32f','次韻邑丞高潔堂任滿來辭','陳著','宋','宋诗','song-poetry','','[]','與雲遊戲佐棠陰，古道誰云不到今。',64,'全唐诗/poet.song.223000.json','["與雲遊戲佐棠陰，古道誰云不到今。", "三載二松公事處，百年喬木世臣心。", "夤緣肯及通家舊，饑餓何妨閉戶深。", "公去那來遺愛在，老猶能聽晝簾琴。"]'),
('531353a5-c759-4c3e-9df1-95e0801e6fec','贈薛總管棄官從□','陳著','宋','宋诗','song-poetry','','[]','壯年自下退工夫，看破人閒戲劇圖。',64,'全唐诗/poet.song.223000.json','["壯年自下退工夫，看破人閒戲劇圖。", "靈運在家心已放，知章還里計非迂。", "梅花夢好拋鴛侶，蕙帳閒多引鶴雛。", "湖海風波任澎湃，白雲飛處結屠蘇。"]'),
('2df1a6ed-1777-4f4a-a1f3-dc110e7ecadf','次韻邑宰丁溉之點舟白杜','陳著','宋','宋诗','song-poetry','','[]','馬首爭迎我魯山，山邨風景趁詩還。',64,'全唐诗/poet.song.223000.json','["馬首爭迎我魯山，山邨風景趁詩還。", "樵蘇飽暖烟千聚，鷗鷺平安淥幾灣。", "似把宦榮拋度外，但收民喜上眉間。", "作舟事業纔輕試，餘刃恢恢心自閒。"]'),
('eb62e234-aa2d-482e-902b-f5e58f2742d4','次韻前人雪中','陳著','宋','宋诗','song-poetry','','[]','晚風吹下六花祥，喜到眉閒色淺黄。',64,'全唐诗/poet.song.223000.json','["晚風吹下六花祥，喜到眉閒色淺黄。", "旋積層寒消夙瘴，平施一白洗時妝。", "要尋閉戶家形迹，肯爲乘騅客斷腸。", "歲事已占禾麥好，與民相慶著詩忙。"]'),
('bc800348-2a81-4605-9b44-244b78897e67','次韻前人道中','陳著','宋','宋诗','song-poetry','','[]','開遍梅花柳漸絲，甘棠次第又添詩。',64,'全唐诗/poet.song.223000.json','["開遍梅花柳漸絲，甘棠次第又添詩。", "馬頭邨路皆官況，面上春風是己知。", "山筆重時諳事體，蒲鞭輕處惜民饑。", "老夫尚解隨人後，舞勸碑潭水一卮。"]'),
('b7d9f456-84b4-4a82-b34f-0e5e86d8193e','次韻前人爲人誣告受羊','陳著','宋','宋诗','song-poetry','','[]','冰蘗肝腸無詭隨，彼嚚何物妄相持。',64,'全唐诗/poet.song.223000.json','["冰蘗肝腸無詭隨，彼嚚何物妄相持。", "夢魂不到菜園破，行止肯教芒屩知。", "安用舌埋防異日，空聞肉袒有當時。", "從他萬口自公議，誰學償金直不疑。"]'),
('fe0662ad-4e9c-428b-a086-6b0a0764aa9b','次前人拉遊南山借意道別','陳著','宋','宋诗','song-poetry','','[]','公與南山是夙知，三年對面肯輕離。',64,'全唐诗/poet.song.223000.json','["公與南山是夙知，三年對面肯輕離。", "長汀明月催孤棹，廣莫高風酹一卮。", "采菊空懷忘辯意，有臺須立太平基。", "坐巖□處如追舊，盡取瑞峯留退思。"]'),
('ac71ba71-e800-4b72-9aa2-322406603e77','次韻邑宰徐何慊出示所作五首  其一','陳著','宋','宋诗','song-poetry','','[]','詩是天機不浪吟，自吟自正自規箴。',64,'全唐诗/poet.song.223000.json','["詩是天機不浪吟，自吟自正自規箴。", "參成鳳詔經綸手，織得麟經筆削心。", "宇宙中閒皆分事，雲霄高處是知音。", "從來老練公名大，兩鬢何妨點雪侵。"]'),
('89dec803-afdb-4d3f-a434-4b806213d96b','次韻邑宰徐何慊出示所作五首  其二','陳著','宋','宋诗','song-poetry','','[]','誰其知我獨春秋，小試毫芒大用留。',64,'全唐诗/poet.song.223000.json','["誰其知我獨春秋，小試毫芒大用留。", "二萬言書關社稷，八分地位傲公侯。", "儒家本色饒青眼，仕路焦心早白頭。", "笑殺庸人漫多事，包荒襟量自休休。"]'),
('19a0ab5d-9dc4-4b59-9a35-a22f4aadebf1','次韻邑宰徐何慊出示所作五首  其三','陳著','宋','宋诗','song-poetry','','[]','嶔崟一嶺曉光寒，胸次乾坤本自寬。',64,'全唐诗/poet.song.223000.json','["嶔崟一嶺曉光寒，胸次乾坤本自寬。", "高處何妨吞裏港，倦時渾欲隠中盤。", "攢眉舊市誰安宅，加額殘民自擁鞍。", "慈父母來千載遇，手將平易掃艱難。"]'),
('be4527b1-b82a-4860-83b3-1501f76e5747','次韻邑宰徐何慊出示所作五首  其四','陳著','宋','宋诗','song-poetry','','[]','錦製丈高底怕傷，手揮煩熱坐清凉。',64,'全唐诗/poet.song.223000.json','["錦製丈高底怕傷，手揮煩熱坐清凉。", "豁開心上平明鏡，看破人間戲散場。", "縣裏方將客醉白，臺端只怕趣催黄。", "梅花本是酸寒物，終累他年鐵石腸。"]'),
('3bd3f072-fc64-4a54-bab1-198c6ee8c337','次韻邑宰徐何慊出示所作五首  其五','陳著','宋','宋诗','song-poetry','','[]','笠戰西風馬噴沙，帆檣迎浪舞神鴉。',64,'全唐诗/poet.song.223000.json','["笠戰西風馬噴沙，帆檣迎浪舞神鴉。", "調舟欲助江流柿，入海非求棗似瓜。", "歸客迂尋桑社景，吟鞭香带木犀花。", "行邊好語應聽得，秋月春風六萬家。"]'),
('a5a3eedb-709c-4b3a-9bb7-7be784cc7221','次韻徐何慊九日登高','陳著','宋','宋诗','song-poetry','','[]','廣莫亭前秋氣清，招邀酒伴走庖兵。',64,'全唐诗/poet.song.223000.json','["廣莫亭前秋氣清，招邀酒伴走庖兵。", "悠然誰解知真意，樂只應須在太平。", "直到上峯饒獨步，盡收下界入雙明。", "滿頭芬馥隨歸馬，惟有黄花不世情。"]'),
('47e67e31-e5be-4167-b940-644ca21091ab','次韻程仲實僉事紀行','陳著','宋','宋诗','song-poetry','','[]','道脈來從洛二程，天教馳轡福東瀛。',64,'全唐诗/poet.song.223000.json','["道脈來從洛二程，天教馳轡福東瀛。", "筆頭有海清塵濁，胸次如春放雪晴。", "喜拍蓬壺鼇亦抃，攀遮梅驛馬難行。", "恨無老翼飛隨去，歲晚江空潮自生。"]'),
('87d9203f-b83b-4439-8e64-8a0aacad236e','次韻翁古晚府判見贈二首  其一','陳著','宋','宋诗','song-poetry','','[]','清風明月滿蓬瀛，誰識監州閒世生。',64,'全唐诗/poet.song.223000.json','["清風明月滿蓬瀛，誰識監州閒世生。", "道義濃香薰政譜，文章餘力到詩城。", "傃儒不買三姝媚，好客能容一座驚。", "見說鋒車春在路，北門西掖是功名。"]'),
('f1c81149-7bb7-40b4-ba7c-5b46e3588795','次韻翁古晚府判見贈二首  其二','陳著','宋','宋诗','song-poetry','','[]','振訊䙰褷病鶴形，箳篂影下話平生。',64,'全唐诗/poet.song.223000.json','["振訊䙰褷病鶴形，箳篂影下話平生。", "受原憲業惟環堵，遡德公心不入城。", "日把寸量著蝶夢，雲拖一出被猨驚。", "自慚迂學經題品，輸與兩生無姓名。"]'),
('c6f85755-d08a-4a61-9313-72d62e2964b3','贈袁杰入越','陳著','宋','宋诗','song-poetry','','[]','綠髮紅顔玉雪膚，南風吹送上雲衢。',64,'全唐诗/poet.song.223000.json','["綠髮紅顔玉雪膚，南風吹送上雲衢。", "平生師友相從去，本色功名一笑圖。", "庠校元非餬口地，詩書却是護身符。", "頹波世事那堪說，要見人閒有丈夫。"]'),
('28a01450-f352-4bd2-af36-8b86f6d5f367','次韻翁古晚見寄就送其之京','陳著','宋','宋诗','song-poetry','','[]','萬里風雲路向前，功名盍趁仕强年。',64,'全唐诗/poet.song.223000.json','["萬里風雲路向前，功名盍趁仕强年。", "文如李杜誰爭燄，心是夷齊不問泉。", "別駕有功歌沸海，築臺在望勇趨燕。", "自慚筋力難追送，側耳凌清上集賢。"]'),
('55a74111-1b9f-4622-94ec-eb48f9f2c3fb','次前人卜居得鄰','陳著','宋','宋诗','song-poetry','','[]','買屋相依老翰林，滿腔新意見新吟。',64,'全唐诗/poet.song.223000.json','["買屋相依老翰林，滿腔新意見新吟。", "浮雲仕宦四方志，明月家山千里心。", "鄰誼可曾分楚越，詩盟那有遠何陰。", "老夫亦忝桐鄉籍，賀厦行須曳足音。"]'),
('fc2b1175-293f-434e-a2c9-55e6937167e0','段縣尉以兄約齋二詩求和因次韻','陳著','宋','宋诗','song-poetry','','[]','兄弟誰無仕宦情，約齋好處最分明。',64,'全唐诗/poet.song.223000.json','["兄弟誰無仕宦情，約齋好處最分明。", "自緣友□勤相遜，可是詩懷要獨清。", "道義終身爲日用，功名外物等雲輕。", "閉門見說都無事，教子詩書是治生。"]'),
('09ae7756-b24c-4c92-b276-fb687fd566aa','女兄歸蕭氏夫死誓守柏舟郡聞於朝賜旌表褒節','陳著','宋','宋诗','song-poetry','','[]','終身堅白表重閽，一粹真如玉不痕。',64,'全唐诗/poet.song.223000.json','["終身堅白表重閽，一粹真如玉不痕。", "能使齊侯歸弔室，自應沛相奏題門。", "青天有眼臨霜節，黄壤知心妥夜魂。", "不見鄞江八行史，葉夫人德長兒孫。"]'),
('a236087d-1563-4ebe-be03-f1b2e67b5a66','送東平趙孟益赴徽政院譯史','陳著','宋','宋诗','song-poetry','','[]','秀出東平禮樂關，將車來覽小南山。',64,'全唐诗/poet.song.223000.json','["秀出東平禮樂關，將車來覽小南山。", "西風承命雙親下，上國媒身九譯閒。", "騰踏青雲金驛去，笑迎綠髮錦衣還。", "氣方銳處須珍重，莫把贈言爲等閒。"]'),
('cde63e37-c522-4b2f-9a8d-a999dd67d6fb','似李德昌州判','陳著','宋','宋诗','song-poetry','','[]','借重東南官府新，與秋高潔更春溫。',64,'全唐诗/poet.song.223000.json','["借重東南官府新，與秋高潔更春溫。", "公心知寄黄堂印，信令如開綵棒門。", "純用詩書中古味，樂聞名利外陳言。", "耄夫也爲鄉民賀，硬忍須臾一出邨。"]'),
('f52544bf-137a-4d95-afce-91187e0ec204','似星同知','陳著','宋','宋诗','song-poetry','','[]','通守魚符委任隆，規模新處見新功。',64,'全唐诗/poet.song.223000.json','["通守魚符委任隆，規模新處見新功。", "來從北斗光躔下，坐治南山紫翠中。", "載路政聲如藥石，契天心畫在屏風。", "深深到底清相映，一派碑潭水最公。"]'),
('09798301-b12f-4f1f-ac0c-3fc1780f6685','似臧伯通','陳著','宋','宋诗','song-poetry','','[]','玉壺冰裏見精神，來望芙蓉幕府新。',64,'全唐诗/poet.song.223000.json','["玉壺冰裏見精神，來望芙蓉幕府新。", "放膽擔當難處事，立身扶植不平人。", "公家退食門如水，淡處論交面自春。", "不是渾身皆古道，肯分一盼老山民。"]'),
('156a782e-01c0-42da-9341-277970d3f934','似鄭宗平','陳著','宋','宋诗','song-poetry','','[]','幕府新開紫氣臨，紅蓮綠水照初心。',64,'全唐诗/poet.song.223000.json','["幕府新開紫氣臨，紅蓮綠水照初心。", "宦遊受用家庭訓，公退尋盟湖海吟。", "傍塔山居真吏隠，酌碑潭飲當官箴。", "自矜出谷兒嬉老，一面春風得最深。"]'),
('b3cde6ec-80eb-4ee6-99ca-20d771b5e906','次韻徐何慊詠雪','陳著','宋','宋诗','song-poetry','','[]','馮夷翦水暗中央，映带同雲淺與黄。',64,'全唐诗/poet.song.223000.json','["馮夷翦水暗中央，映带同雲淺與黄。", "旋積層寒消宿瘴，平鋪一白洗時妝。", "行仙休羨王恭興，僵叟應關洛令腸。", "不覺喜吟豐歲瑞，方知知是爲民忙。"]'),
('dcee5019-0518-447b-b3f2-82da8a1a483e','又次韻前人見示','陳著','宋','宋诗','song-poetry','','[]','世事紛紛亂似絲，放教公道總堪詩。',64,'全唐诗/poet.song.223000.json','["世事紛紛亂似絲，放教公道總堪詩。", "三年仁政從頭去，百里人心是己知。", "脈絡相關真爲國，毫釐不便甚捐肌。", "殘生何幸身親見，也擬公堂舉壽卮。"]'),
('377996f7-a018-45b4-bc1d-7e772934b8b4','代吳景年次韻浄慈寺主僧頔上人二首  其一','陳著','宋','宋诗','song-poetry','','[]','烏驅兔迫一衰翁，始信浮生總是空。',64,'全唐诗/poet.song.223000.json','["烏驅兔迫一衰翁，始信浮生總是空。", "拈掇琴書終日事，依棲梅竹百年叢。", "無官不用憂三黜，安分何勞送五窮。", "咫尺上方鐘鼓地，從師學佛便須躬。"]'),
('a51d4d77-d021-40a1-8579-cda499c7f37f','代吳景年次韻浄慈寺主僧頔上人二首  其二','陳著','宋','宋诗','song-poetry','','[]','遠公陶陸成千古，誰復相從過虎溪。',64,'全唐诗/poet.song.223000.json','["遠公陶陸成千古，誰復相從過虎溪。", "西隠老師雖有約，北山俗駕似難齊。", "詩來日午雙瞳醒，句出天心萬象低。", "時課家僮修茗供，松風清處坐分題。"]'),
('c0ac2c77-20b7-426f-9fd6-eea4af363246','代浦城權縣趙節推鹿鳴宴詩','陳著','宋','宋诗','song-poetry','','[]','潜藩歲貢素多才，捷報歡聲沸似雷。',64,'全唐诗/poet.song.223000.json','["潜藩歲貢素多才，捷報歡聲沸似雷。", "南浦士流新姓字，西山夫子舊胚胎。", "登榮仙籍香浮桂，得意春魁信在梅。", "此去天衢齊縱靶，代庖祗餞幸重來。"]'),
('1f30cb40-1cfa-4c9a-877d-4d685a526a46','代前人次韻趙縣尉即席詩','陳著','宋','宋诗','song-poetry','','[]','舊來曾此攝雷封，勉策駑鞭愧罔功。',64,'全唐诗/poet.song.223000.json','["舊來曾此攝雷封，勉策駑鞭愧罔功。", "自分依蓮遊綠水，豈期沿檄又秋風。", "今來視昔還多事，我亦無他祇一中。", "此去未知能淑後，時知石藥頼明公。"]'),
('42536c46-b8a8-40e9-9bd2-1427cadec959','代天府曾安撫鹿鳴宴詩','陳著','宋','宋诗','song-poetry','','[]','笙簧聲合隘春風，春在江梅第一叢。',64,'全唐诗/poet.song.223000.json','["笙簧聲合隘春風，春在江梅第一叢。", "月旦姓名光上國，日邊步武便南宮。", "看花自是長安客，對客當如橫浦翁。", "杯酒殷勤相屬處，崢嶸頭角已爭雄。"]'),
('e62a3153-f2f8-46fd-bf79-bac89fc11b1a','代京尹吳山雲益雪應賀廟堂二首  其一','陳著','宋','宋诗','song-poetry','','[]','安排寒事做年華，老手薇垣第一家。',64,'全唐诗/poet.song.223000.json','["安排寒事做年華，老手薇垣第一家。", "神女先馳行雨旆，馮夷隨翦舞風花。", "萬塵並納真平等，一色橫陳絕點瑕。", "養樂堂前清賞處，賀班方退紫宸衙。"]'),
('8f862159-9bb6-4bce-bb59-3e7aceba1f5f','代京尹吳山雲益雪應賀廟堂二首  其二','陳著','宋','宋诗','song-poetry','','[]','非才承乏尹瑶京，何幸親逢造化成。',64,'全唐诗/poet.song.223000.json','["非才承乏尹瑶京，何幸親逢造化成。", "凝固地腴豐歲事，均調天氣壽民生。", "春歸休念采薇戍，夜捷已聞垂瓠城。", "方信太平元有象，九街簫鼓合歡聲。"]'),
('0ab7a0f4-b3e5-4351-aa27-4238dd201dea','壽吳景年','陳著','宋','宋诗','song-poetry','','[]','託迹紅塵不染塵，徑梅溪竹共精神。',64,'全唐诗/poet.song.223000.json','["託迹紅塵不染塵，徑梅溪竹共精神。", "字真正逼張居士，禪味曾參印上人。", "聲色素輕非爲老，鬚眉雖皓却如新。", "兒孫須得文章力，富貴叢中一壽椿。"]'),
('ec95ebae-edfe-4026-bf92-6dedc37be4b3','次韻剡僧孜書記','陳著','宋','宋诗','song-poetry','','[]','縣如殘寺裹荒城，僧幹窮緣耐苦聲。',64,'全唐诗/poet.song.223000.json','["縣如殘寺裹荒城，僧幹窮緣耐苦聲。", "雖把慈悲供日用，可能方便徇人情。", "四明山背看雲近，九里灣頭呷水清。", "支遁後身偏念我，惠來詩好愧兼榮。"]'),
('cb63b847-6c06-49d5-8f05-27d705387bb1','如岳上人求賦剡鹿苑寺一覽閣','陳著','宋','宋诗','song-poetry','','[]','層簷危鎮梵王宮，景物都歸兩碧瞳。',64,'全唐诗/poet.song.223000.json','["層簷危鎮梵王宮，景物都歸兩碧瞳。", "九萬里風斯在下，三千世界本來空。", "詩懷浩浩晴瀾外，人事滔滔流水東。", "凝佇移時還暝坐，胸中天地自玲瓏。"]'),
('cf1b1cc1-be6e-42e4-bc95-a3fb5897e692','次韻弟觀詠丹山池荷  其一','陳著','宋','宋诗','song-poetry','','[]','寺枕丹霞五月凉，藕花數朵碧漪塘。',64,'全唐诗/poet.song.223000.json','["寺枕丹霞五月凉，藕花數朵碧漪塘。", "梵天幻出水雲錦，法雨洗空時世妝。", "七寶池邊分得種，大乘經裏噴來香。", "是花是色只如是，笑拍闌干何有鄉。"]'),
('75a29325-c07d-455e-8a2c-17846506431f','次韻弟觀詠丹山池荷  其二','陳著','宋','宋诗','song-poetry','','[]','一雨西來滿寺凉，盈盈不語立方塘。',64,'全唐诗/poet.song.223000.json','["一雨西來滿寺凉，盈盈不語立方塘。", "遠公白社所修種，浄土青胎無點妝。", "要向花光見菩薩，肯從色界問蓮香。", "回頭玉手雙杯處，多少風流墮醉鄉。"]'),
('3bee1258-27a1-44d5-b409-d1b4ddaf3139','次韻張子開教授遊杖錫寺偶成','陳著','宋','宋诗','song-poetry','','[]','禪老慈悲下界愁，長詩招我到深幽。',64,'全唐诗/poet.song.223000.json','["禪老慈悲下界愁，長詩招我到深幽。", "人知晚節陶元亮，誰識初心馬少游。", "星月天高空繞鵲，江湖風惡不容鷗。", "苦無十畝田堪捨，借得僧房飯幾秋。"]'),
('836ccc72-93a6-460f-9e9a-362838c591ba','聞丹山主僧德周欲退慈雲主僧齡叟留此作','陳著','宋','宋诗','song-poetry','','[]','識破機關便出林，滿天劫火可能侵。',64,'全唐诗/poet.song.223000.json','["識破機關便出林，滿天劫火可能侵。", "水流不去青山影，風與俱高白鶴心。", "物外弟昆相契合，眼中世界幾浮沈。", "是知處處虛西榻，難得慈雲一片陰。"]'),
('be08a891-fcc0-4917-9a9f-9131145997e1','次韻前人似前人','陳著','宋','宋诗','song-poetry','','[]','老友姑從方外求，危時亦可少紓憂。',64,'全唐诗/poet.song.223000.json','["老友姑從方外求，危時亦可少紓憂。", "笑圖難贅餘人契，病室應關一世愁。", "淡飯是緣終有味，故山雖好莫回頭。", "滿航雪意元無價，住色空中足應酬。"]'),
('1b3285f4-ae26-46c7-8275-26a83e59c065','壽法椿長老二首  其一','陳著','宋','宋诗','song-poetry','','[]','慈雲一坐十年過，耐受空門末劫魔。',64,'全唐诗/poet.song.223000.json','["慈雲一坐十年過，耐受空門末劫魔。", "晨粥應緣千里到，秋糧入供寸功磨。", "當風松幹神彌爽，經雪梅花韻更多。", "大地山河供一笑，底須天女問云何。"]'),
('011a3e3a-7ecc-44b3-9bfd-3cca81879ae2','壽法椿長老二首  其二','陳著','宋','宋诗','song-poetry','','[]','一相從後便相知，結得因緣似許奇。',64,'全唐诗/poet.song.223000.json','["一相從後便相知，結得因緣似許奇。", "如水笑談多盡日，與雲來往本無時。", "爲蓮社約非吾事，讀藕花詩欲汝師。", "熟處不妨安穩住，江湖風浪更交誰。"]'),
('c56ead9c-e6cd-4a8b-8fda-73baa7daf4ad','次韻弟茝懷歸','陳著','宋','宋诗','song-poetry','','[]','同聲相應甚塤箎，雨夜聯牀只有詩。',64,'全唐诗/poet.song.223000.json','["同聲相應甚塤箎，雨夜聯牀只有詩。", "斷港漫生歸棹興，流年空感浴蘭時。", "良思難與世情說，衰病聊將僧定移。", "須信滯流皆有命，不然安用老天爲。"]'),
('689b50ba-3be1-4dc2-a904-9d00484ece34','似法椿長老','陳著','宋','宋诗','song-poetry','','[]','山林有福足慈雲，一耐中閒百廢新。',64,'全唐诗/poet.song.223000.json','["山林有福足慈雲，一耐中閒百廢新。", "詩榻話香來雅伴，齋鐘聲好撼禪鄰。", "紅顔藥力如平日，青眼梅花又小春。", "欲贊法身安穩處，年年松竹長精神。"]'),
('e7ebf798-7fd4-4eff-9e90-a015c34c627a','壽炳同長老','陳著','宋','宋诗','song-poetry','','[]','飛雪亭邊欲雪天，當年生日又今年。',64,'全唐诗/poet.song.223000.json','["飛雪亭邊欲雪天，當年生日又今年。", "雲山卓錫閑心外，湖海燒香笑面前。", "每爲寒交傾鉢施，更多雅客問詩禪。", "最高高處長長壽，贊嘆中閒歡喜緣。"]'),
('edd35ad7-e945-494f-b70e-55c0df6d6a74','似告成寺主僧蟾秋海','陳著','宋','宋诗','song-poetry','','[]','出宮牆外步冬暄，轉憩黄花翠竹邊。',64,'全唐诗/poet.song.223000.json','["出宮牆外步冬暄，轉憩黄花翠竹邊。", "一笑偈言非本色，相留清供亦前緣。", "土酥飣潔昏眵醒，湯乳包香老齒便。", "祇恐醉陶終愛酒，難陪惠遠共修蓮。"]'),
('8e5af5b6-4285-432b-981e-0321840432ed','次韻趙孟益遊西山寺','陳著','宋','宋诗','song-poetry','','[]','佛何爲者占崔嵬，引得騷朋蹈險來。',64,'全唐诗/poet.song.223000.json','["佛何爲者占崔嵬，引得騷朋蹈險來。", "洗鉢有泉披草見，入門無逕鑿巖開。", "避人幽鳥毛生樣，守屋殘僧面死灰。", "自是世閒心絕處，靈山無分莫徘徊。"]'),
('0c8d17de-e571-4df2-a966-e9333c56077a','次韻石秀叔慈雲避席自解','陳著','宋','宋诗','song-poetry','','[]','幽居便合洗城氛，清隠如何及妓裙。',64,'全唐诗/poet.song.223000.json','["幽居便合洗城氛，清隠如何及妓裙。", "橫浦名爲交佛日，眉山老自愛朝雲。", "逃筵觥罰甯甘受，隔壁釵聲想暗聞。", "色即是空曾記否，饒君百喙亦難文。"]'),
('a25ba641-9a19-49ac-b101-9fd74c138938','次韻竹窗兄松詩爲其病也','陳著','宋','宋诗','song-poetry','','[]','獨立南山嶺，傲視氛翳表。',48,'全唐诗/poet.song.223000.json','["獨立南山嶺，傲視氛翳表。", "虬枝結成蓋，寄託紛蔓蔦。", "風霜受變足，萬古爲一曉。", "日日當戶門，蒼翠濃可抱。"]'),
('ff19ac75-e759-4f2f-ac3f-4a9343e8a065','遊慈雲分韻得是字','陳著','宋','宋诗','song-poetry','','[]','僧關可人心，況此晴色美。',48,'全唐诗/poet.song.223000.json','["僧關可人心，況此晴色美。", "蹈蘚滑路多，訪菊香處是。", "引飲吞山光，清嘯落松子。", "我有即事詩，就掃石壁紀。"]'),
('71697a9d-dfc5-4588-9bef-6d468db6efbe','寄貝勉齋馮桂坡','陳著','宋','宋诗','song-poetry','','[]','美人隔江水，相思江水深。',48,'全唐诗/poet.song.223000.json','["美人隔江水，相思江水深。", "江水日夜流，泛我東去心。", "春風百花老，把酒別草草。", "邂逅未可期，梅杏黄已飽。"]'),
('9dc769fd-c809-4e60-9f84-b054b5586490','次前韻再寄二首  其一','陳著','宋','宋诗','song-poetry','','[]','誰言溝澮淺，誰言滄溟深。',48,'全唐诗/poet.song.223000.json','["誰言溝澮淺，誰言滄溟深。", "淺不如世態，深不如我心。", "我心先齒老，不踏章臺草。", "寄語知心人，故書足自飽。"]'),
('ba1ab6dc-8c3f-42f9-863a-f0b6295b3f29','次前韻再寄二首  其二','陳著','宋','宋诗','song-poetry','','[]','昨日寄君詩，詩說心契深。',48,'全唐诗/poet.song.223000.json','["昨日寄君詩，詩說心契深。", "君詩今日來，深於我詩心。", "期君松不老，我得如蔓草。", "相依無棄憎，分我風月飽。"]'),
('1fefb59e-0980-4eb1-aefc-678bd88d59c0','次韻戴成叔  其一','陳著','宋','宋诗','song-poetry','','[]','君子當固窮，達亦豈吾病。',48,'全唐诗/poet.song.223000.json','["君子當固窮，達亦豈吾病。", "有心事窮達，斯與天者競。", "仕可以致君，止則歸田詠。", "孔子聖之時，善學即鄒孟。"]'),
('335612d5-5b27-427d-8a1b-c53cc2ad9803','次韻戴成叔  其二','陳著','宋','宋诗','song-poetry','','[]','蟋蟀秋乃鳴，反舌不鳴夏。',48,'全唐诗/poet.song.223000.json','["蟋蟀秋乃鳴，反舌不鳴夏。", "天地如草亭，萬物寄虛架。", "達人窮物理，嗜理如嗜炙。", "動靜各有時，油然會心舍。"]'),
('da27a874-97b9-4c4c-b534-1b214bea28f2','次韻戴成叔  其三','陳著','宋','宋诗','song-poetry','','[]','世上貪鄙夫，紛紛如蔓草。',48,'全唐诗/poet.song.223000.json','["世上貪鄙夫，紛紛如蔓草。", "榮華能幾時，風霜不足掃。", "美人如黄金，百鍊色愈好。", "用舍無益損，此理須辨早。"]'),
('e940e35d-0c87-49d6-9612-4943bc4d6f10','次韻戴成叔  其四','陳著','宋','宋诗','song-poetry','','[]','當年雪溪翁，知命故知足。',48,'全唐诗/poet.song.223000.json','["當年雪溪翁，知命故知足。", "平生一退字，厚施不食祿。", "高潔嚴子陵，清賢段干木。", "溪上多子孫，林樹森瑶玉。"]'),
('8a18c1c6-52e8-43fd-b1f8-6fccf6928b8c','次韻戴成叔  其五','陳著','宋','宋诗','song-poetry','','[]','傍家數畝園，景物便偃仰。',48,'全唐诗/poet.song.223000.json','["傍家數畝園，景物便偃仰。", "水近竹愈青，土腴花怒長。", "得閒日月長，萬里歸坐想。", "有時發孤嘯，山谷答清響。"]'),
('d741049a-3e00-4a2a-8203-81807215f273','次韻戴成叔  其六','陳著','宋','宋诗','song-poetry','','[]','鑿池引山泉，泉脈來擾擾。',48,'全唐诗/poet.song.223000.json','["鑿池引山泉，泉脈來擾擾。", "池上有新亭，池下芰荷繞。", "色香兩超絕，天然本非矯。", "花開日開宴，醉裏人世小。"]'),
('a7795292-5942-4869-8e97-4c0e044ff6f3','次韻戴成叔  其七','陳著','宋','宋诗','song-poetry','','[]','青山如有期，佳處故當屋。',48,'全唐诗/poet.song.223000.json','["青山如有期，佳處故當屋。", "山勢西南來，發岡自岷蜀。", "其下生偉人，自反常自縮。", "達觀萬物表，山界歸一粟。"]'),
('43e75369-bb91-486d-87e2-9298c18f50b9','次韻戴成叔  其八','陳著','宋','宋诗','song-poetry','','[]','朝家相真賢，表表梧桐樹。',48,'全唐诗/poet.song.223000.json','["朝家相真賢，表表梧桐樹。", "羣賢如鳳皇，飛翔得依附。", "風來驚四鄰，汗走僵訓註。", "云胡太山巔，蒼蒼豈其數。"]'),
('e83da325-5b90-494e-8300-86250526ef8a','次韻戴成叔  其九','陳著','宋','宋诗','song-poetry','','[]','雪溪後人賢，門戶鬰相扶。',48,'全唐诗/poet.song.223000.json','["雪溪後人賢，門戶鬰相扶。", "牙籤三萬軸，研究勤三餘。", "天命未可期，毋嗟失東隅。", "但問道在己，窮達何關儒。"]'),
('e210215d-01e2-4c18-8949-0c73cf2dedfb','次韻戴成叔  其一○','陳著','宋','宋诗','song-poetry','','[]','我生一斷梗，會見親舊疏。',48,'全唐诗/poet.song.223000.json','["我生一斷梗，會見親舊疏。", "新詩如春風，習習勤噓枯。", "謝君和君詩，句甚形神癯。", "一笑當會此，各道意所如。"]'),
('8b917c4e-1a28-42ac-9568-05f6203932c3','次韻竹窗兄欲死嘆','陳著','宋','宋诗','song-poetry','','[]','人生天地閒，所患在身死。',204,'全唐诗/poet.song.223000.json','["人生天地閒，所患在身死。", "身死人誰逃，所患不在此。", "所患死其心，此患無比侶。", "厥初天賦性，未始分賢鄙。", "賢鄙何由分，由自全自毀。", "是故君子儒，明德至善止。", "不問身死生，誰論時泰否。", "紛紛蒙昧徒，知有外物爾。", "富貴苟可圖，遑恤理如彼。", "求容足稱香，喪志手落匕。", "本心不復存，蹠壽何足美。", "我兄竹窗兄，勁節修竹倚。", "一病二十年，坐受五賊使。", "題齋曰委順，無怨當沒齒。", "聞兄賦欲死，我方疑所以。", "及觀欲死辭，終亦委順矣。", "委順則心安，長須此心理。"]'),
('8a3ea11f-77d6-46b9-8e5d-0ea5e0ee792e','無題','陳著','宋','宋诗','song-poetry','','[]','鏡中看青山，山色非塵寰。',72,'全唐诗/poet.song.223000.json','["鏡中看青山，山色非塵寰。", "月中看水光，全勝日中看。", "山水本無改，所遇成異顔。", "朝過齊王門，暮叩西秦關。", "人生貴知己，不遇何不還。", "了了心自定，我居山水閒。"]'),
('64e9a4a1-1854-4594-a046-671d7a3495bb','送樓佺提舉赴省','陳著','宋','宋诗','song-poetry','','[]','綠髮方山冠，白玉氣色溫。',96,'全唐诗/poet.song.223000.json','["綠髮方山冠，白玉氣色溫。", "高談霏木屑，不問能知文。", "去秋奪標歸，今步南宮雲。", "儒科青氈耳，指取氣欲吞。", "春風看花馬，已繫長安門。", "知君必得意，何以持贈君。", "事業浩無窮，學問爲本根。", "我懷宣獻公，況君乃其孫。"]'),
('2f4c7430-5cd4-47d4-a791-6109b45624bc','送徐倅','陳著','宋','宋诗','song-poetry','','[]','堂堂東嘉英，文章筆如椽。',84,'全唐诗/poet.song.223000.json','["堂堂東嘉英，文章筆如椽。", "箳篂駐鄞城，迎刃解劇煩。", "最聲徹閶闔，詔使歸日邊。", "人方辦杯水，前事乃不然。", "才難復才難，得見青琅玕。", "愛護猶恐傷，那可輕棄捐。", "不見諸葛公，終薦龐士元。"]'),
('1600833c-4a8e-4d35-8a08-975c643347ec','送趙榷院','陳著','宋','宋诗','song-poetry','','[]','彼美稽山松，託根高高峯。',108,'全唐诗/poet.song.223000.json','["彼美稽山松，託根高高峯。", "當年脫蓬蒿，直上將擎空。", "卓立旁無依，磊砢多春冬。", "風霜受變足，身老氣益充。", "蒼翠照四山，枝柯結虬龍。", "世人那能見，塵埃瞇雙瞳。", "匠師知何在，立當要路中。", "需林方皇皇，有林能不容。", "行須中尺度，終爲大厦供。"]'),
('f97f9689-5d44-46b7-beef-1c631dbd5650','賦樓提幹古檜因贈其之官','陳著','宋','宋诗','song-poetry','','[]','我行晝錦坊，老檜欺眼碧。',156,'全唐诗/poet.song.223000.json','["我行晝錦坊，老檜欺眼碧。", "樛枝巧相扶，衆星拱月璧。", "人力固有待，面勢本天則。", "愛益雨露深，風霜莫能賊。", "維黄楊州公，好此如好德。", "千金買歸家，與德共封植。", "秀出攻媿齋，管領無媿色。", "立朝大節成，有詩見胸臆。", "三世傳到君，培養當益力。", "不墜先正心，是乃子孫職。", "君今西入官，此樹留鄉國。", "看君德日進，此樹日滋息。", "他日成名歸，相對兩奇特。"]'),
('1176cef2-7781-4b9b-b921-ce5ef5bd0de5','憐貓示內','陳著','宋','宋诗','song-poetry','','[]','黑花一銜蟬，畜之今幾年。',288,'全唐诗/poet.song.223000.json','["黑花一銜蟬，畜之今幾年。", "捕攫奔走捷，巧黠乃其天。", "一臠亦割啗，分與眠席眠。", "邇來主人出，出久厨無煙。", "罄室鼠輩少，時得聊自延。", "不就鄰婦呼，甯饑肯垂涎。", "夜寒身無棲，竈窟恬餘暄。", "灰染突塵涴，毛色非舊鮮。", "主人來歸初，繞室如訴冤。", "旁人固不解，主人當知憐。", "云何云可惡，惡彼身攣拳。", "依隨行坐閒，呵叱加笞鞭。", "不念昔可愛，惟惡今非前。", "本來是一物，色改愛遂遷。", "吁嗟乎貓乎，豈獨於貓然。", "人於夫婦閒，情義亦罕全。", "花顔少年時，偎倚心相纏。", "皤皤白髮垂，相醜亦相妍。", "吁嗟乎人乎，有耳聽我言。", "人生七十稀，能得幾時安。", "毋以私自賊，同室操戈鋋。", "舉案與齊眉，當如孟光賢。", "糟糠不下堂，當與宋弘肩。", "不然祇自苦，於我何益焉。"]'),
('63e6a8f7-7cb9-464a-a741-3daf54d85d70','無題','陳著','宋','宋诗','song-poetry','','[]','秋色薄山色，黄葉溪景瘠。',72,'全唐诗/poet.song.223000.json','["秋色薄山色，黄葉溪景瘠。", "出門欲何之，失笑坐溪石。", "冥鴻入層霄，感次萬里翼。", "手中鐵拄杖，睨視難枉尺。", "起舞衣袂揚，不借西風力。", "浩浩天地閒，誰能省頭白。"]'),
('eeb34eac-81eb-4908-8d36-2f28291038bb','夜窗書懷','陳著','宋','宋诗','song-poetry','','[]','夜深萬籟平，危坐弗閉戶。',132,'全唐诗/poet.song.223000.json','["夜深萬籟平，危坐弗閉戶。", "不著沈麝香，一空清似許。", "竹凉露易零，鮮鮮正亭午。", "彈琴大小聲，鬼語雜風雨。", "琴罷復長吟，吟罷復起舞。", "人生三萬日，胡可弱不武。", "越石勇著鞭，相如志題柱。", "惟患不自立，彼於我非愈。", "青萍已出匣，撫視氣如虎。", "生侯死廟食，可以噬而取。", "安能久居此，鐙花甘自苦。"]'),
('35c68057-997c-458a-802e-40e0a200ec2b','乙卯鄉貢鹿鳴宴次韻制使陳方叔勸駕','陳著','宋','宋诗','song-poetry','','[]','我朝自開國，聚奎五星明。',144,'全唐诗/poet.song.223000.json','["我朝自開國，聚奎五星明。", "人物輩稷契，製作諧莖英。", "從來詞賦學，尤負器識名。", "沂公事業富，蜀公德望清。", "手提文正印，身爲國長城。", "藐然予小子，亦知師長卿。", "細將狀月露，壯欲吞幽并。", "消磨凡幾載，僥倖才一鳴。", "自謂錐穎脫，猶有劍氣橫。", "師帥重吹送，寒賤分光榮。", "向前步驟闊，平生溫飽輕。", "終懷勸駕禮，肯愧鹿鳴聲。"]'),
('885adb4c-d7a9-4946-90d6-148c271cd4e2','題甯國府涇縣琴高堂','陳著','宋','宋诗','song-poetry','','[]','一山逶迤來，結崖俯寒碧。',84,'全唐诗/poet.song.223000.json','["一山逶迤來，結崖俯寒碧。", "傳聞控鯉仙，垂釣山下石。", "前事不必窮，要是古奇跡。", "山中好事者，築亭占清特。", "數本瀟灑花，松竹共幽閴。", "我來西風晴，一洗塵土昔。", "出門復回首，山前有歸翼。"]'),
('b4954272-8558-4202-8559-3000c03aea04','先兄至能遠忌丙寅十一月十七日行都謝氏家寓作','陳著','宋','宋诗','song-poetry','','[]','人生有兄弟，手足相扶持。',288,'全唐诗/poet.song.223000.json','["人生有兄弟，手足相扶持。", "兄死我獨生，我生獨何爲。", "父母生我晚，我憶我兒癡。", "兄出我挽袖，兄入我迎衣。", "低頭嗅我頭，垂手牽手隨。", "指望我長成，口授書與詩。", "嘉定癸未春，授筆題春詞。", "詞云青春過，二十七年期。", "讖語殊可怪，河魚忽乘之。", "纏綿日以革，醫藥窮所施。", "我父解衣典，我母躬爨炊。", "猶謂病有瘳，誰料終莫醫。", "家徒四壁立，正頼兄撐支。", "進有功名望，退有菽水資。", "胡然遽止此，門戶將依誰。", "風雨屋棟傾，江海亡楫維。", "父母相持哭，二姊哭撫尸。", "時我甫十歲，痛哭已深知。", "我今五十三，夢見猶涕洟。", "今日是何日，有感兄死時。", "老淚滴復滴，往事那可思。", "回首天地閒，鬩牆何人斯。", "我抱無兄恨，且爲世道悲。", "耿耿不成句，聊以示諸兒。"]'),
('feac0cca-7940-448d-b2c1-23d152bf4f6a','壽王修齋樞密 南津梅','陳著','宋','宋诗','song-poetry','','[]','凜凜霜雪根，拍拍天地仁。',48,'全唐诗/poet.song.223000.json','["凜凜霜雪根，拍拍天地仁。", "皎皎枝上花，卷舒幾冬春。", "結實調古鼎，味深薄俗顰。", "珍重不盡用，嚴風護南津。"]'),
('9332d358-f537-45c4-b138-1dbf351ac579','壽王修齋樞密 采若竹','陳著','宋','宋诗','song-poetry','','[]','楚楚青琅玕，亭亭上碧落。',48,'全唐诗/poet.song.223000.json','["楚楚青琅玕，亭亭上碧落。", "層層凜秋稜，不與春芳約。", "動摇清風生，塵濁空萬壑。", "常時一味靜，水月環采若。"]'),
('d2ed48a9-b684-4f25-9895-3c6f398ca536','壽王修齋樞密 霜傑菊','陳著','宋','宋诗','song-poetry','','[]','的的芳種傳，足足清氣結。',48,'全唐诗/poet.song.223000.json','["的的芳種傳，足足清氣結。", "鮮鮮擢寒叢，色正香自冽。", "世人豈不愛，或者隨境別。", "木落百草黄，獨也壽霜傑。"]'),
('ef241a90-fd01-4cab-8e5b-35effbff518e','壽王修齋樞密 石林松','陳著','宋','宋诗','song-poetry','','[]','矯矯千尺强，蒼蒼起層陰。',48,'全唐诗/poet.song.223000.json','["矯矯千尺强，蒼蒼起層陰。", "紛紛相投依，百鳥諧春吟。", "風饕冰雪嚴，誰共歲晚心。", "獨鶴從何來，徘徊行石林。"]'),
('44996937-a569-4134-a82f-c30a3e73cd73','題錢靜觀江山萬里圖','陳著','宋','宋诗','song-poetry','','[]','迢迢江山上，萬變紛起伏。',60,'全唐诗/poet.song.223000.json','["迢迢江山上，萬變紛起伏。", "中閒崛奇多，忽此入平沃。", "草對近或遠，來去自鳬鶩。", "宇宙本來寬，景物常滿目。", "此意知者誰，煙林有茅屋。"]'),
('9b6a22ff-719a-43d8-aa33-27d66e84751f','謝國英送苦筍','陳著','宋','宋诗','song-poetry','','[]','直節見初茁，苦心甘自珍。',60,'全唐诗/poet.song.223000.json','["直節見初茁，苦心甘自珍。", "紛紛夏籜中，獨養歲寒身。", "遣送從山西，衝破赤日塵。", "揖入生菜筵，氣味酷相親。", "譬之美人拳，彼獨爲何人。"]'),
('d162f48a-2b4c-4d50-aac0-996a518d1a3b','次韻弟觀用陶元亮歸田園居韻','陳著','宋','宋诗','song-poetry','','[]','麻麥在東阡，桑柘在南陌。',84,'全唐诗/poet.song.223000.json','["麻麥在東阡，桑柘在南陌。", "鳥飛魚在淵，生意各自適。", "相逢如相知，非苟旦與夕。", "此心乃平生，誰能開閒隙。", "嗟彼何人斯，徒爲形所役。", "役役本無名，於何見勞績。", "富貴死之除，清閒終有益。"]'),
('b989dc6e-ae90-4750-85c8-6fd444fd2149','九月十日鄉人醵飲丹山分韻得地字','陳著','宋','宋诗','song-poetry','','[]','流景赴壑蛇，浮生遷穴蟻。',156,'全唐诗/poet.song.223000.json','["流景赴壑蛇，浮生遷穴蟻。", "世變茲已極，擾擾欲何事。", "淡飲養丹田，守口爲福地。", "常時不出戶，一年兩遊寺。", "清霜又芳菊，與頭花前醉。", "里人重斯集，髣髴鄉飲意。", "敘坐既有倫，交勉言亦至。", "老成示典刑，少壯修容止。", "智者勿籠愚，勿以利傷義。", "實行培本根，餘力及文字。", "宙宇自顛冥，存古强吾里。", "扶持復扶持，相與無彼此。", "酒云酒云乎，淵乎有餘味。"]'),
('0c7c0805-a9ac-4dbb-a08d-3ac459481354','次韻張子開次子試晬','陳著','宋','宋诗','song-poetry','','[]','聞昔甯馨兒，如馬千里馳。',288,'全唐诗/poet.song.223000.json','["聞昔甯馨兒，如馬千里馳。", "或秀如芝蘭，或如飣坐梨。", "居易生七月，已能指無之。", "又比令狐楚，五歲善屬辭。", "是皆非偶爾，陰有造物司。", "吾黨正氣旺，楊泣墨子悲。", "誰知世變極，所見及所期。", "卓哉子張子，不問今何時。", "種德以種子，愈出而愈奇。", "元方既及冠，可寶已不貲。", "經史日研精，甚於渴與饑。", "百發當百中，善射如由基。", "亦曰厚自積，王魏不仕隋。", "再索又得兒，照室光陸離。", "今朝歲一周，岐嶷傲娥羲。", "叢珍試初步，動覺應矩規。", "粲粲文在手，炯炯白在眉。", "但喜家傳昌，浮機豈終危。", "宙宇一開泰，扶植須人爲。", "在外寄藩屏，在朝資棟儀。", "雖當保抱中，方來事可龜。", "風埃自澒洞，庭階且燕熙。", "眼底雙鳳雛，笑唾燕雀卑。", "而況表獨立，硬脊非韋脂。"]'),
('bb93a48b-98f7-49cb-b9bb-c475acec1fe8','用前人代二子用前韻來謝韻','陳著','宋','宋诗','song-poetry','','[]','蒼蒼本無爲，烏兔爭飛馳。',288,'全唐诗/poet.song.223000.json','["蒼蒼本無爲，烏兔爭飛馳。", "今日爲何日，誰叩和與羲。", "舉目萬感集，秋風黍離離。", "人生能幾何，夢境蛛營絲。", "或以烹自售，變詐如鞅斯。", "或以舌交戰，縱橫如秦儀。", "亦或事曠達，蛻形慕安期。", "不則逃空虛，灰心從闍梨。", "不曰古聖賢，自有天根基。", "爲己非爲人，積學如積貲。", "弗廢一日葺，庶幾百志熙。", "世遠教法散，有識如退之。", "試觀訓符讀，道義不以規。", "貴賤何足云，而乃徒費辭。", "進學以爲解，詩易分葩奇。", "安貧以知命，妻兒任寒饑。", "既而及行藝，顧欲中有司。", "未忘功名徑，□□荆棘茨。", "堂堂山斗望，爲論如彼卑。", "吾師吾孔子，曾子而子思。", "以至孟軻氏，四書炳蓍龜。", "君家兩英嗣，珠璧光和隋。", "元方知自力，閫奧次第窺。", "既以習語話，行有向學時。"]'),
('7ea35f2c-817b-44bc-a45f-160d1a243d5d','用前人示諸兒韻','陳著','宋','宋诗','song-poetry','','[]','世事紛游塵，薄俗囂鬭鶉。',288,'全唐诗/poet.song.223000.json','["世事紛游塵，薄俗囂鬭鶉。", "手足誰魯衛，肝膽多越秦。", "獨君先君子，父事吾先人。", "我得從之游，義與同胞鈞。", "上而下四方，相依爲齒脣。", "閒嘗道病殆，飲食藥餌親。", "卓卓乎古道，難言但書紳。", "今及其子交，知愛邁等倫。", "不曰淡無味，如嗜千里蓴。", "其子又其孫，秀異良可珍。", "架有萬牙籤，膝間又循循。", "功名特土苴，學術要深淳。", "工夫入細處，力行自忱恂。", "推而致廣大，直扶天地垠。", "書積非易□，難欺是蒼旻。", "不觀冬閉固，發爲青陽春。", "因知栽者培，根本前人身。", "萬事風絮盡，盛德修唯湮。", "契稠無浪語，感舊還酸辛。", "吾年七十近，不入時材掄。", "眼昏惟內顧，遑知世妝新。", "耳聾謝外聞，免飲聒者醇。", "溪曲五畝園，安受閉戶貧。", "蔬畦野草徑，月夕清風晨。"]'),
('f50583ed-df55-4e3d-ad9a-2622a71a37bb','和單君範古意六首 農','陳著','宋','宋诗','song-poetry','','[]','歲事有豐歉，官稅無減除。',72,'全唐诗/poet.song.223000.json','["歲事有豐歉，官稅無減除。", "誰知山中田，沙土多蒿蔞。", "秋來倘有成，猶恐纔半租。", "或其水旱至，不足償耰鋤。", "嘆息家百畝，無復三代初。", "妻兒忽相問，明朝飲何如。"]'),
('ab9137e1-9f4f-4407-bce2-4ba49c04ecbb','和單君範古意六首 圃','陳著','宋','宋诗','song-poetry','','[]','學圃盍如何，先說畦菜法。',72,'全唐诗/poet.song.223000.json','["學圃盍如何，先說畦菜法。", "栽種及天陰，灌溉須雨歇。", "更欲樹花果，古方難泯滅。", "不見郭橐駝，纖悉傳以列。", "於以供釜烹，於以佐杯勺。", "頗疑魯夫子，却鄙樊遲拙。"]'),
('182f4e6d-f60d-4841-90b9-4962ec403657','和單君範古意六首 樵','陳著','宋','宋诗','song-poetry','','[]','枯者既就拾，濕者亦既束。',60,'全唐诗/poet.song.223000.json','["枯者既就拾，濕者亦既束。", "空此一谷薪，載之可折軸。", "下山售市價，得糧不能宿。", "誰知此時心，氣塞口自嘿。", "安得如買臣，賣薪有時足。"]'),
('46777bf9-b79e-4be9-8026-a3500ca9c6fb','和單君範古意六首 牧','陳著','宋','宋诗','song-poetry','','[]','一笛橫秋風，渺渺心話長。',60,'全唐诗/poet.song.223000.json','["一笛橫秋風，渺渺心話長。", "勿效漢卜式，得即不爲亨。", "當如老甯戚，飯歌不爲狂。", "驊騮正驕騰，萬里水草場。", "誰知北海上，嚙雪對天狼。"]'),
('655d32d9-6adc-4aee-9dee-a2b65f763853','和單君範古意六首 ','陳著','宋','宋诗','song-poetry','','[]','莊叟非觀魚，遊戲何有鄉。',72,'全唐诗/poet.song.223000.json','["莊叟非觀魚，遊戲何有鄉。", "靈均豈漁者，聊以歌滄浪。", "超然網罟外，千載名字香。", "今人志多取，曲鉤有餘殃。", "魚死心亦死，胡爲不自傷。", "勿謂得忘筌，未得筌以忘。"]'),
('d011a038-eba8-4d20-9cb9-79afbb0ccac3','和單君範古意六首 獵','陳著','宋','宋诗','song-poetry','','[]','虎投止三跳，氣暴志匪深。',72,'全唐诗/poet.song.223000.json','["虎投止三跳，氣暴志匪深。", "人皆望而畏，所宅在崎嶔。", "時乎出山谷，爪利牙齒森。", "豈無勉有力，激烈盡殺心。", "我聞亦一快，細思又沈吟。", "就然射石者，未必能生擒。"]'),
('296ac184-207d-4f3a-8b30-4924356d277a','書范景山先丈逸事','陳著','宋','宋诗','song-poetry','','[]','朅來范公亭，聞昔范老子。',276,'全唐诗/poet.song.223000.json','["朅來范公亭，聞昔范老子。", "盛德自有銘，逸事有來紀。", "如彼沙匯墳，實葬外舅氏。", "纍纍塚十四，誰計後不祀。", "懷券售之人，枯骨聽擲棄。", "公心惻惻然，能忘我先妣。", "猛捐十倍價，復此不毛地。", "至今上塚飯，免爲若敖鬼。", "又如域西山，寸山寸金置。", "山人已過望，我懷不自已。", "當公未死時，而適山人死。", "顧斥眠牛岡，欲葬惟其意。", "夫先婦隨後，同穴墳隆起。", "世降俗日薄，安識仁與義。", "先世未百年，來者已弗記。", "況于外氏家，代盡子孫事。", "買山未一刻，賣者不敢視。", "況容賣主葬，爲人重於己。", "中心所樂爲，焉有一毫僞。", "死者豈無知，造物非塊爾。", "公雖不求報，感應乃常理。", "後嗣何其賢，相與繼前志。", "范氏其興乎，吾無閒然矣。"]'),
('ae0e464f-69b5-4fc4-8679-15b66a2eedd2','深出贅歸省再往婦氏家','陳著','宋','宋诗','song-poetry','','[]','父子恩愛重，人生別離苦。',252,'全唐诗/poet.song.223000.json','["父子恩愛重，人生別離苦。", "惟汝善事我，我亦深愛汝。", "我年今七十，又有多病母。", "出贅非汝心，事有難直取。", "寸步安可離，而乃江山阻。", "憶昨汝歸時，大暑走風雨。", "身如出水荄，淋瀝带泥滷。", "弱質又逃病，老懷方免慮。", "胡爲有力者，夜半負篋去。", "本自無完衣，轉使時赤露。", "命窮不可醫，眉攢若爲訴。", "我心愈惻惻，還送汝行路。", "奈何其奈何，聽我細分付。", "出入誰能無，歸期況堪數。", "遠遊必有方，無愧聖人語。", "得失亦何常，翕然雲散聚。", "不見古君子，墮甑甯復顧。", "賢哉汝婦翁，可以就規矩。", "瑟琴相好合，更聞汝得婦。", "足寬父母心，百里在庭戶。", "謹勿困閒愁，宗事要擔負。"]'),
('9f4514d3-5d68-4bed-ab73-bd522a7e0892','喜弟觀得孫彌月數句識之','陳著','宋','宋诗','song-poetry','','[]','我昔四十七，正室熊始抱。',168,'全唐诗/poet.song.223000.json','["我昔四十七，正室熊始抱。", "命蹇坐遲晚，不及含飴笑。", "今汝絕勝我，較我一年早。", "手撫宗嫡孫，況有眉壽老。", "汝心當何如，喜氣浮襁褓。", "何幸親見之，是子當跨竈。", "深源出芳流，盛德受豐報。", "家慶三世圖，人閒如此少。", "彌月湯餠席，雲集尊與少。", "歡極不知醉，老懷得傾倒。", "平生汝從我，篤友肝膽照。", "凜然來者懼，今乃知有紹。", "回首我四兒，賢否雖未料。", "庶如我汝心，世世式相好。"]'),
('750ee70c-faf0-4b06-bccc-5fa0f5594b76','次韻觀弟避難','陳著','宋','宋诗','song-poetry','','[]','北風行黑殺，東南天柱折。',180,'全唐诗/poet.song.223000.json','["北風行黑殺，東南天柱折。", "忠臣鋸解頭，文士刀抉舌。", "我亦走危途，腥埃蒙面鐵。", "攀緣極稜層，雙跟迸皴血。", "山人邂逅驚，强顔取容悅。", "班荆分菜糜，兒童笑流歠。", "荼毒復荼毒，難說更難說。", "十月初五夜，山林陰氣合。", "骨肉復何之，無從知死活。", "眼光射先廬，山人火烈烈。", "虎狼相往來，左右無寸挾。", "吞聲哭達旦，忽與妻孥接。", "相持牽衣裳，透膚霜露浹。", "何時是歸時，細思增鬰結。", "且見脊令飛，繞樹日千匝。"]'),
('7dc5945e-48f8-46bd-9762-a8e781f2f7a7','次韻瀹留避地有書欲歸因用前韻示之','陳著','宋','宋诗','song-poetry','','[]','離亂身命危，煩惱頭髮折。',180,'全唐诗/poet.song.223000.json','["離亂身命危，煩惱頭髮折。", "我兒在山南，百書饒苦舌。", "誰知我憶兒，如火煅心鐵。", "人生恩愛海，各自憐骨血。", "初謂時節好，膝下長娛悅。", "顧今□相遠，矛頭苟餔歠。", "兵馬交往來，近日尤難說。", "急投一隙寬，呼兒歸暫合。", "未問溝壑填，且偷須臾活。", "春來兩日强，寒氣猶凜烈。", "寄巢不蔽風，敗纊聊同挾。", "父坐母蓐卧，兄立弟裾接。", "分散得團欒，不語意自浹。", "爲白潤姊知，未須生悁結。", "明朝倘可行，亦須回一匝。"]'),
('79820cb8-7b49-4448-9c9c-8c6a00f17c91','午酌對盆蘭有感','陳著','宋','宋诗','song-poetry','','[]','山中酒一樽，樽前蘭一盆。',84,'全唐诗/poet.song.223000.json','["山中酒一樽，樽前蘭一盆。", "蘭影落酒卮，疑是湘原魂。", "乘醉讀離騷，意欲招湘原。", "湘原不可招，桃李花正繁。", "春事已如此，難言復難言。", "聊借一卮酒，酹此幽蘭根。", "或者千載後，清香滿乾坤。"]'),
('38003341-469a-43ec-9392-014e1322aced','送竺甥秀','陳著','宋','宋诗','song-poetry','','[]','恭惟吾外祖，盛德表一鄉。',228,'全唐诗/poet.song.223000.json','["恭惟吾外祖，盛德表一鄉。", "身都雲南瑞，一母十郎娘。", "吾母實居長，鍾愛非尋常。", "擇壻流俗外，眼高意見長。", "豈無富豪子，熟視不得當。", "吾父本儒家，詩禮夙自將。", "乃以吾母妻，相期早騰驤。", "誰知古罍洗，不入盆盎場。", "回遡外祖心，終老弗能忘。", "膝閒出苦語，此心汝其償。", "飲泣何敢受，負山類蚊蝱。", "二十一年閒，母沒父亦亡。", "我髮既種種，杏園僅霑芳。", "著鞭幸有路，蓋與忽仆僵。", "前言空在耳，欲報天茫茫。", "吾壻在吾前，吾子羅吾旁。", "努力各努力，世道須明昌。", "聽之勿藐藐，方來那可量。", "庶幾未了事，發爲前人光。"]'),
('fdbc0a80-c59c-44fa-88e3-0c6939db64c0','深自婦氏歸侍','陳著','宋','宋诗','song-poetry','','[]','我生貧非窮，有子環我膝。',252,'全唐诗/poet.song.223000.json','["我生貧非窮，有子環我膝。", "深汝實居長，何可去頃刻。", "顧從百里外，贅滯日復日。", "事有不得已，我心常壹鬰。", "昨朝烏鵲喜，夜得歸端的。", "瀹洵急迎路，呼鐙走奴卒。", "歸兒如猶子，先跳門限出。", "女潤卧東牀，方困寒痰塞。", "忽聞兄到家，夙恙一笑失。", "骨肉恩愛重，此歸真藥石。", "春風花氣香，今夕是何夕。", "酌汝一杯酒，聽我言歷歷。", "我老不任事，幹蠱汝宜力。", "汝母且多病，佐饋婦之職。", "三弟要讀書，惟汝身勵率。", "妹笄何以嫁，汝亦當纖悉。", "如此復如此，汝坐能安席。", "汝今雖有婦，未歸未爲畢。", "而況危亂世，離別重悽惻。", "一家得團欒，荼苦甘于蜜。", "歸來早歸來，我年七十一。"]'),
('2ec1b691-0e12-462e-816c-016a96101e5c','次如心姪古意韻','陳著','宋','宋诗','song-poetry','','[]','妻孥恩愛深，生死同一窗。',60,'全唐诗/poet.song.223000.json','["妻孥恩愛深，生死同一窗。", "胡然成別離，使汝悲涕雙。", "人世能幾何，明滅風鐙幢。", "有家尚堪活，奚豈□他鄉。", "安得歸來舟，順風自南江。"]'),
('a5e002e0-fc82-4f49-9f53-af8958926369','送董伯和西歸','陳著','宋','宋诗','song-poetry','','[]','葉葉青霞衣，來赴山中期。',120,'全唐诗/poet.song.223000.json','["葉葉青霞衣，來赴山中期。", "相看到忘言，日夜春風吹。", "昨夜雨瀟瀟，今日君欲歸。", "人生如夢寐，世道正嶮巇。", "我髮白已委，況堪生別離。", "君歸不可駐，我心得君知。", "闌干與雲平，白鳥來往飛。", "安得身有翼，長與相追隨。", "舉手一揖別，不作兒女悲。", "一樽尚可同，百里非天涯。"]'),
('e1f711f7-7e7c-4fb6-80d7-529b174e63d4','贈僧仁澤邂逅以數語','陳著','宋','宋诗','song-poetry','','[]','溫溫白玉璞，楚楚秋蘭香。',108,'全唐诗/poet.song.223000.json','["溫溫白玉璞，楚楚秋蘭香。", "胡爲乎此中，紙帳柏子房。", "詩書豈不仁，宿念落渺茫。", "況有白渺親，朝露爭餘光。", "時復一回首，雲飛青天長。", "人生能幾何，世事那能量。", "不觀身上衣，昔緇今已黄。", "我亦何心者，邂逅成感傷。", "颯然清風來，欲言言已忘。"]'),
('3980585a-0172-436c-9b86-d415f43a97d3','季秋既望吾族子姪以老人會於我家名曰燕老集此意亦可尚醉後寫其意','陳著','宋','宋诗','song-poetry','','[]','颯颯西風來，吹不開眉端。',264,'全唐诗/poet.song.223000.json','["颯颯西風來，吹不開眉端。", "團團空中月，照不見肺肝。", "菊花仍舊香，過雁秋年年。", "我懷人得知，流光逝如川。", "況此苟活身，包羞天地閒。", "不如先露晞，安用空流連。", "兒輩何爲者，芋栗菘藿盤。", "將以壽我酒，歲晚松在山。", "我謂非我意，掉頭三長嘆。", "繞膝不肯離，且笑且進言。", "陶潛杜少陵，逢時更多艱。", "何嘗便忘軀，得酒即開顔。", "父子恩愛重，一刻難輕拚。", "世路雖偪仄，天道又好還。", "但是强健在，心事終已寬。", "是亦菽水具，非如五鼎難。", "庶幾詩禮風，聊以娛親安。", "再拜固以請，願領家庭歡。", "勤勤苦費辭，細聽理亦然。", "强飲竟成醉，援筆如狂顛。", "梗概粗以見，不覺盈長箋。", "呼兒爲我歌，勿與醒者傳。"]'),
('d066d53b-5e76-463e-bf08-2230bc19ec18','敬賦虛齋孫君容膝','陳著','宋','宋诗','song-poetry','','[]','雲連屋不居，三閒葺茅茨。',228,'全唐诗/poet.song.223000.json','["雲連屋不居，三閒葺茅茨。", "田園非不寬，一畝環竹籬。", "楚楚山下花，湛湛池邊□。", "丈室南坡□，容膝以扁之。", "誰謂方回旋，天境春熙熙。", "壺中著仙翁，芥子藏須彌。", "虛誕彼異端，我□異於斯。", "聖賢與我對，經訓星日垂。", "可以讀離騷，可以擊壤詩。", "回頭紛紛者，金碧貯狂癡。", "聲色性命斧，財貨盜賊資。", "皇皇窘其廬，日懷不足私。", "蚊蚋同旦暮，不滿一唾嗤。", "豈識天下樂，本非外鑠爲。", "己大物自小，心曠神斯怡。", "一則萬條□，靜者動蓍龜。", "吾方謀一榻，盡老聊娛嬉。", "今日爲何日，此理知者誰。", "達哉子孫子，吾知有吾師。"]'),
('f63f33b8-3c88-40b4-863d-19def81659a5','贈弟觀之王傳心館數語送行','陳著','宋','宋诗','song-poetry','','[]','今日爲何日，風雨春寒癡。',228,'全唐诗/poet.song.223000.json','["今日爲何日，風雨春寒癡。", "吾心方惻惻，門外剝啄誰。", "謂我欲見兄，迎面三吁嘻。", "出語復梗塞，書擔行有期。", "豈不懷室家，將以療我饑。", "平生手足誼，奈何忽違離。", "執手因與言，吾道其果非。", "達則仕行志，窮則爲人師。", "去家二舍近，非是天一涯。", "行矣汝其勉，第問歸何時。", "久而俛首答，身如馬受羈。", "去住不在我，此況誰得知。", "吾年七十四，疾病常乘衰。", "汝年亦五十，半髮成雪絲。", "年事俱至此，時光去如飛。", "紫荆次第花，鳴雁□相歸。", "觸目成感慨，贈別難爲辭。", "但聞主人賢，安心免相思。", "明朝溪亭酒，爲我酌一卮。"]'),
('8d285269-74c7-4061-a89f-8315528993d7','張時齋書生也坐窮以星學資身贈其遠行','陳著','宋','宋诗','song-poetry','','[]','書生例饑困，世路方偪仄。',144,'全唐诗/poet.song.223000.json','["書生例饑困，世路方偪仄。", "胡爲乎此中，兀兀朝以夕。", "問之俛而答，初意豈今日。", "幾年鐙火窗，謂可生羽翼。", "時事出料外，竟作沈海石。", "寒谷春難回，涸轍水難激。", "聊分星家波，食此一涓滴。", "終然不自贍，拍案動遠色。", "江湖天風長，萬里誰能縶。", "姑以術資行，或者儒得力。", "泰與否相除，剝與復消息。", "要知窮非窮，當遇識者識。"]'),
('afc69208-d06a-4278-84ec-83eeb814bb76','贈舒亦山入越','陳著','宋','宋诗','song-poetry','','[]','危世無山林，頹俗無門戶。',96,'全唐诗/poet.song.223000.json','["危世無山林，頹俗無門戶。", "彼美詩書身，悠然自爲趣。", "揚揚飛霞珮，清風導前路。", "借問欲何之，謂我稽山去。", "秦風白雲曉，禹穴蒼烟暮。", "平生礧磈懷，高吟弔千古。", "茲行良不惡，欲贈無他語。", "如逢梅市仙，試與謀出處。"]'),
('ef57e236-f5a0-40e5-8f48-38d578130d05','避難西坑用瀹韻','陳著','宋','宋诗','song-poetry','','[]','春雨宜農耕，逆旅愁坐雨。',72,'全唐诗/poet.song.223000.json','["春雨宜農耕，逆旅愁坐雨。", "雪寒饑殺人，豪富雪中舞。", "憂樂古來殊，欲說頭自俯。", "見山豈不愛，身危心不武。", "入深復入深，有谷如子午。", "生死未可知，誰能問甘苦。"]'),
('0cc91b06-6bd2-4abb-a074-3e0ef4e350be','用前韻謝奉慈寺主僧居簡','陳著','宋','宋诗','song-poetry','','[]','人情相入處，春風與時雨。',72,'全唐诗/poet.song.223000.json','["人情相入處，春風與時雨。", "詩來少陵歌，酒到淵明舞。", "我窮適相似，肯爲黄金俯。", "忍饑固其常，笑視京文武。", "忽來方外餉，渾家飽炊午。", "此是法喜供，非如乞字苦。"]'),
('59ddfcdd-be55-41d1-9014-aa0738c21508','遊慈雲似齡叟','陳著','宋','宋诗','song-poetry','','[]','我來景照堂，主人一笑領。',120,'全唐诗/poet.song.223000.json','["我來景照堂，主人一笑領。", "蔬筍充我饑，芎朮療我病。", "坐久不知晚，留以夜榻並。", "世事方東流，人情入西暝。", "茲逢豈假合，如形有隨影。", "不言自相知，無味足雋永。", "潛遠意悠悠，披仰心炯炯。", "顧我爲何人，古今兩照映。", "餘言不可寫，手拍闌干猛。", "雲飛風滿山，萬動歸一靜。"]'),
('fd22940c-92c0-46e1-a5af-01feb74763bf','次韻演雅','陳著','宋','宋诗','song-poetry','','[]','洛陽棘滿門，連昌菌當衙。',108,'全唐诗/poet.song.223000.json','["洛陽棘滿門，連昌菌當衙。", "枸杞怪成犬，寄奴妖見蛇。", "芸香虛辟蠹，鞠梅工兩蛙。", "黄蘗到裏苦，紫荆無外遮。", "衰綠秋蒲柳，赧赤春金沙。", "薰蕕類莫辨，桐梓誰汝嘉。", "山下猶有蕨，邱中能無麻。", "杖老竹生力，炷病艾焮痂。", "芷蘭足幽媚，桃李從俗誇。"]'),
('c8fc73d7-9411-4ef5-b6dd-f5f3b09a106d','梅山弟家醉中','陳著','宋','宋诗','song-poetry','','[]','意行無定處，適口無夙嗜。',96,'全唐诗/poet.song.223000.json','["意行無定處，適口無夙嗜。", "門外自風埃，山中有餘地。", "事事皆順境，物物皆真味。", "梅山今何人，而我亦同數。", "麋鹿所驚怪，草木或不置。", "一杯復一杯，閨中笑聲沸。", "古道固如此，乃有此同氣。", "謂我且須留，崦嵫紅未墜。"]'),
('01d7ca66-60f8-4f57-bbfc-c99d85bfed48','送道士十二姪歸金觀','陳著','宋','宋诗','song-poetry','','[]','世道日以漓，人事日以非。',168,'全唐诗/poet.song.223000.json','["世道日以漓，人事日以非。", "吾宗昔昌繁，儒冠森巍巍。", "時節相會聚，燕笑芳菲菲。", "邇來歲復歲，存者星晨稀。", "我今七十九，奄奄一息微。", "汝亦七十八，褵褷舊羽衣。", "老我雖待盡，猶與墳墓依。", "而汝百里外，煢鶴傍孤飛。", "我非壽彭籛，汝非丁令威。", "年事已到此，餘生露易晞。", "後會安可必，欲別增歔欷。", "相送出門去，溪寒日無輝。", "我佇汝回首，此意知者希。", "丁甯且加餐，得健時一歸。"]'),
('d2afea70-eb5f-4306-ae56-9a8c00563b66','題黄長孺松江圖古箋','陳著','宋','宋诗','song-poetry','','[]','吾行半東南，松江東南奇。',96,'全唐诗/poet.song.223000.json','["吾行半東南，松江東南奇。", "湖鋪天上水，山橫鏡中眉。", "清風明月夜，細雨斜風時。", "扁舟幾來去，長揖三高祠。", "泯默一夢昔，欲語將同誰。", "忽焉入老眼，百年片紙遺。", "□□□□□，人境那可期。", "人境那可期，畫中時見之。"]'),
('b3d7a8a3-f7de-4326-b08a-67d936a4da53','四月十一日與婦小酌玉蓮花前有感','陳著','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖西山坡，水樂洞之側。',168,'全唐诗/poet.song.223000.json','["西湖西山坡，水樂洞之側。", "有池當軒綠，有花當夏白。", "風潤脈柔莖，午芳擅正色。", "方來玉八瓣，圓中珠一的。", "曾携真率杯，相看契清閴。", "主人自城居，付與乘閒客。", "回頭一十年，今日爲何日。", "窗前小盆池，又見此花發。", "花於我何心，我見花自惻。", "老妻頗解事，一笑復太息。", "胡爲不自知，君已八十一。", "洛陽白牡丹，楊家紅芍藥。", "魂夢且不到，何獨□懷昔。", "□□垂頭答，風雨天昏黑。"]'),
('65cdeefe-0e00-4079-98c8-8efd17493ac6','次韻黄巖高志尹寄壽','陳著','宋','宋诗','song-poetry','','[]','冠屨天地間，車笠風雲從。',168,'全唐诗/poet.song.223000.json','["冠屨天地間，車笠風雲從。", "我行半東南，已復八十翁。", "取友必端人，求我我蒙童。", "初見老不化，宿學今何功。", "萬丈委羽山，中有人中龍。", "文氣蘇玉局，心事龐德公。", "豈不願納交，誰與先爲容。", "何物瀹小子，託根歲寒松。", "寄我壽我詩，墨妙揚古風。", "扇開眼眊矂，翼起身龍鍾。", "要知片雲外，實共二浙東。", "氣以類相應，面未心已同。", "端如獲驪珠，不羨放鴿籠。", "濫吹譜美莖，難報來施豐。"]'),
('4a90aa6c-6637-4020-a398-6bc7c39f77e2','送陳孔晨錄鄞學任滿西歸','陳著','宋','宋诗','song-poetry','','[]','思昔南墅翁，用不盡書力。',180,'全唐诗/poet.song.223000.json','["思昔南墅翁，用不盡書力。", "留以裕厥子，著鞭飽諳歷。", "鄞庠多材地，糾錄迂分職。", "休休自無犯，耿耿不事激。", "時雨化後生，春風久宿德。", "妙墨雲烟飛，清吟雪霜逼。", "萬口何異辭，三年如一日。", "芙蓉桂花天，扁舟戒行色。", "帳飲集寮寀，袖詩空士籍。", "相送相致祝，此去萬里翼。", "非入蓬萊觀，則上梧桐掖。", "我素與子契，而況同宗出。", "區區愛莫助，珍重而翁積。", "豈不欲臨餞，耄笑筋力嗇。", "數語教兒洵，持候州西驛。"]'),
('680bc534-f219-4570-9eab-17853fc12755','似戴時芳','陳著','宋','宋诗','song-poetry','','[]','豐山在屋前，後坐龍溪龍。',96,'全唐诗/poet.song.223000.json','["豐山在屋前，後坐龍溪龍。", "中有人中龍，固窮氣自豐。", "溪山千萬狀，朝夕與從容。", "浮塵任開闔，本色無淡濃。", "我本深邨夫，見此更熱中。", "目睹鶴歸雲，耳接漁歌風。", "徘徊不忍去，樂哉此迎逢。", "何當中年留，回顧無宿舂。"]'),
('0ba7f0d0-7ff7-41a6-a6f2-7574512e0b99','次韻張子華九日長詩','陳著','宋','宋诗','song-poetry','','[]','君家脈壽張，文氣雄一鄉。',180,'全唐诗/poet.song.223000.json','["君家脈壽張，文氣雄一鄉。", "顧我不自武，窮於凍履常。", "異盼獨見嗜，古道無炎凉。", "憶昨夏季望，南風溪山香。", "渠渠飛帖盟，佇我高峰行。", "漓俗非所捉，此味如和羹。", "壽我醴蘸甲，飫我熬屑薑。", "別來坐成久，感激時拊牀。", "我耄君亦老，無預世短長。", "向來塵埃迹，如雲風掃將。", "簞瓢足不足，聽天自斟量。", "秋無宋玉悲，春無少陵傷。", "逢迎但歌笑，傲睨劇戲場。", "不然徒自苦，平地皆羊腸。", "加於人數等，衰劣如何當。"]'),
('b02468a0-9f4c-404e-8e45-54913e533b01','送曾孫灼出贅盧氏','陳著','宋','宋诗','song-poetry','','[]','男生必有室，有室在嗣親。',228,'全唐诗/poet.song.223000.json','["男生必有室，有室在嗣親。", "家貧或出贅，出贅難爲人。", "汝今爲此行，及此初花春。", "粼粼潮迎舟，葉葉風吹巾。", "鳳雲已在眼，不覺生精神。", "我方爲汝憂，老語因重陳。", "其修汝容止，其謹汝吻脣。", "門庭勿忘舊，市井勿隨新。", "沈醉不如醒，飫飽不如貧。", "僥倖多非福，歡笑容易顰。", "主敬爲根本，力學解因循。", "賢□□□翁，昔我相面頻。", "別來五十年，怱怱隔一塵。", "誰知有今日，汝得□□□。", "□□翁壻洽，義實師生均。", "造次莫非教，歲月如去輪。", "□□□□□，何此爲終身。", "留欲副清冰，歸欲見老椿。", "要須日凜□，□□□□津。"]'),
('21781b66-9f27-4448-a345-00cb4c23eacf','應吳伯秀縣尉教鄞學求詩','陳著','宋','宋诗','song-poetry','','[]','四明萬丈崖，佳氣蒸氤氳。',252,'全唐诗/poet.song.223000.json','["四明萬丈崖，佳氣蒸氤氳。", "融結固有在，特起誰如君。", "丹霄舞飛霞，青春藹奇芬。", "目下開五色，賸把天香分。", "飄颻忽自得，盤薄蓬海濱。", "無復出岫想，傲睨黄埃塵。", "秋臺挾明月，驅馳下東鄞。", "談言邑庠舊，教事非易新。", "詩書墮寂寞，衿佩苟朝曛。", "欲借膚寸陰，化爲無邊春。", "胡爲乎水雷，珍重經綸屯。", "何當自山川，流動志氣神。", "扇之月旦評，推以天風輪。", "終然難卷藏，快覩本色真。", "詞章要織組，手有錦繡紋。", "道義在培植，身爲枝葉根。", "須知大造化，不問官卑尊。", "因思杜先生，如古王河汾。", "宙宇非不寬，鄉里乃急親。", "賢躅漸寥邈，凜凜哉斯文。", "吾爲石雲賀，亦以勉石雲。"]'),
('4cce64d7-052c-49e4-aeba-f27e46cf2958','寄賦慈溪沈氏愛菊序','陳著','宋','宋诗','song-poetry','','[]','我不識愛菊，却與菊相識。',60,'全唐诗/poet.song.223000.json','["我不識愛菊，却與菊相識。", "寒前後著花，土中央爲色。", "微苦養長壽，晚香擅清德。", "滔滔彼世人，方爲桃李役。", "誰能起淵明，參到菊太極。"]'),
('0fb8c746-f5a0-4ade-952e-c1678d75103e','外孫黄相兒求詩','陳著','宋','宋诗','song-poetry','','[]','可人黄外孫，來吾與汝言。',48,'全唐诗/poet.song.223000.json','["可人黄外孫，來吾與汝言。", "是爲慈溪嫡，未離嵩綠門。", "以身答世譜，學問爲本根。", "吾言雖老拙，銘心其永存。"]'),
('94696802-72b1-4baf-a0c2-3fe0e615f4d8','三月二日醉中快活吟第二筆','陳著','宋','宋诗','song-poetry','','[]','看花須少年，老眼如夢然。',96,'全唐诗/poet.song.223000.json','["看花須少年，老眼如夢然。", "人生不滿百，動要言及千。", "富莫如金谷，貴莫如平泉。", "其能幾何時，回首皆塵煙。", "我貧雖到骨，妻孥尚周全。", "縱有炊斷續，未嘗見憂煎。", "如此只如此，吾有命在天。", "今朝一杯酒，知者誰爲賢。"]'),
('eef7d312-1fef-4a9d-8ed2-d742fe5025bb','新揭州學扁鄉人求賦','陳著','宋','宋诗','song-poetry','','[]','芹水揚新波，杏壇敷新陰。',216,'全唐诗/poet.song.223000.json','["芹水揚新波，杏壇敷新陰。", "春風年年事，迺有春如今。", "薰薰禮義香，洋洋弦誦音。", "但看此身貴，遐不在玉金。", "疇昔豈□夢，足縶口就瘖。", "風雨魑魅多，一坎幾千尋。", "文明應奎壁，杲杲白日臨。", "綆之濯清泠，鼓之起埋沈。", "犂鋤彼自分，丕我以佩衿。", "花封肇魚符，儒庠視泮林。", "筮吉更扁揭，籀法何嚴森。", "正氣護宮牆，精光貫書琴。", "賢侯蒞落成，寮寀分盍簪。", "慇懃公堂酒，再拜奉一斟。", "願言壽斯文，師友相規箴。", "道腴養斯豐，學深浚斯深。", "厎柱既有在，狂瀾可能淫。", "庶爲鄒魯國，不負孔孟心。"]'),
('3f35e0ab-1fc1-41d7-a764-700e034745a9','笑笑一篇代簡答王之朝','陳著','宋','宋诗','song-poetry','','[]','□惠家獅兒，雪白真可取。',216,'全唐诗/poet.song.223000.json','["□惠家獅兒，雪白真可取。", "摩挲方脫懷，跳躍遍庭宇。", "意在飽可饕，飼養如舊主。", "無菜安有肉，無倉那得鼠。", "怒眼如饑鷹，奮爪過虓虎。", "撞破儲粟瓶，翻倒生魚釜。", "謂可共淡薄，豈期遭慢侮。", "今又餉修梅，驚走孩兒女。", "筠籃未壁封，環哄爭起舞。", "獰於猿狖攫，慕其螻蟻聚。", "刑腥手濡血，漬蜜口流乳。", "老齒本自疏，吞吮頗辛苦。", "布衣惜如錦，□染濯不去。", "非不知滋味，亦欲驕腸肚。", "奈非素富貴，□舌崇貧□。", "於我亦云厚，自料無報所。", "聊以此爲祔，免得交□□。", "平生相忘契，笑笑一掌拊。"]'),
('fae66152-85e5-45b8-a3bb-09dc085d358d','題僧維枬詩卷','陳著','宋','宋诗','song-poetry','','[]','鳳□□□鳴，蚓竅出蟲聲。',240,'全唐诗/poet.song.223000.json','["鳳□□□鳴，蚓竅出蟲聲。", "陰雨不見星，腐草流爝螢。", "卓□獨何爲，不與時同情。", "風流晉宋閒，眼中無四靈。", "言言意脈脈，字字聲鏗鏗。", "我老見已曩，讀之水投冰。", "珍重復珍重，好處騰虎谷。", "嗟哉南山下，諸老家爲塾。", "彼饕何人斯，欲食酸寒肉。", "衣冠坐塗炭，袵席生桎梏。", "星節來自西，一見無遺目。", "丰稜霜雪嚴，號令風雷速。", "恩波四溟湧，文燄九霄矗。", "征徭脫濫籍，詩書還致俗。", "蹙蹙愁者欣，嗷嗷流者復。", "耄矣八旬翁，凄其無半菽。", "亦欲學龐公，不著城市足。", "要識澄清轡，滿慰平生欲。", "扶曳語鄉人，其來拜僕僕。", "下爲一邑謝，上賀天下福。"]'),
('250f817a-63a8-49d8-b593-7f5274598479','次韻段約齋送弟嗣宗來赴吾邑縣尉','陳著','宋','宋诗','song-poetry','','[]','宦遊及奉親，同氣有贈言。',72,'全唐诗/poet.song.223000.json','["宦遊及奉親，同氣有贈言。", "至哉天下樂，難與他人論。", "昔綬官憂責，先洗□□冤。", "行志此其始，甯爲利欲昏。", "持此娛祿養，有□□孝門。", "紛紛時勢眼，庶見古罍樽。"]'),
('cd20f654-29ae-4a73-811a-6b790e6019d0','壽天甯寺主僧可舉八十','陳著','宋','宋诗','song-poetry','','[]','□□□□□，化身千百億。',132,'全唐诗/poet.song.223000.json','["□□□□□，化身千百億。", "應世來住山，誰是直翁直。", "海眼□□脚，春心有鐵脊。", "閲歷十五期，作爲萬分一。", "洗盡舊氛□，□出新金碧。", "層霄撼鼓鐘，證明大功德。", "法嗣鎮別洲，澎湃好消息。", "歡喜不聞聲，贊嘆自生福。", "今日是何日，相慶開九秩。", "我亦有偈言，自知非本色。", "□憑南風便，吹入莊嚴域。"]'),
('66657ce7-23c0-43f3-9de5-491d9851d47c','代范景山和弟觀韻','陳著','宋','宋诗','song-poetry','','[]','厦傾木不支，鼎重足先折。',180,'全唐诗/poet.song.223000.json','["厦傾木不支，鼎重足先折。", "關張不終身，儀秦亦無舌。", "兒嬉柵關木，文具鎖江鐵。", "生靈痛何辜，宇宙半流血。", "山中如□□，翁媼自怡悅。", "問我何爲來，留我共朝啜。", "抵掌告時艱，低頭聽我說。", "我家住平原，百年三族合。", "詩書聲相聞，伏臘□爲活。", "一朝北軍飛，連甍歸燄烈。", "驚奔忘險遠，妻孥手扶接。", "豈料哭窮途，忽與親知接。", "患難相勞苦，杯酒□□浹。", "出山未有期，草廬倘同結。", "鷦鷯苟一枝，爲鵲同三匝。"]'),
('e723a54d-32c7-4554-8440-ec211c86c965','戴帥初九日無憀以滿城風雨近重陽爲韻七首袖而示余因次其韻  其一','陳著','宋','宋诗','song-poetry','','[]','畏景日以長，正氣日以短。',48,'全唐诗/poet.song.223000.json','["畏景日以長，正氣日以短。", "過者何憧憧，寂寂笑衰懶。", "浮雲有聚散，明月有虛滿。", "人事有如斯，冷緒聊自纂。"]'),
('64219038-c061-4133-9a1a-b05f18f6dc01','戴帥初九日無憀以滿城風雨近重陽爲韻七首袖而示余因次其韻  其二','陳著','宋','宋诗','song-poetry','','[]','邇來三五年，處處罹過兵。',48,'全唐诗/poet.song.223000.json','["邇來三五年，處處罹過兵。", "誰能宴龍山，無復遊彭城。", "今茲九日至，正爾百感生。", "仰天破帽落，失笑還自驚。"]'),
('e8c67454-28c7-4cfb-9e48-2565a53e9e64','戴帥初九日無憀以滿城風雨近重陽爲韻七首袖而示余因次其韻  其三','陳著','宋','宋诗','song-poetry','','[]','年年好時節，雪月花與風。',48,'全唐诗/poet.song.223000.json','["年年好時節，雪月花與風。", "誰知百年內，憂樂元不同。", "方其少壯日，日日醉夢中。", "年年旋衰颯，有景誰復窮。"]'),
('aa206682-3d0b-48f8-ba36-f0bd519bd39f','戴帥初九日無憀以滿城風雨近重陽爲韻七首袖而示余因次其韻  其四','陳著','宋','宋诗','song-poetry','','[]','吾髮白且老，面目又塵土。',48,'全唐诗/poet.song.223000.json','["吾髮白且老，面目又塵土。", "流落如秋娘，無復畫眉妒。", "徒懷萬里心，夜夢良勞苦。", "欲言言向誰，雞鳴正風雨。"]'),
('2cef5554-66d8-4c91-8b39-d78b6aacd27f','戴帥初九日無憀以滿城風雨近重陽爲韻七首袖而示余因次其韻  其五','陳著','宋','宋诗','song-poetry','','[]','履險須頓足，逢躁須戒吻。',48,'全唐诗/poet.song.223000.json','["履險須頓足，逢躁須戒吻。", "況今爲何時，正恐無地隠。", "柴門倘可閉，即與桃源近。", "豈無耆舊在，努力各自謹。"]'),
('e0da81c2-e9e4-44d9-9e98-152d963e82eb','戴帥初九日無憀以滿城風雨近重陽爲韻七首袖而示余因次其韻  其六','陳著','宋','宋诗','song-poetry','','[]','世多多才翁，誰識識字農。',48,'全唐诗/poet.song.223000.json','["世多多才翁，誰識識字農。", "可人忽來思，勞苦意稠重。", "時危幸未死，尊酒得相從。", "一醉不須辭，毋待漏盡鐘。"]'),
('7eaba932-d018-4c2f-98a5-cd54d63b17ae','戴帥初九日無憀以滿城風雨近重陽爲韻七首袖而示余因次其韻  其七','陳著','宋','宋诗','song-poetry','','[]','平生朋友樂，魚泳雁飛翔。',48,'全唐诗/poet.song.223000.json','["平生朋友樂，魚泳雁飛翔。", "如今不復昔，往往深退藏。", "安得無言心，相照松柏霜。", "飲此九日酒，味哉剝果陽。"]'),
('6ad13a5e-2f43-4498-866e-20951ba861e2','如心姪有詩因用韻','陳著','宋','宋诗','song-poetry','','[]','越鳥不巢北，流水東不西。',48,'全唐诗/poet.song.223000.json','["越鳥不巢北，流水東不西。", "人心胡不常，隨世爲昂低。", "造物善戲人，如兒笑復啼。", "行止當自適，何爲爾棲棲。"]'),
('8b9b19b0-cace-4139-aa24-14c364a7ccdf','剡縣次韻張兼夜月聯句','陳著','宋','宋诗','song-poetry','','[]','停棹即階除，空明一鏡如。',192,'全唐诗/poet.song.223000.json','["停棹即階除，空明一鏡如。", "飛毫僵庶可，吐句走靈舒。", "閙裏自靜好，公餘相起居。", "愛君情款密，裨我事迂疏。", "念念民租少，言言郡計虛。", "入林難即鹿，竭澤恐無魚。", "立政諳平實，行符審疾徐。", "亟牛且雞汁，服驥偶鹽車。", "斟酌黄流瓚，流連翠織裾。", "務滋桃李種，首事草茅鋤。", "願却辛毗子，同商雋永書。", "溪山萬寶藏，穹壤一蘧廬。", "吟吻饞供茗，官庖貴買蔬。", "塵勞資洗濯，技癢互爬梳。", "生活侵韓賈，襟期聽耳餘。", "雪舟如興盡，共此復誰歟。"]'),
('f8af2829-125f-42ce-b452-bc3b54f17604','贈醫相者趙月堂','陳著','宋','宋诗','song-poetry','','[]','維摩居士病不起，却向方丈說法無一事。',232,'全唐诗/poet.song.223000.json','["維摩居士病不起，却向方丈說法無一事。", "此證何證無實證，針灸湯藥所不治。", "子房狀貌如婦人，及到籌帷决勝無比倫。", "此相何相無實相，骨骼毛顔不足論。", "我雖不能學居士，逢人笑語中痛痞。", "我雖不能如子房，崢嶸自在虛皮裏。", "落魄道人趙月堂，挾醫與相走四方。", "肘後有方千金良，眼中有電千里光。", "自謂無病不可藥，不知我病不在脈。", "自謂無人不可相，正恐我形難摸索。", "去年相訪無一辭，忽焉而去豈其欺。", "今年重來又默默，問之不答惟求詩。", "汝袖醫手緘相口，却要我開詩口落汝手。", "一詩贈行聊爾爾，要見我證我相三年後。"]'),
('f87dc477-6591-4342-8bf3-63e67d79d500','前紀時行','陳著','宋','宋诗','song-poetry','','[]','孟春朔日雷聲發，雷後兼旬雨不歇。',194,'全唐诗/poet.song.223000.json','["孟春朔日雷聲發，雷後兼旬雨不歇。", "仲春之朔近春分，一夜風雪四山白。", "豐歉氣候看春頭，乃今變異連兩月。", "陰陽磅礴天地閒，自有常程更閉洩。", "今此胡爲顛倒行，闔闔萬物失其節。", "欲一出門泥濘深，巡檐問天天默默。", "老農忽從何處來，謂見歲時記中說。", "雞旦之雷雖非時，猶曰其占多黍稷。", "今朝有雪却非宜，米價當踴民食缺。", "吉者未幾凶者繼，所喜轉爲憂惙惙。", "向來好事多不應，纔說乖證不可活。", "黯然相對尚何言，但願所應在雷不在雪。"]'),
('e0de0391-bfdc-4b1e-98c3-5dc4a11fd3f1','寄賦黄東發湖山精舍','陳著','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','斷鼇奠極戲者誰，岷山如龍萬里馳。',396,'全唐诗/poet.song.223000.json','["斷鼇奠極戲者誰，岷山如龍萬里馳。", "大江之陽起衡岳，崒嵂散作千委蛇。", "直趨四明卓秀偉，二百八十峯參差。", "潮江合捧山駐脚，伏脈分行東西支。", "東或峨眉或鳳翼，□□萬頃琉璃陂。", "二靈龜浮挾霞嶼，大涵回顧藏嶮巇。", "我昔經行一俯仰，問百年前□何其。", "邇來世變那可道，前輩風流歸春澌。", "山川無言黯失色，徒使旁觀重歔欷。", "西來諸峯江之外，獨抱古青何巍巍。", "遠踏渤澥瀰湠漫，近枕慈水清漣漪。", "平生聽人歷鋪說，屐齒欲到足猶縻。", "況彼地靈所融結，是爲之越老屈奇。", "且聞勝處巧著屋，包括光景無餘遺。", "幾年期我數語贅，終恐摸索非真知。", "忽焉自省筆自舞，但說此翁他何疑。", "怪石稜稜聳瘦骨，秀色隠隠開疏眉。", "寬曠能容萬壑赴，峭特雄壓千秋卑。", "雲雨蓄洩大功用，波濤變化皆文辭。", "上而層陰入鳳凰，下而瑞脈生蘭芝。", "浮□藹藹自來去，本相不受時牡脂。", "曉猿不驚鶴不怨，幽花野草芳菲菲。", "以所見見有如此，又何以觀山水爲。", "君不見蘇子由詣京師，自謂終南嵩華雖已見，不若得見韓公琦。"]'),
('9e041871-f9fb-4638-b240-5e66388b414e','闢戴帥初食長菜','陳著','宋','宋诗','song-poetry','','[]','漂泊無家杜少陵，兵閒奔走如蓬萍。',296,'全唐诗/poet.song.223000.json','["漂泊無家杜少陵，兵閒奔走如蓬萍。", "碧澗香芹固可嗜，鱠鯉豈厭銀絲精。", "百謫九死蘇玉局，到處爲鄉心自足。", "有時珍嘗百糝羹，何嘗不食黄雞粥。", "二子流落甚數奇，攻苦食淡分所宜。", "顧無所擇隨所有，亦曰吾師吾仲尼。", "菜瓜魚肉皆可食，鄉黨一篇炳星日。", "君胡不學聖與賢，乃外吾道從道釋。", "豈薄朱門粉署郎，窮搜滋味豐時壯。", "豈惡氈帽侏𠌯輩，搏攫羊豕飽腥肪。", "不則牀頭怕金盡，不則繼肉乖夙準。", "遂將所受父母身，束縛枯腸强堅忍。", "況聞君家百指餘，正自不同藜莧厨。", "獨立標榜人所駭，此意未知果何如。", "君子之道在中耳，纔落一偏犯公議。", "有則庶羞不爲過，無則□□亦常事。", "朋友切磋欲無瑕，早從吾言勿姑差。", "庶幾上不見摽於仲尼之門，下可□□於杜蘇二子之家。"]'),
('de33ae92-8804-44a7-af6b-010fe988ae7a','弟茝家醉中趁筆','陳著','宋','宋诗','song-poetry','','[]','前山屏開照簷綠，後山如坐膝抱屋。',162,'全唐诗/poet.song.223000.json','["前山屏開照簷綠，後山如坐膝抱屋。", "數畝山園半畝池，松影參差庇梅竹。", "九月九日天氣清，銀白金黄百種菊。", "詩人好事酷喜客，新酒篘醲烹野蔌。", "中有有識剪髮妻，談笑咄嗟具魚肉。", "我醉不知日午晡，但覺意氣橫山谷。", "吁嗟乎爲何如時，我輩得此一日福。", "宇宙自隘我自寬，人生無厭我自足。", "梅山生計亦淒涼，一醉何曾計饘粥。", "浮邱洪崖總妄傳，最好只有三萬六千局。"]'),
('09dbbba0-8d39-4f88-a7cc-2b2196cefb74','弟茝飲至醉醉歸蹶道中荆棘中','陳著','宋','宋诗','song-poetry','','[]','聖俞小飲亦百杯，高叉兩手無欹頹。',294,'全唐诗/poet.song.223000.json','["聖俞小飲亦百杯，高叉兩手無欹頹。", "曼卿登樓終日飲，端坐人謂神仙來。", "二賢佳語三百載，磊磊亦有梅山在。", "有人招邀無不如，吞吸樽罍氣如海。", "夜來一醉不爲淫，歸路胡爲不自禁。", "蹴壓荆棘卧霜草，接䍦倒著披衣襟。", "我來相問胡乃爾，笑而答之言纚纚。", "禮豈爲我輩設哉，君特未知其趣耳。", "今日何日要如何，宇宙偪仄蜂一窠。", "進不得以事業見，退老溪曲山之阿。", "當時仰天月如水，恍惚采石江頭逢醉李。", "或時展轉見鄰簷，如席同舍郎家甕邊地。", "以形骸觀若狂疏，外形骸觀方見吾。", "世人總被形役心，我獨了了心存初。", "淵明對菊敗籬下，豈其嗜酒誰知者。", "少陵非愛牛炙酒，花鳥感時詩淚瀉。", "一聞此語心神驚，大夢忽覺暗忽明。", "自今有酒但相覓，從人看我兄弟醉中醒。"]'),
('6bd2a056-7b2b-4f34-b0db-d283aedef36a','次韻單君範寄梅行','陳著','宋','宋诗','song-poetry','','[]','洛陽今何辰，姚黄委沙塵。',60,'全唐诗/poet.song.223000.json','["洛陽今何辰，姚黄委沙塵。", "豈無桃李花，荆棘相僕臣。", "咄咄歲成晚，山空水粼粼。", "化爲萬葉飛，目斷無可人。", "誰知霜雪根，獨抱寒中春。"]'),
('616fe759-1a34-49dc-8531-afbe830d4823','醉中示姪溥','陳著','宋','宋诗','song-poetry','','[]','山茶風香酒微波，杏花日長人笑歌。',80,'全唐诗/poet.song.223000.json','["山茶風香酒微波，杏花日長人笑歌。", "兒孫歡擁白髮婆，煮菜解醉不厭多。", "人生樂事恐蹉跎，世事等是一夢柯。", "孝義兩字不可磨，當與兄弟相切磋。", "我家兄弟三世過，謹勿令人說如何。"]'),
('160d05e0-a258-43d9-9a91-a70f870d8650','後紀時行','陳著','宋','宋诗','song-poetry','','[]','歲在乙酉孟春朔，天氣凝滯雲不開。',224,'全唐诗/poet.song.223000.json','["歲在乙酉孟春朔，天氣凝滯雲不開。", "一日二日三四日，或雪或雨或夜雷。", "山川失色萬物病，寒氣折骨淖沒脛。", "如大兵後洪水餘，雞犬無聲煙火冷。", "況昔三陽轉新元，公私萬事五日寬。", "上得杯酒壽父母，下與妻孥賀團欒。", "如今景物不可說，官府何曾有時節。", "符移捷出星火飛，吏卒叫囂豺虎烈。", "意謂東風換年頭，眼前百痼庶有瘳。", "天時人事乃如此，何以解吾憂世憂。", "元日連陰至七日，老杜感時詩紀實。", "太平時節身難遇，昌黎此語亦悽惻。", "是時世事未如今，二老已有難言心。", "我今更有難言處，聊記歲月那忍吟。"]'),
('1f1fcbfe-07e9-42f8-817c-b1430cfbc858','吾黨與佛會','陳著','宋','宋诗','song-poetry','','[]','我惜蘇子瞻，氣豪天地隘。',208,'全唐诗/poet.song.223000.json','["我惜蘇子瞻，氣豪天地隘。", "雄文萬斛泉，盛名表昭代。", "自負學見道，欲漲歐陽派。", "胡爲所以學，先與本論背。", "或者交浮屠，聊爾奚足怪。", "何至敢昌言，前身五祖戒。", "眉山世積善，老泉亦英邁。", "脈絡有自來，胚胎乃融會。", "顧誣正大傳，謂感非類穢。", "胡鬼是吾親，父與母安在。", "痛哉復痛哉，不孝此爲大。", "本來中無主，恍惚求諸外。", "一妄流到今，狂瀾正澎湃。", "人人說輪回，處處習夷唄。", "有識或見譏，動以蘇爲解。", "愚者不必責，可責在吾輩。", "當時若遇吾夫子，鳴鼓攻之此其最。"]'),
('d4fe0dcc-02fc-44fc-a633-c303bfe982ce','癸未冬至後與妻對酌偶醉遂賦','陳著','宋','宋诗','song-poetry','','[]','買臣賣薪妻見棄，高鳳嗜學遭妻詈。',192,'全唐诗/poet.song.223000.json','["買臣賣薪妻見棄，高鳳嗜學遭妻詈。", "我窮到骨累百指，黎藿併日一髮氣。", "妻自執爨謀餘生，諸兒忍寒結饑腸。", "有時我癡笑問妻，妻亦笑答貧其常。", "聽之不覺一絕倒，不謂此道君亦曉。", "滿天地間皆浮塵，消磨不盡惟此道。", "低頭拱手說與妻，孟光舉案與眉齊。", "當時豈緣醉飽故，深遠滋味出鹽虀。", "而況今日爲何日，我年今年已七十。", "我妻之年雖少我，老心古道天與質。", "偶然得醉平生歡，醉中寫與諸兒看。", "人閒不必問貧富，須信關雎爲造端。"]'),
('c31aa020-15c7-4917-a138-8a7c757dbfc2','四月五日醉書慈雲閣','陳著','宋','宋诗','song-poetry','','[]','峰開荷葉東南傾，梵宮截斷西來青。',352,'全唐诗/poet.song.223000.json','["峰開荷葉東南傾，梵宮截斷西來青。", "參差樓閣半空起，撞鐘椎魚撼林坰。", "奔走簦笠數百里，隨事來乞山中靈。", "大衆坐飽雲捧足，百需順應水建瓴。", "彼饕者誰尸海閫，日鬻三帖出府庭。", "交馳爭此一席捲，赭山不足搜鉢瓶。", "囊橐所攫鳥獸散，遺臭滿山草亦腥。", "簷棟摧落甚敗驛，旁風雨濕上見星。", "厨煙寂寞甑釜破，殘僧菜色身伶俜。", "山運忽回緣法到，鐵錫飛入總雲亭。", "伽藍起舞山鬼避，擊大法鼓轟雷霆。", "豎硬脊梁施敏手，恢恢餘刃新發硎。", "仆者以興弊者剗，如痼病脫沈醉醒。", "況今佛流正澎湃，平地丈浪騰滄溟。", "何事不可咄嗟辦，寺已如畫山翠屏。", "誰知不忍回首處，山下景色何凋零。", "文獻故家編下戶，瀟瀟四壁門長扃。", "舊來富家鼠竄伏，貧民偶遺風濤萍。", "叫囂隳突尚不已，宛轉就縛垂死丁。", "春風無分日光薄，冤聲苦語那可聽。", "信有天堂與地獄，咫尺中間分異形。", "世變不情至此極，仰面三歎天冥冥。"]'),
('7706b858-b27f-446e-8848-749973a073ee','夜夢在舊京忽聞賣花聲有感至於慟哭覺而泪滿枕上因趁筆記之','陳著','宋','宋诗','song-poetry','','[]','賣花聲，賣花聲，識得萬紫千紅名。',304,'全唐诗/poet.song.223000.json','["賣花聲，賣花聲，識得萬紫千紅名。", "與花結習夙有分，宛轉說出花平生。", "低發緩引晨氣軟，此斷彼續春風縈。", "九街兒女芳睡醒，爭先買新開門迎。", "泥沙視錢不問價，惟欲蕩意摇雙睛。", "薄鬟高髻團團插，玉盆巧浸金盆盛。", "人心世態本浮靡，庶幾治象猶承平。", "賣花聲，賣花聲，如今風景那可評。", "向時樓臺買花戶，淒烟落日迷荆榛。", "但見馬嘶逐水草，狐狸白晝嗥荒城。", "萬花厄運至此極，縱有賣聲誰耳傾。", "我生不辰苦懷舊，如病入痼酒宿酲。", "況被春風暗撩撥，傍無知我難號鳴。", "忽焉夜枕發爲夢，恍恍惚惚行故京。", "一唱再唱破垣隔，聞聲不見花分明。", "謂此何日尚有此，傾面大慟泪縱橫。", "久而方覺更哽塞，擁被危坐百感并。", "我年今已七十一，豈是年少閒關情。", "天空地闊說不盡，山外杜鵑啼殘更。"]'),
('bd892509-e2f1-4cc0-ae1b-0d49306c6303','看花吟','陳著','宋','宋诗','song-poetry','','[]','少陵野老老更癡，看花看開千萬枝。',176,'全唐诗/poet.song.223000.json','["少陵野老老更癡，看花看開千萬枝。", "安樂窩中打乖叟，看花只看半開時。", "二賢看花各有意，我亦有意看離披。", "紅飛換得綠陰出，瀟灑頗與老眼宜。", "麥風揚塵野色秀，梅雨蒸葉香氣滋。", "避人好鳥著巢穩，爭春蜂蝶今何之。", "本來生意無間斷，靜看遊戲造物兒。", "不觀聖人畫剝卦，剝窮於上復下隨。", "嗟乎人事正如此，盛非終盛衰非衰。", "衰盛相乘乃常理，盛不必喜衰奚悲。", "誰知世情偏喜盛，我看花衰我自知。"]'),
('7a9bd1b4-3c88-4393-bbce-2caa3cf336fe','六月五日大風雨水弟觀有詩道其事因和之','陳著','宋','宋诗','song-poetry','','[]','自古人間多水旱，人事盡時功過半。',288,'全唐诗/poet.song.223000.json','["自古人間多水旱，人事盡時功過半。", "區區事空不事實，三代以後人心亂。", "吾鄉薄産寄山溪，崎嶇隨勢無尺齊。", "受水通灌盍預備，隄防以石堰築泥。", "顧不此信信偶木，鴂舌唄誦淫比屋。", "豈知性本依人行，方信之中神所宿。", "大雲遮日雷無聲，兼旬望霓憂羣生。", "更兼五日天不雨，原無黍稷田無秔。", "田里倚龍爲人命，百拜哀鳴聒龍聽。", "忽焉夜雨一霑濡，咸謂卧龍今睡醒。", "胡爲詰朝天晦冥，颶母橫挾揚威靈。", "撼山崩谷發廬舍，掀播兩間摧萬形。", "初謂得雨龍之賜，誰料此風隨後至。", "或者風雨自有數，龍亦無知天做事。", "不如反己自求天，難獨靠龍圖萬全。", "況持紙錢徼妄想，正似銜石將海填。", "里無千戶分十甲，諂鬼誅裒知幾匝。", "流俗酣溺死不怪，我有苦言誰聽納。"]'),
('4bd49d3c-9c2d-4f67-98fd-d6abd275879e','綠萼梅歌','陳著','宋','宋诗','song-poetry','','[]','君不見宣和艮岳綠萼梅，百花魁中此爲魁。',296,'全唐诗/poet.song.223000.json','["君不見宣和艮岳綠萼梅，百花魁中此爲魁。", "絳霄燈火不終夕，剪爲荆薪燬爲灰。", "又不見駐蹕錢塘開聚景，此梅又花天寵幸。", "江神不才馬飛渡，踏碎禁地花無影。", "兩地百五十年餘，花與國都相有無。", "誰知造物不盡意，尚留人間一種癯。", "山中佳人清似水，放開吟饕嚼花髓。", "我未見花得見詩，見詩便與花相似。", "且聞九月花已芳，奇觀到眼詩爲忙。", "臘前年後是正候，忽爲秋光豈其常。", "大庾嶺頭炎瘴地，年年早開不爲異。", "四明相去數千里，不應早花亦如此。", "吁嗟地氣如車輪，自南而北知幾春。", "如今所見到草木，不獨飛鳥啼天津。", "梅乎梅乎本清絕，花如白玉枝如鐵。", "矯矯胡爲心亦隨，不念從前傲霜雪。", "唐苑九月誇梨花，鶴林九月艷杜鵑。", "我欲梅根一酹酒，謹勿與彼爭取非時妍。"]'),
('dfcf571a-cadc-4d92-8af7-cc16e3b888b0','丙戌二月廿五日梅山弟爲孫試周遂賦','陳著','宋','宋诗','song-poetry','','[]','梅山種梅封且培，梅山種善如種梅。',224,'全唐诗/poet.song.223000.json','["梅山種梅封且培，梅山種善如種梅。", "有善必報既有子，有子且復生孫來。", "蕭艾中間芝挺出，今朝纔爲兩三日。", "咿嘔似欲指之無，燁燁眼光如點漆。", "中庭展席分排鋪，童冠環立覘所趨。", "從容顧視前舉手，干戈俎豆詩與書。", "吾家昆弟存者幾，六十見孫有吾弟。", "未聞他日成人事，庶幾正脈存祖禰。", "杯盤團欒家庭春，豈是閑心競芳辰。", "危時閉門獨生意，一醉有感天猶仁。", "吾弟所喜吾亦喜，亦欲含飴娛晚歲。", "自知無德開後人，有不盡澤吾先世。", "不觀呂范兩名家，賢子若是何其多。", "皆從世積心上出，安知他日吾非他。"]'),
('e59b1804-1e01-45f2-a925-6d4379f5c656','夜飲慈雲諸公索詩因成長篇','陳著','宋','宋诗','song-poetry','','[]','世艷明滅螢尾光，客氣騰躍煙中香。',146,'全唐诗/poet.song.223000.json','["世艷明滅螢尾光，客氣騰躍煙中香。", "煙消螢死竟何有，要知人事亦何常。", "今夕何夕山中集，六客相對通肺腸。", "樽中不問酒聖賢，得醉即是無何鄉。", "耳邊鼓笛有自好，忽散而去何吾妨。", "吾輩本非淫湎流，聊以寄意齊興亡。", "老禪知我酷信我，謂此非癡亦非狂。", "呼童展紙快磨墨，聽我趁筆窮夜長。", "砉然一笑如夢覺，清風明月自有天文章。"]'),
('3a912872-9615-4076-bd67-58a235316dba','登慈雲閣示齡叟月嶠','陳著','宋','宋诗','song-poetry','','[]','人間何處無春風，春風好處山林中。',160,'全唐诗/poet.song.223000.json','["人間何處無春風，春風好處山林中。", "我與齡叟心事通，去年雪外來共松鑪紅。", "梅花窗下今日還相逢，鏗然者誰敲竹筇。", "吾友月嶠勤相從，拍手一笑意氣同。", "各饌所有留從容，叢盤簇豆異味重。", "傾壺倒榼新篘濃，瀹我以茶鼎之芳茸。", "戰我以詩筆之銛鋒，浮生誰能百歲終。", "世變翕忽雲飛空，烏輪無情已下舂。", "白鳥翩翩投前峯，歸興浩浩舞而東，醉中無語可謝兩主翁。"]'),
('2256c49d-b342-43fb-bcdc-dd24831ff118','寄盧致遠','陳著','宋','宋诗','song-poetry','','[]','春來日日雪滿山，雪晴初放春風還。',224,'全唐诗/poet.song.223000.json','["春來日日雪滿山，雪晴初放春風還。", "高人佳處獨先得，挼藍新漲溪一灣。", "垂楊隔岸竹隔水，梅花飛香莎草斑。", "市聲咫尺自辟易，天景呈發無留慳。", "何須學徐生東泛海，也休問老子西入關。", "手招鴻鵠碧雲遠，耳狎雞犬白日閒。", "雨畦灌蔬翠鼎鼎，春槽壓酒紅潺潺。", "可以仙吾氣，可以童吾顔。", "可以平步騷吾吟，免著蠟屐窮躋攀。", "可以曠視舞吾醉，安用長袖妍弓彎。", "乾坤雖大此輒少，媿我衰老非其班。", "投我之轄下我榻，便欲援我起塵寰。", "携持雅道歸破屋，分與松菊盟長跧。", "君如不能棄我去，倘可畫我浮邱洪崖間。"]'),
('8c6d3ba4-8271-403d-9675-a4c1dbc5f2e3','正月二日游慈雲爲齡叟作','陳著','宋','宋诗','song-poetry','','[]','丹霞前，慈雲頂，兩壁相看蒼鐵冷。',160,'全唐诗/poet.song.223000.json','["丹霞前，慈雲頂，兩壁相看蒼鐵冷。", "春風秋月一逢迎，菜碗茶甌拍香鼎。", "有時話到有處無，有時瞑到入禪定。", "本來僧俗不相干，氣味投時堪雋永。", "九年卓錫興百廢，誰與挽之欲去猛。", "我年今已七十六，師五十二亦多病。", "人生契合是因緣，臨老相分重悽哽。", "東湖水寬萬頃烟，風波簸弄羲娥影。", "西山有寺古佛境，啼鳥落花雲水靜。", "醉中覶縷醒時語，師亦兩下如何領。"]'),
('624ec759-85a5-4c74-ad74-acb32f74ae78','庚寅仲冬七日醉書梅山弟家','陳著','宋','宋诗','song-poetry','','[]','我來不爲一醉期，忽焉一醉留者誰。',104,'全唐诗/poet.song.223000.json','["我來不爲一醉期，忽焉一醉留者誰。", "山川無言豈有意，陰與造物昌吾詩。", "吾詩不受世促迫，亦不肯與人諧嬉。", "鳶飛戾天魚躍淵，動筆自有風月隨。", "我欲寫時君莫問，君欲問時我不知。", "此時此意有此樂，梅山□梅花開時，爲我痛飲而讀之。"]'),
('e8906bed-18f3-474e-bc11-cc4db2d47cb3','醉書','陳著','宋','宋诗','song-poetry','','[]','庚寅仲冬之八日，與諸兄弟諸子姪。',182,'全唐诗/poet.song.223000.json','["庚寅仲冬之八日，與諸兄弟諸子姪。", "濁酒數杯菜一盆，醉後相忘見真實。", "誰云人閒天地窄，但覺物外山林逸。", "人生安能皆百年，洪崖浮邱亦浪傳。", "妻孥安穩雞犬樂，此外無復有神仙。", "甚哉世人不知足，苦積銖縷多買田。", "子孫賢否誰能料，近足此身難自保。", "舉頭問天天不應，聊向虛空一舒嘯。", "得一聚首便爲福，得一晌閒真是寶。", "但願如安樂窩中長打乖，微醺著面春拍懷。", "不願如荷鍤自隨死便埋，以酒爲命忘形骸。"]'),
('1637f31c-8a34-4534-b106-0afc426169bb','老興行慈雲醉中','陳著','宋','宋诗','song-poetry','','[]','梅花斕斑春漸芳，山弄晴色溪生光。',266,'全唐诗/poet.song.223000.json','["梅花斕斑春漸芳，山弄晴色溪生光。", "筍擔自隨信老步，一步一佇春意長。", "路逢鄰叟笑謂我，鬚鬢皓矣脚尚强。", "及今行樂刻當歲，莫學癡人無知死亦忙。", "味哉此語舉手謝，乘興迤邐入寶坊。", "住山老子拍手喜，翠微摇曳白鳥翔。", "本來未有十日別，已似故知久別遇他鄉。", "坐我以蒲團疊膝之榻，薰我以柏鼎醒心之香。", "飽我以銀絲之餠長菜之饌，瀹我以石花之水申椒之湯。", "世方慕羨黄粱枕，誰顧蕭颯芙蓉裳。", "獨如羊棗昌歜嗜，要與古柏寒松蒼。", "可但三宿桑下生恩愛，已是十年方外通肝腸。", "疇昔盡隨電光一抹過，方來能有日晷幾寸量。", "劃然長嘯出門去，弟遵吾前子扶傍。", "慈雲信美非吾□，歸與歸與仰面天茫茫。"]'),
('c885c781-4bc1-4657-b00a-8f608c779775','送春醉吟','陳著','宋','宋诗','song-poetry','','[]','三月二十有一日，絮雲弄日風力薄。',210,'全唐诗/poet.song.223000.json','["三月二十有一日，絮雲弄日風力薄。", "家人報我明日夏，草草杯盤軟春脚。", "世人心眼最無常，景物流禪爭頃刻。", "南風一轉垂青陰，回首芳塵是陳迹。", "天公好事亦世情，約束花神呈未著。", "放開酴醿紫心香，安排芍藥無留發。", "流鶑調笙舌尚存，倦蝶依然舞還拍。", "杜鵑無知只催歸，何物惡聲誰聽著。", "不妨長筵達詰旦，餞舊迎新兩無怍。", "傍觀笑我八十翁，翁亦自知身是客。", "安問家無擔石儲，時節猶自沈沈酌。", "我聞此語三歎息，酒邊寄耳非莫逆。", "杜老憂懷醒時多，誰道醉狂放吟如李白。"]'),
('4696f40b-c8c6-4b71-95cb-3e6f57fe2841','賞轉官毬花酒邊分韻得剪字','陳著','宋','宋诗','song-poetry','','[]','天機地軸隨時轉，萬物生生就裁剪。',244,'全唐诗/poet.song.223000.json','["天機地軸隨時轉，萬物生生就裁剪。", "庭前一種可人花，獨殿春深交夏淺。", "團團自是渾沌胎，皎皎不事兒女婉。", "照見胸中本色正，洗盡世上芳容靦。", "我來把酒笑問花，花爲我開恐非便。", "意將遜歸金谷園，不則直進玉華苑。", "庶幾異質逢異顧，百卉千葩羞著面。", "花不解答我已醉，醉夢恍與花神見。", "若曰幸自託君家，朝夕安知有貧賤。", "香何用多無眩鬻，靜與誰爭却悠遠。", "紛紛桃李吾輿臺，只許雪裏梅同傳。", "富貴自有富貴花，强顔諂事非其願。", "妄人或呼轉官毬，正欲馮君力辭免。", "胡爲亦動流俗心，忽向醉中遭發遣。", "跫然而喜豁然醒，前言戲耳起舞花前心服善。"]'),
('40f2a667-f46a-4608-90e2-2ed244ebcfa6','戴時可家賞木芙蓉花醉賦','陳著','宋','宋诗','song-poetry','','[]','西風不是芳菲節，木落山空景淒切。',164,'全唐诗/poet.song.223000.json','["西風不是芳菲節，木落山空景淒切。", "頼有桂菊聊記時，殿後拒霜花始發。", "我携樽酒來問花，花於此時擅奇絕。", "先白後紅知物變，有色無香自韻別。", "寓軒主人古風流，不肯移種防慢褻。", "兩根兩花相嫵媚，自況鴻光自娛悅。", "幸而桃李不同時，彼紛紛者當愧殺。", "頗云此花最宜霜，待有霜時酒還設。", "良辰美景休拈掇，白髮朱顔易交割。", "我今耄矣不足云，勸君年年自此醉倒梅花雪。"]'),
('dbf4bffc-842e-4090-b6aa-bafb37f58d11','與前人對酌醉中','陳著','宋','宋诗','song-poetry','','[]','天寬地闊無拘嫌，日往月來無留淹。',134,'全唐诗/poet.song.223000.json','["天寬地闊無拘嫌，日往月來無留淹。", "有興一日是一日，賞心樂事古難兼。", "我貧到底君不問，君自與我相嬉恬。", "安知朝夕不自給，有酒須與我共酣。", "窗前有菊相色向，採掇爲我苦中甜。", "老妻在傍發一噱，謂雖謔浪意自嚴。", "想見古來聖賢酒無量，千瓢百榼非傷廉。", "回頭笑謂安得此，但與劉伶阮嗣宗後佳話添。"]'),
('419acc83-b063-405b-bfa6-cfee2f4363ff','送黄少孺遠游','陳著','宋','宋诗','song-poetry','','[]','慈溪先生擅天章，胸中奎壁躔諸郎。',328,'全唐诗/poet.song.223000.json','["慈溪先生擅天章，胸中奎壁躔諸郎。", "君生坐後秀愈卓，骨骼昂昂氣揚揚。", "黄金滿籝父訓重，青簡插架家傳光。", "九經本也末百氏，一目誰如我百行。", "木根盤龍幹必異，要須培植爲棟梁。", "寶氣貫虹玉必粹，亦在磨琢成珪璋。", "第方靴笠爭徑捷，難把章掖入時妝。", "既不必效阮籍哭，亦不必學接輿狂。", "仰天俯地道固在，往古來今人漫忙。", "安居茅茨即臺閣，雋永藜藿勝膏粱。", "大蓬山下遠塵境，晴嵐暖翠松竹房。", "小鑑湖中落天鏡，明月清風芰荷裳。", "內可以存養性情之正，外可以舒暢詩書之香。", "上可以奉萱庭壽康之慶，下可以遂棣華和樂之常。", "立我之大無愧怍，敬天之命爲行藏。", "不然荆璞輕自售，恐如梅實酸誰嘗。", "君不見蘇老泉，年二十七始自强。", "渟涵滿腹抑不發，直待知我逢歐陽。", "又不見徐仲車，力學篤孝母在堂。", "大賢刮目他日事，自有了翁鄒道鄉。"]'),
('6d10c9a2-4255-4d07-8857-1314acd1fbae','送洵之越','陳著','宋','宋诗','song-poetry','','[]','有美一人來自東，與兒洵約西游同。',241,'全唐诗/poet.song.223000.json','["有美一人來自東，與兒洵約西游同。", "謂聞古越多勝跡，庶可洗眼開心胸。", "窆石亭空思禹迹，飛翼樓高憶蠡功。", "過司馬寓第，如見涑水叟。", "入稽山書院，如見晦菴翁。", "東山則想謝太傅之雅量，上虞則感李參伯之孤忠。", "讀范老堂記則懷憩堂於出守，問祈國里曲則想持帽於方童。", "偉哉聖賢所森布，關乎名教無終窮。", "彼柯亭之煙竹，蘭亭之觴水。", "剡溪之雪舟，邪溪之樵風。", "雖非本色□慕羨，然亦餘興相迎逢。", "盍陪簦笠風雨外，固異萍梗江湖中。", "八十一歲汝我懼，二百里近我汝容。", "目而送之豈漫往，歸以復我將誰從。", "滔滔世變猶古道，修竹可竹兩人龍。"]'),
('b8798bb9-6ea8-40f9-b7bd-47c18be27b46','後圃侍郎芍藥酴醿三花競發戴時可載酒來同酌醉中','陳著','宋','宋诗','song-poetry','','[]','前日對花賦三詩，醉後誰復記當時。',162,'全唐诗/poet.song.223000.json','["前日對花賦三詩，醉後誰復記當時。", "雪溪公子忽呈似，一見如夢中見之。", "世閒何事非虛妄，嘯裏著句豈狂癡。", "富公園有凌霄樹，獨立不蔓今古希。", "碧雞坊頭海棠花，花開如屋樹丈圍。", "洛與蜀，今已非，雖欲勝賞將何歸。", "我家貧極花未厭，我亦未敢輕拋離。", "茶一盞，酒數卮，邀朋命友長娛嬉。", "今日何日晴且暖，三花相得心自知。", "旁觀索賦不須訝，要問底藴自有造物兒。"]'),
('6e6ef236-f8f7-4346-8553-a8a73b2954c1','前人載酒光風霽月□醉中','陳著','宋','宋诗','song-poetry','','[]','春漸老，年已耄，一時自適非不要。',152,'全唐诗/poet.song.223000.json','["春漸老，年已耄，一時自適非不要。", "花香妙，柳腰裊，老懷未怯輸年少。", "東風吹吹杖履便，燕嬌鶑姹不我嫌。", "南鄰載酒西鄰會，鴨肝豬肚供肥甘。", "回頭看浮世，晨炊晚不繼。", "我非世外人，乃爲醉飽計。", "樂極愧生難爲辭，禮謹意厚辭則非。", "何妨真率存古道，杯茶盞酒會亦奇。", "雨韭夜，菜羹社，前有杜老後司馬。", "金谷樓臺灰塵飛，兩家淡薄千年話。"]'),
('7dc59780-1f78-4cc4-841f-cb695a37d43e','又似前人','陳著','宋','宋诗','song-poetry','','[]','寓軒愛客還愛酒，酒常不足客常有。',136,'全唐诗/poet.song.223000.json','["寓軒愛客還愛酒，酒常不足客常有。", "有時寧輟炊糧資，買秫盆釀不盈斗。", "今日何日天氣新，和粕傾來賞春韭。", "安問門外有飛塵，且向樽前開笑口。", "岸幘舞得雲山摇，揮毫寫出風光透。", "足以樂矣文字醉，彼何人斯囚躶醜。", "君記取，今而後，但師會數司馬家，薄物勤勤意自厚。", "莫學豪飲陳孟公，投轄關門妨客走。"]'),
('67e73342-da12-4d2d-af9e-fa90aa0684a0','送前人之董氏館','陳著','宋','宋诗','song-poetry','','[]','雪溪公子清於冰，與人心事秋月明。',192,'全唐诗/poet.song.223000.json','["雪溪公子清於冰，與人心事秋月明。", "黄塵滿目分不入，却向嵩曲尋幽盟。", "山之趾，水之裔，花柳之時風月夜。", "避喧何必武陵源，得閒便是羲皇世。", "俗情詡詡有僞真，道義之交無故新。", "我今年已八十一，君今亦是半百人。", "日日聚首能幾日，況我殘陽出入息。", "聞君束書將有行，萬里弱水在咫尺。", "相望怨被浮雲妨，有夢難託清風將。", "豈是臨分語太苦，此味昔我實備嘗。", "一杯一杯莫辭勸，此酒中間膠漆釅。", "記得希夷一語不，優好之所勿久戀。"]'),
('5e5b0cd4-2249-4414-9662-630b9dbc346b','二月十五日酴醾洞醉中','陳著','宋','宋诗','song-poetry','','[]','木香架下春未饒，纍纍叢蕤方弄嬌。',133,'全唐诗/poet.song.223000.json','["木香架下春未饒，纍纍叢蕤方弄嬌。", "含香不吐有時發，只須十日晴光牢。", "滿腔醖藉固有在，花心雅欲投金焦。", "逐時消遣老者事，頗與酒興無花妖。", "不妨掇纈細咀嚼，與知味者相招邀。", "而況逢迎骨肉親，酒無清濁和粕澆。", "百年此樂能幾日，今日何日是花朝。", "誰知醉無以將還自愧，終不如獨醒君子賦離騷。"]'),
('42a040ff-46f1-4e2a-bd04-dbcb58c7a192','中秋月下醉筆','陳著','宋','宋诗','song-poetry','','[]','去年賞月待晴開，今年賞月月待來。',150,'全唐诗/poet.song.223000.json','["去年賞月待晴開，今年賞月月待來。", "去年酒少輒醉倒，今年酒多如未杯。", "信知豪飲不在我，月色爲我生飲材。", "舉頭試看月如許，皎皎冰壺在玉臺。", "西風不動露已下，碧落萬里無纖埃。", "胸中磊磈正欲吐，不仗此酒誰我陪。", "落落魄魄空宇宙，何事不入我樽罍。", "素娥於我本無情，任渠驚見摑掌咍。", "誰知狂非是狂醉非醉，自有老天知我我亦何求哉。"]'),
('a10db369-f7d3-4c0f-ab52-ca65c4cf4ef3','送陳笠峰路教之燕','陳著','宋','宋诗','song-poetry','','[]','笠峰秀甲東南郊，面勢雄特根基牢。',330,'全唐诗/poet.song.223000.json','["笠峰秀甲東南郊，面勢雄特根基牢。", "上與日月星辰交，下走海脈通六鼇。", "藴蓄玉金賁山毛，噴洩雲雨蘇焦熬。", "之子生於其間擅英豪，重不輕試厚自韜。", "中歲一跨鵬風翱，道之行也茲其遭。", "越庠素號多俊髦，博士一飯久爲妄者饕。", "芹藻泛泛隨波濤，茅葦彌望誰其薅。", "拜舞異渥開新陶，長身古眼空滔滔。", "正如矢初脫箙弓離弢，又如砥斂水淬出匣刀。", "朝講暮說音奏諧肆驁，日漸月漬學子飽雋詩書膏。", "意欲國爲鄒魯家稷皋，斥其餘忍百廢鏖。", "百年功績三年勞，臺府交牘爭薦褒。", "雖欲頓轡將焉逃，小春布暖風未號。", "陸可鞍馬水可艘，齏根鱠鱸蠏霜螯。", "一飲百榼新篘醪，梅花驛路萬里重游遨。", "大則徑上玉堂揮健毫，不亦小駐粉省班郎曹。", "我欲餞送乏酒羔，贈言一紙忘忉忉。", "峻坂立馬嚴提鑣，急流放船穩著篙。", "他日清望拂星旄，衣錦歸時當與笠峰相爲高。"]'),
('08f413b8-7120-43a0-9b91-09fedb8faa64','送兒沆再之婺','陳著','宋','宋诗','song-poetry','','[]','父母生汝期望汝，地闊天寬從著步。',178,'全唐诗/poet.song.223000.json','["父母生汝期望汝，地闊天寬從著步。", "霜葉飛紅橙橘黄，一笠西風正宜路。", "送汝出門不肯行，低頭進前出苦語。", "雙親雖安身已高，菽水爲歡盍朝暮。", "夏初奉命見兩山，往還恨不身生羽。", "如今又爲千里行，直是戀慕難輕去。", "有不忍聽手撫背，至哉天理人倫處。", "我豈欲汝寸步離，事有乘機恐差誤。", "晚年正欲汝有成，此行倘與心相副。", "皺皮瘦骨便精神，當爲汝喜非汝懼。", "不妨安穩趁前程，但及梅花時歸學萊舞。"]'),
('a898aa4b-097c-42a2-bb69-2cb6cba26099','送沆赴台州學錄','陳著','宋','宋诗','song-poetry','','[]','山連霞，水半沙，十步九步神仙家。',260,'全唐诗/poet.song.223000.json','["山連霞，水半沙，十步九步神仙家。", "草初芽，樹欲花，香風二百里春華。", "人謂此行良可樂，我送出門還作惡。", "初心謂何姑勿道，爲貧去抱夫子脚。", "天台如今人物林，芹芳藻潔紛佩衿。", "物議無情憂責重，盡人須要先盡心。", "好爲人師古所戒，況汝大欠鐙窗債。", "理義無窮白日速，相長工夫方有在。", "視身如玉宜好修，守口如瓶勿起羞。", "平平之外無赫赫，介介之中有休休。", "勞其筋骨餓膚體，乃汝法家并拂士。", "恩愛極處言語切，豈得已哉汝行矣。", "我年雖邁尚自强，藜藿能延壽命長。", "相望只有片雲隔，不比遠去無遊方。", "時節飛書當萊舞，兩字平安勝三釜。", "三年電光一抹過，但要學成身立來歸見父母。"]'),
('041df339-f975-4d05-97df-9ce7de22fc07','送邑簿李大用任滿','陳著','宋','宋诗','song-poetry','','[]','綵旗蔽野南風香，歡門遮馬東路長。',195,'全唐诗/poet.song.223000.json','["綵旗蔽野南風香，歡門遮馬東路長。", "黄童白叟百拜酒，鸞棲主人今日行。", "憶昔焦氛漲天赤，手挽龍津力輸滌。", "簿領爲職關係重，儒術飾吏經綸密。", "學校一新衿佩來，市井再復圖畫開。", "男耕女織各按堵，山居海藏皆熙臺。", "口不言功心自諭，三年任滿留不住。", "我窮欲餞惟有心，一詩收拾行碑語。", "如之何說見事明，自有夜月光山亭。", "如之何說律已清，亦有秋水鋪長汀。", "留此賢勞書縣譜，携此聲名步雲去。", "君不見政事堂中李參伯，即是當年長社簿。"]'),
('85135717-5f62-4914-9db9-59ab4d98ca26','送邑宰丁溉之任滿','陳著','宋','宋诗','song-poetry','','[]','君不見南山峯晴倚空，有時烟嵐失青葱。',388,'全唐诗/poet.song.223000.json','["君不見南山峯晴倚空，有時烟嵐失青葱。", "又不見碑潭水清貫市，有時波濤漲黄滓。", "銅章一臨山水閒，變態有甚水與山。", "自從有邑知幾尹，仁聞始終無二三。", "況直焦氛半封內，轉爲樂國非容易。", "飛鳬忽載福星來，力量精神有餘地。", "吾鄉由來文獻多，道脈無如世故何。", "蔬園每每今棟宇，芹波瀰瀰新弦歌。", "小民艱食業山海，弱肉難供虎狼噬。", "寒忽煖衣饑忽食，晝無打門夜無吠。", "百里乳哺父母懷，惡稔時勞匣劍開。", "同寮議論兄弟視，理到肯放山筆回。", "苦蘗雋永世味外，甘棠種在人心裏。", "圖誌雖書不盡書，頌碑歌記如何記。", "及瓜而代芒芒行，花城如畫琴在堂。", "手揮帳餞前路闊，唾去金饋西風香。", "來不携家影相逐，去不挑包心自足。", "眉閒迎笑動瑶琴，膝下候歸翻綵服。", "南溪景擅孟城奇，酒丹米白魚蟹肥。", "家林燕喜莫惜醉，仕宦得閒能幾時。", "平實工夫根本大，舒徐步武官職耐。", "向上規模看宰邑，誰能如公三出宰。", "誰能如公徹底清，誰能如公不眩名。", "卓乎高哉日月證，足以行矣雲霄程。"]'),
('e99a3abb-1520-4a54-8f2d-5889a68d1c81','送兒沆再之台學併似許梧山張在軒','陳著','宋','宋诗','song-poetry','','[]','學古入官非易事，同寅協恭第一義。',186,'全唐诗/poet.song.223000.json','["學古入官非易事，同寅協恭第一義。", "昨汝行矣重吾憂，今吾聞之爲汝喜。", "有如此廣文先生，真所謂法家拂士。", "寄聲忽到我，用情應爲汝。", "我欲謝之難爲語，汝其聽之告以意。", "古天台，多士類，文有風檣陣馬之奇，氣有霜林老鶻之鷙。", "鎮之以靜重，行之以平易。", "艱難見初心，苦淡得真味。", "人謂著脚危於淵，我知進德此其地。", "汝不見范文正公家書片幅戒子姪，有事只與同官議。", "又不見歐陽朋黨一論質鬼神，同道相益乃君子。"]'),
('6c326ba3-5e07-4a53-9216-68b693e764bb','送兒深赴婺之月泉山長','陳著','宋','宋诗','song-poetry','','[]','來汝深，吾語汝，汝今此行五百里。',328,'全唐诗/poet.song.223000.json','["來汝深，吾語汝，汝今此行五百里。", "吾豈不欲汝在傍，朝夕告教從容裏。", "世莫難於續書脈，孝莫大於養吾志。", "男兒須爲大丈夫，遠遊有方學者事。", "汝行乎，吾决矣。", "名山大川如不識，坎井中見能有幾。", "嚴師良友如不親，家庭閒語未必是。", "若曰高車過萬里橋，非所羨於司馬氏。", "若曰榮鄉佩六相印，亦何取於蘇季子。", "區區物外先入心，役役終身非切己。", "星婺域，月泉水，古到今，最多士。", "要知三人必有師，毋謂一日長乎爾。", "賊人之子乃自賊，毀人之善是自毀。", "同寮當出肺肝話，諸生當如手足視。", "回顧弱植荷倚重，雋永古訓滋味旨。", "遇食不求飽，飲酒不至醉。", "閒事付浮雲，本色爲實地。", "詩書何幸薄有祿，齏鹽猶勝空煮字。", "仕未可養汝奈何，耄猶加餐我自慰。", "要得友朋之譽可聽聞，即是父母之前相諾唯。", "三年日月一箭過，不必吾懼但爲吾所喜。"]'),
('5fc96d4b-1ea5-4ab2-8385-891508c88b8b','贈郡經歷韓君美','陳著','宋','宋诗','song-poetry','','[]','易爲六經彝訓祖，詩關萬里風化機。',298,'全唐诗/poet.song.223000.json','["易爲六經彝訓祖，詩關萬里風化機。", "周孔派外誰復得，商賜言後知者誰。", "穿鑿簸弄到今日，家自爲詩人自易。", "數不及理數亦妄，吟而無用吟何益。", "京房輩，晚唐詩，悖謬之渠漓之靡。", "雖不能爲本真累，能誤來者滔滔地。", "鄞幕多緣奎壁照，鐵做脊梁主公道。", "有時發經本旨坐虎皮，有時續古正音斥蟬噪。", "老夫耄矣不出山，宿學已墮寒灰閒。", "卓哉斯文有可宗，身雖不前心已攀。", "二松主人忽傳意，謂曾齒及窮姓字。", "生來欠識韓荆州，我亦自分陳無己。", "此心胡爲乎來哉，清風明月肝膽開。", "滿天下是可爲事，終歸敏手經綸才。", "人文所以經天地，直須掀揭山火賁。", "民事所以壽根本，要使人人歌既醉。", "自顧光陰迫下舂，猶欲拭目儒術功。", "不能頌泰交於風雲之表，亦可歌豐年於畎畝之中。"]'),
('a29139fb-0f52-4f9f-b7f7-96a354ce8562','行路易送陳晟謀仕','陳著','宋','宋诗','song-poetry','','[]','行路易，行路易，方寸中閒是天地。',224,'全唐诗/poet.song.223000.json','["行路易，行路易，方寸中閒是天地。", "詩書能生萬里翼，一出門外風雲起。", "彼水馬兒如江河，彼醯雞輩知甕耳。", "汝今此行有足行，我爲之喜非徒喜。", "先生在前充安公，後學在側太初子。", "如舟順流帆佐使，如轅欲南車有指。", "有文舉表人已羨，入夫子門誰敢議。", "機會來時非偶然，功名發軔斯可矣。", "豈知我，猶望汝，謙以養高勿自高，虛以求是勿自是。", "覓慈湖，拜象山，不見了翁愧程氏。", "終爲巍巍大儒宗，可是錄錄常流士。", "自顧衰景薄下舂，聊寫苦語累行李。", "行路易，行路易，易處有難從此始，試深思之有餘味。"]'),
('ee048cd0-6d9c-4489-b3b3-2d1fdc07b119','送邑簿阮杏山解任','陳著','宋','宋诗','song-poetry','','[]','杏山高高壓羣山，山靈發秀生鳳鸞。',162,'全唐诗/poet.song.223000.json','["杏山高高壓羣山，山靈發秀生鳳鸞。", "便應鶱騰梧桐表，胡爲回翔枳棘閒。", "誰知異物非凡翼，志在遠大須培植。", "固非燕雀所能知，正恐鴻鵠亦未識。", "去年桂子香中晴，五綵颺下民歡迎。", "雝雝仁氣才鼓盪，今春已趣雲霄程。", "清水一壺留矮屋，順風萬里送行色。", "內將攬輝儀周行，外將和鳴福萬國。", "老夫耄矣阻攀行，一詩寄意無他腸。", "願言雙旌導前路，飛致鳳花開處是桐鄉。"]'),
('20bc8925-b59b-4dc5-b566-21e21189c4a2','送邑簿周信解任','陳著','宋','宋诗','song-poetry','','[]','秋風好，秋風好，吹起棲鸞上雲表。',146,'全唐诗/poet.song.223000.json','["秋風好，秋風好，吹起棲鸞上雲表。", "邑人欲留留不住，綵旗繡帳長安道。", "歌者相和舞者蹈，欲說遺愛知多少。", "朱絃直，青銅照，姦回百巧終莫欺，正大一交如夙好。", "處事無難輕車就熟路，據理必爭疾風加勁草。", "三年任滿如始至，萬里當遠到。", "擁箳篂，植旌纛，分內功名非外求，時來爲之特談笑。", "尚須續續□飛箋，勿謂老夫年已耄。"]'),
('91ea844e-94e0-4966-b4b0-b10ac8455d8b','寄台教王吉甫','陳著','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','直溪之水清且洌，可以沃我老枯渴。',282,'全唐诗/poet.song.223000.json','["直溪之水清且洌，可以沃我老枯渴。", "直溪之風空且闊，可以舒我窮鬰結。", "自聞西來飛霞佩，使我南望片雲隔。", "苦無筋力抗塵埃，徒有心事交冰雪。", "長庚分光到寂寞，好風流閒無時節。", "癭木豈是罍洗材，歜葅不登鼎俎列。", "見何所見斯未信，取非所取毋乃褻。", "俗眼滔滔鄂州花，古道卓卓元城鐵。", "自昔甕城地最靈，而況金壇人更傑。", "漫塘詞源有流傳，實齋理學素磨切。", "忽乘朝陽下赤城，坐覺文星燦東浙。", "龜手之藥或以封，皋皮之座嘯自徹。", "糠粃在前吾不妨吾後，瓦注者巧吾但安吾拙。", "教鐸重新雷霆鳴，儒流勇赴江河决。", "弦誦洋洋正聲合，芹藻楚楚生香發。", "北斗泰山收寶望，東觀蓬萊是途轍。", "何時鐙前相對一杯酒，未見顔色惟看山中秋夜月。"]'),
('f7f93a6f-0e05-46c8-962d-835673de1694','送兒沆赴昌國學錄','陳著','宋','宋诗','song-poetry','','[]','來汝沆，吾語汝。',346,'全唐诗/poet.song.223000.json','["來汝沆，吾語汝。", "蓬萊鄉，仙者寓，汝行豈爲求仙故。", "寶陀山，佛者住，汝今豈爲禮佛去。", "吾聞滃洲好學舍，兵後弦歌尚存魯。", "巨鼇拄牢蒼璧島，長鯨截斷紅塵路。", "黄公高節懔猶在，茹侯英標儼如覩。", "芷翁器業國有傳，逸少詞章家有譜。", "扶桑日出長精神，滄溟際天豁襟宇。", "潮水生落見乘除，風濤澎湃嘗斂阻。", "耳目所接皆爲學，身心所會當約取。", "旦氣清明方見性，人生涉歷終知趣。", "規模要放面前闊，議論要到心平處。", "雪霜之際有陽春，波浪之中有砥柱。", "畏友當如父師敬，平交當以兄弟處。", "我雖自餒耄何及，汝方年壯力須努。", "亦欲長教在我傍，深恐獨學爲汝誤。", "不然何以資一出，幸猶近只寸半渡。", "駕言曰仕實從游，自昔成人出辛苦。", "著汝意氣勉自强，味哉言語謹勿負。", "東雲在望道路開，西風吹送衣裳舞。", "消受宮牆飯幾盂，勝舉家庭祿三釜。", "歲月箭過歸有期，却把本色初心娛父母。"]'),
('a77686a0-5a1a-4958-8146-1ca6d788c107','壽雪竇寺炳同長老','陳著','宋','宋诗','song-poetry','','[]','昌黎大顛相接識，爲說道理驚孤寂。',234,'全唐诗/poet.song.223000.json','["昌黎大顛相接識，爲說道理驚孤寂。", "歐公喜與惟儼交，愛其文逸通經術。", "自顧擬非韓歐倫，漫遊亦到沙門釋。", "明覺後人少野師，湖海宿尊推第一。", "胸中自有大藏經，此外三兼翰林筆。", "坐斷名山皆梵家，能有幾人知本色。", "不從鉢盂計顆粒，則向棟宇爭寸尺。", "彼滔滔者何足云，我油油然自相得。", "年年荷師壽我生，今何以壽師生日。", "欲寫丹霞贊其高，師自有流乳一峯矗天碧。", "欲傾嵩淥揚其清，師自有飛雪千丈挂空白，但有數語一溪藤，相伴瓣香飛入室。", "緣師法門本是空，我也將空當真實。", "世閒何事非戲劇，請師一笑撼動天開圖畫壁。"]'),
('2e4d733b-431e-4058-b2e8-dee1db2f5fca','可舉長老退休於西山菴賦西山好以送之','陳著','宋','宋诗','song-poetry','','[]','西山好，西山好，天開畫閣勝蓬島。',258,'全唐诗/poet.song.223000.json','["西山好，西山好，天開畫閣勝蓬島。", "千峯盡頭地脈舒，萬頃如掌湖光抱。", "清風佳月自時節，暖翠晴嵐互昏曉。", "逢人大觀夙契心，小築數閒謀退老。", "欲歸去來不由身，妙莊嚴域須手了。", "平平穩穩經理去，纖纖悉悉工夫到。", "棟宇崢嶸巾笠湊，鐘鼓震撼鉢盂飽。", "今日何日滿十分，是空非空歸一笑。", "於戲分付善舞人，曳錫逍遥忙劫表。", "老鶴飛迎出山深，馴龍拜伏候門早。", "便應管領古烟霞，何妨評論閒花草。", "樵歌漁唱如梵唄，茶約詩盟足吟嘯。", "淡中滋味苦亦甜，靜處風光安是寶。", "顧我門戶雖不同，如此林泉均所好。", "霜松雪柏夢相知，布襪青鞋嗟已耄。", "西山好，西山好，世閒何處不是邯鄲道。"]'),
('15c2adec-d9bc-4b0b-8b0a-4c2fe6f8367b','似法椿長老還住浄慈','陳著','宋','宋诗','song-poetry','','[]','寺後山，青巑岏，忽如憔悴忽又開容顔。',288,'全唐诗/poet.song.223000.json','["寺後山，青巑岏，忽如憔悴忽又開容顔。", "寺前灘，聲潺湲，忽然枯澀忽又起波瀾。", "知爲誰乎醜或妍，只在主者往與還。", "追思疇昔狎羣攫，痛卷無餘遺百難。", "山林赬矣囊橐外，棟宇委之荆棘閒。", "飛錫一來重悲慨，張弮勇欲興頹廢。", "積勞落成逾一紀，大書記實光千載。", "彼物何物衆所唾，無事生事幾乎駡。", "蟻將撼木不自分，犬或見雪從他吠。", "無辯之辯如我何，有怪不怪當自壞。", "胡爲撞鐘擊鼓辭上方，若曰挑包頂笠皆吾鄉。", "戲衫脫了因甚快，大權契合終難忘。", "風曾相送迎亦好，雲與俱出歸何妨。", "兩不著相是去住，一撥便轉無思量。", "人生忽忽夢幻身，世界茫茫戲劇場。", "我老不覺八十三，師今亦且半百强。", "石塔重來我愧不是蘇玉局，茅屋可賦師却自愛杜草堂。"]'),
('6f4f53d0-4b24-47ed-9ca6-cc23ebc2aa38','代天甯寺僧可舉贈梓人善斲歌','陳著','宋','宋诗','song-poetry','','[]','四明山南鬰嵯峨，異氣上與青天摩。',364,'全唐诗/poet.song.223000.json','["四明山南鬰嵯峨，異氣上與青天摩。", "人豪挾秀布山下，餘爲巧匠擅一窩。", "頎然而長獨出者，此中巧處得最多。", "誰知造物亦有意，要爲公輸世其科。", "天甯古剎本雄麗，一旦忽受融風苛。", "作而新之豈易事，一手足任奚謀他。", "前年起山門，見者贊歎誰敢呵。", "今年起佛殿，鎮壓大地山與河。", "百川奏材奔贔屭，萬夫應役鳴鸛鵝。", "眼意所及規矩就，頤指之下鋸斧羅。", "巍巍列柱鐵直立，整整駢榱玉圓瑳。", "層檐飛走鳳翼舞，修梁騰上虹光拖。", "上入雲霄爭雁路，下臨城市眇蟻窠。", "可以坐三大如來於中閒正面，可以奉五百羅漢於東西兩阿。", "我仗我佛大勢力，翻起尺水成大波。", "汝有妙思隨我意，輪奐視昔百倍過。", "寶坊突兀見此屋，回首人世今如何。", "當年大而富貴戶，寒煙落日廢址迷蓬莎。", "小而苟活破茅舍，淒風苦雨不識陽春和。", "慈悲法門何遮礙，平等世界何偏頗。", "安得如汝千百億，莊嚴棟宇徧婆娑。", "有快活，無障魔，大家拍手齊唱善斲歌。"]'),
('9805bca4-b52d-4843-8e6a-9cc575674135','代趙信甫千人助冬衣','陳著','宋','宋诗','song-poetry','','[]','憶昔渾家衣天香，翩翩風流公子裳。',312,'全唐诗/poet.song.223000.json','["憶昔渾家衣天香，翩翩風流公子裳。", "蟾宮步武雲送上，雁塔姓名星摇芒。", "綠袍照眼初意銳，青氈入手前路長。", "誰知蕉鹿成夜夢，日與蓬鷃爭時光。", "纍纍鵠形走山谷，戰戰繭足履冰霜。", "貂裘已弊有嫂輕季子，牛衣雖泣無妻問王章。", "懸鶉襹褷不投俗，捫蝨勃窣徒談王。", "豈不欲羨補衮居峻地，豈不欲著錦繡歸故鄉。", "顧瞻外飾至此面自赬，摸索中襟淒其汗如滂。", "況今玄冥令凜冽，難把赤立身支當。", "彼狨鞍寶馬重狐貉，彼毳茵繡帳雙鴛鴦。", "或錦步障五十里，或金縷衣十二行。", "與富貴家自擇伴，如衰颯輩難登堂。", "老者衣帛盍早計，大寒索裘真癡忙。", "縉紳遺緒慘莫繼，章縫本色終難忘。", "從來固多急義譜，今亦何敢淺識量。", "君不見履常長貧凍至死，絮襖不具有識空悲傷。", "又不見范叔一寒如此極，綈袍之戀千載猶芬芳。"]'),
('e24a1c41-3f9e-4e75-800d-f56d53f8e429','悼出童尚質二首  其一','陳著','宋','宋诗','song-poetry','','[]','南山山最秀，之子得其精。',48,'全唐诗/poet.song.223000.json','["南山山最秀，之子得其精。", "年少文偏老，身通道自亨。", "得交空所藴，見義勇於行。", "今日知無憾，聲名一死生。"]'),
('eee0f326-e6e8-4f1c-859a-19c975c0a07f','悼出童尚質二首  其二','陳著','宋','宋诗','song-poetry','','[]','聚散幾怱怱，真如醉夢中。',48,'全唐诗/poet.song.223000.json','["聚散幾怱怱，真如醉夢中。", "分雖甥舅異，情實弟兄同。", "坐夜鐙前雨，噓春扇底風。", "傷心今已矣，庭草泣秋蟲。"]'),
('284e7702-f789-48cd-a71f-0624b3ab03c7','弔單方菴墓','陳著','宋','宋诗','song-poetry','','[]','方菴居士死，歸骨白雲根。',48,'全唐诗/poet.song.223000.json','["方菴居士死，歸骨白雲根。", "霜暑三年別，風流萬古存。", "月梁空夜夢，宿草長春痕。", "松底幽蘭發，清香是夢魂。"]'),
('2281ae80-b4d9-4e33-947d-8540b6c1becd','挽陳菊坡樞密二首  其一','陳著','宋','宋诗','song-poetry','','[]','家學淵源遠，公今德行科。',48,'全唐诗/poet.song.223000.json','["家學淵源遠，公今德行科。", "一純光白璧，重望壓頹波。", "職業居朝久，文章八石多。", "平生何所似，霜菊在秋坡。"]'),
('edfb657b-5ff0-4709-a2ea-2a51f3205348','挽陳菊坡樞密二首  其二','陳著','宋','宋诗','song-poetry','','[]','身到西樞府，黄扉一蹴開。',48,'全唐诗/poet.song.223000.json','["身到西樞府，黄扉一蹴開。", "急流知有退，樂處在人閒。", "健領耆英社，清標利欲關。", "典刑今已矣，風雨暗青山。"]'),
('2c683820-6bf3-488b-a0c3-b9de28f3f7a9','挽董帥幹二首  其一','陳著','宋','宋诗','song-poetry','','[]','裔自杏林仙，清閑福最全。',48,'全唐诗/poet.song.223000.json','["裔自杏林仙，清閑福最全。", "獨醒偏醉客，鰥宿似逃禪。", "古貌堯民老，風流晉世賢。", "應門付兒輩，花竹小壺天。"]'),
('73ffaaec-ec27-47db-83bd-d2049f3f8068','挽董帥幹二首  其二','陳著','宋','宋诗','song-poetry','','[]','向來相與處，欲說淚先滂。',48,'全唐诗/poet.song.223000.json','["向來相與處，欲說淚先滂。", "笑席平交等，名鞭夙許長。", "宦遊成離索，歸見及康强。", "如今果何日，忍聽歌些章。"]'),
('9d6846fa-2cd1-4d4f-a0e6-74405bbe654e','挽黄提舉震三章  其一','陳著','宋','宋诗','song-poetry','','[]','江山古四明，獨立表平生。',48,'全唐诗/poet.song.223000.json','["江山古四明，獨立表平生。", "敏處經綸密，癯中氣局宏。", "鴻毛看勢利，虎口見功名。", "麾節那能究，東南天已傾。"]'),
('1417f18b-d0d9-4dc7-93f8-d45a088e7405','挽黄提舉震三章  其二','陳著','宋','宋诗','song-poetry','','[]','文弊莫如今，獨存師古心。',48,'全唐诗/poet.song.223000.json','["文弊莫如今，獨存師古心。", "汲深六經海，茹實百家林。", "公有傳賢筆，私無諛墓金。", "晚年北山北，誰識醒中吟。"]'),
('9ecf1ea0-d69d-4af7-97e7-ea43e58c01bd','挽黄提舉震三章  其三','陳著','宋','宋诗','song-poetry','','[]','當年時事誰，咄咄賦歸與。',48,'全唐诗/poet.song.223000.json','["當年時事誰，咄咄賦歸與。", "同是無枝鵲，危如游釜魚。", "偷生盟世好，訪遠記山居。", "已矣向誰慟，兒孫書滿廬。"]'),
('249be97b-cc8b-4542-9cc3-476a33ae914c','挽黄祖勉三首  其一','陳著','宋','宋诗','song-poetry','','[]','世遠太和散，儒門有若人。',48,'全唐诗/poet.song.223000.json','["世遠太和散，儒門有若人。", "沈潛勤汲古，澹靜肯妍春。", "識到寡輕語，觸來無量顰。", "淵乎莫澄撓，叔度乃其倫。"]'),
('4d68b92a-8855-4652-85a9-95162f7fc2af','挽黄祖勉三首  其二','陳著','宋','宋诗','song-poetry','','[]','平生不行怪，流俗自難同。',48,'全唐诗/poet.song.223000.json','["平生不行怪，流俗自難同。", "原明無仕志，公休有父風。", "肯堂勞未艾，反席壽俄終。", "誰料生芻奠，今年又乃翁。"]'),
('0f3a4bc5-4137-42fe-b10b-0c2a13ced50d','挽黄祖勉三首  其三','陳著','宋','宋诗','song-poetry','','[]','夙是通家契，姻盟又此時。',48,'全唐诗/poet.song.223000.json','["夙是通家契，姻盟又此時。", "相依百罹世，多活幾年期。", "辰龍竟歸夢，子書誰續爲。", "九京不可作，喬梓北風悲。"]'),
('7a58c076-4f90-4d19-8037-c3f4b35a2573','挽曹泰宇居士三首  其一','陳著','宋','宋诗','song-poetry','','[]','忠義垂青脈，癯然獨飯蔬。',48,'全唐诗/poet.song.223000.json','["忠義垂青脈，癯然獨飯蔬。", "生涯一身寄，禪學九經餘。", "有教甯分類，逢人只借書。", "世方饜粱肉，視此愧何如。"]'),
('8b4544fe-f4c5-4833-8577-6c376b3c5664','挽曹泰宇居士三首  其二','陳著','宋','宋诗','song-poetry','','[]','滔滔彼居士，誰得似君真。',48,'全唐诗/poet.song.223000.json','["滔滔彼居士，誰得似君真。", "盍駐香山社，俄拋病室身。", "首邱存故我，手澤付何人。", "此理本來悟，浮生一窖塵。"]'),
('7770422b-1cbd-4dd0-a903-cfb0a9b4ad2e','挽曹泰宇居士三首  其三','陳著','宋','宋诗','song-poetry','','[]','怱怱相聚處，未足滿平生。',48,'全唐诗/poet.song.223000.json','["怱怱相聚處，未足滿平生。", "鐙雨對眠夢，花晴携話行。", "前盟空在耳，外哭若爲情。", "已矣不可作，高山孤月明。"]'),
('a2b89943-5d8e-4a8d-8e01-3af584a6ca57','挽范千之二首  其一','陳著','宋','宋诗','song-poetry','','[]','得年雖欠壽，凡事孰能瑕。',48,'全唐诗/poet.song.223000.json','["得年雖欠壽，凡事孰能瑕。", "識老語言簡，學充文賦葩。", "劉蕡胡不第，靈運欲忘家。", "已矣歸何處，虛留海上槎。"]'),
('7c7aeb81-1cc5-47e7-a393-6d6653d65d48','挽范千之二首  其二','陳著','宋','宋诗','song-poetry','','[]','翛然形早蛻，遺痛在家人。',48,'全唐诗/poet.song.223000.json','["翛然形早蛻，遺痛在家人。", "手澤泣孤子，篋封悲二親。", "菟裘行計舊，牛隴窆銘新。", "我亦知君者，酸心唐隩春。"]'),
('c3708685-912b-4bb8-a2da-8a8da591835f','挽樊君修','陳著','宋','宋诗','song-poetry','','[]','憶昨會山中，危時苦話同。',48,'全唐诗/poet.song.223000.json','["憶昨會山中，危時苦話同。", "老枝期共雪，喬木慮摧風。", "弟有文銘竁，兒能禮送終。", "九京無可憾，後死愧衰翁。"]'),
('37949905-39a8-4dd2-a4c0-324d2f0e7240','挽孫大監二首  其一','陳著','宋','宋诗','song-poetry','','[]','家學自相師，名成六館推。',48,'全唐诗/poet.song.223000.json','["家學自相師，名成六館推。", "春風中哨立，古道上安馳。", "朝擅敢言直，民歌不忍欺。", "危時方倚重，猨鶴已追隨。"]'),
('b33594fc-981b-4c5e-a447-46bef21f615c','挽孫大監二首  其二','陳著','宋','宋诗','song-poetry','','[]','憶昨叩溪扃，承聞病莫迎。',48,'全唐诗/poet.song.223000.json','["憶昨叩溪扃，承聞病莫迎。", "雲山成永訣，膠漆感平生。", "紼送老無力，薤歌遥寄聲。", "何須聞宿草，未死有餘情。"]'),
('8344d6c6-089e-4076-83c8-a9764919ec06','挽孫處士','陳著','宋','宋诗','song-poetry','','[]','魁閥分根異，充然秀氣儲。',48,'全唐诗/poet.song.223000.json','["魁閥分根異，充然秀氣儲。", "少年古心貌，危世舊詩書。", "鵩怪來何早，熊祥夢竟虛。", "遥知蕙帳下，晝哭痛何如。"]'),
('a4e73edf-55bf-4d33-86ba-bcf54f66d2e9','挽少保王平章二首  其一','陳著','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','氣貌古心盎，淵源早學成。',48,'全唐诗/poet.song.223000.json','["氣貌古心盎，淵源早學成。", "三朝尊汲直，四海頌夷清。", "憂國生如死，誠身實過名。", "巍巍叔季世，人重泰山輕。"]'),
('552e09b1-79d6-41ff-bc12-097c9efbaa9e','挽少保王平章二首  其二','陳著','宋','宋诗','song-poetry','','[]','大老關元命，平生坐十年。',48,'全唐诗/poet.song.223000.json','["大老關元命，平生坐十年。", "權奸以國斃，柄用已天顛。", "痛事自屧去，忠魂客寄然。", "猶遺簪□舊，血慟北風前。"]'),
('bef0f6f3-eabf-4469-9576-b60d9df8eb7c','挽江陰軍王寺丞','陳著','宋','宋诗','song-poetry','','[]','自是元台嗣，心如白屋英。',48,'全唐诗/poet.song.223000.json','["自是元台嗣，心如白屋英。", "老成涵古氣，清勁立平生。", "孝養官居少，幽恬俗念輕。", "栖栖甲子晚，誰識病淵明。"]'),
('bbc14bbb-6047-4a49-97c6-725bd43fc82e','挽趙集賢□□三首  其一','陳著','宋','宋诗','song-poetry','','[]','雍容存器局，沈細入經綸。',48,'全唐诗/poet.song.223000.json','["雍容存器局，沈細入經綸。", "心好難爲弟，身危活得民。", "餘生盟蕙帳，急召應蒲輪。", "松下舊遊處，爲誰芳草新。"]'),
('24e84682-842b-4257-bda4-809e9fe5a2f9','挽趙集賢□□三首  其二','陳著','宋','宋诗','song-poetry','','[]','三年集賢院，一老遠遊身。',48,'全唐诗/poet.song.223000.json','["三年集賢院，一老遠遊身。", "鐙火影相弔，家山眉兩顰。", "生還空有日，病卧竟無晨。", "瞑斂夫何憾，同朝多故人。"]'),
('dfcd6649-2f7b-4f9b-b9d5-1438f4aee29d','挽趙集賢□□三首  其三','陳著','宋','宋诗','song-poetry','','[]','命也誰無死，恩斯獨異今。',48,'全唐诗/poet.song.223000.json','["命也誰無死，恩斯獨異今。", "人迎萬里櫬，天報一生心。", "紅炬護舟穩，白雲歸窆深。", "蹣跚得臨坎，痛器撼山林。"]'),
('cf800709-c6b5-44e0-b492-90559cd48ca4','挽張梅坦二首  其一','陳著','宋','宋诗','song-poetry','','[]','之子吾鄉秀，生來踏上風。',48,'全唐诗/poet.song.223000.json','["之子吾鄉秀，生來踏上風。", "蘭亭高擢穎，芹泮早稱雄。", "科第孫山秀，吟情灞雪中。", "□□□□□，□□□□□。"]'),
('8524fabb-b949-4e4f-9137-dd2d81740dfb','挽張梅坦二首  其二','陳著','宋','宋诗','song-poetry','','[]','同飲嵩溪水，綢繆况有連。',48,'全唐诗/poet.song.223000.json','["同飲嵩溪水，綢繆况有連。", "心期天地闊，情話歲時遷。", "一病胡三暑，長歸竟九泉。", "誰知之子憾，薛鳳定翩翩。"]'),
('f1ee7f1c-5da7-4cfb-b444-c9ac13ea17e3','挽舒亦山少母鄒氏','陳著','宋','宋诗','song-poetry','','[]','我與亦山連，因聞少母賢。',48,'全唐诗/poet.song.223000.json','["我與亦山連，因聞少母賢。", "順柔知自分，勤檢樂吾便。", "心積兒孫福，家修香火緣。", "平生庶無憾，此去坐青蓮。"]'),
('72dfbf5c-8272-4ff5-b8e0-61b6b4e41386','挽蔣質甫','陳著','宋','宋诗','song-poetry','','[]','誰能傳耆舊，善譽在鄉關。',48,'全唐诗/poet.song.223000.json','["誰能傳耆舊，善譽在鄉關。", "教子籯金外，和家棣萼閒。", "死心多佛悟，生世半詩閒。", "逝矣夫何憾，逍遥玉女山。"]'),
('d1203580-f004-4635-acaa-46b21730b87c','挽袁鎮','陳著','宋','宋诗','song-poetry','','[]','名筆記新塋，何須更乞銘。',48,'全唐诗/poet.song.223000.json','["名筆記新塋，何須更乞銘。", "空山有琴瑟，有子足門庭。", "死異十年遠，歸同一穴甯。", "鄉人指餘慶，書氣發林坰。"]'),
('820d7425-2d9b-42fb-bf26-981821275e49','挽孫常州寺簿二首  其一','陳著','宋','宋诗','song-poetry','','[]','早宦早收還，相從溪與山。',48,'全唐诗/poet.song.223000.json','["早宦早收還，相從溪與山。", "身曾五□貴，心自一鷗閒。", "留訓金籯外，尋盟貝葉閒。", "手銘平日事，打破死生關。"]'),
('ebf86344-2e36-49f0-a314-0fd5e9e2ca62','挽孫常州寺簿二首  其二','陳著','宋','宋诗','song-poetry','','[]','青春到白首，膠漆更他誰。',48,'全唐诗/poet.song.223000.json','["青春到白首，膠漆更他誰。", "話別水亭酒，斷章山驛詩。", "平生今地下，後死獨天涯。", "執紼萬官路，欲前筋力衰。"]'),
('e664f922-12fb-4403-8721-7563d58d6391','挽范節幹二首  其一','陳著','宋','宋诗','song-poetry','','[]','君墓我其銘，誰知不盡情。',48,'全唐诗/poet.song.223000.json','["君墓我其銘，誰知不盡情。", "半生萍梗過，晚歲柏松盟。", "輦下清相諗，兵閒老共驚。", "芙蓉堂在否，回首淚縱橫。"]'),
('e066176c-7a37-4eb8-b9b7-ab7eec0a1163','挽范節幹二首  其二','陳著','宋','宋诗','song-poetry','','[]','去秋言別時，執手水之湄。',48,'全唐诗/poet.song.223000.json','["去秋言別時，執手水之湄。", "猶侈春風會，那知夜壑移。", "鬣封期已薄，眉案死相隨。", "君可無遺憾，其如我自悲。"]'),
('5f5a57f5-e593-4bca-832d-3b4f5c522527','挽董監鎮','陳著','宋','宋诗','song-poetry','','[]','宿善有君□，幽銘豈溢言。',48,'全唐诗/poet.song.223000.json','["宿善有君□，幽銘豈溢言。", "何妨儒鶡弁，自可客龍門。", "瑞竹松根見，叢編手澤存。", "壽終無一憾，更是好兒孫。"]'),
('e14c1361-0d7f-4165-b5ee-9fc0074201e1','挽史允叟慈母王氏','陳著','宋','宋诗','song-poetry','','[]','彼美蘭儀盎粹溫，誰知肅肅範閨門。',64,'全唐诗/poet.song.223000.json','["彼美蘭儀盎粹溫，誰知肅肅範閨門。", "生榮夢視金花誥，死瞑培成玉樹根。", "中一祔嚴家稱禮，終三年制子權恩。", "我來欲送銘旌路，客病棲棲悵莫奔。"]'),
('d1901da4-0d66-4cb5-815b-315a441da785','挽王開叔','陳著','宋','宋诗','song-poetry','','[]','裔自三吳秀四明，士林著不盡崢嶸。',64,'全唐诗/poet.song.223000.json','["裔自三吳秀四明，士林著不盡崢嶸。", "江淮遊覽詩隨氣，鄉里推評實過名。", "最是與梅相契友，翛然易簀了平生。", "北風飛旐余山路，稍得悲歌薤露聲。"]'),
('12edf4c3-2788-4478-a333-24abae698115','挽張正甫二首  其一','陳著','宋','宋诗','song-poetry','','[]','別來倏忽一周星，君住家林我泛萍。',64,'全唐诗/poet.song.223000.json','["別來倏忽一周星，君住家林我泛萍。", "到處逢人問梅坦，有時見夢說蘭亭。", "自憐倦翼歸遲暮，已報清魂入杳冥。", "多少微言今已矣，義難辭處寫爲銘。"]'),
('b7ab83f4-2990-42f8-9423-44c26bea0649','挽張正甫二首  其二','陳著','宋','宋诗','song-poetry','','[]','河汾坐下舊諸生，拔穎叢中學早成。',64,'全唐诗/poet.song.223000.json','["河汾坐下舊諸生，拔穎叢中學早成。", "公相品題文藝價，鄉人辟易義風情。", "本來雲雨蛟龍志，老去山林猨鶴盟。", "桂子不須墳上落，此君原自不爭名。"]'),
('d44ac24d-5e48-4047-ac54-07a16e098e30','挽校書郎方公夫人二首  其一','陳著','宋','宋诗','song-poetry','','[]','有美女中玉，來嬪天下魁。',48,'全唐诗/poet.song.223000.json','["有美女中玉，來嬪天下魁。", "心無慚藻澗，眼及到蘭臺。", "欲伴春行樂，俄纏晝哭哀。", "誰知餘地在，五桂總翹材。"]'),
('ed8038f0-6729-4eca-863c-24d04341e72d','挽校書郎方公夫人二首  其二','陳著','宋','宋诗','song-poetry','','[]','七十七年春，斑衣堂上新。',48,'全唐诗/poet.song.223000.json','["七十七年春，斑衣堂上新。", "魚軒宜有晚，恙枕竟無晨。", "空感通家淚，難隨執紼塵。", "望雲飛老□，聊聒薤歌人。"]'),
('189d9ff9-dcdc-43f2-a809-f36acbc4430e','挽卓生甫二首  其一','陳著','宋','宋诗','song-poetry','','[]','風雨瀟瀟境，山林落落姿。',48,'全唐诗/poet.song.223000.json','["風雨瀟瀟境，山林落落姿。", "安貧清似玉，嗜學苦如飴。", "世事兩顰送，古心諸老知。", "家庭多手澤，幸有甯馨兒。"]'),
('b27b9cf4-b4f8-4789-98f1-562344d08cab','挽卓生甫二首  其二','陳著','宋','宋诗','song-poetry','','[]','袖携文滿卷，下問及深衣。',48,'全唐诗/poet.song.223000.json','["袖携文滿卷，下問及深衣。", "擬議金難訂，稽遲璧未歸。", "重逢何日是，一夢已人非。", "宿草自春處，老心東向飛。"]'),
('ceb49d4a-feab-43ee-825f-391897edc280','挽族父承務郎衡之三首  其一','陳著','宋','宋诗','song-poetry','','[]','人物瑞丹霞，翛然絕點瑕。',48,'全唐诗/poet.song.223000.json','["人物瑞丹霞，翛然絕點瑕。", "寬心無厭客，急義不謀家。", "一室琴棋畫，四時風月花。", "晚來滿山菊，消得澹生涯。"]'),
('09c9e6b1-b9ad-4b0b-9d79-95e7bbaef9eb','挽族父承務郎衡之三首  其二','陳著','宋','宋诗','song-poetry','','[]','庭桂出心根，天風香滿門。',48,'全唐诗/poet.song.223000.json','["庭桂出心根，天風香滿門。", "初封緣子貴，上壽稱君恩。", "正爾需三釜，胡然夢九原。", "有餘無盡澤，留下長蘭孫。"]'),
('9af273d7-efbd-4753-bc5b-4d82a4d4bacf','挽族父承務郎衡之三首  其三','陳著','宋','宋诗','song-poetry','','[]','當年延桂塾，承乏愧無能。',48,'全唐诗/poet.song.223000.json','["當年延桂塾，承乏愧無能。", "以子視宗族，如家安友朋。", "春風文字酒，夜雨誦絃鐙。", "古首淒誰續，心安淚欲冰。"]'),
('236ae9e4-41db-4b2e-bb53-312ea6da8846','剡縣解雨五龍潭等處送神辭','陳著','宋','宋诗','song-poetry','','[]','稼如茨兮黍與粳，十日不雨兮彼蒼。',85,'全唐诗/poet.song.223000.json','["稼如茨兮黍與粳，十日不雨兮彼蒼。", "御龍君兮徼祥，環嵊之土兮雨其滂。", "焦捲發秀兮摇晚凉，田水泱泱兮秋風香。", "旄倪舞歌兮飽有望，神之賜兮何可忘。", "登山臨水兮送將，神亦勞止兮歸安故鄉。"]'),
('02ff0fde-1907-4e23-9f69-e6f37e41c0f2','賦虛谷黄子羽所藏吳山西墨蘭三章  其一','陳著','宋','宋诗','song-poetry','','[]','虛谷兮委蛇，雲英英兮日遲遲。',31,'全唐诗/poet.song.223000.json','["虛谷兮委蛇，雲英英兮日遲遲。", "繁陰兮土滋，蘭之生兮彼桃李其安知。"]'),
('f5402a67-1b67-4b65-a778-5576d1d3822a','賦虛谷黄子羽所藏吳山西墨蘭三章  其二','陳著','宋','宋诗','song-poetry','','[]','虛谷兮明陽，紛百草兮樹千章。',31,'全唐诗/poet.song.223000.json','["虛谷兮明陽，紛百草兮樹千章。", "馨香兮自將，蘭之有兮何蕙茝之敢芳。"]'),
('31765f80-b28a-41ed-b805-ce983456a0a2','賦虛谷黄子羽所藏吳山西墨蘭三章  其三','陳著','宋','宋诗','song-poetry','','[]','虛谷兮泬寥，霜雪降兮風蕭蕭。',31,'全唐诗/poet.song.223000.json','["虛谷兮泬寥，霜雪降兮風蕭蕭。", "榮華兮飄摇，蘭之全兮清寂寂而彌高。"]'),
('75538076-bed0-4e94-a1a1-e85afd4a45fc','賦墨梅','陳著','宋','宋诗','song-poetry','','[]','直放而爲橫出之勁兮，瘦吐而爲淡佇之馨。',67,'全唐诗/poet.song.223000.json','["直放而爲橫出之勁兮，瘦吐而爲淡佇之馨。", "羌寂寞以自韻兮，而萬里其流聲。", "風霜之表神與交兮，明月在天水在下。", "耿耿於其閒兮，於以觀我生之清明。"]'),
('f7d1c320-da48-402a-a02e-f9653b8a156d','賦墨鷺','陳著','宋','宋诗','song-poetry','','[]','山林以爲家兮，出而與風烟之爲縹緲。',66,'全唐诗/poet.song.223000.json','["山林以爲家兮，出而與風烟之爲縹緲。", "水之湄素所狎兮，專一嗜而謀飽。", "紛紛下而上兮，若不能以終日。", "矯靜潔以待時兮，固有獨立於寒梢之表者也。"]'),
('24201472-75fa-4a93-93f0-223164634716','題畫扇','陳著','宋','宋诗','song-poetry','','[]','江極目兮沙路平，馿卓耳兮風蹄輕。',32,'全唐诗/poet.song.223000.json','["江極目兮沙路平，馿卓耳兮風蹄輕。", "彼何人兮爲此行，我欲從之到蓬瀛。"]'),
('43739c62-3703-40e5-a797-261bb704b4a5','賦賈養晦所藏王庭吉墨水仙花','陳著','宋','宋诗','song-poetry','','[]','歲云暮兮陰凝，若有人兮亭亭。',59,'全唐诗/poet.song.223000.json','["歲云暮兮陰凝，若有人兮亭亭。", "玉質兮黄中，淡無言兮含馨。", "雪霜貿貿兮弱植自矜，宇宙納納兮誰與爲情，斂而全其素兮何有乎丹青。"]'),
('bf79fea9-5749-4920-90f1-8faf148950ff','題女沖所藏彩箋','陳著','宋','宋诗','song-poetry','','[]','天空闊兮西東兩山，路平平兮春草班班。',36,'全唐诗/poet.song.223000.json','["天空闊兮西東兩山，路平平兮春草班班。", "今而後兮百里之閒，思渺渺兮水竹之灣。"]'),
('c3c31cec-02c1-4d60-8493-885ad2297403','題兒泌所藏彩箋','陳著','宋','宋诗','song-poetry','','[]','山一抹於天之末兮，彌隠隠而彌妍。',60,'全唐诗/poet.song.223000.json','["山一抹於天之末兮，彌隠隠而彌妍。", "松矯矯龍其脊兮，颯張髯而自全。", "有美一人兮，橋之外水之邊。", "意其悠然有見兮，雙鷺飛飛而在天。"]'),
('8dcd5951-d722-42c0-8976-09aae19a5871','吳景年真贊','陳著','宋','宋诗','song-poetry','','[]','其容淵，其髯掀，其服野，其冠圜。',89,'全唐诗/poet.song.223000.json','["其容淵，其髯掀，其服野，其冠圜。", "是誰筆之得其粗焉，孰若見君於此筆之外，而知君於此筆之前。", "氣以直而肆，神以藏而全。", "付所無於自信，處所有如不然。", "夫固欲謝吳楚之塵，而游戲乎羲皇之天也。"]'),
('04c58295-faaf-4d9f-89a8-c3b90d66e01b','石藏玉贊','陳著','宋','宋诗','song-poetry','','[]','天下之寶，惟玉爲最。',40,'全唐诗/poet.song.223000.json','["天下之寶，惟玉爲最。", "然不受觸，觸之則碎。", "如何如何，可全其粹。", "亦曰珍藏，光華自賁。"]'),
('ceb32d56-6ad7-4a06-94c5-fd33e9f23b5d','林樂閒真贊','陳著','宋','宋诗','song-poetry','','[]','皎然其毛顔也似玉，癯然其骨相也似竹。',66,'全唐诗/poet.song.223000.json','["皎然其毛顔也似玉，癯然其骨相也似竹。", "悠悠然其心也，雲與上雲與下，飄飄然其身也，江之南江之北。", "此所謂樂閒之道人，贊之者本堂老夫之醉墨。"]'),
('61365c25-359f-438d-9516-4038908b497c','汪日賓真贊','陳著','宋','宋诗','song-poetry','','[]','詩書以沃其中兮，睟自盎乎吾之餘。',83,'全唐诗/poet.song.223000.json','["詩書以沃其中兮，睟自盎乎吾之餘。", "衣冠以正其外兮，儼自媚乎吾之初。", "情周乎與物兮，於由由而介介。", "義見乎應事兮，於膠膠而舒舒。", "庶乎免於今之世兮，其將進於馬少游王彥方之徒與。"]'),
('384c159e-7e71-40e9-9b48-be48fa0bbeb4','僧雍野堂贊','陳著','宋','宋诗','song-poetry','','[]','野堂之野，大千世界。',70,'全唐诗/poet.song.223000.json','["野堂之野，大千世界。", "野堂之堂，匪茅一把。", "也無籓籬，也無閒架。", "風月往來，雲壑上下。", "空空洞洞，規模廣大。", "是真非真，是假非假。", "善哉善哉，無成無壞。"]'),
('c6472cba-7048-4ed7-a747-939053007a6e','僧可正真贊','陳著','宋','宋诗','song-poetry','','[]','古巖氣骨，春風面皮。',44,'全唐诗/poet.song.223000.json','["古巖氣骨，春風面皮。", "是人認得靈溪，靈溪元自不知。", "一片妙莊嚴域，千古萬古光輝。", "本堂老人書。"]'),
('4ffa25a3-5e16-49b2-92f9-53b132425a34','筠溪八景詩 筆架文峰','陳著','宋','宋诗','song-poetry','','["\u897f\u6e56"]','巧奪西湖五姥峰，架中時見挂長虹。',64,'全唐诗/poet.song.223000.json','["巧奪西湖五姥峰，架中時見挂長虹。", "近聯霞彩箋呈錦，遥對巖牙筆露蹤。", "翰墨雲烟來璧水，丹青桃李出花叢。", "恩承斗柄回春律，待詔東封陟泰嵸。"]'),
('621fea19-51aa-4241-9ed2-5f58fcba2880','筠溪八景詩 旗臺勝境','陳著','宋','宋诗','song-poetry','','[]','□□□中不老方，石臺白戰幾多場。',64,'全唐诗/poet.song.223000.json','["□□□中不老方，石臺白戰幾多場。", "登樓歡笑□□□，□□□□姓氏香。", "雲擁貔貅天地謐，□□□□□□□。", "□□□□□馮試，採取梅花插鬢芳。"]'),
('afe662be-fca9-4094-9b42-471a8d5e697e','筠溪八景詩 桃崖暄日','陳著','宋','宋诗','song-poetry','','[]','盛陽淑氣滿巖前，誤認仙桃開洞天。',64,'全唐诗/poet.song.223000.json','["盛陽淑氣滿巖前，誤認仙桃開洞天。", "根老種傳王母顆，花嬌色映武陵田。", "輝增晴旭香盈袖，影落溪流錦障川。", "幾度遊山偏著眼，世傳春信豈無緣。"]'),
('e614723d-a976-4d44-a5b1-9784138ddab9','筠溪八景詩 穀岫陵雲','陳著','宋','宋诗','song-poetry','','[]','毓秀山根插翠峰，如陵如阜起嶐嵸。',64,'全唐诗/poet.song.223000.json','["毓秀山根插翠峰，如陵如阜起嶐嵸。", "堆高鹿苑沖銀漢，積擬鉅橋跨玉虹。", "斂厚難輸王廩粟，歲豐長守大夫松。", "乾坤種此昭宏德，陰濟鄉區皎髮翁。"]'),
('60462398-e416-421f-8ff1-27946fda54cb','筠溪八景詩 徐鳬蛟瀑','陳著','宋','宋诗','song-poetry','','[]','一流瀑瀉九重天，長挂如虹引洞仙。',64,'全唐诗/poet.song.223000.json','["一流瀑瀉九重天，長挂如虹引洞仙。", "巖壁鳬飛延歲月，石梁龍滾起雲烟。", "滿山藥味增新色，夾岸桃花勝舊年。", "愧我白頭登覽日，詠歸賡韻信多緣。"]'),
('14df53f3-6264-4b27-8acf-6a5a8a1984d2','筠溪八景詩 設僧龍湫','陳著','宋','宋诗','song-poetry','','[]','金猊擅藝寶筵開，蓬海真僧駕霧來。',64,'全唐诗/poet.song.223000.json','["金猊擅藝寶筵開，蓬海真僧駕霧來。", "講透精光圖上點，默收塵火座閒埋。", "鉢龍靜聽金風細，幢鶴驚聞唳月哀。", "莫道洞深無興會，蓮花朵朵水晶臺。"]'),
('91a654d6-06e7-461e-adac-6ac5e406d2d9','筠溪八景詩 金雞報曙','陳著','宋','宋诗','song-poetry','','[]','千金鑠鑠獨文身，五德名標莫與羣。',64,'全唐诗/poet.song.223000.json','["千金鑠鑠獨文身，五德名標莫與羣。", "振翼豈愁天色暝，曲頭如盼曙光新。", "鳥穿竹韻窗談巧，風捲塵嵐士□勤。", "□見雞人□□隴，漏殘驚起侍朝臣。"]'),
('90a46e4b-dcd2-4e6d-8527-fe5a82bac959','筠溪八景詩 玉鷺迎暉','陳著','宋','宋诗','song-poetry','','[]','□□□□□□評，巖供詩料鷺飛形。',64,'全唐诗/poet.song.223000.json','["□□□□□□評，巖供詩料鷺飛形。", "□□□□□□□，片片白雲兩翼輕。", "渚水靜觀清且淺，蘆花□□□還興。", "鳶魚活潑天空闊，信足長飛萬里程。"]'),
('26b92fc8-d358-4dbf-81c8-a7cbda35da10','次韻弟觀用王介甫桃源行韻寫感爲西湖行','陳著','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f", "\u897f\u6e56"]','錢塘江頭駐龍馬，西湖風光甲天下。',128,'全唐诗/poet.song.223000.json','["錢塘江頭駐龍馬，西湖風光甲天下。", "西湖西邊屋萬閒，中有沈沈醉花者。", "鶑鶑燕燕日日春，萍虀豆粥蠟代薪。", "黑殺吹飈忽過江，憂貽君父辱在臣。", "烽火連天天已近，浪將督師答天問。", "畏縮不前江神嗔，坐受排牆侶西晉。", "我行六橋扇障塵，仰面發慟風岸巾。", "誤國至此臍莫噬，安得包胥哭向秦。"]'),
('a9c2fb2e-a4cd-4875-a376-6bc8d006a8c9','再次前韻','陳著','宋','宋诗','song-poetry','','[]','大地山河屬司馬，雲闕岧嶢都洛下。',128,'全唐诗/poet.song.223000.json','["大地山河屬司馬，雲闕岧嶢都洛下。", "夕陽亭上已賣國，無與東門長嘯者。", "銅駝荆榛不成春，華林轉眼爲樵薪。", "連牆枯骨若有聲，啾啾知是清談臣。", "中原雖遠江東近，典午偏安姑莫問。", "苻堅百萬捲淝波，猶有安石能强晉。", "嗟今玉輦竟蒙塵，將相受辱甘幗巾。", "求如西晉已觖望，萬世遺笑無人秦。"]'),
('f39eba04-b0f6-4b0d-ac87-58082b26384f','勝因院','陳著','宋','宋诗','song-poetry','','[]','轉路便幽深，曾來不用尋。',48,'全唐诗/poet.song.223000.json','["轉路便幽深，曾來不用尋。", "寺依仙石脚，僧識老巖心。", "是處鬼無墓，此山松自林。", "滔滔未涯事，分付一蟬吟。"]'),
('8a92cd45-90ae-4db4-9c79-f7c9125339a6','屬酒歌','陳著','宋','宋诗','song-poetry','','[]','險難兮更嘗，淡泊兮悠長。',27,'全唐诗/poet.song.223000.json','["險難兮更嘗，淡泊兮悠長。", "翕與張兮何嘗，如友良何兮友良。"]'),
('4b643e89-bbe0-4a9a-bbe0-092991af5305','答本堂先生歌','趙必興','宋','宋诗','song-poetry','','[]','往事兮浮雲，偕老兮天倫。',27,'全唐诗/poet.song.223000.json','["往事兮浮雲，偕老兮天倫。", "樂莫樂兮天真，如良人何兮良人。"]'),
('ebf52bfd-a865-428a-bbe9-30e7a75a9c30','黄陵題咏','趙希鄂','宋','宋诗','song-poetry','','[]','悵望鑾輿不復還，令人疑盡九疑山。',64,'全唐诗/poet.song.223000.json','["悵望鑾輿不復還，令人疑盡九疑山。", "朱弦一斷南風操，粉淚長留楚竹斑。", "往事悠悠流水去，空祠寂寂暮雲閑。", "客情弔古多悲恨，趣理歸舟遡碧灣。"]'),
('3b83622b-9eee-4719-ad9b-184abe43be78','汨羅廟','趙希鄂','宋','宋诗','song-poetry','','[]','懷沙一死固堪傷，千載修名實未亡。',64,'全唐诗/poet.song.223000.json','["懷沙一死固堪傷，千載修名實未亡。", "舉國無人君不悟，斯文有幸日爭光。", "讒言枉以艾蕭惡，正論終歸蘭芷香。", "解印欲辭羅水去，祇傾羅水奠離觴。"]'),
('67440b1b-7052-4470-8760-e72cc9a35d5d','苕溪晚泊','程以南','宋','宋诗','song-poetry','','[]','一笑苕溪上，微茫駐日曛。',48,'全唐诗/poet.song.223000.json','["一笑苕溪上，微茫駐日曛。", "鷺沙行个字，魚水呷圓紋。", "晚色三家市，秋容幾樹雲。", "行藏知有分，莫誦北山文。"]'),
('2fff21ed-31ec-41d0-b864-3ecec3599f6d','登曬蓑臺','程以南','宋','宋诗','song-poetry','','[]','曬蓑臺子上，載酒共躋攀。',48,'全唐诗/poet.song.223000.json','["曬蓑臺子上，載酒共躋攀。", "竟日何妨醉，看雲終是閒。", "千絲平岸柳，一髮別州山。", "頗亦關鄉念，春深未得閒。"]'),
('fb7636a5-e2ba-4415-a889-9ae6a8fc0a8c','見方虛谷後自述','程以南','宋','宋诗','song-poetry','','[]','清泠空想離騷國，至理難窮太極圖。',32,'全唐诗/poet.song.223000.json','["清泠空想離騷國，至理難窮太極圖。", "知有老人圮下履，恨無鴻寶枕中書。"]'),
('133cd63f-e3a6-4a7e-ad69-6fd4845ed202','句','程以南','宋','宋诗','song-poetry','','[]','欲居東西瀼。',6,'全唐诗/poet.song.223000.json','["欲居東西瀼。"]'),
('0b389dd7-41c5-4c28-a770-4a98fe709569','淳祐七年丁未十一月朔蔡久軒自江東提刑歸抵家時三館諸公以風霜隨氣節河漢下文章分韻賦詩送別得文字','留夢炎','宋','宋诗','song-poetry','','[]','天地蕃庶草，美惡極蕕薰。',192,'全唐诗/poet.song.223000.json','["天地蕃庶草，美惡極蕕薰。", "古來誰覽察，離騷清楚氛。", "著作大雅姿，書傳挾香芸。", "蠹簡不煩碎，豕牙貴能豶。", "仰天瀝肝膽，端欲涇渭分。", "太阿秘尚方，風霆發絪縕。", "臣直彰主聖，聲容諒沄沄。", "平生本朝心，𤱶畝豈忘君。", "見幾誠不忍，屬茲宸慮殷。", "自從春無澤，牲璧委冬雰。", "何者最感觸，民氣愁深文。", "儒服今繡衣，片言況前聞。", "四牡何騑騑，迢遞沮遵濆。", "君爲朝陽鳳，我非相府群。", "小草志或遠，深情詞不耘。", "幽屏未須去，聖德如放勳。"]'),
('5dee99d1-aee1-40dc-a867-97702979eb59','手中烏啄食','潛說友','宋','宋诗','song-poetry','','[]','靈烏渾覺不相猜，啄食翩翩手上來。',32,'全唐诗/poet.song.223000.json','["靈烏渾覺不相猜，啄食翩翩手上來。", "自笑老軀頑似石，被渠認作出生臺。"]'),
('58935b5a-ae30-48e5-85ba-9a086c4222ba','和賈魏公冬大雪詩  其一','潛說友','宋','宋诗','song-poetry','','[]','海水飛花到上林，氣形和處總由心。',64,'全唐诗/poet.song.223000.json','["海水飛花到上林，氣形和處總由心。", "采薇指日休兵甲，宿麥連雲辦輦任。", "熾炭酒行懷往昔，老枝詩句詔來今。", "燮調妙用誰知得，端在崇陽與抑陰。"]'),
('501220d6-dc3c-4000-b84d-9301078ac69e','和賈魏公冬大雪詩  其二','潛說友','宋','宋诗','song-poetry','','[]','雲氣崢嶸衆俊林，聖朝事事合天心。',64,'全唐诗/poet.song.223000.json','["雲氣崢嶸衆俊林，聖朝事事合天心。", "梅根依傍蒙嘉澤，竹力低垂愧重任。", "有美江山祗如舊，無塵宇宙幸逢今。", "坐令清晝閒鈴索，白戰工夫效汝陰。"]'),
('67c40d4e-5c66-414b-8dbb-fb60f0f6267e','再和  其一','潛說友','宋','宋诗','song-poetry','','[]','突兀瓊樓照武林，淋漓黄榜快群心。',64,'全唐诗/poet.song.223000.json','["突兀瓊樓照武林，淋漓黄榜快群心。", "成功共說平淮度，經世誰如釣海任。", "後樂園應看最好，婁豐年又數從今。", "太平君子方宵旰，想讀豳風到凌陰。"]'),
('32d765f7-e3e0-4923-97ea-ceab0a7fe01c','再和  其二','潛說友','宋','宋诗','song-poetry','','[]','句落孤山壓老林，橫枝解識燮調心。',64,'全唐诗/poet.song.223000.json','["句落孤山壓老林，橫枝解識燮調心。", "衆賢戛擊宗韶頀，外域流傳洗靺任。", "不有鹿磯功許大，那能兔苑樂如今。", "非才久愧班東上，抱甕何當學漢陰。"]'),
('2a9863e1-071e-42a5-8a4a-f7004f8d1578','古意','徐集孫','宋','宋诗','song-poetry','','[]','彼美山中桐，千古生清風。',120,'全唐诗/poet.song.223000.json','["彼美山中桐，千古生清風。", "斲削羅徽弦，不費膠漆工。", "伊石臺有梅，月冷雲空濛。", "一彈彈春江，遲日春融融。", "再彈彈招隠，霜木吟樵楓。", "三彈彈離騷，感慨古道隆。", "大羹玄酒味，旨趣回顓蒙。", "世無子期耳，知音未易逢。", "袖手長太息，所聽何不同。", "所聽非不同，舉世鄭衛聾。"]'),
('5764a557-4b7f-4b56-88c5-0dce1169795e','智果寺觀東坡墨蹟參寥泉','徐集孫','宋','宋诗','song-poetry','','[]','煮茗評詩歲月深，堂堂遺像篆煙沉。',64,'全唐诗/poet.song.223000.json','["煮茗評詩歲月深，堂堂遺像篆煙沉。", "數間老屋關興廢，一段清名無古今。", "碑斷亂雲封字脚，井昏落葉覆泉心。", "斜陽影裏夷猶處，仰止高風不敢吟。"]'),
('acc31851-b8c6-4d78-9499-388224cb2954','暇日言事二首  其一','徐集孫','宋','宋诗','song-poetry','','[]','雨苔侵逕客來稀，官事纔閒便掩扉。',32,'全唐诗/poet.song.223000.json','["雨苔侵逕客來稀，官事纔閒便掩扉。", "欹枕忽生鄉國念，夢中喜得一番歸。"]'),
('38f01a81-3e0a-4e46-8293-72577c0e961f','暇日言事二首  其二','徐集孫','宋','宋诗','song-poetry','','[]','西風落葉滿庭除，隠几清吟獨撚鬚。',32,'全唐诗/poet.song.223000.json','["西風落葉滿庭除，隠几清吟獨撚鬚。", "官地莫將私地比，菊苗也種兩三株。"]'),
('6d2d93ef-53f0-48b4-922e-1b8479cfb3df','送葉靖逸之維揚','徐集孫','宋','宋诗','song-poetry','','[]','竹西亭下路，二十四橋迂。',48,'全唐诗/poet.song.223000.json','["竹西亭下路，二十四橋迂。", "有志風寒地，携家雨雪途。", "杯酣看玉蘂，橐重載湖珠。", "寫就烏絲句，無妨寄雁奴。"]'),
('180fd335-dd47-465e-8b31-8308c2ef70fc','中秋夜雨','徐集孫','宋','宋诗','song-poetry','','[]','兩年客帝畿，圓月浸秋輝。',48,'全唐诗/poet.song.223000.json','["兩年客帝畿，圓月浸秋輝。", "今夜月圓時，風雨打門歸。", "年年此桂魄，不照今年客。", "明月應團團，只被浮雲隔。"]'),
('9377385c-aa29-464d-9257-1a680c21bbf0','觀秋潮','徐集孫','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','八月西風噓沆瀣，長江協候肆澎湃。',128,'全唐诗/poet.song.223000.json','["八月西風噓沆瀣，長江協候肆澎湃。", "錢塘王氣天所鍾，非爲子胥逞靈怪。", "海門三山縹緲青，雙練夾岸奔雷霆。", "蛟龍黿鼉匿形影，銀濤雪浪翻滄溟。", "踏浪羣兒慣行險，出沒波心旗閃閃。", "須臾瀲灧潮信平，蕩漾漁舟千萬點。", "天低暮靄襲人衣，游子興盡各云歸。", "獨有騷翁看不足，吟到夜月揚清輝。"]'),
('29037965-abd3-4e80-a913-54b7e23c827c','江湖偉觀','徐集孫','宋','宋诗','song-poetry','','[]','昔日山中一小亭，重新輪奐轉崢嶸。',64,'全唐诗/poet.song.223000.json','["昔日山中一小亭，重新輪奐轉崢嶸。", "著身梯磴千層上，到眼江湖兩派明。", "鼎藥丹成仙已去，盃泉墨冷水猶清。", "壽星炯炯無今古，長照東南王氣生。"]'),
('0da58b18-ea28-4a2f-8b3c-72794aac7fe2','聞蛩','徐集孫','宋','宋诗','song-poetry','','[]','獨搔短髮坐更深，夜雨書燈半欲陰。',32,'全唐诗/poet.song.223000.json','["獨搔短髮坐更深，夜雨書燈半欲陰。", "近日病魔詩思澀，一秋清句付蛩吟。"]'),
('326e3c0c-b5d3-4997-a698-bba5e41b033e','對菊','徐集孫','宋','宋诗','song-poetry','','[]','未能籬下學悠然，慚爲微官繫日邊。',32,'全唐诗/poet.song.223000.json','["未能籬下學悠然，慚爲微官繫日邊。", "造物似憐清俸少，菊花隨地鑄金錢。"]'),
('76eeee2a-22ba-4cb8-832f-a98965c9e290','同杜北山鄭渭濱湖邊小憩','徐集孫','宋','宋诗','song-poetry','','[]','與朋看落葉，捨棹踏湖西。',48,'全唐诗/poet.song.223000.json','["與朋看落葉，捨棹踏湖西。", "野店傳盃酌，殘陽索品題。", "雲隨波影動，山被柳陰迷。", "一點寒鴉過，知他何處棲。"]'),
('f1932364-48b7-4f40-82bb-b5691bbec8f5','看梅','徐集孫','宋','宋诗','song-poetry','','[]','歲寒氣味少人知，一度相逢一度奇。',64,'全唐诗/poet.song.223000.json','["歲寒氣味少人知，一度相逢一度奇。", "不受陽和私點化，慣經風雪冷禁持。", "影橫坡老數枝畫，香沁逋仙兩句詩。", "相對依依吟未得，斜陽歸路不妨遲。"]'),
('cde055ae-17b3-4e12-8347-884bdebeae9e','公無渡河','徐集孫','宋','宋诗','song-poetry','','[]','公無渡河，公無渡河，公必欲渡意如何。',50,'全唐诗/poet.song.223000.json','["公無渡河，公無渡河，公必欲渡意如何。", "波濤洶湧何足畏，中原未復一身多。", "爭知平地有風波，人心之險險於河。"]'),
('fe03b5ce-2bf2-4d68-9483-ee49d9e86ccf','水樂洞','徐集孫','宋','宋诗','song-poetry','','[]','路穿巖竇折羊腸，處處亭臺御墨香。',32,'全唐诗/poet.song.223000.json','["路穿巖竇折羊腸，處處亭臺御墨香。", "流水不隨人事去，尚餘絲竹舊宮商。"]'),
('39848247-2f31-4ce9-9a0a-1a7120c427a8','玉清宮初陽臺','徐集孫','宋','宋诗','song-poetry','','[]','守藥胎仙去不來，空留山頂煉丹臺。',32,'全唐诗/poet.song.223000.json','["守藥胎仙去不來，空留山頂煉丹臺。", "明眸炯炯初陽在，知隔人間幾劫灰。"]'),
('18f97577-a825-43b0-98b7-f5c70f5ed498','下竺看猿','徐集孫','宋','宋诗','song-poetry','','[]','渴泉飲罷過別枝，株守山林得便宜。',100,'全唐诗/poet.song.223000.json','["渴泉飲罷過別枝，株守山林得便宜。", "伸手攫拏野僧果，貴游玩弄如兒嬉。", "膏粱恣欲甚丘壑，苞苴賸把實囊橐。", "本然無物拋乞與，縱有腥羶醫無藥。", "勸汝儔侶只依僧，殘齋剩核亦潔澄。", "切勿自照具人面，便爾忘却當初洞口呼不應。"]'),
('ff4e045a-5286-4fb7-a4d7-8add1c30f0a0','聞鶴','徐集孫','宋','宋诗','song-poetry','','[]','千年華表竟何榮，曾結孤山夙世盟。',64,'全唐诗/poet.song.223000.json','["千年華表竟何榮，曾結孤山夙世盟。", "午夜露零和月冷，一聲風靜仰天鳴。", "既歸蕙帳情何怨，不上揚州韻更清。", "未必湖陰人聽得，聽來好爵謾營營。"]'),
('3fca1699-6e2c-4de7-ab46-10caa98d7a89','玉泉看金魚','徐集孫','宋','宋诗','song-poetry','','[]','石沼鑿瓊瑶，金鱗數百條。',48,'全唐诗/poet.song.223000.json','["石沼鑿瓊瑶，金鱗數百條。", "年深須變化，泉潔自逍遥。", "網罟難垂手，公卿擬上腰。", "龍宮依梵法，翻水雨青霄。"]'),
('57c7d5ed-93d6-4452-8baa-0f12f37271ae','訪僧不遇','徐集孫','宋','宋诗','song-poetry','','[]','特地尋君選佛場，行行踏遍古苔荒。',64,'全唐诗/poet.song.223000.json','["特地尋君選佛場，行行踏遍古苔荒。", "不因坐石貪搜句，何事抽單輟赴堂。", "空榻日移懸錫影，別寮風過煮茶香。", "忙中我爲閒來到，君本閒人爲甚忙。"]'),
('c16dbfcf-1a8f-44e7-8dc3-fe217cd1f7dd','六一泉','徐集孫','宋','宋诗','song-poetry','','[]','惠勤已蛻老歐仙，物逐人非井便乾。',32,'全唐诗/poet.song.223000.json','["惠勤已蛻老歐仙，物逐人非井便乾。", "不是坡翁重到此，此泉安得到今寒。"]'),
('6094a136-2bac-4dc5-a322-3141f1be4489','金沙井','徐集孫','宋','宋诗','song-poetry','','[]','修綆垂瓶自汲深，水澄沙瑩幾星金。',32,'全唐诗/poet.song.223000.json','["修綆垂瓶自汲深，水澄沙瑩幾星金。", "分明不與貪泉比，莫爲金沙起利心。"]'),
('5f40651d-42a9-4537-8fd9-b95c91dd4571','乍晴','徐集孫','宋','宋诗','song-poetry','','[]','吟情天遠倚闌干，聲歇鳴渠雨乍乾。',64,'全唐诗/poet.song.223000.json','["吟情天遠倚闌干，聲歇鳴渠雨乍乾。", "只爲湖山居宦舍，却因笋蕨憶家餐。", "燕窠出子春游懶，燈燼開花夜話殘。", "收拾柳綿囊楮被，麥秋猶有一番寒。"]'),
('0e98cefe-e8f9-4673-aaf9-0b22f89317bd','重拜和靖先生墓','徐集孫','宋','宋诗','song-poetry','','[]','秋聲爾許悲，懷古若爲思。',48,'全唐诗/poet.song.223000.json','["秋聲爾許悲，懷古若爲思。", "菊老泉堪薦，山孤草亦萎。", "高風留塑鶴，殘雨暗荒碑。", "依舊梅千樹，無花香似詩。"]'),
('fe8c6663-9066-4ff0-8d35-e07d2d86dfd6','竹閣','徐集孫','宋','宋诗','song-poetry','','[]','昔日孤山像，重移閣幾春。',48,'全唐诗/poet.song.223000.json','["昔日孤山像，重移閣幾春。", "騷名垂句法，遺愛稔邦民。", "雨剝一碑古，風摇萬竹新。", "來游興感慨，誰繼若而人。"]'),
('9669d6d1-18e3-4eb3-8064-7f271e6a81d1','夜過富春','徐集孫','宋','宋诗','song-poetry','','[]','夜船摇兀當乘槎，得與僧俱似出家。',64,'全唐诗/poet.song.223000.json','["夜船摇兀當乘槎，得與僧俱似出家。", "數幅征帆拋草渡，一團幽夢繞梅花。", "風傳山縣殘更漏，潮練霜江淡月華。", "所恨釣臺眠裏過，磯邊不及理漁車。"]'),
('724b1a02-d8d0-4647-b8a6-fcb29512af04','清明','徐集孫','宋','宋诗','song-poetry','','[]','春風客裏動經年，寂寞松楸入夢邊。',32,'全唐诗/poet.song.223000.json','["春風客裏動經年，寂寞松楸入夢邊。", "斗酒誰爲寒食奠，懶將楊柳插門前。"]'),
('6c34a6f6-82fe-4459-a510-38959d31988a','燕子','徐集孫','宋','宋诗','song-poetry','','[]','呢喃不聽一年餘，又見雙飛向竹廬。',32,'全唐诗/poet.song.223000.json','["呢喃不聽一年餘，又見雙飛向竹廬。", "翻笑人間湖海客，重來仍占故巢居。"]'),
('33402007-17bd-48a1-a3ae-058570503564','訪林可山不值','徐集孫','宋','宋诗','song-poetry','','[]','尋君每自恨遲遲，及扣巖扃誤所期。',64,'全唐诗/poet.song.223000.json','["尋君每自恨遲遲，及扣巖扃誤所期。", "空放山間雲外鶴，只吟篷底雪中詩。", "孤燈欹枕勞頻夢，樽酒憑欄定幾時。", "獨立小橋回首處，籬邊猶喜見橫枝。"]'),
('fce34bad-5810-42f3-9738-07ff609aa321','促刺詞','徐集孫','宋','宋诗','song-poetry','','[]','促刺復促刺，勸織聲轉劇。',124,'全唐诗/poet.song.223000.json','["促刺復促刺，勸織聲轉劇。", "小婦跣雨採桑歸，大姑煮雪抽絲繹。", "辛勤欲織禦寒衣，朝暮惟恐不盈尺。", "織成門外迫催租，不了輸租仍賣綌。", "婦姑對泣兒號寒，更無可補兒衣隙。", "帛暖本擬代綌寒，賣綌寒來愈無策。", "促刺兮，促刺兮，勸人織兮織何益。", "貯之金屋是何人，重重綾錦飾珠璧。"]'),
('c678c834-7836-4974-afab-3486c2b00a46','鷺','徐集孫','宋','宋诗','song-poetry','','[]','素狎沙鷗水國盟，一生蹤跡任飄零。',64,'全唐诗/poet.song.223000.json','["素狎沙鷗水國盟，一生蹤跡任飄零。", "漫誇霜雪精神別，難洗蝦魚氣習腥。", "點破青山成曉畫，飛來紅蓼稱秋汀。", "江湖出入風波裏，比著胎仙欠典刑。"]'),
('17d5f776-822e-40c9-bcd7-c2bedf77ded6','蟬','徐集孫','宋','宋诗','song-poetry','','[]','高蹈槐梢與柳陰，爭鳴直到日西沉。',64,'全唐诗/poet.song.223000.json','["高蹈槐梢與柳陰，爭鳴直到日西沉。", "初無識見偏容喙，不讀詩書却好吟。", "風露細餐雖足飽，山林爲計更宜深。", "所談幸爾非人事，逆耳從來欠賞音。"]'),
('9d554a45-f782-4be9-9f70-e34d89dfb5f3','贈相士','徐集孫','宋','宋诗','song-poetry','','[]','好爵縻人見不休，更饒君盡許封侯。',32,'全唐诗/poet.song.223000.json','["好爵縻人見不休，更饒君盡許封侯。", "山林朝市心殊相，莫誤平人枉白頭。"]'),
('9b4f2f2a-7a08-442f-9d21-2a5a49f31a88','遺僧楮衾','徐集孫','宋','宋诗','song-poetry','','[]','練從秋水桂華鄉，雅稱分供衲子床。',64,'全唐诗/poet.song.223000.json','["練從秋水桂華鄉，雅稱分供衲子床。", "一段溫和雲共軟，十分明潔月爭光。", "吟魂有夢圓春草，禪骨無因怯曉霜。", "金帳繡衾皆業境，此中清趣最深長。"]'),
('8fdfb089-90c1-41fe-91fd-d4aa487bc090','可賦軒避暑','徐集孫','宋','宋诗','song-poetry','','[]','萬箇琅玕爽氣浮，何妨暫借著詩流。',64,'全唐诗/poet.song.223000.json','["萬箇琅玕爽氣浮，何妨暫借著詩流。", "世人奔競長爲暑，心地清凉即是秋。", "普供茶瓜醒眊矂，自携枕簟足夷猶。", "從今只有山林好，浮世炎炎卒未休。"]'),
('2d343789-e488-473e-b74c-a42b2b1e2682','客夢','徐集孫','宋','宋诗','song-poetry','','[]','人生總總汩浮榮，勘破令人厭宦情。',64,'全唐诗/poet.song.223000.json','["人生總總汩浮榮，勘破令人厭宦情。", "竹屋無時勞結夢，秫田何日遂歸耕。", "雨侵藥竈莓苔長，秋透書臺筆硯清。", "漸老鬢毛猶未雪，此身猶及見升平。"]'),
('c0a17ee7-e2e8-434b-acdc-087e432e9bbe','夜雨','徐集孫','宋','宋诗','song-poetry','','[]','夜半倏驚覺，狂風攪秋鳴。',48,'全唐诗/poet.song.223000.json','["夜半倏驚覺，狂風攪秋鳴。", "掣電起迅雷，驟雨翻盆傾。", "逆知造物意，揫斂萬寶成。", "天威不竟夕，須臾山月明。"]'),
('d32130f5-7ce4-4453-a729-1efe27f3e976','官舍雙桂','徐集孫','宋','宋诗','song-poetry','','[]','翠玉黄金剪綴成，幽香不斷襲人清。',64,'全唐诗/poet.song.223000.json','["翠玉黄金剪綴成，幽香不斷襲人清。", "獨披月色連宵看，更結秋風來歲盟。", "好夢偏爲蛩叫破，吟身那似蝶飛輕。", "紛紛凡卉誰堪眼，說與寒梅蚤合并。"]'),
('0883ee39-378b-48cd-87e4-9066e7c83077','雨中用進退格','徐集孫','宋','宋诗','song-poetry','','[]','秋來天氣半晴陰，塊坐山窗一欠伸。',64,'全唐诗/poet.song.223000.json','["秋來天氣半晴陰，塊坐山窗一欠伸。", "欲睡却思妨官業，怕吟惟恐動鄉心。", "遠書難準衣仍薄，清俸無多橐慣貧。", "箇種關情畦稻熟，雨宜時降不宜霪。"]'),
('35e15007-9c3e-4541-8188-aab6ffed947a','岳鄂王墓','徐集孫','宋','宋诗','song-poetry','','[]','古木號風抱不平，百年忠義日爭明。',32,'全唐诗/poet.song.223000.json','["古木號風抱不平，百年忠義日爭明。", "墳前人馬空存石，何似當時聽用兵。"]'),
('6700b3e2-e6b8-456d-84ce-d3f5eb453871','喜鵲寺','徐集孫','宋','宋诗','song-poetry','','[]','鵲巢不見委空枝，透徹機關在險時。',32,'全唐诗/poet.song.223000.json','["鵲巢不見委空枝，透徹機關在險時。", "自後非無禪可問，多因險處怕人窺。"]'),
('7953a7f8-0919-453c-91af-4cec5118a36c','訪詩人','徐集孫','宋','宋诗','song-poetry','','[]','得得訪詩僊，平湖水接天。',48,'全唐诗/poet.song.223000.json','["得得訪詩僊，平湖水接天。", "身輕如鶴羽，路遠買漁船。", "日上荷撐蓋，春深柳脫綿。", "造門人已出，冷漱石山泉。"]'),
('c2ea4013-34e9-427e-a4de-81cb94629c59','湖亭夜坐','徐集孫','宋','宋诗','song-poetry','','[]','片葉秋風數日程，爭如天籟未秋聲。',64,'全唐诗/poet.song.223000.json','["片葉秋風數日程，爭如天籟未秋聲。", "厭居塵境炎威熾，來納虛亭夜氣清。", "萬點螢光移醉眼，一湖蟾影蕩吟情。", "笙歌寂寂重關掩，獨許高僧並臂行。"]'),
('b82f78cb-124f-4304-a619-81a8d8299cab','即事','徐集孫','宋','宋诗','song-poetry','','[]','無端梅潦肆鳴渠，官舍蕭條似僦居。',64,'全唐诗/poet.song.223000.json','["無端梅潦肆鳴渠，官舍蕭條似僦居。", "把酒厭談天下事，挑燈頻讀故人書。", "吏抄詩懶多訛字，僮治餐遲少嫩蔬。", "濁世炎蒸方鬰鬰，庭前新草不令除。"]'),
('ecf45091-075b-4898-b1e2-525347d06ef4','挽北磵','徐集孫','宋','宋诗','song-poetry','','[]','本分參禪學，吟中透一關。',48,'全唐诗/poet.song.223000.json','["本分參禪學，吟中透一關。", "清名傳北磵，遺像在南山。", "石塔人千古，煙梯屋數間。", "詩魂何處覓，應伴白雲閒。"]'),
('000d46b1-eaa1-459a-96a6-5c0ff5adb8dc','石屋','徐集孫','宋','宋诗','song-poetry','','[]','路僻鳥關關，行吟逐字刪。',48,'全唐诗/poet.song.223000.json','["路僻鳥關關，行吟逐字刪。", "偶來游石屋，却喜見香山。", "閣峭寒雲護，巖深野水閒。", "坡僊留墨在，姓字有無間。"]'),
('71bf3352-498e-4322-8fbd-6382ac0d7cf6','杯泉','徐集孫','宋','宋诗','song-poetry','','[]','一方石甃溜涓涓，扁以杯稱萬古傳。',32,'全唐诗/poet.song.223000.json','["一方石甃溜涓涓，扁以杯稱萬古傳。", "名利醉人醲似酒，誰甘恬澹酌清泉。"]'),
('aa5c6399-ffc1-4c9d-a636-0a9c885efffc','此君軒','徐集孫','宋','宋诗','song-poetry','','[]','此君瀟灑翠團欒，軒扁佳名墨已乾。',32,'全唐诗/poet.song.223000.json','["此君瀟灑翠團欒，軒扁佳名墨已乾。", "欲識清風千古在，試將石刻句吟看。"]'),
('177b04f2-c2b6-48cc-92c1-ecf10cb3ca3b','湖西納凉','徐集孫','宋','宋诗','song-poetry','','[]','小艇撐過第一橋，酌泉橋下擲詩瓢。',64,'全唐诗/poet.song.223000.json','["小艇撐過第一橋，酌泉橋下擲詩瓢。", "來游道院分荷供，擬拉吟僧遣鶴招。", "暮靄直從漁笛起，月華高過塔燈遥。", "且於靜處偷清福，人海驚人湧似潮。"]'),
('1821fe9a-07ab-4ed8-a86a-da87e0b7786b','寄題漱玉','徐集孫','宋','宋诗','song-poetry','','[]','一派潺湲迸石溪，直疑寒碧練玻璃。',64,'全唐诗/poet.song.223000.json','["一派潺湲迸石溪，直疑寒碧練玻璃。", "百川流去須歸海，萬籟喧來有定時。", "橋接丹山橫夜月，柳籠碧草拂晴曦。", "吟廬此去雖相近，爭似閒鷗立渺瀰。"]'),
('fbd30eaf-c78d-4972-89c4-fac6bf705653','春日訪四聖鄭渭濱','徐集孫','宋','宋诗','song-poetry','','[]','訪舊孤山去，桃花觀裏春。',48,'全唐诗/poet.song.223000.json','["訪舊孤山去，桃花觀裏春。", "迎香開道室，借酒酌吟人。", "琴操音還古，蔬盤味却真。", "斜陽各分散，一水隔紅塵。"]'),
('6bf765c9-bd3d-48f4-b615-7fca9fcf8fa4','檐上木香','徐集孫','宋','宋诗','song-poetry','','[]','無奈聲聲杜宇頻，木香猶有一分春。',32,'全唐诗/poet.song.223000.json','["無奈聲聲杜宇頻，木香猶有一分春。", "檐頭分得清香到，却謝尋常過路人。"]'),
('fac8e125-6098-4232-9e6e-64024d485f16','和趙冰巖借宿僧房韻','徐集孫','宋','宋诗','song-poetry','','[]','鷗盟鄉國外，簪盍把題分。',48,'全唐诗/poet.song.223000.json','["鷗盟鄉國外，簪盍把題分。", "旅舍嫌紅日，僧房卧白雲。", "茶新翻雪乳，硯古带潮紋。", "黜陟人間事，棲心耳不聞。"]'),
('0700d564-8ff9-446c-84a4-ae25020468bd','中元','徐集孫','宋','宋诗','song-poetry','','[]','今朝逢令節，依舊客殊鄉。',48,'全唐诗/poet.song.223000.json','["今朝逢令節，依舊客殊鄉。", "禪衲同分席，清齋若過堂。", "江茶浮水色，野菜带山香。", "忽憶三秋菊，誰鋤小逕荒。"]'),
('7e368e59-9d1f-49e6-ad04-c001445d84ea','餞吳西疇東歸','徐集孫','宋','宋诗','song-poetry','','[]','交情寥落若商參，誰是如蘭可斷金。',64,'全唐诗/poet.song.223000.json','["交情寥落若商參，誰是如蘭可斷金。", "別去社中懷舊友，喜來湖上共新吟。", "好山爭似居家看，冷菊難禁在旅心。", "我欲學君歸未得，來年竹屋再相尋。"]'),
('cbed40e6-4ac8-41d4-960b-6c808f2713db','習懶','徐集孫','宋','宋诗','song-poetry','','[]','風撼西窗夕照明，習成懶散澹無營。',64,'全唐诗/poet.song.223000.json','["風撼西窗夕照明，習成懶散澹無營。", "頗諳讀易深知命，却怕吟詩浪得名。", "款對山僧開月酒，旋蒸湖蟹切秋橙。", "有來歸自江干客，爲說錢塘潮信平。"]'),
('9f0b4908-a705-465a-ac97-340940d14424','送庵僧歸山','徐集孫','宋','宋诗','song-poetry','','[]','微官驅我離家山，何日歸休得遂閒。',32,'全唐诗/poet.song.223000.json','["微官驅我離家山，何日歸休得遂閒。", "先隴陰陰松影裏，春來青草倩師刪。"]'),
('b9e898d7-7dff-4af5-9d2d-9c11638482f5','跋竹間僧詩藁','徐集孫','宋','宋诗','song-poetry','','[]','借來香墨本，相對坐孤檠。',48,'全唐诗/poet.song.223000.json','["借來香墨本，相對坐孤檠。", "句似寒梅好，夢從春草生。", "逼人禪價重，喚我宦情輕。", "一事猶相得，此君同此盟。"]'),
('54493eb9-1e1a-47a4-8e3f-826c1846f6a3','歲律','徐集孫','宋','宋诗','song-poetry','','[]','歲律又侵尋，桃符句索吟。',48,'全唐诗/poet.song.223000.json','["歲律又侵尋，桃符句索吟。", "經年爲客夢，每日在家心。", "眼老看山慣，愁多怯酒深。", "公餘惟讀易，世事任浮沉。"]'),
('51f9d0eb-6834-4ba9-8625-cea51c0eb84e','趙紫芝墓','徐集孫','宋','宋诗','song-poetry','','[]','晚唐吟派續於誰，一脈纔昌復已而。',64,'全唐诗/poet.song.223000.json','["晚唐吟派續於誰，一脈纔昌復已而。", "對月難招青塚魄，見梅如揖紫芝眉。", "四靈人物嗟寥落，千古風騷憶俊奇。", "公去遥遥誰可法，少陵終始是吾師。"]'),
('40b59c9a-d091-466f-9a7e-ba4cab32240f','落梅','徐集孫','宋','宋诗','song-poetry','','[]','春雨敲花逐水流，游蜂催課未知休。',64,'全唐诗/poet.song.223000.json','["春雨敲花逐水流，游蜂催課未知休。", "生來獨冷嫌無雪，別去相逢又隔秋。", "紫蒂窠窠凝酒恨，蒼苔點點落詩愁。", "黄昏未覺師雄夢，塞管一聲何處樓。"]'),
('6fa87c16-734b-4afd-97ab-01a7b31b1ec1','冷泉亭','徐集孫','宋','宋诗','song-poetry','','[]','山遠源深絕市聲，許由因此隠方成。',64,'全唐诗/poet.song.223000.json','["山遠源深絕市聲，許由因此隠方成。", "一生獨喜枕流好，萬事何如酌水清。", "野衲洗心滋味淡，騷人照影利名輕。", "軟紅塵裏渾如醉，誰識斯泉可濯纓。"]'),
('0a8050aa-3000-453b-b7f6-1472c1df5308','玉岑','徐集孫','宋','宋诗','song-poetry','','[]','一抹斜陽掛淺林，細聽山鳥說春心。',32,'全唐诗/poet.song.223000.json','["一抹斜陽掛淺林，細聽山鳥說春心。", "千年古寺多奇迹，讀了豐碑看玉岑。"]'),
('2cf76771-b90f-4014-8754-66f63d53037f','觀音泉','徐集孫','宋','宋诗','song-poetry','','[]','巖石留雲裛翠煙，古松知歷幾千年。',32,'全唐诗/poet.song.223000.json','["巖石留雲裛翠煙，古松知歷幾千年。", "凈瓶一滴楊枝水，湧作巖前大士泉。"]'),
('6799ce56-fbff-4eb8-bb87-0dd54437c47b','除夕','徐集孫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一歲驚心忽已除，宦游尚自客西湖。',64,'全唐诗/poet.song.223000.json','["一歲驚心忽已除，宦游尚自客西湖。", "漫題桃板標茅屋，旋買梅花插瓦壺。", "俸薄幸無賒酒債，官閒却有索詩逋。", "明朝萬事從頭起，依舊山肩竹樣癯。"]'),
('41971adc-a304-4eb6-adc9-79c3ee0b27d5','舟中','徐集孫','宋','宋诗','song-poetry','','[]','厭殺人間名利忙，我忘名利只詩狂。',64,'全唐诗/poet.song.223000.json','["厭殺人間名利忙，我忘名利只詩狂。", "雅陪雲衲三生話，分得漁舟半日凉。", "傍水細看鷗鷺浴，隔蘆吹過芰荷香。", "從容飽遂清游勝，那似家居卧竹房。"]'),
('c989caeb-78b9-4d40-823f-8d44656f4700','秋風悲','徐集孫','宋','宋诗','song-poetry','','[]','秋風悲，秋風悲，秋風悲兮落葉飛。',137,'全唐诗/poet.song.223000.json','["秋風悲，秋風悲，秋風悲兮落葉飛。", "豪家不識秋風悲，杯酒暖熱兒女嬉。", "秋風悲，秋風悲，秋風悲兮隴穗萎。", "田舍不識秋風悲，腰鎌收刈雞豚肥。", "秋風悲，秋風悲，秋風悲兮塞角吹。", "戍人不識秋風悲，只願封侯不顧死，棗紅十載忘歸期。", "秋風悲，秋風悲，秋風最可悲兮。", "江流滔滔，禾黍離離，爲此悲者其知誰。"]'),
('f4205b30-e9b5-4183-a1af-c7e4e8a5823d','訪周伯弜後寄','徐集孫','宋','宋诗','song-poetry','','[]','獨坐湖窗水一杯，好懷竟日向誰開。',32,'全唐诗/poet.song.223000.json','["獨坐湖窗水一杯，好懷竟日向誰開。", "火雲六月天無夜，不爲先生定不來。"]'),
('5e871f35-2381-439c-9b91-08796901a943','書瘦巖僧詩卷後','徐集孫','宋','宋诗','song-poetry','','[]','泛湘游嶽慣風寒，怯掛田文半臂衫。',32,'全唐诗/poet.song.223000.json','["泛湘游嶽慣風寒，怯掛田文半臂衫。", "吐出煙雲冰雪句，山肩莫怪瘦巖巖。"]'),
('5969ad74-4760-45b0-a55b-5a42582f5948','休日招李山房杜北山訪渭濱秋浦于孤山即席用韻','徐集孫','宋','宋诗','song-poetry','','[]','凜凜僊風匝葑田，徘徊懷古事茫然。',64,'全唐诗/poet.song.223000.json','["凜凜僊風匝葑田，徘徊懷古事茫然。", "眼空湖海無塵累，身在蓬萊有宿緣。", "孤策遍尋儲鶴地，偏提自汲煮茶泉。", "詩家眷屬通詩譜，不枉微官客日邊。"]'),
('a4862747-e5d6-47ba-9c48-ee1c98ecfcc4','有感','徐集孫','宋','宋诗','song-poetry','','[]','華陽暫脫戴朝簪，悔被浮雲惹動心。',64,'全唐诗/poet.song.223000.json','["華陽暫脫戴朝簪，悔被浮雲惹動心。", "世事可驚如雨驟，客懷無限併秋深。", "能歸不似天邊燕，怯冷愁聞月下碪。", "幾許清高堪自慰，官居頼有竹蕭森。"]'),
('11dc78e2-eca1-49b1-b764-eea545deb8da','舊圓覺','徐集孫','宋','宋诗','song-poetry','','[]','雲氣濕香埃，門蹊印碧苔。',48,'全唐诗/poet.song.223000.json','["雲氣濕香埃，門蹊印碧苔。", "金奎今日賜，翠輦昔時來。", "禪定琴臺廢，詩寒石刻嵬。", "萬斯年勝地，不敢肆徘徊。"]'),
('0575316b-7c09-4052-ae2e-e3950e0880ac','清溪','徐集孫','宋','宋诗','song-poetry','','[]','不比江湖汗漫流，山林冷澹氣涵秋。',32,'全唐诗/poet.song.223000.json','["不比江湖汗漫流，山林冷澹氣涵秋。", "泠泠一派源頭水，岸影中間見白鷗。"]'),
('66332334-d782-4ec6-ab1d-21cda1691004','獨坐','徐集孫','宋','宋诗','song-poetry','','[]','老屋蕭條半欲斜，繩床獨坐看蜂衙。',64,'全唐诗/poet.song.223000.json','["老屋蕭條半欲斜，繩床獨坐看蜂衙。", "經年官況渾如客，計日安書已到家。", "策策冷風刪樹葉，絲絲暮雨織簷花。", "夢魂不那歸心切，小圃堪鋤自種瓜。"]'),
('7df6b55f-7f4d-4246-bce7-79dbb01503d5','挽孫花翁','徐集孫','宋','宋诗','song-poetry','','[]','清氣散乾坤，人亡名尚存。',48,'全唐诗/poet.song.223000.json','["清氣散乾坤，人亡名尚存。", "玉寒埋葛嶺，墨淡慘秦村。", "井菊風號塚，山花月返魂。", "子孫無處覓，吟客酹芳尊。"]'),
('e22a4682-065b-4f6a-9223-e197e84e452a','餞平洲僧','徐集孫','宋','宋诗','song-poetry','','[]','天地一身閒，袈裟裹亂山。',48,'全唐诗/poet.song.223000.json','["天地一身閒，袈裟裹亂山。", "聽經離竺寺，結制去雲間。", "包重懸詩稿，藤枯带蘚斑。", "西風落梧葉，應又向西還。"]'),
('8528480e-89c7-4c2f-af8e-90cc88200ff3','雲谷','徐集孫','宋','宋诗','song-poetry','','[]','月浸千林萬壑秋，聽琴驚起鶴回頭。',32,'全唐诗/poet.song.223000.json','["月浸千林萬壑秋，聽琴驚起鶴回頭。", "孤雲带濕藏空谷，不逐人間富貴浮。"]'),
('56507a58-7db0-4c77-9edc-b5a7e6728103','北高峰','徐集孫','宋','宋诗','song-poetry','','[]','閒處春光淡，逢僧共採蒿。',48,'全唐诗/poet.song.223000.json','["閒處春光淡，逢僧共採蒿。", "曲盤山磴嶮，直上塔峯高。", "風露侵衣冷，江湖送眼豪。", "近年無隠者，空負數株桃。"]'),
('3e415260-57ff-4b4e-9018-7e11e396d4eb','靈芝寺','徐集孫','宋','宋诗','song-poetry','','[]','梵宇背湖光，朱橋度綠楊。',48,'全唐诗/poet.song.223000.json','["梵宇背湖光，朱橋度綠楊。", "折藤維小艇，拂石坐幽房。", "齋版驚閒鷺，苔碑卧夕陽。", "都人喧鼓吹，未識此徜徉。"]'),
('4b5db990-97d3-4a42-895e-ba3c68c8ac81','跋吳西疇東游詩卷','徐集孫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','兩袂薰風過傳廬，鷗盟又結向西湖。',32,'全唐诗/poet.song.223000.json','["兩袂薰風過傳廬，鷗盟又結向西湖。", "東游雙幅雲煙句，寫出江心雁蕩圖。"]'),
('45ded8ab-2928-4611-90e9-1eb084ee9522','湖上','徐集孫','宋','宋诗','song-poetry','','[]','不分雨色共晴光，每攪吟魂夢草塘。',32,'全唐诗/poet.song.223000.json','["不分雨色共晴光，每攪吟魂夢草塘。", "數日不來湖上看，西風次第水蒼茫。"]'),
('f144d796-3ae4-4f4a-aae5-9437c1e51e8c','借林可山韻餞蘿屋僧','徐集孫','宋','宋诗','song-poetry','','[]','吟卷多題品，君齊賈島才。',48,'全唐诗/poet.song.223000.json','["吟卷多題品，君齊賈島才。", "聞風知竹瘦，載雨過湖來。", "交淡杯中水，儒酸葉底梅。", "便辭京口去，覓取近詩開。"]'),
('7fa0d3e3-65cf-4764-907f-ec29ae6241fb','杪歲','徐集孫','宋','宋诗','song-poetry','','[]','幾多風月費招邀，傳舍侵尋一載僑。',64,'全唐诗/poet.song.223000.json','["幾多風月費招邀，傳舍侵尋一載僑。", "客久夢魂安澹泊，歲殘老態厭喧囂。", "晴空雪片飄梅瓣，冷地春光上柳條。", "世事每從兒戲過，門前歌舞又元霄。"]'),
('1b3f7e12-5af4-4fa3-b0d4-b5eea9ade2f3','聽雪窗','徐集孫','宋','宋诗','song-poetry','','[]','靜擁寒爐逼硯冰，凍蠅怪有撲窗聲。',32,'全唐诗/poet.song.223000.json','["靜擁寒爐逼硯冰，凍蠅怪有撲窗聲。", "拋松撒竹清眠思，吹滅吟燈坐到明。"]'),
('8943c3a2-37bb-4d00-bcf5-2300b8781d8b','寄懷里中諸社友','徐集孫','宋','宋诗','song-poetry','','[]','自笑初無作吏能，却因作吏遠詩朋。',64,'全唐诗/poet.song.223000.json','["自笑初無作吏能，却因作吏遠詩朋。", "與君交訊欠逢鴈，知我懷人獨是僧。", "客枕夢殘聽夜雨，鄉心愁絕對秋燈。", "何時歲老梅花下，石鼎分茶共煮冰。"]'),
('7547d55f-24ac-4c05-82cd-11835e2d4624','贈黄羽士','徐集孫','宋','宋诗','song-poetry','','[]','閑披鶴氅紫藤冠，带得林泉骨相寒。',64,'全唐诗/poet.song.223000.json','["閑披鶴氅紫藤冠，带得林泉骨相寒。", "落魄一身風雪冷，飄蓬千里水雲寬。", "素餐洗硯抄詩句，清夜敲鍾上醮壇。", "準擬學僊僊遇否，何年煉就九還丹。"]'),
('bfcccda1-962a-4408-b0a3-d9b5656eb5fd','寄詩僧','徐集孫','宋','宋诗','song-poetry','','[]','昔日剡溪曾載雪，君今訪我以晴期。',32,'全唐诗/poet.song.223000.json','["昔日剡溪曾載雪，君今訪我以晴期。", "一庭梅雨何時竟，吟得詩來舉似誰。"]'),
('6301597f-eae5-445d-b6a3-16f2b3f24de2','惜春','徐集孫','宋','宋诗','song-poetry','','[]','輕寒測測雨絲絲，獨坐吟床日較遲。',32,'全唐诗/poet.song.223000.json','["輕寒測測雨絲絲，獨坐吟床日較遲。", "方此惜春容易老，晚風吹落野棠梨。"]'),
('1b57f53c-83eb-496c-bb73-6ea6789044f2','酬雲間僧見寄','徐集孫','宋','宋诗','song-poetry','','[]','一從湖上別，無處問相知。',48,'全唐诗/poet.song.223000.json','["一從湖上別，無處問相知。", "幾夜頻馳夢，今朝忽寄詩。", "山昏雲過濕，院靜鶴歸遲。", "此去秋風近，應須動客思。"]'),
('532f33bd-3ae9-4ee7-992b-1d1a5f9ea257','謝林可山序詩','徐集孫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','不枉西湖住兩年，窮吟活計又成編。',32,'全唐诗/poet.song.223000.json','["不枉西湖住兩年，窮吟活計又成編。", "生平不得春風力，只與梅花結得緣。"]'),
('9abc40b9-1984-4dc4-882b-47d40546c460','送僧之毗陵','徐集孫','宋','宋诗','song-poetry','','[]','無意坐林叢，雲飛天四空。',48,'全唐诗/poet.song.223000.json','["無意坐林叢，雲飛天四空。", "禪心包影外，客夢艣聲中。", "勝負機何密，窮通算儘工。", "此行應不錯，知遇有詩翁。"]'),
('136f34ff-455e-4ba6-8eb3-2e66205662c5','雨作','徐集孫','宋','宋诗','song-poetry','','[]','薰風入斷籬，猶自雨凄凄。',48,'全唐诗/poet.song.223000.json','["薰風入斷籬，猶自雨凄凄。", "數日無人過，終朝共鶴棲。", "雲濃山寺失，水汎板橋低。", "亦有田堪秫，何時得荷犁。"]'),
('738c511a-6400-40e2-934e-a67ea5e069b0','爲瘦巖僧題西山爽氣','徐集孫','宋','宋诗','song-poetry','','[]','背却殘陽翠欲流，一窗長占四時秋。',32,'全唐诗/poet.song.223000.json','["背却殘陽翠欲流，一窗長占四時秋。", "逼人風露衣巾脆，拄笏朝來獨倚樓。"]'),
('12b40f50-32a6-46c1-8927-936ad0c69413','紫笑','徐集孫','宋','宋诗','song-poetry','','[]','雨濕晴烘乃破慳，時聞旖旎度簷間。',32,'全唐诗/poet.song.223000.json','["雨濕晴烘乃破慳，時聞旖旎度簷間。", "不知失笑緣何事，每對薰風自赭顔。"]'),
('8c81202a-4d3e-4c58-9409-862bbc7064b3','客懷','徐集孫','宋','宋诗','song-poetry','','[]','衣袂半埃塵，堪嗟白髮新。',48,'全唐诗/poet.song.223000.json','["衣袂半埃塵，堪嗟白髮新。", "古今同逆旅，湖海未歸人。", "雨霽船爭渡，花飛鳥怨春。", "片雲千里迥，日日謾烹鱗。"]'),
('a8d1ba3d-4f3b-4d27-8099-ba2e80a801ba','月夜泛湖','徐集孫','宋','宋诗','song-poetry','','[]','買得扁舟載月明，喜它簫鼓巳歸城。',64,'全唐诗/poet.song.223000.json','["買得扁舟載月明，喜它簫鼓巳歸城。", "一襟風露清吟骨，四望湖山見道情。", "花港採菱供果飣，蘋洲擷荇薦杯行。", "此歡不許人多得，破曉西村雞犬鳴。"]'),
('7d8b0331-d508-4a61-82d0-efff948b4a47','靜中','徐集孫','宋','宋诗','song-poetry','','[]','靜中白日十分遲，喚起鄉心怯子規。',64,'全唐诗/poet.song.223000.json','["靜中白日十分遲，喚起鄉心怯子規。", "客味有如杯水淡，宦情肯被一塵緇。", "瓶儲餘粟緣供鶴，俸乏零金爲買詩。", "坐久不禁春雨暗，誰家樓上笛頻吹。"]'),
('5f901577-48ee-43b6-acbf-f161ea750166','午夢','徐集孫','宋','宋诗','song-poetry','','[]','篇詩纔欠急忙償，似有奚奴督和章。',64,'全唐诗/poet.song.223000.json','["篇詩纔欠急忙償，似有奚奴督和章。", "望斷曉山雲破碎，驚回午夢雨淋浪。", "春光一半歸楊柳，花事三分屬海棠。", "靜坐小窗人語寂，閒聽梁燕話行藏。"]'),
('a03d61f0-55ae-467f-9103-cdefcf16dad6','蝸牛','徐集孫','宋','宋诗','song-poetry','','[]','分岐頭角出於天，盤泊委蛇巧並緣。',32,'全唐诗/poet.song.223000.json','["分岐頭角出於天，盤泊委蛇巧並緣。", "到了升高翻墜失，徒然陰地肆垂涎。"]'),
('c82d7c09-0965-41b7-b0c6-43603b905e1e','末利菊','徐集孫','宋','宋诗','song-poetry','','[]','瑶華細簇翠廉纖，耐得籬邊曉露淹。',32,'全唐诗/poet.song.223000.json','["瑶華細簇翠廉纖，耐得籬邊曉露淹。", "晚節清香猶更好，雖名末利不趨炎。"]'),
('897c2ef9-3bfc-4cb5-b2dc-c326f63f04f3','杜北山同石峰僧來訪','徐集孫','宋','宋诗','song-poetry','','[]','梅花同伴瘦，一瘦有誰過。',48,'全唐诗/poet.song.223000.json','["梅花同伴瘦，一瘦有誰過。", "歲事那堪晚，心期未易多。", "杯深和月吸，硯冷带冰磨。", "山暝歸鴉急，相分獨奈何。"]'),
('dfc0e08f-40aa-4282-973e-c8668a8b9ac2','謝偃溪惠索淘','徐集孫','宋','宋诗','song-poetry','','[]','與客敲詩倚古松，亂蟬聲裏夕陽舂。',32,'全唐诗/poet.song.223000.json','["與客敲詩倚古松，亂蟬聲裏夕陽舂。", "幾年飯顆山頭瘦，槐葉今朝得飽供。"]'),
('277cccbd-88e0-4967-bfb8-5b8825ce7cd9','題贈命士','徐集孫','宋','宋诗','song-poetry','','[]','富貴功名世競癡，清吟往往不趨時。',32,'全唐诗/poet.song.223000.json','["富貴功名世競癡，清吟往往不趨時。", "請君多算公卿命，莫要逢人舉似詩。"]'),
('537ad3bc-4ecb-40cd-95d6-361c972a514f','挽靈隠僧玨月窗','徐集孫','宋','宋诗','song-poetry','','[]','秋月只清輝，窗明人不歸。',48,'全唐诗/poet.song.223000.json','["秋月只清輝，窗明人不歸。", "嘔心成宿病，蛻骨悟前非。", "書偈辭禪院，緘衾寄母闈。", "猿啼泉石冷，客淚爲君揮。"]'),
('65686c6f-0912-41b5-8bf8-18c75e229a58','牧溪上人爲作戲墨因賦二首 鷺','徐集孫','宋','宋诗','song-poetry','','[]','宿葦臨流去就輕，生平慣與爾同盟。',32,'全唐诗/poet.song.223000.json','["宿葦臨流去就輕，生平慣與爾同盟。", "相從奚假歸圖畫，特畫江湖一段清。"]'),
('8cd2bcd1-9d29-4299-8003-af44b3935efe','牧溪上人爲作戲墨因賦二首 猿','徐集孫','宋','宋诗','song-poetry','','[]','峭壁懸崖隠趣深，每來洞口費呼尋。',32,'全唐诗/poet.song.223000.json','["峭壁懸崖隠趣深，每來洞口費呼尋。", "啼雲嘯月聲難寫，只寫山林一片心。"]'),
('2d2fa621-5f58-46f6-a655-d10333939ab6','酬里中友人代簡韻','徐集孫','宋','宋诗','song-poetry','','[]','鬢絲冉冉負年華，客夢無時不在家。',32,'全唐诗/poet.song.223000.json','["鬢絲冉冉負年華，客夢無時不在家。", "吟得新詩三百首，却慚籬下見黄花。"]'),
('85204da6-19d3-42c0-b157-c008f6188f1d','古樂府','徐集孫','宋','宋诗','song-poetry','','[]','郎別二十春，未報淮頭捷。',72,'全唐诗/poet.song.223000.json','["郎別二十春，未報淮頭捷。", "空房守節心，羞見雙胡蝶。", "滴淚寫臙脂，欲寄南雁羣。", "恐蕩郎客思，封了却還焚。", "妾甘奉姑老，妾甘育子穉。", "它日晝錦歸，願郎無棄置。"]'),
('0fa55091-b8a7-499f-8dd7-7fd56d4f0ef2','言事','徐集孫','宋','宋诗','song-poetry','','[]','讀了南華枕曲肱，無端客夢冷偏增。',64,'全唐诗/poet.song.223000.json','["讀了南華枕曲肱，無端客夢冷偏增。", "官將滿去多逃吏，詩不吟來少寄僧。", "亂葉打窗貓上案，斜陽過屋鼠窺燈。", "孤山在望何時雪，問訊梅花策瘦藤。"]'),
('7d90190f-d2f7-4fa6-ab2a-aa2397ca685e','挽李山房','徐集孫','宋','宋诗','song-poetry','','[]','吟譽先君者，多埋葛嶺傍。',48,'全唐诗/poet.song.223000.json','["吟譽先君者，多埋葛嶺傍。", "幾年千里客，一夕九原傷。", "琴硯遺兒遠，棺衾得友償。", "玉樓天上事，應有舊山房。"]'),
('2549b39e-3fd2-4c39-aeab-bf9b018cfc7f','鄭渭濱過訪而杜北山諸友繼至惜乎招石峰月溪二禪不來','徐集孫','宋','宋诗','song-poetry','','[]','未見南枝與北枝，一清誰可話襟期。',64,'全唐诗/poet.song.223000.json','["未見南枝與北枝，一清誰可話襟期。", "不嫌添客重行酒，所欠惟僧共說詩。", "竹影因風和雀動，水聲带雨啟鷗疑。", "黄昏緊閉寒扉坐，自展韋編對伏犧。"]'),
('929c9484-f406-40c1-b81e-ffe11156b44a','采蓮曲','徐集孫','宋','宋诗','song-poetry','','[]','朝露濕妾衣，暮霞耀妾矚。',72,'全唐诗/poet.song.223000.json','["朝露濕妾衣，暮霞耀妾矚。", "一葉小如瓜，去住無拘束。", "兀棹歌採菱，襲襲薰風足。", "蘆葉映港清，捉對鴛鴦浴。", "蓮中有苦心，欲折手還曲。", "折蓮恐傷藕，藕斷絲難續。"]'),
('61644a7f-68c8-4b58-ada6-cfa9af168b62','菊','徐集孫','宋','宋诗','song-poetry','','[]','寂寂東籬姿，淒彼霜露濕。',36,'全唐诗/poet.song.223000.json','["寂寂東籬姿，淒彼霜露濕。", "不肯出春風，俗眼豈相入。", "世無陶靖節，此趣誰收拾。"]'),
('504fea10-82db-4f75-8099-98c6df7c692a','蘭','徐集孫','宋','宋诗','song-poetry','','[]','淡淡九畹質，雅好住山林。',36,'全唐诗/poet.song.223000.json','["淡淡九畹質，雅好住山林。", "幽香不求知，伯夷叔齊心。", "世道不復古，紉佩取騷吟。"]'),
('decef830-5d03-4c1f-a47a-86f67a554f07','自君之出矣','徐集孫','宋','宋诗','song-poetry','','[]','自君之出矣，蛾眉不復掃。',24,'全唐诗/poet.song.223000.json','["自君之出矣，蛾眉不復掃。", "寶鑑委埃塵，玉容爲誰好。"]'),
('babe8d9c-b40e-4a43-8985-e5f76c691552','堅冰','徐集孫','宋','宋诗','song-poetry','','[]','滕六巧呈瑞，平白一尺高。',96,'全唐诗/poet.song.223000.json','["滕六巧呈瑞，平白一尺高。", "霜風凜烈生，挾夜聲如號。", "冰澌條玉筯，瓦縫鏡銀膏。", "茆簷頓暴富，掩映何奢豪。", "晶光動閭里，健羨等兒曹。", "此時輕脆資，堅謂千載牢。", "一旦陽明升，消泮蔑纖毫。", "奚獨此爲然，世事亦滔滔。"]'),
('11e54b83-9b23-4df8-ad84-081d90f538fb','閑賦','徐集孫','宋','宋诗','song-poetry','','[]','梅花白向鬢根生，歲月蹉跎事欠成。',64,'全唐诗/poet.song.223000.json','["梅花白向鬢根生，歲月蹉跎事欠成。", "讀過故書溫有味，借來新絮冷無情。", "未霜山寺昏鍾勁，欲霽湖亭夕照明。", "多少紅塵留滯客，可曾歸去力春耕。"]'),
('4e4995f5-56c9-48b9-8743-3eed7689ac6b','渡湖','徐集孫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','漠漠西湖匝野煙，夕陽柳下買歸船。',32,'全唐诗/poet.song.223000.json','["漠漠西湖匝野煙，夕陽柳下買歸船。", "關心一紙平安報，雁字縱橫寫碧天。"]'),
('550de7c5-d653-4c2c-adff-f674816d72ef','官舍庭前古梅尋常開拶歲暮余整歸裝而乃蚤花不容自默','徐集孫','宋','宋诗','song-poetry','','[]','猙獰古怪虬龍枝，著花傳舍賓歲晚。',196,'全唐诗/poet.song.223000.json','["猙獰古怪虬龍枝，著花傳舍賓歲晚。", "往往來來幾番人，老大相期疑未諼。", "顧我冷眼慣相看，嗅花嚼蕊當餐飯。", "橫斜峭拔耐雪霜，肯媚陽和齊婉娩。", "把酒邀月共說詩，疎影上衣成繾綣。", "朔風吹夢入家山，鼓舞倦矣客兮返。", "誰謂花先常歲期，澈夜萬葩玉一本。", "花應有心餞我行，吐芳非爲冬日煖。", "我亦逆知此花意，孤潔難與俗人混。", "似嫌托根富貴場，不若棲身山林穩。", "惜乎花只不能言，一花一心誠懇懇。", "任它世間競酣桃李春，花獨與我結交歲寒遠。"]'),
('436f4fcc-e25d-451f-8132-6180eb54f40a','秋胡行','徐集孫','宋','宋诗','song-poetry','','[]','五年行邁兮歸遲遲，採桑山陰兮奉親慈。',106,'全唐诗/poet.song.223000.json','["五年行邁兮歸遲遲，採桑山陰兮奉親慈。", "冰霜自潔兮清節持，有客遺金兮志不移。", "橐有金兮盍專爲母馳，心悅桑女下車兮人可知。", "庭中見妾兮徒忸怩，載思往事兮妾心孔悲。", "君不如妾之有節兮言姑已而，君不知孝兮世道衰，妾不死兮欲何爲。"]'),
('879c2687-9143-4d33-90d4-d3b594081b8f','賦雪','徐集孫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','漫天飄瑞壓囂塵，一夜西湖幻出銀。',64,'全唐诗/poet.song.223000.json','["漫天飄瑞壓囂塵，一夜西湖幻出銀。", "煎入茶鐺清肺腑，吟歸詩句爽精神。", "糝填鶴跡看旋沒，封合梅花認不真。", "茅舍竹籬猶富貴，長安安得有貧民。"]'),
('8fe58154-4b1b-445c-9e18-d27c14421962','寄里中社友','徐集孫','宋','宋诗','song-poetry','','[]','欠作故人書，侵尋半載餘。',48,'全唐诗/poet.song.223000.json','["欠作故人書，侵尋半載餘。", "窮吟雖各自，入夢不相疎。", "梅蕊通春信，霜風促歲除。", "待余歸故里，鷗約復如初。"]'),
('fbf9e1b9-a567-4b21-bb43-67318ddb6a97','孤山訪鄭渭濱不值','徐集孫','宋','宋诗','song-poetry','','[]','寂寞石琴臺，香雲撥不開。',48,'全唐诗/poet.song.223000.json','["寂寞石琴臺，香雲撥不開。", "多知騎鶴出，自欲買舟來。", "葑岸春回草，山亭雨謝梅。", "懷人成悵惘，日暮惜空回。"]'),
('dc821e91-2ca5-4281-8335-68f2b5fef018','本心參政約游西山分韻得頂字','徐集孫','宋','宋诗','song-poetry','','[]','僕僕事行役，度盡千峯頂。',168,'全唐诗/poet.song.223000.json','["僕僕事行役，度盡千峯頂。", "恣覽亦云倦，困卧殊未醒。", "西爽俄見要，前約欲重訂。", "結習若猶在，寧復計兩脛。", "天際豁輕陰，溪頭橫短艇。", "摇手謝籃輿，信步蹋荒徑。", "適意自忘遠，迷途誰爲詗。", "此翁平生意，故自畧畦町。", "何妨一笑回，呼童催煮茗。", "兩年已三至，我如飫五鼎。", "無乃大屬厭，徒欲逃酩酊。", "老筆忽先倡，高標誰與並。", "尚記去載游，金碧光炯炯。", "何處非吾鄉，一氣相溟涬。"]'),
('21e8feee-2acf-4048-b675-aeea36da668a','余種竹方成扁其室曰竹所友人以詩至用其韻','徐集孫','宋','宋诗','song-poetry','','[]','屋老苔荒席久虛，近分一榻與雲俱。',64,'全唐诗/poet.song.223000.json','["屋老苔荒席久虛，近分一榻與雲俱。", "梅花未種招蜂怨，竹所雖青欠鶴圖。", "無事看山如對客，有時隠几亦忘吾。", "過門除却能吟者，不是高僧即老儒。"]'),
('9687e8bb-9196-447d-85d0-9f24af458ce9','句','徐集孫','宋','宋诗','song-poetry','','[]','莫言滿眼無知己，耐久黄花是故人。',16,'全唐诗/poet.song.223000.json','["莫言滿眼無知己，耐久黄花是故人。"]'),
('37feadd4-26eb-4b30-a90c-53d01eef4c93','山行','趙立','宋','宋诗','song-poetry','','[]','愛殺瀟湘境，山行知幾重。',48,'全唐诗/poet.song.223000.json','["愛殺瀟湘境，山行知幾重。", "風清秋思重，雲淡曉陰濃。", "隔水時呼艇，經崖自策筇。", "巖扃聊問訊，把酒欠從容。"]'),
('ce5a2c45-1df6-404f-9ad6-0bceb5963b6e','飛狐','趙立','宋','宋诗','song-poetry','','[]','舞毒山中誇巨蟒，問經巖下化靈狐。',32,'全唐诗/poet.song.223000.json','["舞毒山中誇巨蟒，問經巖下化靈狐。", "不知昨夜飛鳴處，曾報溪翁到此無。"]'),
('f0997b50-ca36-4637-b334-1b770497046d','山谷碑','趙立','宋','宋诗','song-poetry','','[]','長記兒童膝下時，便聞山谷澹巖詩。',32,'全唐诗/poet.song.223000.json','["長記兒童膝下時，便聞山谷澹巖詩。", "江湖老矣瀟湘過，始得摩挲石罅碑。"]'),
('0fbc8ac8-883f-4357-b962-3bd8660f630a','雷神碑','趙立','宋','宋诗','song-poetry','','[]','此洞當年本祀雷，棟梁見我忽傾摧。',32,'全唐诗/poet.song.223000.json','["此洞當年本祀雷，棟梁見我忽傾摧。", "寺僧爲報山靈說，不用驚疑俗客來。"]'),
('3756372a-1815-42e4-869c-b0073bf9d116','丹鑪藥臼','趙立','宋','宋诗','song-poetry','','[]','巖中二子已飛仙，藥臼丹鑪尚儼然。',32,'全唐诗/poet.song.223000.json','["巖中二子已飛仙，藥臼丹鑪尚儼然。", "無奈故鄉心正切，末由此地結清緣。"]'),
('70398028-6b93-4565-adee-2108dafd0e25','石井','趙立','宋','宋诗','song-poetry','','[]','酌泉石井喜無涯，喜與貪泉隔嶺西。',32,'全唐诗/poet.song.223000.json','["酌泉石井喜無涯，喜與貪泉隔嶺西。", "况有中秋明夜月，輕舟同載下浯溪。"]'),
('31a5f675-99ad-4c9d-b2e4-32beff8808a5','觀石魚嗣劉忠順韻','劉叔子','宋','宋诗','song-poetry','','[]','啣尾洋洋石上鎸，或依于藻或依蓮。',64,'全唐诗/poet.song.223000.json','["啣尾洋洋石上鎸，或依于藻或依蓮。", "夢占周室中興日，刻自唐人多歷年。", "隠見有時非强致，豐凶當歲必開先。", "太平誰謂真無象，罩罩還歌樂與賢。"]'),
('e913e6c4-25bc-4ddf-bb0a-5943d668341e','題石魚','蹇材望','宋','宋诗','song-poetry','','[]','何代潛鱗翠琰鎸，雙雙依藻更依蓮。',64,'全唐诗/poet.song.223000.json','["何代潛鱗翠琰鎸，雙雙依藻更依蓮。", "夢符端報屢豐兆，物盛宜歌大有年。", "玉燭調和從可卜，金刀題詠又開先。", "渾如潑剌波心躍，感召還知太守賢。"]'),
('832ca873-9b4a-4bff-9a2d-e04bc723b8fd','秀野亭','郭閶','宋','宋诗','song-poetry','','[]','插漢森森萬丈扶，一亭危瞰汨江隅。',64,'全唐诗/poet.song.223000.json','["插漢森森萬丈扶，一亭危瞰汨江隅。", "幽深石壁涵清泚，崒嵂雲山引翠蕪。", "變化陰晴詩作料，招呼豪傑酒爲徒。", "客來莫擬閒居賦，後有千年八陣圖。"]'),
('fc9a7697-af63-4ae6-a2dc-4dc5842c2e1c','白華巖','俞掞','宋','宋诗','song-poetry','','[]','風剪飛絲雨脚殘，半山虛曠九秋寒。',32,'全唐诗/poet.song.223000.json','["風剪飛絲雨脚殘，半山虛曠九秋寒。", "洗開萬里乾坤眼，更上蒼巖頂上看。"]'),
('60837244-f77e-4984-8340-44701ed87ff2','三巖','俞掞','宋','宋诗','song-poetry','','[]','三巖之下有賢良，暮史朝經萬卷長。',32,'全唐诗/poet.song.223000.json','["三巖之下有賢良，暮史朝經萬卷長。", "樹老山空人已盡，烱然千古姓名香。"]'),
('dfaba7fb-11e1-4980-b4fe-90b75d796fa3','六石峰','俞掞','宋','宋诗','song-poetry','','[]','劚石雲邊著著高，幾經吟筆寫風騷。',32,'全唐诗/poet.song.223000.json','["劚石雲邊著著高，幾經吟筆寫風騷。", "山翁莫袖經綸手，好趁春風釣六鼇。"]'),
('3b24b031-d59b-4c49-a42f-fbd9d057d45d','浯溪  其一','俞掞','宋','宋诗','song-poetry','','[]','大唐有頌到浯溪，翠蘚蒼崖古畫垂。',32,'全唐诗/poet.song.223000.json','["大唐有頌到浯溪，翠蘚蒼崖古畫垂。", "西望函關今萬里，淡煙斜日幾荒碑。"]'),
('5c84326f-c40c-4e83-8c8f-ef06a1b21fba','浯溪  其二','俞掞','宋','宋诗','song-poetry','','[]','宋朝一統舊江山，南北中分已百年。',32,'全唐诗/poet.song.223000.json','["宋朝一統舊江山，南北中分已百年。", "壯士不須誇此頌，健提椽筆上燕然。"]'),
('edf5020d-ebae-4e7a-b71b-2c45291e0db9','軍山','張顯','宋','宋诗','song-poetry','','[]','亂石如羣羊，合沓千里奔。',72,'全唐诗/poet.song.223000.json','["亂石如羣羊，合沓千里奔。", "軍山屹當前，盤踞作虎蹲。", "巨鎮壓坤維，層巔白雲屯。", "下瞰大溪流，三尺清不渾。", "舟人落風帆，繫纜前山根。", "我欲摘星斗，懸崖那可捫。"]'),
('b924980d-fb0b-4381-ab24-6a02065d54c3','吳興舟中','盧鉞','宋','宋诗','song-poetry','','[]','笠澤高風寒凜凜，苕溪凝雪白皚皚。',32,'全唐诗/poet.song.223000.json','["笠澤高風寒凜凜，苕溪凝雪白皚皚。", "扁舟我獨乘歸興，自是不因安道來。"]'),
('0de3d7f4-155a-4fce-b838-70314db3dae7','投壺','盧鉞','宋','宋诗','song-poetry','','[]','離騷課罷便投壺，長日身心得自娛。',32,'全唐诗/poet.song.223000.json','["離騷課罷便投壺，長日身心得自娛。", "多少論籌閑殿最，始終中節定工夫。"]'),
('2eb0816c-0950-45d6-a2b2-d60e789a0633','和太傅平章魏公咸淳庚午冬大雪遺安撫潛侍郎  其一','盧鉞','宋','宋诗','song-poetry','','[]','天花六出瑞午林，公溥明通造化心。',64,'全唐诗/poet.song.223000.json','["天花六出瑞午林，公溥明通造化心。", "農望豐年知兆朕，物涵生意總懷任。", "兔圍奕奕誇圭璧，薇戍霏霏詠昔今。", "擎重老枝長玉立，主張陽類杜群陰。"]'),
('8cfa61dd-50ba-4720-a174-b65b912431fc','和太傅平章魏公咸淳庚午冬大雪遺安撫潛侍郎  其二','盧鉞','宋','宋诗','song-poetry','','[]','底用封書禱梵林，瑞霙先臘感由心。',64,'全唐诗/poet.song.223000.json','["底用封書禱梵林，瑞霙先臘感由心。", "豫知農畝宜禾稼，復喜邊儲足輦任。", "民樂齊宮誇往昔，捷歌周戍屬斯今。", "燮調妙造推元老，治象陽明無伏陰。"]'),
('6f4afa9a-1b03-4425-8a9d-e9592009c228','姑蘇臺覽古','盧鉞','宋','宋诗','song-poetry','','[]','姑蘇臺下百花洲，解語香魂此舊遊。',64,'全唐诗/poet.song.223000.json','["姑蘇臺下百花洲，解語香魂此舊遊。", "巧笑已傾吳子國，淺顰又涴范公舟。", "湖山四顧無奇骨，五霸俱空等拙謀。", "杯酒酹江應自誓，男兒西北有神州。"]'),
('cc15f005-0558-4e6c-9a37-e71135e3df9a','送汪水雲入湘','吳仁傑','宋','宋诗','song-poetry','','[]','碧水波翻海亦摧，奮身鰲背護蓬萊。',64,'全唐诗/poet.song.223000.json','["碧水波翻海亦摧，奮身鰲背護蓬萊。", "忍隨天上紅雲散，却馭關中紫氣回。", "天道有常須變化，元關無鑰任敲推。", "携琴更拜蒼梧野，□想南薰入調來。"]'),
('98f063d5-c2a4-4541-9356-2a6ee0174d58','句','魯仕能','宋','宋诗','song-poetry','','[]','萬劫灰中存世界，千層浪裏惜儒珍。',16,'全唐诗/poet.song.223000.json','["萬劫灰中存世界，千層浪裏惜儒珍。"]'),
('1a100b4c-4c94-400f-a220-5b7b565057de','金精歌','趙崇懌','宋','宋诗','song-poetry','','[]','東風飛霖雨，一洗桃李塵。',259,'全唐诗/poet.song.223000.json','["東風飛霖雨，一洗桃李塵。", "快馬紫遊韁，來賞金精春。", "連林翠氣妙不動，時作佛髻螺頭青。", "劖劖天壁面削起，中可建旗坐萬人。", "豁然呀呀，怫然憑憑。", "蹲蹲者爲虎豹，兀兀者爲墉城。", "千年老狖學春吟，白日龍雷藏樹陰。", "蓮花峰下久無路，時有樵子攀藤尋。", "丹光出屋水涔涔，白鶴飛去棲桃林。", "桃今幾熟枝尚青，石田玉子無龍耕。", "雲蒸甑腹爛青{飠卂}，雪凍地骨迷黄精。", "靈君久矣鞭玉麟，今作天上何公卿。", "崖前老竹屢生米，夜有石犬當階鳴。", "我亦三生家石鼓，花落花開不知數。", "人間漁沫吹秦橋，漫有姓名刻洞府。", "試爲靈君覓杯水，水中白晝青虬起。", "便令紫霧生風霆，一舉直上九萬里。"]'),
('21828537-2e3b-4fd4-922d-2cd656cdb178','和太師平章賈魏公咸淳庚午冬大雪遺安撫潛侍郎','曹元發','宋','宋诗','song-poetry','','[]','乾坤滿眼盡琪林，擎玉詩傳魏國心。',64,'全唐诗/poet.song.223000.json','["乾坤滿眼盡琪林，擎玉詩傳魏國心。", "寫琰已增天府重，掌冰匪媿地官任。", "三千界內清無際，數十年來瑞獨今。", "喜雪未幾還喜雨，老農歌舞愛春陰。"]'),
('5d151da5-1a0e-46e0-b7bc-a268be52e690','題龜峰詞後','陳合','宋','宋诗','song-poetry','','[]','西晉風流自一家，憶君魂夢到梅花。',32,'全唐诗/poet.song.223000.json','["西晉風流自一家，憶君魂夢到梅花。", "梅花深處無人迹，明月一枝霜外斜。"]'),
('be5115d6-dbe3-4980-ad2a-8232999befab','摇摇花行','章采','宋','宋诗','song-poetry','','[]','摇摇花，長安城南道。',175,'全唐诗/poet.song.223000.json','["摇摇花，長安城南道。", "小草欣欣造物勻，三月來來野田好。", "女郎厭踏王孫園，出郊更覺春嫣然。", "五家蹙成錦繡谷，雙鬟妙舞玳瑁筵。", "合歡扇裁七寶月，蔭步蓋簇空青天。", "分司自訟狂驚坐，拾遺勸我莫近前。", "此時摇摇絕低小，媚紫得映車閒鈿。", "幸承踏歌羅襪暖，偶荷細摘春心憐。", "豈如黄土岡頭古柟樹，花開花落無人覷。", "一枝折頓固弗班，五陵雋賞初何預。", "嗚呼世無賞音兮竟大奇，古柟蒼蒼雲雨垂。"]'),
('081b6425-149b-4363-bd09-5bfaa258ddf6','秋日過清江傅聘君石溪隠居','章采','宋','宋诗','song-poetry','','[]','有美人如玉，招尋故意長。',48,'全唐诗/poet.song.223000.json','["有美人如玉，招尋故意長。", "山衣猶芰製，野飯只菰粱。", "秋入遥空白，霜飛一葉黄。", "年年三徑裏，來往有求羊。"]'),
('e3aa44f4-14c8-4e96-90ef-afecf6c7568b','九江庾樓作  其一','章采','宋','宋诗','song-poetry','','[]','去晉千年後，風流尚庾郎。',48,'全唐诗/poet.song.223000.json','["去晉千年後，風流尚庾郎。", "地收三楚大，天過兩淮長。", "北望驚塵暗，西歸短髮蒼。", "空留江上月，夜夜照興亡。"]'),
('3ea68e15-7c25-4615-a4ae-f96a9af7e9b9','九江庾樓作  其二','章采','宋','宋诗','song-poetry','','[]','結架思梁日，登臨憶漢年。',48,'全唐诗/poet.song.223000.json','["結架思梁日，登臨憶漢年。", "佳遊驚我老，孤思爲誰牽。", "春水江湖大，夕陽天地偏。", "萋萋青草外，何處是秦川。"]'),
('dabd3e3b-257c-4234-abd8-e6c1f8b59a62','發興','章采','宋','宋诗','song-poetry','','[]','主靜觀心妙，耽奇發興長。',48,'全唐诗/poet.song.223000.json','["主靜觀心妙，耽奇發興長。", "蘭邊招翡翠，梧下待鸞凰。", "天地東風綠，江湖西日黄。", "靈修猶浩蕩，誰與玩瓊芳。"]'),
('e3ec7ab6-8bbb-4103-ac21-3f992fb66127','武昌南樓懷古','章采','宋','宋诗','song-poetry','','[]','青虬修士去遒遒，黄鶴飛仙苒苒遊。',64,'全唐诗/poet.song.223000.json','["青虬修士去遒遒，黄鶴飛仙苒苒遊。", "北望日邊秦樹遠，西來雪外蜀江浮。", "吳時宮殿千年夢，晉國風塵萬里愁。", "今古茫茫無限事，月明倚遍庾公樓。"]'),
('1a649bf0-f15c-4d58-ae2c-a3e06991911b','滕王閣','章采','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','佩玉鳴鑾一笑空，至今華觀疊青穹。',64,'全唐诗/poet.song.223000.json','["佩玉鳴鑾一笑空，至今華觀疊青穹。", "西山殘雨虹腰白，南浦驕陽雁背紅。", "幾度登臨添感慨，半生漂泊老英雄。", "檻前猶是唐年水，曾見王郎泛短篷。"]'),
('12a4849b-2db0-42de-b0e2-3e97c1be16e3','武昌江漢亭憶南軒','章采','宋','宋诗','song-poetry','','[]','亭下雙來綠玉虯，岷嶓萬里會吳頭。',64,'全唐诗/poet.song.223000.json','["亭下雙來綠玉虯，岷嶓萬里會吳頭。", "江穿南北天心過，漢接東西地脈流。", "水上龍爭方一夢，山中鵲起已千秋。", "張劉精爽知何在，安得同來賦遠遊。"]'),
('3b6fa701-6f03-4e54-8bfb-1e319145cec2','別鄂倅趙有孚','章采','宋','宋诗','song-poetry','','[]','芙蓉花下把離觴，江漢秋生夕漲涼。',64,'全唐诗/poet.song.223000.json','["芙蓉花下把離觴，江漢秋生夕漲涼。", "騕褭神駒行地急，迢遥仙鶴去天長。", "蜀兵未解星辰赤，淮哨將來日月黄。", "近世平戎無好手，請陳上策獻君王。"]'),
('39add158-2455-4d55-9dea-925450d083c9','花樹','章采','宋','宋诗','song-poetry','','[]','風吹花樹昨朝紅，今日看花樹已空。',32,'全唐诗/poet.song.223000.json','["風吹花樹昨朝紅，今日看花樹已空。", "可惜天高花薄命，年年開落只由風。"]'),
('79b4f903-2536-4b55-b1b0-cbbe7f329daf','學易齋','章粲','宋','宋诗','song-poetry','','[]','天目鑒孤明，地籟奠衆響。',84,'全唐诗/poet.song.223000.json','["天目鑒孤明，地籟奠衆響。", "慮淡世欲輕，性復道心長。", "斂襟步前庭，手執周易往。", "得知三畫初，真契貫穹壤。", "圖書詣其微，精實超惚恍。", "啟蒙析其義，端倪見俯仰。", "九京如可作，舍此吾安放。"]'),
('b4f240f8-eb8b-4289-9f91-b830d37f7c42','題楊總卿鹿岡菴','章粲','宋','宋诗','song-poetry','','[]','客行鹿岡暮，四顧秋滿目。',48,'全唐诗/poet.song.223000.json','["客行鹿岡暮，四顧秋滿目。", "澗碧烟草滋，林黄霜橘熟。", "歸鳥各東西，啼螿相斷續。", "愁心浩難留，故山正幽獨。"]'),
('71f34421-e523-457e-a3fa-8f3a4fd85286','秋日懷松溪趙宰經父','章粲','宋','宋诗','song-poetry','','[]','晴窗靜繙書，凝塵掩行迹。',48,'全唐诗/poet.song.223000.json','["晴窗靜繙書，凝塵掩行迹。", "花影晝簾閒，苔痕秋徑寂。", "憑高招遠風，緣流弄寒碧。", "緘情寄天涯，杳杳江閩隔。"]'),
('bb6f1613-e25e-4d71-b153-9c5d1df2bcc2','湖上游矚寄家兄','章粲','宋','宋诗','song-poetry','','[]','花霧壓晴埃，柳風蕩暄濁。',48,'全唐诗/poet.song.223000.json','["花霧壓晴埃，柳風蕩暄濁。", "錢塘佳麗地，春華大堤曲。", "幽禽粲林白，野水明湖綠。", "清賞遠難期，懷哉美如玉。"]'),
('d92fbc08-9876-40ed-a860-491f6d67a190','豫章寄家兄','章粲','宋','宋诗','song-poetry','','[]','雨時山色深，雨餘山意醒。',48,'全唐诗/poet.song.223000.json','["雨時山色深，雨餘山意醒。", "千山萬山閒，秋風雁聲冷。", "澄江浄秋思，明霞炯秋影。", "遥想大雲心，華觴誰與領。"]'),
('d2bd28a0-5f6b-4155-8ad5-9e975ae6a18d','春日憶平陽郡博士大雲心兄','章粲','宋','宋诗','song-poetry','','[]','東風歸林園，雲日靉春事。',48,'全唐诗/poet.song.223000.json','["東風歸林園，雲日靉春事。", "靜觀化道伸，良感幽貞利。", "烟芳生暮愁，晴思起新思。", "有酒誰見同，惻惻夜亡寐。"]'),
('77dd2011-a1fa-41ad-a569-0053049940f5','春日效韋體','章粲','宋','宋诗','song-poetry','','[]','新綠灩晴池，涓涓泉脈動。',48,'全唐诗/poet.song.223000.json','["新綠灩晴池，涓涓泉脈動。", "東風度花梢，春音入禽哢。", "而我理羣書，朋儔罕迎送。", "翛然愜心期，此樂誰能共。"]'),
('b2809a01-b503-4741-9d54-81b9dff22af9','豫章宋都官聲父樓上','章粲','宋','宋诗','song-poetry','','[]','結架鬰岧嶢，登眺齊近遠。',48,'全唐诗/poet.song.223000.json','["結架鬰岧嶢，登眺齊近遠。", "江湖萬頃秋，風烟四山晚。", "心賞地曾妍，目行天不盡。", "振衣聊消摇，閒看雲舒卷。"]'),
('6c25912b-0051-4dbc-956c-7713ad8a4cac','詠二疏','章粲','宋','宋诗','song-poetry','','[]','人生白駒過，世態蒼狗變。',120,'全唐诗/poet.song.223000.json','["人生白駒過，世態蒼狗變。", "紛紛慕跖蹻，寥寥志務卞。", "赫赫王侯居，翕翕富貴戀。", "翠蓋擁游雲，朱鞍曜驚電。", "金張財力豪，許史名聲衒。", "滔滔利欲波，卓卓見所見。", "長揖萬乘君，玄髮謝朝弁。", "行人相歎咨，羣公遥祖餞。", "高風振朝野，流光照史傳。", "嗟嗟紳緌士，來者宜知勸。"]'),
('a7f6c2f5-5fe1-45d2-b192-28d2d0f8084b','絜矩書院示學子','章粲','宋','宋诗','song-poetry','','[]','四時配四德，元亨利與貞。',288,'全唐诗/poet.song.223000.json','["四時配四德，元亨利與貞。", "天德元最重，方春木主生。", "夏火物暢茂，是爲德之亨。", "金利秋向實，水貞冬日成。", "既貞又爲元，循環未嘗停。", "天高而地下，陰降復陽升。", "氣理本同運，天人特異名。", "性情即理氣，其義明且精。", "元亨利貞理，因時有足徵。", "生長斂藏氣，依理常偕行。", "仁禮義知性，一初同聖氓。", "惻隠至羞惡，辭讓是非情。", "天人二而一，如射中鵠正。", "奈何天無心，人欲易纏縈。", "無心自無妄，通復皆一誠。", "吁嗟其有欲，天理隨榛荆。", "殘忍仁斧斤，貪冒義蝗螟。", "禮失之綿蕞，知止於絜缾。", "天人一而二，如水分渭涇。", "大哉古聖人，一念天是承。", "仰觀俯以察，天降地上騰。", "夭桃華灼灼，好鳥鳴嚶嚶。", "木德自此盛，我心惟和平。", "恢炱行熾景，是月陰陽爭。"]'),
('3bf0bac6-3d3d-46f5-bf89-1ebd0b5c1102','別楊尊','章粲','宋','宋诗','song-poetry','','[]','遠遊同是客，執別兩情牽。',48,'全唐诗/poet.song.223000.json','["遠遊同是客，執別兩情牽。", "天地愁眉破，山林歸夢圓。", "西行迷蜀道，北望黯淮邊。", "馬上封侯事，相期在少年。"]'),
('76406af4-b025-462a-b249-846b65aa97f2','重陽後送謹常兄之符離','章粲','宋','宋诗','song-poetry','','[]','嶺外分携處，離觴話遠途。',48,'全唐诗/poet.song.223000.json','["嶺外分携處，離觴話遠途。", "黄花看不足，寒雁去何孤。", "農圃非吾業，衣冠本世儒。", "應當重行止，無使世氛汙。"]'),
('cc51a08d-019f-4ba2-97a7-cfe62de83c1e','敬賦大人竹林真隠之圖','章粲','宋','宋诗','song-poetry','','[]','野草閒花競賞音，蕭然坐閲歲年深。',64,'全唐诗/poet.song.223000.json','["野草閒花競賞音，蕭然坐閲歲年深。", "當貞固日知高節，只靜虛中見本心。", "何處乾坤無鳳集，他時風雨有龍吟。", "向來七子皆充隠，不止山王累晉林。"]'),
('2edafbea-1f2c-426f-9907-df4f963ce3fe','題蘇子瞻書天慶觀乳泉賦帖','王亞夫','宋','宋诗','song-poetry','','[]','蘇公早聞道，文章乃其戲。',48,'全唐诗/poet.song.223000.json','["蘇公早聞道，文章乃其戲。", "乳泉出重海，作賦聊記異。", "玉池嚥中夜，挈瓶非小智。", "氣者水之生，此語可深味。"]'),
('eb2cc772-de9b-4ae5-9ce5-71fba6acd3ba','十七字謠','臨安里人','宋','宋诗','song-poetry','','[]','光祖做總領，許堪爲節制。',21,'全唐诗/poet.song.223000.json','["光祖做總領，許堪爲節制。", "丞相要起復，援例。"]'),
('ab79e09a-1031-44b0-b504-10d0425240e0','祖庭觀丁歌','王奕','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','吾祖河汾文中氏，受恩未報夫子靈。',384,'全唐诗/poet.song.223000.json','["吾祖河汾文中氏，受恩未報夫子靈。", "末孫願言無忝爾，幸際天地還清寧。", "奔波水陸數千里，袖香今得拜祖庭。", "天欲使觀周禮在，時哉巧值開上丁。", "北方學者曹博士，新膺上命來交承。", "聖門不敢負所學，事事必欲行六經。", "爾時己丑八月朔，大中門闢天微明。", "左開毓粹右觀德，燈毬燦爛交流星。", "奎文閣下爇柴燎，柏林鳩鵲爭飛鳴。", "金絲堂前班引出，笙鏞隠隠金石聲。", "三氏諸孫列左右，皎潔宿鷺排圓汀。", "各崇尊長例就位，深衣徵及江南生。", "禮官三請詣磬所，朱扉咿𠵣開中扃。", "太常金樂交佚奏，秩秩籩豆環簪纓。", "首從先聖告祝後，鄒兖次第彝罇傾。", "却詣齊國父母廟，泗沂分配隨重輕。", "五賢推尊孔道者，俎豆亦得陳其誠。", "春秋天下祀文廟，太常四丁惟魯行。", "青衿白髮老學校，觀丁未有如斯榮。", "儼然清都聽雅樂，耳目變換心神驚。", "南門禮畢飲福胙，公堂交錯飛兕觴。", "飲餘獨立杏壇下，予懷縹緲欣嘅并。", "恭惟素王師萬世，道如日月行天晴。", "幾年讀易坐甕牖，景仰闕里真蓬瀛。"]'),
('baeddee4-51a5-4a40-bcd5-6b621c221ae4','八月八日偕廟學教授曹彥禮及孔顔孟三氏諸孫童齊集遊逵泉到沂水緬想風雩之樂余乃浴沂作詠歸歌','王奕','宋','宋诗','song-poetry','','[]','浴乎沂，潄乎逵，晞予髮兮二水之湄。',77,'全唐诗/poet.song.223000.json','["浴乎沂，潄乎逵，晞予髮兮二水之湄。", "風飄飄兮吹衣，高門出兮雩門歸。", "千八百年之下兮何時，得躡遐蹤兮逶迤，欣嘅交集兮眇黄唐之莫追。", "已而已而，逝者如斯兮予將何之。"]'),
('95e80d9d-3ba9-4dd8-8be6-9090444497f5','八月望日深衣抱高廟御琴首歌南風繼作憶顔三氏諸孫環立以聽爲杏壇一時之盛千古之下令人憮然作歌云','王奕','宋','宋诗','song-poetry','','[]','秋日暉暉兮槐市成林，白鳩關關兮漢柏陰陰。',83,'全唐诗/poet.song.223000.json','["秋日暉暉兮槐市成林，白鳩關關兮漢柏陰陰。", "杏壇高兮幾尋，奠桂酒兮孤斟。", "蒼梧不可呼兮猶得抱南風之琴。", "哀顔夭之不永兮，傷哉兮遺音，契千古兮遐心。", "歸兮歸兮，乃今不負吾衣之深。"]'),
('01dd6fcb-b2a0-4398-a8ad-df8038370de5','孔廟既拜之後又不遠三百里過泰山過汶河壯哉斯遊上日觀作賓日歌少發葵戀之私','王奕','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','日月東行天左旋，丸中久矣知乾圜。',387,'全唐诗/poet.song.223000.json','["日月東行天左旋，丸中久矣知乾圜。", "稔聞泰山有日觀，竊疑板墨多夸傳。", "甚言抱雞候其上，雞鳴海水如炊煎。", "火輪磨蕩上復下，崖撞石裂聲填填。", "天門鐘皷報清曉，塵世正爾沉元元。", "幾回掩卷信且惑，安得臂羽如飛仙。", "誰知白髮際同軌，得來鄒魯拜聖賢。", "竟遊曲阜至岱嶽，捫參歷井登其巔。", "濯足就宿會真殿，如乘析木棲微垣。", "是時八月二十夜，明月正值奎婁躔。", "窗明斗落懼失曉，一宵十起無寧眠。", "偕行諸子大鼾睡，笑我歷轆狂且顛。", "深衣端坐愈不寐，湔腸滌胃玉女泉。", "少需道人謂予曰，若欲觀日今當前。", "忙迷扶策抉草莽，翩躚攙奪諸公前。", "諸公拍手笑於後，被公吞了丹砂元。", "{⻊盤}跣一氣涉觀頂，隠隠紅罅開東邊。", "玄雲荏苒幻紫色，金樓寶闕蒸瓊田。", "秋深露重濕我趾，扶桑望决眼欲穿。", "須臾眉黛抹天杪，脫然寶鏡開微奩。", "上上下下復上下，千辛萬苦方團圓。", "小臣不敢瞠目視，九拜塌額肝膽懸。", "起來恍惚抱影泣，昔何容易沉虞淵。", "羲和湎淫失賓餞，掩覆白日爲元天。"]'),
('42f60b16-5434-456b-834b-f64359df9d9f','金餘元遺山來拜祖庭有紀行十首遂倚歌之先後殊時感慨一也 和元遺山一首','王奕','宋','宋诗','song-poetry','','[]','魯橋卸淮舸，淖塗歷蓁蕪。',144,'全唐诗/poet.song.223000.json','["魯橋卸淮舸，淖塗歷蓁蕪。", "翠嶧倚天末，髣髴東南隅。", "薄暮曲紀城，三清敞仙居。", "平原積磥砢，靈河鳴泉珠。", "小徑斗折上，行與狐兔俱。", "循崖索斯篆，恍惚東封書。", "叢巔集蓮瓣，巖巖瞰青徐。", "正途盡茅塞，正爾宜羊車。", "蚌珍不蔽美，岧嶢到枌榆。", "南門肅孟廟，冠袂先摳趨。", "氣大夙有配，邾少不必都。", "盥既覿慈靖，擇師誰復如。"]'),
('40a2dd6b-e966-41ec-afde-1ee307b88cdb','金餘元遺山來拜祖庭有紀行十首遂倚歌之先後殊時感慨一也 和元遺山二首','王奕','宋','宋诗','song-poetry','','[]','高垣門十一，云是魯城基。',84,'全唐诗/poet.song.223000.json','["高垣門十一，云是魯城基。", "浮浮化荆榛，孔廟存威儀。", "奎門出浩蕩，杏壇歷逶迤。", "古今帝王所，形仆影即隨。", "人間此天闕，可望不可躋。", "詩書壽老壁，孫子綿遺規。", "杲杲不可尚，百世當前知。"]'),
('752bef6d-e1d9-458e-b604-cedec1855bf7','金餘元遺山來拜祖庭有紀行十首遂倚歌之先後殊時感慨一也 和元遺山三首','王奕','宋','宋诗','song-poetry','','[]','聖人與天遊，擇地豈必巧。',144,'全唐诗/poet.song.223000.json','["聖人與天遊，擇地豈必巧。", "袤延十里林，老翠鎮盤繞。", "斧斤不可尋，兵劫不能燎。", "翁仲儼冠带，麟虎峙强矯。", "書生拜風木，起立九腸攪。", "築室今不多，馳蹕古應少。", "春秋泉壤幽，日月天地曉。", "洙橋一線流，滲注入萬沼。", "入陵見金椀，公相計不早。", "父乾兮母坤，白骨無壽夭。", "啣冤絕歸鶴，誰復訢華表。", "九原信可作，兩觀事未了。"]'),
('24cf2d7e-73df-44e8-9a6d-eba22b84a550','金餘元遺山來拜祖庭有紀行十首遂倚歌之先後殊時感慨一也 和元遺山四首','王奕','宋','宋诗','song-poetry','','[]','西偏顔樂園，屋角接聖境。',144,'全唐诗/poet.song.223000.json','["西偏顔樂園，屋角接聖境。", "想當坐忘時，聰明盡黜屏。", "上植松數株，下種麻千頃。", "蛛網結秋絲，綿密藏廢井。", "東連勝果寺，元此誕莊穎。", "象教剝牀膚，所事終不永。", "興亡有定在，雖帝不可請。", "緬想書雲時，五色垂燦炳。", "三家浚深井，錄訖水亦冷。", "卓卓正憲祠，蒸嘗猶定省。", "金縢宗老心，復辟直要領。", "照影弔伯禽，抱渴空望綆。"]'),
('71e0f581-b094-489a-b6f1-d2eba7b67e42','金餘元遺山來拜祖庭有紀行十首遂倚歌之先後殊時感慨一也 和元遺山五首','王奕','宋','宋诗','song-poetry','','[]','高門連曲沼，上有泮宮臺。',120,'全唐诗/poet.song.223000.json','["高門連曲沼，上有泮宮臺。", "芹藻莽不復，菰蒲弄風埃。", "靈光突其右，荒穢良可哀。", "兩阜爪距地，驅車儼臨淮。", "雞蟲爭得失，擾擾胡爲哉。", "何如袖春服，行歌與時偕。", "我來晞白髮，歸詠同此懷。", "柴桑志童冠，寤寐須偕來。", "酌逵洗逸盼，雅趣孰此偕。", "步雩習風腋，自覺聰明開。"]'),
('efd9e163-bcf7-4d0c-a9d3-455cbd49f040','金餘元遺山來拜祖庭有紀行十首遂倚歌之先後殊時感慨一也 和元遺山六首','王奕','宋','宋诗','song-poetry','','[]','壯哉景陵宮，龜屭極神猛。',120,'全唐诗/poet.song.223000.json','["壯哉景陵宮，龜屭極神猛。", "洪惟大庭庫，制度合雄騁。", "聖世尚封崇，功擬天地並。", "中天怪事發，靈長轉俄頃。", "我登望嶽臺，一慨心自領。", "涿鹿策奇勳，自謂出天幸。", "大運旋丸棋，捧首歸舊鼎。", "富貴積金臺，礎礫揜營屏。", "倘無六籍在，詎免胥狒獷。", "下土位人上，奈何不深儆。"]'),
('86ed9331-1418-4168-96f5-4dff9dd2ff16','金餘元遺山來拜祖庭有紀行十首遂倚歌之先後殊時感慨一也 和元遺山七首','王奕','宋','宋诗','song-poetry','','[]','雞豚隣柵翁，盼盼延允譜。',120,'全唐诗/poet.song.223000.json','["雞豚隣柵翁，盼盼延允譜。", "仲尼土萬世，豈必志百畝。", "誰知弗父何，讓德報以魯。", "蟻穴幾王侯，林廟此其所。", "東周禮樂心，豈不在文武。", "大器信有神，予奪孰敢侮。", "郟鄏鼎鉉雄，弱臂竟莫舉。", "大厦庇生民，雲仍合分廡。", "詩禮世其傳，嘉種無莽鹵。", "庭趨揖鬚眉，返此末代古。"]'),
('5bd389b7-ecfa-4fdd-9d9d-3ecffdd23a4d','金餘元遺山來拜祖庭有紀行十首遂倚歌之先後殊時感慨一也 和元遺山八首','王奕','宋','宋诗','song-poetry','','[]','荒荒望魯甸，姬孔廟粼粼。',144,'全唐诗/poet.song.223000.json','["荒荒望魯甸，姬孔廟粼粼。", "允祚五十代，顔孟東西鄰。", "旁求侍坐翁，草莽迷城闉。", "豈應髮膚體，竟此成湮淪。", "鏗爾續道韻，垂此天倫親。", "犁鋤供子職，猶裕耕鑿民。", "可能百世祀，不廟三省身。", "亦必有壇壝，尚稽廓荆榛。", "五賢配西序，餘瀝波楊荀。", "肥馬視輕服，此景良清新。", "微言苟不及，往迹亦易陳。", "安得沂水上，菊泉薦斯人。"]'),
('5183e87b-50e3-4b71-885b-ada283300cda','金餘元遺山來拜祖庭有紀行十首遂倚歌之先後殊時感慨一也 和元遺山九首','王奕','宋','宋诗','song-poetry','','[]','耕民昧帝力，焉用典與謨。',120,'全唐诗/poet.song.224000.json','["耕民昧帝力，焉用典與謨。", "奈何降衷後，氣稟分賢愚。", "天錫孔孟氏，一整綽有餘。", "廓哉鄒魯地，良足容軒車。", "皇皇七十國，轍迹何區區。", "誰知百世下，流作章句儒。", "掌股弄神器，敝屣直棄如。", "遂令桐梓地，盡化荆棘塗。", "昏林畏饞啖，秉燭來趨隅。", "巫咸倘可問，爲我還其初。"]'),
('216738e5-039a-4be6-9f38-c745409b10a2','金餘元遺山來拜祖庭有紀行十首遂倚歌之先後殊時感慨一也 和元遺山十首','王奕','宋','宋诗','song-poetry','','[]','人惟君與師，得在天地間。',108,'全唐诗/poet.song.224000.json','["人惟君與師，得在天地間。", "蜂蟻失所主，生息决不蕃。", "逐日渴未死，顧影悲余年。", "平生東魯心，皓首瞻聖賢。", "上下二千載，歷歷觀遺鎸。", "惜哉數墨子，想像成虛傳。", "十章紀大略，盡和遺山篇。", "忠腸攪葵漆，喉棘不忍言。", "持歸刻瑘石，何□勒燕然。"]'),
('213c53fb-85a0-4c3b-a57b-5d855cf8c79c','和杜少陵望嶽一首','王奕','宋','宋诗','song-poetry','','[]','封禪七十二，萬古事未了。',48,'全唐诗/poet.song.224000.json','["封禪七十二，萬古事未了。", "兩儀一開闢，三觀幾昏曉。", "自昔祖龍來，訖今歌鳳鳥。", "吾嘗登東山，魯亦未可小。"]'),
('4b9adca7-8447-4f44-ae5b-d4a917998f1e','和李太白泰山一首','王奕','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','泰山天地極，鄒魯聖賢關。',84,'全唐诗/poet.song.224000.json','["泰山天地極，鄒魯聖賢關。", "周匝二千里，卓然位其間。", "五文合泗水，八荒無競山。", "扶輿清淑運，日夜何曾閑。", "尼山連嶧阜，豈徒翠浮鬟。", "軒轅與羲皞，孔孟垂曾顔。", "正氣盡此出，高哉其可攀。"]'),
('9608a045-2769-404e-8e71-b04d888b2853','和元遺山太山古句','王奕','宋','宋诗','song-poetry','','[]','我來拜鄒魯，舟過歌鳳臺。',274,'全唐诗/poet.song.224000.json','["我來拜鄒魯，舟過歌鳳臺。", "登嶧仰東蒙，自謂高矣哉。", "及登東山頂，天級真難階。", "河瀆走罅漏，嵪陵塌埏垓。", "己大物自小，夙學得所諧。", "聖賢分地步，高下隨其材。", "於道既有覺，沿崖剔碑苔。", "七十二君者，謬迷良可哀。", "王侯鬨蟻穴，休王滋無涯。", "三千六百朞，治忽知幾回。", "悠哉身後史，聊爾生前杯。", "大塊囿軀殻，客氣行風雷。", "神功一收斂，非去亦非來。", "試出亭毒表，岱峰赤微埃。", "安得鐵柄箒，埽盡兀突堆。", "上下一無極，釋然暢虛懷。", "平明下山去，天門掛芒鞋。", "金童玉女夾道迎，鸞鈴鳳翟紅雲開。", "道逢明復與守道，拊肩携手歌崔嵬。", "謂予如欲看白日，請騎黄鵠同上無色空界外。", "蒼梧帝子正與彼，倏忽混沌高卧真蓬萊。"]'),
('b33fce59-7646-4839-8834-97aa49056801','和趙若倫舊題多景樓','王奕','宋','宋诗','song-poetry','','[]','大地山河合九州，秋風吹起故鄉愁。',64,'全唐诗/poet.song.224000.json','["大地山河合九州，秋風吹起故鄉愁。", "洛山冉冉機雲出，漢水瀟瀟巡遠羞。", "東望海連甘露寺，北來詩滿鎮江樓。", "金臺萬里天門杳，且問東津汶上舟。"]'),
('45622d29-5001-4bae-bfe6-de75183d2437','和羅隠詩再題多景樓','王奕','宋','宋诗','song-poetry','','[]','老了英雄費了吟，鹿兒化馬不消尋。',64,'全唐诗/poet.song.224000.json','["老了英雄費了吟，鹿兒化馬不消尋。", "死生壽夭蒼生命，治亂存亡上帝心。", "嶓塚西來山疊疊，焦金東望海深深。", "眼前參透坎中畫，始識恒河只寸涔。"]'),
('934c1ca6-a5fb-49f9-9bed-f1936f5e69bd','和盧疎齋多景樓韻','王奕','宋','宋诗','song-poetry','','[]','一合乾坤氣脈連，蜜甜本不揀中邊。',64,'全唐诗/poet.song.224000.json','["一合乾坤氣脈連，蜜甜本不揀中邊。", "幾千萬劫本同此，百八十年何間然。", "北固英雄前去古，中原文獻後來賢。", "老懷登此成欣感，日落蒼梧生紫烟。"]'),
('263341d1-0afe-450d-8fb4-cbe44c99067a','題北固亭','王奕','宋','宋诗','song-poetry','','[]','杜老當年識恨遺，與天爭漢死奚疑。',64,'全唐诗/poet.song.224000.json','["杜老當年識恨遺，與天爭漢死奚疑。", "伏羱猶憶分三日，老驥空悲混一時。", "往事竟隨東逝水，新題全是北來詩。", "如今多景樓頭酒，免得諸公賦黍離。"]'),
('a1e21fbf-57ac-4b0f-b47e-d787d723e05e','題焦山吸江亭','王奕','宋','宋诗','song-poetry','','[]','甲子三千六百朞，此山崒嵂起何時。',64,'全唐诗/poet.song.224000.json','["甲子三千六百朞，此山崒嵂起何時。", "雄吞海瀆金獅子，霸斷吳門鐵犍兒。", "水鏡照空三國恨，浪黿撞破六朝悲。", "後來儘有無窮事，留與他年再賦詩。"]'),
('a7f685b4-2bf1-43af-978f-9f90b1cfafac','題焦山客位','王奕','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','鎖斷長江鐵戶門，風帆雲海幾朝昏。',64,'全唐诗/poet.song.224000.json','["鎖斷長江鐵戶門，風帆雲海幾朝昏。", "能依佛教綿遺址，大勝焦家裕後昆。", "鶴骨已仙羲帖在，鰲身不動米碑存。", "住山傳得文殊印，遮莫前身是了元。"]'),
('9d9b598c-3e8c-4097-8af0-ca4acd074db5','題金山金鰲閣','王奕','宋','宋诗','song-poetry','','[]','誰橐紅爐鑄寶刀，闢開太極奠金鰲。',64,'全唐诗/poet.song.224000.json','["誰橐紅爐鑄寶刀，闢開太極奠金鰲。", "尾摇光岳星辰轉，背負乾坤日月勞。", "潮落潮生通氣息，帆來帆去動毫毛。", "不知南北車書混，此際翻身第幾遭。"]'),
('12e5dde8-af46-4ee1-9c68-e223045dbef2','書趙忠靖公祠堂','王奕','宋','宋诗','song-poetry','','[]','老臣將略服先零，撐拓淮江五十年。',64,'全唐诗/poet.song.224000.json','["老臣將略服先零，撐拓淮江五十年。", "不把壑舟移半夜，未應杞國墜中天。", "父奢既不慚諸葛，子括胡爲愧仲連。", "節義功名父兄在，摩挲豐碣重潸然。"]'),
('c6173bd2-837b-4677-a10d-5d1cbb4f2ff3','到揚州','王奕','宋','宋诗','song-poetry','','[]','仙去瓊花不見根，津橋明月共誰論。',64,'全唐诗/poet.song.224000.json','["仙去瓊花不見根，津橋明月共誰論。", "百餘載作江藩翰，十幾年來薊戶門。", "淮海樓頭諸老眼，平山堂外六軍魂。", "翻愁吳楚空遺彥，作史無人歲月昏。"]'),
('0f175edd-2916-456e-8b6a-968074a7a78b','題維揚','王奕','宋','宋诗','song-poetry','','[]','半生書劍走閩甌，三十年前欠此遊。',64,'全唐诗/poet.song.224000.json','["半生書劍走閩甌，三十年前欠此遊。", "赤脚有心尊魯國，白頭無力賦揚州。", "花明靴巷新番市，草暗城隅舊敵樓。", "橋上更無何遜迹，梅花明月爲誰留。"]');
